export const QUESTIONS = {

/* ──────────── A1 · CE ──────────── */
CE_A1: [
  {t:'mc',q:'Que signifie le mot "bonjour" ?',a:['Bonne nuit','Au revoir','Buenos días / Buenas tardes','Merci'],c:2,e:'"Bonjour" es el saludo más común del día. Se usa desde la mañana hasta la tarde. Por la noche se dice "bonsoir".'},
  {t:'mc',q:'Quel article est correct pour le mot "livre" (libro) ?',a:['la livre','le livre','les livre','un livres'],c:1,e:'"Livre" es masculino en francés → "le livre". Artículos: le (masc.), la (fem.), les (plural). Un/une para indefinidos.'},
  {t:'tf',q:'La phrase suivante est-elle vraie ?\n\n"La Tour Eiffel se trouve à Paris."',c:true,e:'¡Correcto! La Torre Eiffel está en París, en el Champ-de-Mars (7º arrondissement). Fue construida en 1889 por Gustave Eiffel.'},
  {t:'mc',q:'Quel est le pluriel correct de "un chat" ?',a:['un chats','des chat','des chats','les chats'],c:2,e:'Para el plural en francés: artículo "un/une" → "des" y se añade -s al sustantivo. "Un chat" → "des chats" (unos gatos).'},
  {t:'mc',passage:'Lisez ce texte :\n\n« Je m\'appelle Marie. J\'ai 8 ans. Je suis française. »',q:'Quel est l\'âge de Marie ?',a:['18 ans','80 ans','8 ans','28 ans'],c:2,e:'"J\'ai 8 ans" = tengo 8 años. En francés la edad se expresa con AVOIR: "Quel âge as-tu?" → "J\'ai X ans."'},
  {t:'mc',q:'Que signifie "merci" en espagnol ?',a:['S\'il vous plaît','Au revoir','Por favor','Gracias'],c:3,e:'"Merci" = gracias. La respuesta estándar es "de rien" (de nada) o "je vous en prie" (con mucho gusto, formal).'},
  {t:'match',q:'Associez chaque chiffre à son nom en français.',p:[['1','un'],['2','deux'],['3','trois'],['4','quatre']],e:'Los números cardinales básicos: 1=un, 2=deux, 3=trois, 4=quatre. Son la base para contar y decir horas, precios, etc.'},
  {t:'mc',q:'Quel jour vient APRÈS "mardi" dans la semaine ?',a:['lundi','jeudi','mercredi','vendredi'],c:2,e:'Semana: lundi(lun), mardi(mar), MERCREDI(mié), jeudi(jue), vendredi(vie), samedi(sáb), dimanche(dom).'},
  {t:'tf',q:'La phrase suivante est-elle vraie ?\n\n"Une" est un article féminin indéfini.',c:true,e:'"Une" = artículo indefinido femenino (una). "Un" = masculino (un). "Des" = plural. Ej: "un livre" vs "une table".'},
  {t:'mc',passage:'Lisez ce texte :\n\n« Je voudrais un café, s\'il vous plaît. »',q:'Que veut cette personne ?',a:['Un thé','Un café','De l\'eau','Un jus'],c:1,e:'"Je voudrais" = quisiera (condicional de vouloir). Es la forma educada de pedir: "Je voudrais + artículo + cosa".'},
  {t:'mc',q:'Que signifie "s\'il vous plaît" en espagnol ?',a:['Merci','Pardon','Por favor','Au revoir'],c:2,e:'"S\'il vous plaît" (formal) / "s\'il te plaît" (informal) = "por favor". Indispensable en cualquier interacción educada.'},
  {t:'tf',q:'La phrase suivante est-elle vraie ?\n\n"Février" est le deuxième mois de l\'année.',c:true,e:'Los meses: janvier(1), FÉVRIER(2), mars(3), avril(4), mai(5), juin(6), juillet(7), août(8), sept.(9), oct.(10), nov.(11), déc.(12).'},
  {t:'mc',passage:'Lisez cette affiche :\n\n« Fermé le dimanche. »',q:'Quand ce magasin est-il ouvert ?',a:['Le dimanche seulement','Jamais','Tous les jours sauf dimanche','Le week-end seulement'],c:2,e:'"Fermé le dimanche" = cerrado el domingo. Por tanto abre TODOS los días excepto el domingo. "Sauf" = excepto.'},
  {t:'mc',q:'Quel verbe complète correctement la phrase : "Elle ___ professeure."',a:['ai','suis','est','sont'],c:2,e:'Conjugación de "être" (ser/estar): je SUIS, tu ES, il/elle EST, nous SOMMES, vous ÊTES, ils/elles SONT.'},
  {t:'match',q:'Associez chaque couleur à sa traduction en espagnol.',p:[['rouge','rojo'],['bleu','azul'],['vert','verde'],['jaune','amarillo']],e:'Colores fundamentales: rouge=rojo, bleu=azul, vert=verde, jaune=amarillo. Los adjetivos de color van DESPUÉS del sustantivo.'},
  {t:'mc',q:'Que signifie "au revoir" en espagnol ?',a:['Bonjour','Bonne nuit','Hasta luego / Adiós','S\'il vous plaît'],c:2,e:'"Au revoir" = la despedida estándar. Lit: "hasta volver a verse". Informal: "salut", "tchao". Más formal: "au revoir, Madame".'},
  {t:'tf',q:'La phrase suivante est-elle vraie ?\n\n"Le chien" est un mot féminin en français.',c:false,e:'¡Falso! "Le chien" usa el artículo "le" → es MASCULINO. La forma femenina es "la chienne". Siempre observa el artículo para saber el género.'},
  {t:'mc',passage:'Lisez ce texte :\n\n« Bonjour! Je m\'appelle Paul. Je viens de Lyon. »',q:'D\'où vient Paul ?',a:['Paris','Marseille','Lyon','Bordeaux'],c:2,e:'"Je viens de" = vengo de. Pregunta: "D\'où viens-tu?" (¿De dónde eres?). Paul viene de Lyon, ciudad al sureste de París.'},
  {t:'mc',q:'Quel est le contraire de "grand" en français ?',a:['gros','vieux','petit','fort'],c:2,e:'Antónimos básicos: grand(e)/petit(e) (grande/pequeño), vieux/jeune (viejo/joven), fort/faible (fuerte/débil).'},
  {t:'tf',q:'La phrase suivante est-elle vraie ?\n\nEn français, on utilise toujours "tu" pour s\'adresser à son professeur.',c:false,e:'¡Falso! Con profesores, superiores y desconocidos adultos se usa "VOUS" (usted). "Tu" es el tuteo para amigos, familia y niños. ¡Error común en el TEF!'},
],

/* ──────────── A1 · CO ──────────── */
CO_A1: [
  {t:'mc',audio:'Bonjour, comment allez-vous ?',q:'Quelle salutation entendez-vous ?',a:['Bonsoir','Bonjour','Bonne nuit','Au revoir'],c:1,e:'"Bonjour" (buenos días/tardes) se distingue de "bonsoir" (buenas noches). Pronunciación: /bɔ̃.ʒuʁ/. El sonido "on" es nasal.'},
  {t:'mc',audio:'Il y a cinq livres sur la table.',q:'Combien de livres y a-t-il sur la table ?',a:['3','5','15','50'],c:1,e:'"Cinq" = 5. Pronunciado /sɛ̃k/. "Il y a" = hay (haber). Fórmula clave: "Il y a + número + cosa" para decir cuántos hay.'},
  {t:'mc',audio:'La voiture est rouge.',q:'De quelle couleur est la voiture ?',a:['bleue','verte','rouge','jaune'],c:2,e:'"Rouge" = rojo/roja. Los adjetivos de color se colocan DESPUÉS del sustantivo: "la voiture rouge" (no "la rouge voiture"). "Voiture" = auto/carro.'},
  {t:'mc',audio:'Aujourd\'hui, c\'est mercredi.',q:'Quel jour est-ce aujourd\'hui ?',a:['lundi','mardi','mercredi','vendredi'],c:2,e:'"Aujourd\'hui" = hoy. Pronunciado /o.ʒuʁ.dɥi/. "C\'est mercredi" = es miércoles. Nota el sonido /mɛʁ.kʁə.di/.'},
  {t:'mc',audio:'J\'ai un chien et deux chats.',q:'Combien d\'animaux a cette personne en tout ?',a:['1','2','3','4'],c:2,e:'1 chien + 2 chats = 3 animaux au total. "En tout" = en total. Escuchar y sumar: "un" (1) + "deux" (2) = trois (3).'},
  {t:'tf',audio:'Il fait froid aujourd\'hui et il neige.',q:'Entendez-vous qu\'il fait beau dans ce texte ?',c:false,e:'"Il fait froid" = hace frío. "Il neige" = está nevando. Opuesto de "il fait beau" (hace buen tiempo). Météo: beau, froid, chaud, nuageux, pluvieux.'},
  {t:'mc',audio:'Je m\'appelle Sophie. J\'ai vingt ans. Je suis étudiante.',q:'Quel est l\'âge de Sophie ?',a:['12 ans','20 ans','30 ans','25 ans'],c:1,e:'"Vingt" = 20. Pronunciado /vɛ̃/. La -t final no suena en "vingt" solo, pero sí en "vingt et un" (21). "Étudiante" = estudiante (femenino).'},
  {t:'mc',audio:'Le restaurant est fermé le lundi.',q:'Quel jour le restaurant est-il fermé ?',a:['le mardi','le dimanche','le lundi','le vendredi'],c:2,e:'"Fermé" = cerrado (participio pasado de "fermer"). "Le lundi" = los lunes (artículo definido con días = hábito/rutina).'},
  {t:'tf',audio:'Je voudrais un thé, s\'il vous plaît.',q:'La personne commande-t-elle un café ?',c:false,e:'La persona pidió "un thé" (té), NO "un café". En CO es crucial distinguir entre palabras similares: thé/café, lait/lait froid, etc.'},
  {t:'mc',audio:'Ma mère est médecin et mon père est professeur.',q:'Quelle est la profession du père ?',a:['médecin','professeur','ingénieur','avocat'],c:1,e:'"Mon père est professeur" = mi padre es profesor. "Ma mère est médecin" = mi madre es médica. Professions: sans article en francés (je suis médecin).'},
  {t:'mc',audio:'Tournez à gauche, puis continuez tout droit.',q:'Quelle est la PREMIÈRE direction indiquée ?',a:['tout droit','à droite','à gauche','en arrière'],c:2,e:'"Tournez à gauche" = gira a la izquierda. "Puis" = luego/después. Direcciones: à gauche (izq.), à droite (der.), tout droit (recto).'},
  {t:'tf',audio:'Nous sommes en décembre.',q:'Est-ce en été ?',c:false,e:'Décembre (diciembre) = invierno en el hemisferio norte. "L\'été" = verano (juin-août). "L\'hiver" = invierno (déc.-fév.). Saisons: printemps, été, automne, hiver.'},
  {t:'match',audio:'Associez chaque animal à son cri en français.',q:'Associez chaque animal au son qu\'il fait.',p:[['Le chat','Miaou'],['Le chien','Ouaf ouaf'],['La vache','Meuh'],['Le coq','Cocorico']],e:'Sonidos de animales en francés: chat→miaou, chien→ouaf, vache→meuh, coq→cocorico (¡el gallo francés dice "cocorico"!).'},
  {t:'mc',audio:'Bonjour madame, est-ce que vous avez du pain ?',q:'Que demande la personne ?',a:['Du lait','Du beurre','Du pain','Des fruits'],c:2,e:'"Du pain" = (del) pan. "Est-ce que vous avez...?" = ¿Tiene usted...? "Du" es el artículo partitivo (parte de algo). Pain=/pɛ̃/.'},
  {t:'mc',audio:'Il est huit heures du matin.',q:'Quelle heure est-il ?',a:['8h00','18h00','20h00','8h30'],c:0,e:'"Huit heures du matin" = las 8 de la mañana. "Du matin" (AM) vs "du soir" (PM). Horas: il est + heure(s). Huit=/ɥit/.'},
  {t:'tf',audio:'Je n\'aime pas le football.',q:'Cette personne aime-t-elle le football ?',c:false,e:'"Je n\'aime pas" = no me gusta. La negación rodea el verbo: NE...PAS. Je N\'aime PAS = negación clara. ¡Atención a "ne" que puede sonar suave!'},
  {t:'mc',audio:'Pardon, où est la bibliothèque, s\'il vous plaît ?',q:'Que cherche cette personne ?',a:['L\'hôpital','La gare','Le restaurant','La bibliothèque'],c:3,e:'"Bibliothèque" = biblioteca. Pronunciado /bi.blio.tɛk/. "Pardon" se usa para dirigirse a alguien o pedir disculpas. "Où est...?" = ¿Dónde está...?'},
  {t:'tf',audio:'Nous avons trois enfants : deux filles et un garçon.',q:'Y a-t-il plus de filles que de garçons dans cette famille ?',c:true,e:'2 filles > 1 garçon → sí, hay más niñas. "Enfants" = niños/hijos. "Filles" = niñas/hijas. "Garçon" = niño/hijo. "Plus de X que de Y".'},
  {t:'mc',audio:'Le chat est sous la table.',q:'Où se trouve le chat ?',a:['Sur la table','Derrière la table','Devant la table','Sous la table'],c:3,e:'Preposiciones de lugar: sur (sobre), sous (debajo), devant (delante de), derrière (detrás de), dans (dentro de), entre (entre).'},
  {t:'match',audio:'Écoutez et associez les salutations à leur contexte d\'utilisation.',q:'Associez chaque salutation à son moment d\'utilisation.',p:[['Bonjour','Matin et après-midi'],['Bonsoir','Le soir'],['Bonne nuit','Avant de dormir'],['Salut','Entre amis']],e:'Contexto de saludos: Bonjour (mañana-tarde), Bonsoir (tarde-noche, al encontrarse), Bonne nuit (al acostarse), Salut (informal, entre conocidos).'},
],

/* ──────────── A1 · EE ──────────── */
EE_A1: [
  /* ── FILL (1-10) ── */
  {t:'ee',mode:'fill',q:'Complétez avec la bonne forme du verbe "être" :\n\n« Je ___ Marie. »',a:'suis',alt:['SUIS'],e:'Conjugación de ÊTRE: je SUIS, tu ES, il/elle EST, nous SOMMES, vous ÊTES, ils/elles SONT. Es el verbo más importante del francés.'},
  {t:'ee',mode:'fill',q:'Choisissez le bon article indéfini masculin :\n\n« ___ café, s\'il vous plaît. »',a:'Un',alt:['un','UN'],e:'Articles indéfinis: UN (masc. sing.), UNE (fém. sing.), DES (pluriel). "Café" est masculin → "un café". Attention: "un thé", "une eau".'},
  {t:'ee',mode:'fill',q:'Mettez ce mot au pluriel :\n\n« un livre → des ___ »',a:'livres',alt:['LIVRES'],e:'Pluriel régulier: on ajoute -S. un livre → des livres. Les articles changent aussi: un/une → des. Exceptions: un bal→bals, un genou→genoux.'},
  {t:'ee',mode:'fill',q:'Traduisez ce mot en français :\n\n« Thank you »',a:'Merci',alt:['merci','MERCI'],e:'"Merci" = gracias. Réponses: "de rien" (de nada), "je vous en prie" (con mucho gusto, formal). Prononciation: /mɛʁ.si/.'},
  {t:'ee',mode:'fill',q:'Complétez avec le contraire de "froid" :\n\n« En été, il fait ___ . »',a:'chaud',alt:['CHAUD'],e:'Météo: froid (frío) ↔ chaud (caluroso). Saisons: printemps, ÉTÉ (verano), automne, hiver. "Il fait chaud/froid" = hace calor/frío.'},
  {t:'ee',mode:'fill',q:'Écrivez le résultat en lettres :\n\n« Cinq + trois = ___ »',a:'huit',alt:['HUIT'],e:'Nombres: 1=un, 2=deux, 3=trois, 4=quatre, 5=cinq, 6=six, 7=sept, 8=HUIT, 9=neuf, 10=dix. Huit se prononce /ɥit/.'},
  {t:'ee',mode:'fill',q:'Écrivez le contraire de "grand" :\n\n« Il est ___ (≠ grand). »',a:'petit',alt:['petite','PETIT','PETITE'],e:'Antónimos A1: grand/petit, vieux/jeune, fort/faible, beau/laid, content/triste. Los adjetivos se acuerdan en género y número.'},
  {t:'ee',mode:'fill',q:'Complétez cette formule de départ :\n\n« ___ revoir ! »',a:'Au',alt:['au','AU'],e:'"Au revoir" = au + revoir (a + volver a ver). Au = à + le (contractión). Informal: Salut!, Tchao! Formal: Au revoir, Madame/Monsieur.'},
  {t:'ee',mode:'fill',q:'Donnez la forme féminine de ce mot :\n\n« un acteur → une ___ »',a:'actrice',alt:['ACTRICE'],e:'Féminin irrégulier: acteur→actrice, directeur→directrice, chanteur→chanteuse, serveur→serveuse. Régulier: ami→amie, étudiant→étudiante.'},
  {t:'ee',mode:'fill',q:'Pour parler poliment à quelqu\'un qu\'on ne connaît pas, on utilise le pronom : ___',a:'vous',alt:['VOUS','Vous'],e:'VOUS = vouvoiement (usted). TU = tutoiement (amigos, familia, niños). En el TEF oral y escrito, siempre VOUS con desconocidos.'},
  /* ── WRITE (11-20) ── */
  {t:'ee',mode:'write',q:'Rédigez 2-3 phrases pour vous présenter.',prompt:'Donnez votre prénom, votre âge et votre pays d\'origine.',criteria:['Mention du prénom avec "Je m\'appelle"','Âge avec le verbe avoir ("J\'ai... ans")','Origine avec "Je viens de..."'],model:'Je m\'appelle Ana. J\'ai 28 ans. Je viens du Mexique et je suis mexicaine.',e:'Formules: "Je m\'appelle..." (prénom), "J\'ai... ans" (âge avec AVOIR), "Je viens de..." (origen). C\'est la base du TEF oral et écrit.'},
  {t:'ee',mode:'write',q:'Décrivez la météo d\'aujourd\'hui en 2 phrases.',prompt:'Utilisez: il fait beau/froid/chaud, il pleut, il neige, il y a du soleil...',criteria:['Au moins une expression météo correcte','Verbe conjugué à la 3e personne','2 phrases minimum'],model:'Aujourd\'hui il fait beau et il fait chaud. Le ciel est bleu et il n\'y a pas de nuages.',e:'Météo A1: "Il fait beau/chaud/froid", "Il pleut" (llueve), "Il neige" (nieva), "Il y a du vent/du soleil" (hay viento/sol).'},
  {t:'ee',mode:'write',q:'Passez une commande dans un café en français.',prompt:'Commandez 1 boisson et 1 nourriture en utilisant des formules de politesse.',criteria:['Formule de politesse (s\'il vous plaît)','Une boisson mentionnée','Une nourriture mentionnée'],model:'Bonjour ! Je voudrais un café et un croissant, s\'il vous plaît. Merci !',e:'"Je voudrais" (quisiera) est plus poli que "je veux". Formule complète: Bonjour + commande + s\'il vous plaît + merci.'},
  {t:'ee',mode:'write',q:'Écrivez un court message pour vous excuser d\'être en retard.',prompt:'SMS ou note à un ami ou un collègue, 2-3 phrases.',criteria:['Formule d\'excuse (désolé/e, pardon)','Raison du retard mentionnée','Formule finale'],model:'Désolé(e), je suis en retard ! Il y a un problème avec le bus. J\'arrive dans 10 minutes. À tout de suite !',e:'"Désolé(e)" = lo siento. "Je suis en retard" = llego tarde. "À tout de suite" = hasta ahorita/ya voy.'},
  {t:'ee',mode:'write',q:'Décrivez votre famille en 2-3 phrases.',prompt:'Mentionnez 2-3 membres de la famille, leur relation et une caractéristique.',criteria:['Membres de la famille nommés','Adjectif ou description inclus','Verbe conjugué correctement'],model:'J\'ai un frère et une sœur. Mon frère s\'appelle Carlos, il est grand et sympa. Ma sœur est petite et très drôle.',e:'Famille: père, mère, frère, sœur, mari/femme, fils/fille, grand-père, grand-mère. Adjectifs: grand, petit, sympa, gentil, drôle.'},
  {t:'ee',mode:'write',q:'Écrivez les jours de la semaine dans l\'ordre, en commençant par lundi.',prompt:'Listez les 7 jours. Pas de majuscule en français pour les jours.',criteria:['7 jours listés','Ordre correct (lundi en premier)','Sans majuscule (optionnel)'],model:'Lundi, mardi, mercredi, jeudi, vendredi, samedi, dimanche.',e:'Semaine française: commence par LUNDI (no Sunday). Les jours n\'ont pas de majuscule en français. À mémoriser pour le TEF.'},
  {t:'ee',mode:'write',q:'Rédigez une question polie pour demander le prix d\'un vêtement dans un magasin.',prompt:'Utilisez une formule de politesse et une question sur le prix.',criteria:['Formule de politesse (excusez-moi)','Question sur le prix','Ton approprié'],model:'Excusez-moi, combien coûte cette veste, s\'il vous plaît ? Quel est le prix de ce manteau ?',e:'"Combien coûte...?" = ¿Cuánto cuesta? "Quel est le prix de...?" = ¿Cuál es el precio? "Excusez-moi" para dirigirse a alguien.'},
  {t:'ee',mode:'write',q:'Saluez votre voisin le matin et demandez comment il va.',prompt:'Rédigez un bref échange de 2-3 phrases.',criteria:['Salutation appropriée (bonjour)','Question sur l\'état (comment allez-vous?)','Réponse incluse'],model:'Bonjour Monsieur Dupont ! Comment allez-vous ? — Très bien, merci ! Et vous ? — Bien également, merci !',e:'"Comment allez-vous?" (formal) / "Comment vas-tu?" (informal). Réponse standard: "Très bien, merci ! Et vous/toi?"'},
  {t:'ee',mode:'write',q:'Remplissez cette fiche d\'identité : Prénom, Nom, Âge, Nationalité.',prompt:'Utilisez vos vraies informations ou des données inventées.',criteria:['Prénom et Nom renseignés','Âge avec chiffre ou lettres','Nationalité en français'],model:'Prénom : Marie  |  Nom : Durand  |  Âge : 30 ans  |  Nationalité : canadienne',e:'Nationalités féminines: française, canadienne, espagnole, mexicaine, brésilienne. Masculines: français, canadien, espagnol...'},
  {t:'ee',mode:'write',q:'Terminez cet email formel avec une formule de politesse.',prompt:'Écrivez 1-2 phrases de clôture pour un email adressé à un employeur.',criteria:['Formule de politesse formelle','Ton respectueux','Signature ou prénom'],model:'Je vous remercie de l\'attention portée à ma candidature. Cordialement, Marie Dupont.',e:'Clôtures formelles: "Cordialement" (más usado), "Bien à vous" (semi-formal), "Salutations distinguées" (muy formal). Évitez "Bisous" (très informel)!'},
],

/* ──────────── A1 · EO ──────────── */
EO_A1: [
  /* ── REPEAT (1-8) ── */
  {t:'eo',mode:'repeat',q:'Répétez cette phrase de présentation à voix haute :',model:'Bonjour ! Je m\'appelle [votre prénom]. Enchanté(e) !',keywords:['bonjour','appelle','enchanté'],e:'Formule d\'introduction TEF oral. Intonation montante sur "Bonjour". "Enchanté(e)" = mucho gusto. Gardez un ton naturel et clair.'},
  {t:'eo',mode:'repeat',q:'Répétez cette question à voix haute avec la bonne intonation :',model:'Quel temps fait-il aujourd\'hui ?',keywords:['temps','fait','aujourd'],e:'Intonation montante en fin de phrase interrogative (tipo TEF). "Quel" = qué/cuál. "Fait-il" = inversion sujeto-verbo para preguntas formales.'},
  {t:'eo',mode:'repeat',q:'Répétez les jours de la semaine à voix haute dans l\'ordre :',model:'Lundi, mardi, mercredi, jeudi, vendredi, samedi, dimanche.',keywords:['lundi','mardi','mercredi','vendredi'],e:'Pronunciación: lundi=/lœ̃.di/, mardi=/maʁ.di/, mercredi=/mɛʁ.kʁə.di/. Marque une légère pause entre chaque jour.'},
  {t:'eo',mode:'repeat',q:'Répétez les chiffres de 1 à 10 à voix haute :',model:'Un, deux, trois, quatre, cinq, six, sept, huit, neuf, dix.',keywords:['deux','trois','cinq','huit','dix'],e:'Pronunciación clave: cinq=/sɛ̃k/, six=/sis/, sept=/sɛt/, huit=/ɥit/, neuf=/nœf/, dix=/dis/. Los nasales (in, an, on) son difíciles.'},
  {t:'eo',mode:'repeat',q:'Répétez cette demande de direction à voix haute :',model:'S\'il vous plaît, où se trouve la gare ?',keywords:['plaît','trouve','gare'],e:'"Où se trouve...?" = ¿Dónde se encuentra? Sinónimo: "Où est...?" (más simple). "S\'il vous plaît" siempre al inicio o final.'},
  {t:'eo',mode:'repeat',q:'Répétez cette commande au café à voix haute :',model:'Je voudrais un café et un croissant, s\'il vous plaît.',keywords:['voudrais','café','croissant','plaît'],e:'"Je voudrais" = quisiera (condicional de vouloir). Más educado que "je veux". Siempre terminar con "s\'il vous plaît" en el TEF oral.'},
  {t:'eo',mode:'repeat',q:'Répétez cette formule de rencontre à voix haute :',model:'Enchanté(e) de faire votre connaissance.',keywords:['enchanté','connaissance'],e:'"Enchanté(e)" = mucho gusto. "De faire votre connaissance" = de conocerle. Muy formal, frecuente en situaciones TEF de presentación.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase pour demander de répéter à voix haute :',model:'Excusez-moi, je ne comprends pas. Pouvez-vous répéter, s\'il vous plaît ?',keywords:['excusez','comprends','répéter'],e:'Esencial en el oral TEF: "Je ne comprends pas" (no entiendo). "Pouvez-vous répéter?" (¿Puede repetir?). No tener miedo de pedirlo.'},
  /* ── ANSWER (9-15) ── */
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Comment vous appelez-vous ? »',model:'Je m\'appelle [votre prénom et nom].',keywords:['appelle','m\'appelle'],e:'"Je m\'appelle + prénom". Jamais "je suis appelé" (error común). "Mon nom est..." aussi acceptable. Réponse toujours en phrase complète.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Quel âge avez-vous ? »',model:'J\'ai [votre âge] ans.',keywords:['ai','ans'],e:'Structure: "J\'ai + chiffre + ans". AVOIR (no être) para la edad. Jamais "je suis X ans" → erreur très fréquente! Âge=AVOIR en français.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« D\'où venez-vous ? »',model:'Je viens de [votre pays ou ville].',keywords:['viens','de'],e:'"Je viens de + pays féminin": France, Espagne, Colombie. "Je viens du + pays masculin": Mexique, Canada. "Je viens de + ville": Paris.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Quelle est votre profession ? »',model:'Je suis [votre profession].',keywords:['suis','travaille'],e:'"Je suis + profession" sans article: "je suis médecin" (NO "je suis un médecin"). Autres: étudiant(e), professeur, ingénieur, infirmier/ière.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Quel temps fait-il aujourd\'hui ? »',model:'Il fait beau / Il fait froid / Il pleut / Il neige...',keywords:['fait','il','temps'],e:'Météo orale A1: "Il fait beau/chaud/froid", "Il pleut" (llueve), "Il neige" (nieva), "Il y a du vent/du soleil". Pas besoin d\'être très précis à l\'A1.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Quelle est votre couleur préférée ? »',model:'Ma couleur préférée est le bleu / le rouge / le vert...',keywords:['couleur','préférée','est'],e:'"Ma couleur préférée est le/la...". Les couleurs avec article défini: j\'aime LE bleu. Adjectif: j\'ai une voiture ROUGE (après le nom).'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question mathématique :\n\n« Combien font deux plus trois ? »',model:'Deux plus trois font cinq.',keywords:['deux','trois','cinq','font'],e:'Mathématiques orales: "X plus Y font Z". Verbo "faire" para resultados: "ça fait..." / "deux plus trois FONT cinq". Cinq=/sɛ̃k/.'},
  /* ── PRODUCE (16-20) ── */
  {t:'eo',mode:'produce',q:'Décrivez à voix haute le temps qu\'il fait dans votre ville en ce moment.',model:'Aujourd\'hui, dans ma ville, il fait... Le ciel est... Il y a du/de la...',keywords:['fait','temps','ville','aujourd'],e:'Utilisez: "il fait + adjectif", "il y a + nom", "le ciel est + adjectif". Donnez 2-3 informations météo. Parlez lentement et clairement.'},
  {t:'eo',mode:'produce',q:'Présentez-vous complètement à voix haute : prénom, âge, origine et profession.',model:'Bonjour, je m\'appelle... J\'ai... ans. Je viens de... Je suis... de profession.',keywords:['appelle','ai','viens','suis','bonjour'],e:'Ordre TEF oral: salutation + prénom + âge + origine + profession. Parlez avec confiance, à vitesse modérée, en articulant bien.'},
  {t:'eo',mode:'produce',q:'Commandez à voix haute dans un café français (boisson + nourriture + question sur le prix).',model:'Bonjour ! Je voudrais un café et un croissant, s\'il vous plaît. C\'est combien ?',keywords:['voudrais','plaît','bonjour','combien'],e:'Étapes: saluer → commander (je voudrais) → préciser → demander le prix (c\'est combien?) → remercier. Ton naturel et poli.'},
  {t:'eo',mode:'produce',q:'Décrivez votre famille à voix haute en 3-4 phrases.',model:'J\'ai... personnes dans ma famille. Mon/Ma... s\'appelle... Il/Elle a... ans et il/elle est...',keywords:['famille','appelle','ai','frère','sœur','père','mère'],e:'Vocabulaire famille: père, mère, frère, sœur, mari, femme, fils, fille. Adjectifs: grand, petit, sympa, gentil, drôle. Utilisez AVOIR et ÊTRE.'},
  {t:'eo',mode:'produce',q:'Dites au revoir à votre professeur de façon formelle, à voix haute.',model:'Au revoir, Monsieur / Madame. Merci pour la leçon. À la prochaine fois !',keywords:['revoir','merci','monsieur','madame'],e:'"Au revoir" + titre (Monsieur/Madame) + remerciement. "À la prochaine" (hasta la próxima). Ton respectueux, légèrement formel.'},
],

/* ──────────── A2 · CE ──────────── */
CE_A2: [
  {t:'mc',passage:'Lisez cet email :\n\nDe : sophie.martin@mail.fr\nObjet : Ma nouvelle routine\n\nSalut Lucie,\nDepuis que j\'ai un nouveau travail, ma routine a changé. Je me lève à 6h30, je prends le métro 45 minutes pour aller au bureau. Le midi, je mange à la cantine avec mes collègues. Le soir, je rentre vers 19h. Je suis fatiguée mais contente !\nBises, Sophie',q:'À quelle heure Sophie rentre-t-elle généralement chez elle le soir ?',a:['À 6h30','À 8h00','Vers 19h00','À 17h00'],c:2,e:'"Je rentre vers 19h" = llego a casa alrededor de las 19h. "Vers" = aproximadamente. "Rentrer" = volver a casa. "Cantine" = comedor/cafetería del trabajo.'},
  {t:'tf',passage:'SOLDES D\'ÉTÉ – Boutique Élégance\n30 % à 50 % de réduction sur toute la collection\nDu 1er au 31 juillet\nArticles déjà en promotion exclus\nPaiement en 3 fois sans frais possible',q:'L\'annonce indique qu\'il est possible de payer en plusieurs fois sans frais supplémentaires.',c:true,e:'"Paiement en 3 fois sans frais" = pago en 3 cuotas sin cargos adicionales. "Sans frais" = sin gastos adicionales. "Exclus" = excluidos. "Soldes" = rebajas.'},
  {t:'mc',passage:'Lisez cet avis dans un hôtel :\n\nCHERS CLIENTS,\nVotre chambre est disponible à partir de 15h00.\nLe départ doit s\'effectuer avant 11h00.\nLe petit-déjeuner est servi de 7h00 à 10h00 au restaurant du rez-de-chaussée.\nWi-Fi gratuit dans toutes les chambres (code : HOTEL2024).',q:'À quelle heure le check-out (départ) doit-il avoir lieu ?',a:['Avant 11h00','Avant 15h00','Avant 10h00','Avant 12h00'],c:0,e:'"Le départ doit s\'effectuer avant 11h00" = el check-out debe realizarse antes de las 11h. "Rez-de-chaussée" = planta baja. "S\'effectuer" = realizarse. "À partir de" = a partir de.'},
  {t:'match',q:'Associez chaque profession à sa description.',p:[['Infirmier/ière','Soigne les malades à l\'hôpital'],['Pompier','Lutte contre les incendies'],['Architecte','Conçoit des bâtiments'],['Comptable','Gère les finances d\'une entreprise']],e:'Profesiones: infirmier=enfermero, pompier=bombero, architecte=arquitecto, comptable=contador. Verbos: soigner=cuidar, lutter=luchar, concevoir=diseñar, gérer=gestionar.'},
  {t:'mc',passage:'Lyon est la troisième ville de France, après Paris et Marseille. Connue comme la capitale mondiale de la gastronomie, elle est célèbre pour ses restaurants traditionnels appelés "bouchons". La ville est traversée par deux fleuves : le Rhône et la Saône. Son Vieux-Lyon est classé au patrimoine mondial de l\'UNESCO depuis 1998.',q:'Quelle est la particularité gastronomique de Lyon mentionnée dans le texte ?',a:['Ses boulangeries artisanales','Ses restaurants appelés « bouchons »','Ses marchés en plein air','Ses vins réputés'],c:1,e:'"Bouchons" = restaurantes tradicionales lyoneses. "Célèbre pour" = famosa por. "Traversée par" = atravesada por. UNESCO desde 1998. Lyon = capital gastronómica mundial.'},
  {t:'tf',passage:'RESTAURANT LE PROVENÇAL\nMenu du jour – 15,90 €\n• Entrée : Salade niçoise OU Soupe de légumes\n• Plat : Poulet rôti aux herbes OU Ratatouille (végétarien)\n• Dessert : Tarte aux pommes OU Crème brûlée\nBoisson non comprise\nService 12h–14h et 19h–22h',q:'Le prix de 15,90 € inclut les boissons.',c:false,e:'"Boisson non comprise" = bebida NO incluida. "Compris(e)" = incluido. "Non compris" = no incluido. En menús franceses: "service compris" (propina incluida), "boisson comprise" (bebida incluida).'},
  {t:'mc',passage:'HORAIRES PARIS → BORDEAUX\nTrain 1 : Départ 08h15 – Arrivée 10h32 – Direct\nTrain 2 : Départ 10h00 – Arrivée 13h45 – Arrêts : Tours, Poitiers, Angoulême\nTrain 3 : Départ 14h30 – Arrivée 16h48 – Direct\nRéservation obligatoire. Tarif réduit pour les moins de 26 ans.',q:'Combien de temps dure le trajet direct du Train 1 ?',a:['3h45','2h17','1h32','4h00'],c:1,e:'08h15 → 10h32 = 2h17 de trajet. Calcul: 10h32 - 08h15. "Direct" = "sans arrêt" = sin paradas. "Trajet" = trayecto/viaje. "Tarif réduit" = tarifa reducida.'},
  {t:'mc',passage:'MÉTÉO DE LA SEMAINE\nLundi : Ensoleillé, 24°C\nMardi : Quelques nuages, 20°C\nMercredi : Pluie matinale, averses l\'après-midi, 15°C\nJeudi : Vent fort et pluie toute la journée, 12°C\nVendredi : Éclaircies en fin de journée, 17°C',q:'Quel jour faut-il absolument prévoir un parapluie pour toute la journée ?',a:['Lundi','Mardi','Mercredi','Jeudi'],c:3,e:'Jeudi = pluie TOUTE la journée. Mercredi = seulement le matin + averses l\'après-midi. "Averses" = aguaceros. "Éclaircies" = claros/despejamientos. "Vent fort" = viento fuerte.'},
  {t:'tf',passage:'CONSEIL SANTÉ\nDormir suffisamment est essentiel pour la santé. Les médecins recommandent entre 7 et 9 heures de sommeil par nuit pour les adultes. Une bonne nuit de sommeil améliore la concentration, renforce le système immunitaire et aide à maintenir un poids équilibré. En revanche, le manque de sommeil peut provoquer stress, irritabilité et problèmes de mémoire.',q:'Selon cet article, les adultes devraient dormir au minimum 10 heures par nuit.',c:false,e:'¡Falso! La recommandation est de 7 à 9 heures, PAS 10. "En revanche" = en cambio/por el contrario. "Renforcer" = fortalecer. "Manque de" = falta de. "Sommeil" = sueño.'},
  {t:'match',q:'Associez chaque loisir à son activité principale.',p:[['La randonnée','Marcher dans la nature pendant des heures'],['Le tricot','Créer des vêtements avec de la laine'],['La photographie','Capturer des moments avec un appareil'],['Le jardinage','Cultiver des plantes et des fleurs']],e:'Loisirs A2: randonnée=senderismo, tricot=tejido/crochet, photographie=fotografía, jardinage=jardinería. Verbos: marcher=caminar, créer=crear, capturer=capturar, cultiver=cultivar.'},
  {t:'mc',passage:'Monsieur,\nJe vous contacte au sujet de l\'appartement que j\'ai loué dans votre immeuble en mars. Depuis mon arrivée, le chauffage ne fonctionne pas correctement. J\'ai signalé ce problème à plusieurs reprises sans résultat. Je vous demande de faire réparer ce problème dans les plus brefs délais.\nCordialement, M. Leconte',q:'Pourquoi M. Leconte écrit-il cette lettre ?',a:['Pour demander une réduction de loyer','Pour signaler un problème de chauffage','Pour résilier son contrat','Pour se plaindre du bruit'],c:1,e:'"Je me permets de vous contacter" = fórmula formal. "Chauffage" = calefacción. "Dans les plus brefs délais" = lo antes posible. C\'est une lettre de réclamation (carta de queja/reclamación).'},
  {t:'tf',passage:'OFFRE D\'EMPLOI – Assistant(e) comptable\n• Expérience : 2 ans minimum\n• Formation : BTS Comptabilité ou équivalent\n• Langues : Anglais intermédiaire requis\n• Contrat : CDI – Temps plein 35h/semaine\n• Rémunération : 1 800 € brut/mois\n• Avantages : Tickets restaurant, mutuelle\nEnvoyez CV + lettre de motivation à rh@entreprise.fr',q:'Ce poste est proposé en temps partiel.',c:false,e:'¡Falso! "Temps plein, 35h/semaine" = tiempo completo. CDI = Contrat à Durée Indéterminée (indefinido). "Temps partiel" = tiempo parcial. "Mutuelle" = seguro médico. "Brut" = bruto (antes de impuestos).'},
  {t:'mc',passage:'CRÊPES FRANÇAISES (pour 4 personnes)\nIngrédients : 250g farine, 3 œufs, 500ml lait, 1 pincée sel, 2 cuillères d\'huile\n1. Mélangez la farine et le sel.\n2. Ajoutez les œufs un par un.\n3. Versez le lait progressivement en mélangeant.\n4. Ajoutez l\'huile. Laissez reposer 30 minutes.\n5. Faites cuire dans une poêle chaude.',q:'Combien de temps faut-il laisser reposer la pâte ?',a:['15 minutes','30 minutes','1 heure','Pas de repos nécessaire'],c:1,e:'"Laissez reposer 30 minutes" = deje reposar la mezcla. "Pâte" = masa. Vocabulaire culinaire: mélanger (mezclar), verser (verter), faire cuire (cocinar). "Pincée" = pizca.'},
  {t:'mc',passage:'A LOUER – Appartement T3, 68 m²\nSituation : 3e étage avec ascenseur\n2 chambres, séjour, cuisine équipée, salle de bain\nParking inclus dans le prix\nMétro ligne 4 à 5 min à pied\nLoyer : 950 € charges comprises\nDisponible le 1er septembre – Tél : 06 12 34 56 78',q:'Qu\'est-ce qui est inclus dans le loyer mensuel de 950 € ?',a:['Seulement le parking','Les charges et le parking','Le parking et le mobilier','Seulement les charges'],c:1,e:'"Charges comprises" = gastos incluidos. "Parking inclus dans le prix" = parking incluido. Le loyer inclut LES DEUX : charges + parking. T3 = appartement de 3 pièces principales.'},
  {t:'tf',passage:'INFORMATION AUX PARENTS\nLes vacances de printemps commenceront le vendredi 21 avril à 16h30.\nLes cours reprendront le lundi 8 mai à 8h30.\nDurant cette période, la cantine sera fermée.\nLes inscriptions pour les activités périscolaires de mai sont ouvertes jusqu\'au 15 avril.',q:'Les élèves auront cours le samedi 22 avril.',c:false,e:'¡Falso! Les vacances commencent le vendredi 21 → le samedi 22 est pendant les vacances. Les cours reprennent le 8 mai. "Reprendre" = retomar. "Périscolaire" = extracurricular. "Cantine" = comedor.'},
  {t:'match',q:'Associez chaque endroit à l\'activité principale qu\'on y pratique.',p:[['La médiathèque','Emprunter des livres et des films'],['La salle de sport','Faire de l\'exercice physique'],['La boulangerie','Acheter du pain et des pâtisseries'],['La mairie','Accomplir des démarches administratives']],e:'Lieux A2: médiathèque (biblioteca multimedia), salle de sport (gimnasio), boulangerie (panadería), mairie (ayuntamiento). "Emprunter" = tomar prestado. "Démarche administrative" = gestión administrativa.'},
  {t:'mc',passage:'Bonjour,\nJe vous contacte suite à votre annonce pour le poste de réceptionniste. Je suis très intéressé(e) par cette opportunité. J\'ai 3 ans d\'expérience dans l\'hôtellerie et je parle couramment français, espagnol et anglais. Je serais disponible pour un entretien à votre convenance. Je joins mon CV à ce message.\nCordialement, Ana Gomez',q:'Pourquoi Ana Gomez envoie-t-elle ce message ?',a:['Pour réserver une chambre','Pour postuler à un emploi','Pour demander des informations touristiques','Pour annuler une réservation'],c:1,e:'"Suite à votre annonce pour le poste de" = en respuesta a su anuncio para el puesto de. "Entretien" = entrevista. "Je joins mon CV" = adjunto mi CV. C\'est une lettre de candidature.'},
  {t:'tf',passage:'RECYCLAGE EN FRANCE\nSelon une étude récente, 68 % des Français trient leurs déchets à la maison. Ce chiffre a augmenté de 15 % en dix ans. Cependant, les experts estiment que beaucoup de progrès restent à faire, notamment dans les grandes villes où les taux restent insuffisants.',q:'D\'après l\'article, le taux de recyclage en France a diminué ces dix dernières années.',c:false,e:'¡Falso! "Ce chiffre a augmenté de 15 % en dix ans" = ha AUMENTADO. "Augmenter" ≠ diminuer. "Trier ses déchets" = separar la basura. "Notamment" = especialmente. "Insuffisant" = insuficiente.'},
  {t:'mc',passage:'Guide d\'utilisation de votre cafetière\n1. Remplissez le réservoir d\'eau jusqu\'à la marque souhaitée.\n2. Placez un filtre dans le porte-filtre.\n3. Ajoutez 1 cuillère de café par tasse désirée.\n4. Appuyez sur le bouton ON/OFF.\n5. L\'appareil s\'arrête automatiquement après 2 heures.\nATTENTION : Ne laissez jamais l\'appareil sans surveillance.',q:'Que se passe-t-il automatiquement après 2 heures de fonctionnement ?',a:['La cafetière sonne','La cafetière s\'arrête','Elle redémarre automatiquement','Elle fait un bip prolongé'],c:1,e:'"L\'appareil s\'arrête automatiquement après 2 heures" = el aparato se apaga solo. "Réservoir" = depósito. "Porte-filtre" = portafiltro. "Cuillère" = cuchara. "Sans surveillance" = sin vigilancia.'},
  {t:'mc',passage:'"Je m\'appelle Karim. Il y a deux ans, j\'ai décidé de changer de vie. J\'ai quitté mon travail de comptable pour ouvrir un café littéraire dans mon quartier. Au début, c\'était très difficile et j\'avais peur de tout perdre. Mais aujourd\'hui, mon café est plein tous les week-ends. Je ne regrette rien !"',q:'Quel était le métier de Karim AVANT d\'ouvrir son café ?',a:['Restaurateur','Libraire','Comptable','Barista'],c:2,e:'"J\'ai quitté mon travail de comptable" = dejé mi trabajo de contador. "Quitter" = dejar/abandonar. Imparfait (c\'était) = descripción del pasado. Passé composé (j\'ai décidé, j\'ai quitté) = acciones completadas.'},
],

/* ──────────── A2 · CO ──────────── */
CO_A2: [
  {t:'mc',audio:'Bonjour, je suis Thomas. Ma journée commence tôt. Je me réveille à six heures trente, je prends une douche et je déjeune tranquillement. Je prends le bus à sept heures quarante-cinq pour arriver au bureau à huit heures trente. Je mange à la cantine le midi. Le soir, je rentre vers dix-neuf heures et je regarde une série ou je lis.',q:'À quelle heure Thomas prend-il le bus pour aller au travail ?',a:['À 6h30','À 7h45','À 8h30','À 19h00'],c:1,e:'"Je prends le bus à sept heures quarante-cinq" = toma el bus a las 7h45. Vocabulaire de routine: se réveiller (despertarse), prendre une douche (ducharse), déjeuner (almorzar/desayunar).'},
  {t:'mc',audio:'Voici la météo pour demain sur toute la France. Le matin, des nuages couvriront le nord et l\'est du pays, avec quelques averses possibles. L\'après-midi, le soleil fera son apparition dans le sud et le centre. Les températures oscilleront entre douze et dix-neuf degrés selon les régions.',q:'Quel temps fera-t-il dans le SUD de la France l\'après-midi ?',a:['Il y aura des nuages','Il pleuvra toute la journée','Le soleil sera présent','Il y aura du brouillard'],c:2,e:'"Le soleil fera son apparition dans le sud" = el sol aparecerá en el sur. "Faire son apparition" = aparecer. "Averses" = aguaceros. Nord/Sud/Est/Ouest = norte/sur/este/oeste.'},
  {t:'tf',audio:'Mesdames et messieurs, votre attention s\'il vous plaît. Le train numéro sept cent deux à destination de Lyon-Part-Dieu, prévu à seize heures quinze, partira avec un retard de vingt minutes environ. Nous vous prions de nous excuser pour ce désagrément. Les voyageurs sont priés de rester en salle d\'attente.',q:'Le train pour Lyon partira exactement à l\'heure initialement prévue.',c:false,e:'"Partira avec un retard de vingt minutes" = saldrá con 20 minutos de retraso. "Prévu à" = previsto a. "Désagrément" = inconveniente. "Salle d\'attente" = sala de espera. Retard = retraso (¡muy útil en el TEF!).'},
  {t:'mc',audio:'Allô, bonjour. Je vous laisse un message pour confirmer votre rendez-vous de vendredi prochain à dix heures. Le docteur Moreau vous recevra au cabinet, au vingt-trois rue de la Paix. Si vous devez annuler, merci de nous appeler avant jeudi midi au zéro un quarante-cinq soixante-dix-huit.',q:'Quel est l\'objet principal de ce message téléphonique ?',a:['Annuler un rendez-vous médical','Confirmer une adresse de cabinet','Confirmer un rendez-vous médical','Demander une ordonnance'],c:2,e:'"Je vous laisse un message pour confirmer votre rendez-vous" = es un mensaje de confirmación de cita. "Cabinet médical" = consultorio médico. "Avant jeudi midi" = antes del mediodía del jueves. "Ordonnance" = receta médica.'},
  {t:'tf',audio:'Bonjour ! Je m\'appelle Céline. Mon mari s\'appelle Pierre, il est ingénieur. Nous avons deux enfants : une fille de dix ans et un garçon de sept ans. Ma belle-mère vit avec nous depuis six mois car elle ne va pas très bien. Le week-end, nous aimons tous aller à la campagne ensemble.',q:'La belle-mère de Céline habite chez elle depuis plus d\'un an.',c:false,e:'"Depuis six mois" = desde hace 6 meses (NO más de un año). "Belle-mère" = suegra/madrastra. Attention: DEPUIS + durée = desde hace X tiempo. "À la campagne" = en el campo. Distinction: 6 mois ≠ plus d\'un an.'},
  {t:'mc',audio:'Bonjour madame. Je cherche un cadeau pour ma femme. Elle aime beaucoup la cuisine et la lecture. Mon budget est d\'environ cinquante euros. Qu\'est-ce que vous me conseillez comme cadeau ?',q:'Quel est le budget maximum de ce client pour le cadeau ?',a:['Trente euros','Quarante euros','Cinquante euros','Soixante euros'],c:2,e:'"Mon budget est d\'environ cinquante euros" = mi presupuesto es de unos 50€. "Environ" = aproximadamente. Vocabulaire commerce: cadeau (regalo), conseiller (aconsejar), budget (presupuesto).'},
  {t:'mc',audio:'Bonjour, je m\'appelle Marie et je vais vous parler de mes loisirs. J\'adore aller au cinéma, surtout les films en version originale. Chaque week-end, je joue au tennis avec des amis au club de mon quartier. Le soir, après le travail, j\'aime lire des romans policiers. J\'essaie aussi de faire de la natation deux fois par semaine.',q:'Quelle activité Marie pratique-t-elle deux fois par semaine ?',a:['Le cinéma','Le tennis','La natation','La lecture'],c:2,e:'"J\'essaie de faire de la natation deux fois par semaine" = intenta nadar dos veces a la semana. "Version originale" = versión original (VO). "Roman policier" = novela policiaca. "Essayer de" = intentar.'},
  {t:'mc',audio:'Allô, bonjour, je voudrais réserver une table pour ce soir, s\'il vous plaît. Nous serons quatre personnes. Nous préférerions une table en terrasse si c\'est possible. À vingt heures, ça vous convient ?',q:'Pour combien de personnes la personne souhaite-t-elle réserver une table ?',a:['2 personnes','3 personnes','4 personnes','5 personnes'],c:2,e:'"Nous serons quatre personnes" = seremos cuatro personas. "Réserver une table" = reservar una mesa. "Terrasse" = terraza. "Ça vous convient ?" = ¿Le viene bien? / ¿Le parece bien?'},
  {t:'tf',audio:'Dans notre journal local, une bonne nouvelle pour les habitants de la ville. La nouvelle piscine municipale ouvrira ses portes le premier juin. Elle sera équipée d\'un bassin olympique, d\'un espace bien-être et d\'une pataugeoire pour les tout-petits. Des tarifs réduits seront appliqués pour les moins de dix-huit ans et pour les seniors.',q:'La nouvelle piscine sera réservée uniquement aux adultes.',c:false,e:'"Pataugeoire pour les tout-petits" + "tarifs réduits pour les moins de 18 ans" → ouverte à TOUS. "Bien-être" = bienestar. "Bassin olympique" = piscina olímpica. "Habitant" = habitante/vecino.'},
  {t:'mc',audio:'Je m\'appelle Nadia. Je travaille comme infirmière depuis huit ans dans un hôpital public. C\'est un métier très exigeant : je travaille souvent la nuit et le week-end. Mais j\'adore mon travail car j\'aime aider les gens. Les moments de guérison des patients sont très émouvants.',q:'Depuis combien de temps Nadia travaille-t-elle comme infirmière ?',a:['3 ans','5 ans','8 ans','12 ans'],c:2,e:'"Depuis huit ans" = desde hace 8 años. DEPUIS + durée = desde hace X tiempo. "Exigeant" = exigente. "Guérison" = curación/recuperación. "Émouvant" = emocionante/conmovedor.'},
  {t:'mc',audio:'Pour aller à la gare, vous prenez la première rue à droite, puis vous continuez tout droit pendant environ deux cents mètres. Au feu rouge, vous tournez à gauche. La gare sera sur votre droite, juste en face de la pharmacie.',q:'Où se trouve la gare par rapport à la pharmacie ?',a:['Derrière la pharmacie','À gauche de la pharmacie','En face de la pharmacie','À droite de la pharmacie'],c:2,e:'"Juste en face de la pharmacie" = justo enfrente de la farmacia. Directions: à droite (derecha), à gauche (izquierda), tout droit (recto), en face (enfrente), au feu rouge (en el semáforo).'},
  {t:'tf',audio:'Notre appartement est au quatrième étage d\'un immeuble sans ascenseur. Il y a un grand salon avec une belle vue sur le parc, deux chambres, une cuisine moderne et une salle de bain. Nous avons aussi une cave et un grenier. L\'appartement fait soixante-quinze mètres carrés.',q:'L\'immeuble décrit dispose d\'un ascenseur.',c:false,e:'"Sans ascenseur" = sin ascensor. "Grenier" = desván/ático. "Cave" = bodega/sótano. "Vue sur le parc" = vista al parque. "Mètres carrés" = metros cuadrados. Vocabulaire logement: très fréquent dans le TEF.'},
  {t:'mc',audio:'Bonjour docteur, j\'ai un peu mal à la gorge depuis hier et j\'ai aussi de la fièvre depuis ce matin. Je pense que j\'ai peut-être une angine. J\'ai pris du paracétamol mais ça ne va pas mieux. Est-ce que je peux avoir un rendez-vous aujourd\'hui ?',q:'Quel symptôme a commencé en PREMIER selon le patient ?',a:['La fièvre','Le mal de gorge','Le mal de tête','La toux'],c:1,e:'"Mal à la gorge depuis HIER" = primero. "Fièvre depuis ce matin" = después. "Angine" = angina/amigdalitis. "Paracétamol" = paracetamol. Vocabulaire santé A2: fièvre (fiebre), toux (tos), mal à (me duele).'},
  {t:'mc',audio:'Je viens de voir le nouveau film de Léa Dupont. Franchement, c\'était excellent ! L\'histoire est très originale et les acteurs jouent très bien. Par contre, le film dure presque trois heures, ce qui est un peu long pour moi. Mais les effets spéciaux sont incroyables. Je le recommande vraiment à tout le monde.',q:'Quel est le seul aspect négatif mentionné sur ce film ?',a:['Les effets spéciaux déçoivent','Le jeu des acteurs','La durée du film','L\'histoire est banale'],c:2,e:'"Par contre, le film dure presque trois heures, ce qui est un peu long" = única crítica. "Par contre" = sin embargo. "Franchement" = francamente. "Recommander" = recomendar. "Durée" = duración.'},
  {t:'tf',audio:'Le week-end dernier, j\'ai participé à un club de randonnée. Nous étions vingt personnes. Nous avons marché cinq heures dans la forêt. C\'était fatiguant mais magnifique ! Nous avons pique-niqué au bord d\'un lac. Le retour a été difficile car il a commencé à pleuvoir.',q:'Le groupe a pique-niqué dans la forêt selon ce témoignage.',c:false,e:'"Au bord d\'un lac" = à orillas de un lago (NO dans la forêt). "Randonnée" = senderismo. "Pique-niquer" = hacer un picnic. "Bord de" = orilla de. "Il a commencé à pleuvoir" = empezó a llover.'},
  {t:'match',audio:'Voici les activités du week-end de quatre amis. Pierre aime faire du vélo le dimanche matin. Emma préfère visiter des musées ou des expositions. Lucas joue aux échecs avec son grand-père chaque samedi. Et Léa passe son dimanche à cuisiner de nouvelles recettes.',q:'Associez chaque personne à son activité du week-end.',p:[['Pierre','Faire du vélo'],['Emma','Visiter des musées'],['Lucas','Jouer aux échecs'],['Léa','Cuisiner de nouvelles recettes']],e:'Activités week-end: vélo=ciclismo, musées/expositions=museos, échecs=ajedrez, cuisiner=cocinar. Memorizar quién hace qué. "Chaque samedi" = cada sábado. "Exposition" = exposición.'},
  {t:'mc',audio:'Attention, chère clientèle. Le magasin fermera ses portes dans quinze minutes. Nous vous invitons à vous diriger vers les caisses pour régler vos achats. Nous espérons vous revoir très bientôt. Le magasin rouvrira demain matin à neuf heures trente.',q:'À quelle heure le magasin ouvre-t-il le lendemain ?',a:['À 8h00','À 9h00','À 9h30','À 10h00'],c:2,e:'"Rouvrira demain matin à neuf heures trente" = reabrirá mañana a las 9h30. "Se diriger vers les caisses" = dirigirse a las cajas. "Régler ses achats" = pagar las compras. "Clientèle" = clientela.'},
  {t:'tf',audio:'Bonjour ! Aujourd\'hui au marché, les tomates coûtent deux euros le kilo, les pommes sont à un euro cinquante et les haricots verts sont en promotion : trois euros pour deux kilos. L\'huile d\'olive est un peu chère ce mois-ci, à huit euros la bouteille.',q:'Les tomates coûtent plus cher que les pommes au marché.',c:true,e:'Tomates = 2,00€/kg > Pommes = 1,50€/kg → tomates PLUS chères. "Haricots verts" = judías verdes. "En promotion" = en oferta. Comparaisons: plus cher que (más caro que), moins cher que (más barato que).'},
  {t:'mc',audio:'Cet été, nous avons passé deux semaines en Bretagne. Nous avons loué une petite maison près de la mer. Tous les jours, nous allions à la plage et nous nous baignions dans l\'océan. Nous avons aussi visité des châteaux et des villages typiques. La cuisine bretonne est délicieuse, surtout les crêpes et les fruits de mer !',q:'Combien de temps ont-ils séjourné en Bretagne ?',a:['Une semaine','Deux semaines','Trois semaines','Un mois'],c:1,e:'"Deux semaines" = dos semanas. "Se baigner" = bañarse. "Cuisine bretonne" = cocina bretona. "Fruits de mer" = mariscos. Passé composé pour raconter les vacances: nous avons loué, nous avons visité.'},
  {t:'mc',audio:'Bonjour à tous. Je voulais vous informer d\'une réunion importante qui aura lieu jeudi prochain à quatorze heures dans la salle de conférence du troisième étage. La présence de tous les membres de l\'équipe est obligatoire. Merci d\'apporter vos rapports du mois dernier. Si vous avez des questions, contactez-moi avant mercredi.',q:'Que doit-on apporter à cette réunion ?',a:['Ses cartes de visite','Les rapports du mois dernier','Son ordinateur portable','Les projets pour l\'an prochain'],c:1,e:'"Merci d\'apporter vos rapports du mois dernier" = traigan los informes del mes pasado. "Réunion" = reunión. "Salle de conférence" = sala de conferencias. "Présence obligatoire" = asistencia obligatoria.'},
],

/* ──────────── A2 · EE ──────────── */
EE_A2: [
  /* ── FILL (1-10) ── */
  {t:'ee',mode:'fill',q:'Conjuguez "vendre" au présent (1re personne) :\n\n« Je ___ ma vieille voiture. »',a:'vends',alt:['VENDS'],e:'"Vendre" = vender. Présent: je VENDS, tu vends, il vend, nous vendons, vous vendez, ils vendent. Terminaison -ds au singulier pour les verbes en -dre. Verbe du 3e groupe.'},
  {t:'ee',mode:'fill',q:'Complétez avec l\'auxiliaire du passé composé de "finir" :\n\n« Hier, j\'___ fini mon rapport. »',a:'ai',alt:['AI'],e:'"Finir" au passé composé = AVOIR + participe passé: j\'AI fini. Verbes avec AVOIR = transitifs directs. Verbes avec ÊTRE = mouvement (aller, venir, partir…) et pronominaux.'},
  {t:'ee',mode:'fill',q:'Quel auxiliaire utilise-t-on avec "partir" au passé composé ?\n\n« Elle ___ partie tôt ce matin. »',a:'est',alt:['EST'],e:'"Partir" se conjugue avec ÊTRE: elle EST partie. Accord du participe : partie (féminin). Verbes avec ÊTRE: aller, venir, partir, arriver, naître, mourir, entrer, sortir, monter, descendre + tous les pronominaux.'},
  {t:'ee',mode:'fill',q:'Conjuguez "se lever" au présent (3e personne) :\n\n« Il ___ lève à 7h chaque matin. »',a:'se',alt:['SE'],e:'Pronominaux: pronom réfléchi change avec le sujet. Je ME lève, tu TE lèves, il SE lève, nous NOUS levons, vous VOUS levez, ils SE lèvent. Courants: se lever, se doucher, s\'habiller, se coucher.'},
  {t:'ee',mode:'fill',q:'Complétez avec le futur proche :\n\n« Demain, nous ___ visiter le Louvre. »',a:'allons',alt:['ALLONS'],e:'Futur proche = ALLER (présent) + infinitif. Je VAIS, tu vas, il va, nous ALLONS, vous allez, ils vont + infinitif. Exprime un futur planifié ou imminent.'},
  {t:'ee',mode:'fill',q:'Complétez le comparatif de supériorité :\n\n« Le TGV est ___ rapide que le bus. »',a:'plus',alt:['PLUS'],e:'Comparatifs: PLUS + adj + QUE (supériorité), MOINS + adj + QUE (infériorité), AUSSI + adj + QUE (égalité). Exceptions: bon → MEILLEUR (pas "plus bon"), mauvais → PIRE.'},
  {t:'ee',mode:'fill',q:'Quelle préposition place-t-on devant un pays féminin ?\n\n« Je pars ___ France cet été. »',a:'en',alt:['EN'],e:'Prépositions de pays: EN + féminin/voyelle (en France, en Espagne, en Italie), AU + masculin (au Mexique, au Canada), AUX + pluriel (aux États-Unis, aux Pays-Bas). France est féminin → EN.'},
  {t:'ee',mode:'fill',q:'Conjuguez "aimer" à l\'imparfait (1re personne) :\n\n« Quand j\'étais enfant, j\'___ les glaces. »',a:'aimais',alt:['AIMAIS'],e:'Imparfait: radical de NOUS au présent + terminaisons -ais/-ais/-ait/-ions/-iez/-aient. Nous aimons → j\'AIMAIS. Usage: habitudes passées, descriptions, contexte d\'une action ponctuelle.'},
  {t:'ee',mode:'fill',q:'Donnez le superlatif de "bon" (masculin singulier) :\n\n« C\'est le ___ café de la ville ! »',a:'meilleur',alt:['MEILLEUR'],e:'BON est irrégulier: comparatif MEILLEUR, superlatif LE MEILLEUR (jamais "le plus bon"!). De même: mauvais → pire / le pire. Petit → moindre / le moindre.'},
  {t:'ee',mode:'fill',q:'Conjuguez "faire" au conditionnel présent (1re personne) :\n\n« Si j\'avais le temps, je ___ du sport. »',a:'ferais',alt:['FERAIS'],e:'Conditionnel présent: radical spécial + terminaisons imparfait. FAIRE → FER- + ais = FERAIS. Irréguliers: avoir→aurait, être→serait, aller→irait, vouloir→voudrait, pouvoir→pourrait.'},
  /* ── WRITE (11-20) ── */
  {t:'ee',mode:'write',q:'Décrivez votre ville natale en 3-4 phrases.',prompt:'Mentionnez sa taille, ses caractéristiques principales et votre opinion personnelle.',criteria:['Taille ou type de ville précisé','Au moins une caractéristique concrète','Opinion personnelle exprimée'],model:'Je viens de Grenoble, une ville moyenne dans les Alpes françaises. Il y a beaucoup de montagnes autour et les habitants aiment le ski en hiver. J\'aime ma ville car elle est animée, mais elle est moins grande que Lyon.',e:'Structures A2: "Il y a...", "Je viens de...", comparatifs (moins grand que). Vocabulaire: animé=animado, entouré de=rodeado de, habitants=habitantes.'},
  {t:'ee',mode:'write',q:'Racontez ce que vous avez fait le week-end dernier.',prompt:'Utilisez le passé composé. Mentionnez au moins 3 activités avec des expressions de temps.',criteria:['Passé composé utilisé (j\'ai… / je suis…)','Au moins 3 activités mentionnées','Expressions de temps (samedi, le matin, le soir…)'],model:'Samedi matin, je suis allé(e) au marché. L\'après-midi, j\'ai regardé un film. Le soir, j\'ai dîné au restaurant avec des amis. Dimanche, je me suis reposé(e) et j\'ai lu un roman.',e:'Passé composé avec AVOIR (j\'ai regardé) et ÊTRE (je suis allé[e], je me suis reposé[e]). Accord du PP avec être. Expressions: samedi matin, l\'après-midi, le soir.'},
  {t:'ee',mode:'write',q:'Rédigez un email à un(e) ami(e) pour proposer une sortie au cinéma.',prompt:'Proposez un film, un jour et une heure. Demandez s\'il/elle est disponible.',criteria:['Formule d\'ouverture informelle (Salut…)','Proposition claire avec film, jour et heure','Question sur la disponibilité'],model:'Salut Lucas ! Tu es libre samedi soir ? Il y a un super film au Gaumont, séance à 20h. Ça te dirait d\'y aller ? Réponds-moi vite ! À bientôt, Marie.',e:'"Ça te dirait de + infinitif ?" = ¿Te apetecería? "Séance" = función. Style informel: tutoiement (tu), "Salut!", "À bientôt!".'},
  {t:'ee',mode:'write',q:'Décrivez votre logement actuel en 4-5 phrases.',prompt:'Type de logement, taille, pièces principales et votre opinion.',criteria:['Type de logement précisé','Au moins 2 pièces mentionnées','Opinion personnelle (j\'aime / par contre…)'],model:'J\'habite dans un appartement de 60 m² au 4e étage. Il y a un salon lumineux, deux chambres et une cuisine équipée. J\'aime mon appartement car il est bien situé, près du métro. Par contre, il n\'y a pas de balcon, ce qui est dommage.',e:'Vocabulaire: lumineux=luminoso, équipé=equipado, bien situé=bien ubicado. "Par contre" = sin embargo. "Ce qui est dommage" = lo cual es una pena.'},
  {t:'ee',mode:'write',q:'Décrivez votre routine matinale en 4-5 phrases.',prompt:'Utilisez des verbes pronominaux et des marqueurs temporels (d\'abord, puis, ensuite, enfin).',criteria:['Au moins 2 verbes pronominaux conjugués','Ordre chronologique logique','Marqueurs de temps présents'],model:'Le matin, je me lève à 7h. Je me douche d\'abord, puis je m\'habille. Ensuite, je prends mon petit-déjeuner. Je me brosse les dents et enfin je pars au travail à 8h.',e:'Pronominaux matin: se lever, se doucher, s\'habiller, se coiffer, se brosser les dents. Marqueurs: d\'abord, puis, ensuite, enfin = primero, luego, después, por fin.'},
  {t:'ee',mode:'write',q:'Répondez à ce SMS : « On se voit toujours demain à 14h pour le café ? »',prompt:'Confirmez le rendez-vous, proposez un détail et terminez par une formule amicale.',criteria:['Confirmation du rendez-vous','Ton informel et naturel','Formule de clôture amicale'],model:'Oui bien sûr ! Je serai là à 14h. Je connais un super café près de la gare, on peut s\'y retrouver si tu veux ? Sinon, dis-moi où tu préfères. À demain ! 😊',e:'"Je serai là" = futur simple de être. "On peut s\'y retrouver" = podemos encontrarnos allí. "Sinon" = si no. "À demain!" = ¡Hasta mañana!'},
  {t:'ee',mode:'write',q:'Décrivez un membre de votre famille (physique + personnalité) en 3-4 phrases.',prompt:'Choisissez un membre de votre famille. Décrivez son apparence physique et sa personnalité.',criteria:['Relation familiale précisée','Au moins 1 adjectif physique','Au moins 1 adjectif de personnalité'],model:'Ma sœur s\'appelle Clara et elle a 24 ans. Elle est grande et mince, avec les cheveux longs et bruns. Elle est très sociable et toujours de bonne humeur. Elle travaille comme infirmière et adore son métier.',e:'Physique: grand/petit, mince/fort, cheveux longs/courts/bouclés. Personnalité: sociable, timide, généreux, sérieux, drôle, patient. Accords adjectifs selon le genre!'},
  {t:'ee',mode:'write',q:'Exprimez vos préférences pour des vacances idéales avec des comparatifs.',prompt:'Comparez deux types de vacances (mer/montagne, ville/campagne…) et justifiez votre préférence.',criteria:['Comparatif utilisé (plus/moins… que)','Deux types de vacances comparés','Justification de la préférence'],model:'Je préfère les vacances à la mer plutôt qu\'à la montagne. La mer est plus relaxante et il fait plus chaud. Cependant, la montagne est plus calme et moins chère. Pour moi, une semaine à la plage est idéale.',e:'Comparatifs: plus + adj + que, moins + adj + que. "Plutôt que" = más que/en lugar de. "Cependant" = sin embargo. Structure argumentée fréquente au TEF EE.'},
  {t:'ee',mode:'write',q:'Répondez à cette annonce de colocation :\n\n« Cherche colocataire sympa · Appt 2 pièces · Paris · 600€/mois charges comprises »',prompt:'Rédigez un court email : présentez-vous, exprimez votre intérêt et posez une question.',criteria:['Courte présentation (prénom, âge, profession)','Intérêt pour la colocation exprimé','Une question posée'],model:'Bonjour,\nJe m\'appelle Sofia, j\'ai 27 ans et je suis étudiante à Paris. Je cherche un logement calme pour travailler. Votre annonce m\'intéresse beaucoup ! Est-ce que les animaux sont acceptés ?\nMerci, Sofia',e:'"Colocation" = piso compartido. "Charges comprises" = gastos incluidos. Email semi-formel: "Bonjour," pas "Cher/Chère". Fermeture simple "Merci" + prénom.'},
  {t:'ee',mode:'write',q:'Racontez un souvenir d\'enfance à l\'imparfait (3-4 phrases).',prompt:'Décrivez une habitude ou activité régulière de votre enfance. Commencez par "Quand j\'étais enfant…"',criteria:['Imparfait utilisé pour les habitudes','Contexte "enfance" établi','2-3 détails descriptifs ou habitudes'],model:'Quand j\'étais enfant, j\'habitais dans une grande maison avec un jardin. Chaque été, ma famille allait à la plage. Mes parents préparaient toujours un pique-nique et nous jouions au ballon. C\'était le meilleur moment de l\'année !',e:'Imparfait pour habitudes: j\'habitais, nous allions, ils préparaient, nous jouions. Marqueurs: chaque été, toujours. "C\'était" = imparfait descriptif. "Le meilleur" = superlatif irrégulier de bon.'},
],

/* ──────────── A2 · EO ──────────── */
EO_A2: [
  /* ── REPEAT (1-8) ── */
  {t:'eo',mode:'repeat',q:'Répétez cette phrase au passé composé à voix haute :',model:'Le week-end dernier, je suis allé(e) au cinéma avec des amis. C\'était super !',keywords:['suis','allé','cinéma','super'],e:'Passé composé avec ÊTRE: je SUIS allé(e). Accord du participe: allé/allée. "C\'était" = imparfait d\'opinion. Prononciation naturelle: "je suis allé" /ʒsɥi za.le/. Très fréquent dans le TEF oral A2.'},
  {t:'eo',mode:'repeat',q:'Répétez cette formule de politesse complexe à voix haute :',model:'Pourriez-vous me dire où se trouve la pharmacie la plus proche, s\'il vous plaît ?',keywords:['pourriez','pharmacie','trouve','proche'],e:'"Pourriez-vous" = conditionnel de politesse, plus formel que "pouvez-vous". "Se trouver" = estar ubicado. "La plus proche" = superlatif (la más cercana). Structure formelle très utile au TEF oral.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase comparative à voix haute :',model:'Je préfère le train à la voiture parce que c\'est plus rapide et moins fatigant.',keywords:['préfère','train','rapide','fatigant'],e:'"Préférer A à B" = preferir A a B. Comparatifs: PLUS rapide, MOINS fatigant. Justification avec "parce que". Structure typique des réponses orales au TEF A2 pour exprimer une opinion.'},
  {t:'eo',mode:'repeat',q:'Répétez cette description de logement à voix haute :',model:'Mon appartement se trouve au troisième étage d\'un immeuble moderne, près du centre-ville.',keywords:['appartement','troisième','immeuble','centre'],e:'"Se trouver" = estar ubicado. "Troisième" /tʁwa.zjɛm/. "Étage" = piso/planta. "Immeuble" = edificio de pisos. "Près du centre-ville" = cerca del centro. Vocabulaire logement A2 fréquent.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase à l\'imparfait à voix haute :',model:'Quand j\'étais petit(e), je passais tous mes étés chez mes grands-parents à la campagne.',keywords:['étais','passais','grands-parents','campagne'],e:'Imparfait pour habitudes passées: j\'étais, je passais. "Tous mes étés" = todos mis veranos. "Chez + personne" = en casa de. "À la campagne" = en el campo. Liaison: "quand j\'étais" /kɑ̃.ʒe.tɛ/.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase de réservation hôtelière à voix haute :',model:'Je voudrais réserver une chambre double pour deux nuits, du vendredi au dimanche.',keywords:['voudrais','réserver','chambre','vendredi'],e:'"Je voudrais réserver" = conditionnel de politesse. "Chambre double" = habitación doble. "Du vendredi au dimanche" = del viernes al domingo. Formule clé pour hôtels et restaurants dans le TEF oral.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase de conseil à voix haute :',model:'Il vaudrait mieux partir tôt pour éviter les embouteillages sur l\'autoroute.',keywords:['vaudrait','partir','éviter','autoroute'],e:'"Il vaudrait mieux + infinitif" = sería mejor. Conditionnel de "valoir". "Éviter" = evitar. "Embouteillages" = atascos. "Autoroute" = autopista. Expression de conseil très courante en français oral.'},
  {t:'eo',mode:'repeat',q:'Répétez cette excuse à voix haute avec une intonation expressive :',model:'Je suis vraiment désolé(e), j\'avais complètement oublié notre rendez-vous d\'hier.',keywords:['désolé','oublié','rendez-vous','hier'],e:'"Je suis vraiment désolé(e)" = lo siento mucho. "Vraiment" = de verdad. "J\'avais oublié" = plus-que-parfait (había olvidado). Ton repentant et expressif. Très utile en situation réelle et au TEF.'},
  /* ── ANSWER (9-15) ── */
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Qu\'est-ce que vous avez fait hier soir ? »',model:'Hier soir, j\'ai regardé un film / mangé au restaurant / travaillé...',keywords:['hier','soir','ai'],e:'Passé composé: hier soir + j\'ai + participe passé. PP fréquents: regardé, mangé, lu, fait, vu, écouté. Répondre en phrase complète. Ajouter un détail (avec qui, comment c\'était).'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Quel est votre plat préféré ? Pourquoi ? »',model:'Mon plat préféré est le... parce que c\'est délicieux et facile à préparer.',keywords:['plat','préféré','parce','que'],e:'"Mon plat préféré est…" + "parce que c\'est…". Adjectifs: délicieux, savoureux, épicé, léger, copieux, fait maison. Donner une vraie raison. Structure opinion + justification fréquente au TEF oral.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Depuis combien de temps habitez-vous dans votre ville actuelle ? »',model:'J\'habite à [ville] depuis [X] ans.',keywords:['habite','depuis','ans'],e:'"Depuis" + présent = desde hace. J\'habite ici depuis 3 ans = llevo 3 años aquí. Attention: DEPUIS + PRÉSENT (pas passé composé!). Exprimer la durée avec précision est une compétence clé A2.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Qu\'est-ce que vous allez faire ce week-end ? »',model:'Ce week-end, je vais aller au marché / voir des amis / me reposer...',keywords:['week-end','vais','aller'],e:'Futur proche: je VAIS + infinitif. "Ce week-end" = este fin de semana. Plans: "je vais aller", "je vais voir", "je vais me reposer". La réponse la plus naturelle à l\'oral pour parler du futur en A2.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Comment était votre enfance ? »',model:'Quand j\'étais enfant, j\'habitais à... et je jouais souvent...',keywords:['étais','enfant','habitais','jouais'],e:'Imparfait pour décrire l\'enfance: j\'habitais, je jouais, j\'aimais, je faisais. "Quand j\'étais enfant" = cuando era niño/a. Marqueurs d\'habitudes: souvent, tous les jours, chaque été.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Qu\'est-ce que vous aimeriez faire si vous aviez plus de temps libre ? »',model:'Si j\'avais plus de temps libre, je voudrais... / j\'aimerais...',keywords:['temps','voudrais','aimerais','si'],e:'"Si j\'avais + imparfait → je voudrais + conditionnel" = hypothèse irréelle présente. "J\'aimerais" = me gustaría. "Je voudrais" = quisiera. Structure hypothétique fréquente dans le TEF oral A2.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à la question :\n\n« Pouvez-vous comparer deux moyens de transport que vous utilisez ? »',model:'Le métro est plus rapide que le bus, mais moins confortable. Je préfère le métro.',keywords:['plus','que','moins','préfère','métro'],e:'Comparatifs: PLUS + adj + QUE, MOINS + adj + QUE. Adjectifs utiles: rapide, confortable, cher, pratique, écologique. "Je préfère A à B" = prefiero A a B. Structure comparative très fréquente au TEF oral A2.'},
  /* ── PRODUCE (16-20) ── */
  {t:'eo',mode:'produce',q:'Décrivez votre quartier à voix haute : ce qu\'il y a, comment il est, ses avantages et inconvénients.',model:'Mon quartier est [adj]. Il y a beaucoup de... C\'est pratique car... Par contre, il manque...',keywords:['quartier','il y a','calme','animé','manque'],e:'Vocabulaire quartier: animé/calme, commerçant, résidentiel, bien desservi. "Il y a" + commerces/parcs/transports. "Il manque" = falta. "Par contre" = sin embargo. Avantages/inconvénients = structure argumentative de base.'},
  {t:'eo',mode:'produce',q:'Racontez à voix haute votre dernier voyage ou une sortie mémorable.',model:'L\'été dernier, je suis allé(e) à... Nous avons visité... C\'était vraiment...',keywords:['suis','allé','avons','visité','était'],e:'Mélanger passé composé (actions) et imparfait (descriptions). Je SUIS allé(e). Nous AVONS visité. "C\'était" = imparfait descriptif. Narration structurée: lieu → activités → impression générale.'},
  {t:'eo',mode:'produce',q:'Expliquez à voix haute votre trajet habituel pour aller au travail ou à l\'école.',model:'Pour aller au travail, je prends d\'abord le bus, puis le métro. Ça prend environ 40 minutes.',keywords:['prends','bus','métro','prend','environ'],e:'Transports: prendre le bus/métro/tramway, marcher, faire du vélo. "Ça prend + durée" = tarda X minutos. Séquence: d\'abord, puis, ensuite. "Environ" = aproximadamente. Réponse pratique et courante.'},
  {t:'eo',mode:'produce',q:'Décrivez votre repas idéal à voix haute : entrée, plat, dessert — et justifiez vos choix.',model:'Pour mon repas idéal, je commencerais par une salade. Comme plat, je choisirais... Et pour finir, je prendrais...',keywords:['commencerais','choisirais','prendrais','plat','dessert'],e:'Conditionnel pour exprimer l\'idéal: je commencerais, je choisirais, je prendrais. Structure: entrée → plat → dessert. Adjectifs: savoureux, léger, copieux, fait maison. Justifier avec "parce que" ou "car".'},
  {t:'eo',mode:'produce',q:'Parlez d\'un hobby que vous pratiquez régulièrement à voix haute.',model:'J\'aime beaucoup... Je pratique cela deux fois par semaine. Ça m\'aide à me détendre. J\'ai commencé il y a...',keywords:['aime','pratique','semaine','commencé','aide'],e:'Fréquence: deux fois par semaine, chaque week-end, tous les jours. "Ça m\'aide à + infinitif" = me ayuda a. "Il y a + durée" = hace X tiempo. Parler de ses loisirs = compétence clé du TEF EO A2.'},
],


/* ──────────── B1 · CE ──────────── */
CE_B1: [
  /* ── PASSAGE 1 : Le télétravail (Q1-4) ── */
  {t:'mc',passage:'Depuis 2020, le télétravail s\'est largement répandu en France. Selon une étude récente, 35 % des salariés travaillent désormais au moins un jour par semaine depuis leur domicile. Si les employés apprécient la flexibilité et le gain de temps sur les trajets, les entreprises constatent des difficultés en matière de cohésion d\'équipe. La frontière entre vie professionnelle et vie personnelle tend également à s\'estomper, certains salariés travaillant bien au-delà des heures habituelles.',q:'Quel est le sujet principal de cet article ?',a:['Les problèmes de transport en commun','L\'essor du télétravail en France','Les nouvelles lois du travail','La durée légale du temps de travail'],c:1,e:'"L\'essor" = l\'essor, desarrollo o auge. El artículo trata la expansión del teletrabajo en Francia desde 2020. En el TEF B1, identifica el tema principal buscando la idea repetida en todo el texto.'},
  {t:'mc',passage:'Depuis 2020, le télétravail s\'est largement répandu en France. Selon une étude récente, 35 % des salariés travaillent désormais au moins un jour par semaine depuis leur domicile. Si les employés apprécient la flexibilité et le gain de temps sur les trajets, les entreprises constatent des difficultés en matière de cohésion d\'équipe. La frontière entre vie professionnelle et vie personnelle tend également à s\'estomper, certains salariés travaillant bien au-delà des heures habituelles.',q:'Selon l\'étude citée, quelle proportion des salariés pratique le télétravail ?',a:['15 %','25 %','35 %','50 %'],c:2,e:'"Selon une étude récente, 35 % des salariés…" = selon une étude = según un estudio. Dato explícito en el texto. "Au moins" = al menos. Práctica TEF: siempre localiza cifras y porcentajes directamente en el texto.'},
  {t:'tf',passage:'Depuis 2020, le télétravail s\'est largement répandu en France. Selon une étude récente, 35 % des salariés travaillent désormais au moins un jour par semaine depuis leur domicile. Si les employés apprécient la flexibilité et le gain de temps sur les trajets, les entreprises constatent des difficultés en matière de cohésion d\'équipe. La frontière entre vie professionnelle et vie personnelle tend également à s\'estomper, certains salariés travaillant bien au-delà des heures habituelles.',q:'Les salariés apprécient de ne pas avoir à se déplacer pour aller travailler.',c:true,e:'Vrai. "Le gain de temps sur les trajets" = la ganancia de tiempo en los desplazamientos. "Trajet" = trayecto/viaje. Los empleados valoran este ahorro de tiempo en los desplazamientos al trabajo.'},
  {t:'mc',passage:'Depuis 2020, le télétravail s\'est largement répandu en France. Selon une étude récente, 35 % des salariés travaillent désormais au moins un jour par semaine depuis leur domicile. Si les employés apprécient la flexibilité et le gain de temps sur les trajets, les entreprises constatent des difficultés en matière de cohésion d\'équipe. La frontière entre vie professionnelle et vie personnelle tend également à s\'estomper, certains salariés travaillant bien au-delà des heures habituelles.',q:'L\'expression « la frontière tend à s\'estomper » signifie que la limite entre travail et vie privée :',a:['est mieux respectée qu\'avant','disparaît progressivement','est fixée par la loi','n\'a jamais existé'],c:1,e:'"S\'estomper" = desvanecerse, difuminarse. "La frontière tend à s\'estomper" = el límite tiende a desvanecerse. En B1 CE, debes inferir el significado de expresiones por contexto. "Au-delà des heures habituelles" confirma que se trabaja más allá del horario normal.'},
  /* ── PASSAGE 2 : Offre d\'emploi (Q5-8) ── */
  {t:'mc',passage:'RESPONSABLE MARKETING DIGITAL – CDI\nEntreprise : NovaCom Solutions (Paris, 75009)\nPoste à pourvoir : septembre 2024\n\nMissions principales :\n- Élaboration et suivi de la stratégie digitale\n- Gestion des réseaux sociaux et des campagnes publicitaires en ligne\n- Analyse des données et reporting mensuel à la direction\n\nProfil recherché :\n- Bac+3 ou plus en marketing, communication ou équivalent\n- Minimum 3 ans d\'expérience en marketing digital\n- Maîtrise des outils SEO/SEA et Google Analytics\n- Anglais courant requis\n\nConditions : Salaire 38 000 € – 48 000 € brut/an, 2 jours de télétravail/semaine, tickets restaurant, mutuelle.\n\nCandidatures : rh@novacom.fr (CV + lettre de motivation)',q:'Quel type de contrat est proposé dans cette annonce ?',a:['Un contrat intérimaire','Un stage de 6 mois','Un CDI','Un CDD d\'un an'],c:2,e:'"CDI" = Contrat à Durée Indéterminée = contrato por tiempo indefinido. C\'est le type de contrat le plus sécurisé en France. À distinguer du CDD (Contrat à Durée Déterminée = contrato temporal).'},
  {t:'tf',passage:'RESPONSABLE MARKETING DIGITAL – CDI\nEntreprise : NovaCom Solutions (Paris, 75009)\nPoste à pourvoir : septembre 2024\n\nMissions principales :\n- Élaboration et suivi de la stratégie digitale\n- Gestion des réseaux sociaux et des campagnes publicitaires en ligne\n- Analyse des données et reporting mensuel à la direction\n\nProfil recherché :\n- Bac+3 ou plus en marketing, communication ou équivalent\n- Minimum 3 ans d\'expérience en marketing digital\n- Maîtrise des outils SEO/SEA et Google Analytics\n- Anglais courant requis\n\nConditions : Salaire 38 000 € – 48 000 € brut/an, 2 jours de télétravail/semaine, tickets restaurant, mutuelle.\n\nCandidatures : rh@novacom.fr (CV + lettre de motivation)',q:'L\'annonce exige un diplôme de niveau Bac+5 minimum.',c:false,e:'Faux. L\'annonce demande "Bac+3 ou plus", pas nécessairement Bac+5. "Ou plus" = o más. "Équivalent" = equivalente. Ojo: la palabra "minimum" en la pregunta puede confundir, pero el texto dice claramento "Bac+3 ou plus".'},
  {t:'mc',passage:'RESPONSABLE MARKETING DIGITAL – CDI\nEntreprise : NovaCom Solutions (Paris, 75009)\nPoste à pourvoir : septembre 2024\n\nMissions principales :\n- Élaboration et suivi de la stratégie digitale\n- Gestion des réseaux sociaux et des campagnes publicitaires en ligne\n- Analyse des données et reporting mensuel à la direction\n\nProfil recherché :\n- Bac+3 ou plus en marketing, communication ou équivalent\n- Minimum 3 ans d\'expérience en marketing digital\n- Maîtrise des outils SEO/SEA et Google Analytics\n- Anglais courant requis\n\nConditions : Salaire 38 000 € – 48 000 € brut/an, 2 jours de télétravail/semaine, tickets restaurant, mutuelle.\n\nCandidatures : rh@novacom.fr (CV + lettre de motivation)',q:'Quelle compétence linguistique est obligatoire selon l\'annonce ?',a:['L\'espagnol niveau B2','L\'allemand courant','Le français niveau C2','L\'anglais courant'],c:3,e:'"Anglais courant requis" = inglés fluido requerido (obligatorio). "Courant" = fluido, corriente. "Requis" = requerido, obligatorio. En el TEF CE, diferencia entre "requis/obligatoire" (obligatorio) y "souhaité/apprécié" (deseable).'},
  {t:'mc',passage:'RESPONSABLE MARKETING DIGITAL – CDI\nEntreprise : NovaCom Solutions (Paris, 75009)\nPoste à pourvoir : septembre 2024\n\nMissions principales :\n- Élaboration et suivi de la stratégie digitale\n- Gestion des réseaux sociaux et des campagnes publicitaires en ligne\n- Analyse des données et reporting mensuel à la direction\n\nProfil recherché :\n- Bac+3 ou plus en marketing, communication ou équivalent\n- Minimum 3 ans d\'expérience en marketing digital\n- Maîtrise des outils SEO/SEA et Google Analytics\n- Anglais courant requis\n\nConditions : Salaire 38 000 € – 48 000 € brut/an, 2 jours de télétravail/semaine, tickets restaurant, mutuelle.\n\nCandidatures : rh@novacom.fr (CV + lettre de motivation)',q:'Quand le poste doit-il être pourvu, selon l\'annonce ?',a:['En janvier 2024','En juin 2024','En septembre 2024','En janvier 2025'],c:2,e:'"Poste à pourvoir : septembre 2024" = puesto a cubrir en septiembre 2024. "Pourvoir un poste" = cubrir/llenar un puesto de trabajo. Dato explícito en el texte.'},
  /* ── PASSAGE 3 : Environnement (Q9-11) ── */
  {t:'mc',passage:'La France s\'est fixé l\'objectif ambitieux d\'atteindre la neutralité carbone d\'ici 2050. Pour y parvenir, le gouvernement mise sur le développement massif des énergies renouvelables — éolien, solaire et hydraulique — qui représentent déjà 25 % de la production électrique nationale. Des aides financières sont proposées aux ménages souhaitant réaliser des travaux d\'isolation thermique ou installer des panneaux solaires. Malgré ces efforts institutionnels, les experts climatiques soulignent que la réduction de la consommation individuelle reste le levier d\'action le plus efficace et le plus rapide.',q:'Quel objectif climatique la France s\'est-elle fixé ?',a:['Réduire ses émissions de CO₂ de 50 % d\'ici 2030','Atteindre la neutralité carbone en 2050','Produire 100 % d\'électricité renouvelable d\'ici 2040','Fermer toutes ses centrales nucléaires d\'ici 2035'],c:1,e:'"Neutralité carbone" = neutralidad de carbono (emisiones netas = cero). "D\'ici 2050" = para el año 2050. "S\'est fixé un objectif" = se ha fijado/propuesto un objetivo. Comprensión de objetivos climáticos: tema frecuente en el TEF B1.'},
  {t:'tf',passage:'La France s\'est fixé l\'objectif ambitieux d\'atteindre la neutralité carbone d\'ici 2050. Pour y parvenir, le gouvernement mise sur le développement massif des énergies renouvelables — éolien, solaire et hydraulique — qui représentent déjà 25 % de la production électrique nationale. Des aides financières sont proposées aux ménages souhaitant réaliser des travaux d\'isolation thermique ou installer des panneaux solaires. Malgré ces efforts institutionnels, les experts climatiques soulignent que la réduction de la consommation individuelle reste le levier d\'action le plus efficace et le plus rapide.',q:'Les énergies renouvelables couvrent déjà plus de la moitié de la production électrique française.',c:false,e:'Faux. "25 % de la production électrique nationale" = un quart, pas plus de la moitié. "Représenter" = representar. "La moitié" = la mitad = 50%. Ojo con los porcentajes: 25% ≠ 50%.'},
  {t:'mc',passage:'La France s\'est fixé l\'objectif ambitieux d\'atteindre la neutralité carbone d\'ici 2050. Pour y parvenir, le gouvernement mise sur le développement massif des énergies renouvelables — éolien, solaire et hydraulique — qui représentent déjà 25 % de la production électrique nationale. Des aides financières sont proposées aux ménages souhaitant réaliser des travaux d\'isolation thermique ou installer des panneaux solaires. Malgré ces efforts institutionnels, les experts climatiques soulignent que la réduction de la consommation individuelle reste le levier d\'action le plus efficace et le plus rapide.',q:'D\'après les experts climatiques, quelle mesure serait la plus efficace pour lutter contre le changement climatique ?',a:['Construire davantage d\'éoliennes offshore','Subventionner l\'isolation des logements','Réduire la consommation individuelle','Développer le transport en commun'],c:2,e:'"Le levier d\'action le plus efficace" = la palanca de acción más eficaz. "La consommation individuelle" = el consumo individual. Ojo: el texto dice "malgré les efforts institutionnels" → implica que las soluciones del gobierno no son suficientes por sí solas.'},
  /* ── PASSAGE 4 : Lettre formelle (Q12-14) ── */
  {t:'mc',passage:'Monsieur le Directeur,\n\nJe me permets de vous écrire suite à ma visite dans votre restaurant le 18 mars dernier, à l\'occasion d\'un dîner en famille. Dans l\'ensemble, nous avons passé une très belle soirée : la cuisine était remarquable et le personnel, très attentionné.\n\nToutefois, j\'aimerais vous soumettre une remarque constructive. Le niveau sonore dans la salle était particulièrement élevé ce soir-là, ce qui rendait la conversation difficile. Un peu d\'isolation acoustique ou une disposition différente des tables pourrait améliorer notablement l\'expérience.\n\nJe compte revenir prochainement dans votre établissement et espère que vous prendrez en considération cette suggestion.\n\nCordialement,\nIsabelle Fontaine',q:'Quel est l\'objectif principal de cette lettre ?',a:['Demander un remboursement pour une mauvaise expérience','Formuler des éloges et proposer une amélioration','Signaler un vol dans le restaurant','Réserver une table pour un prochain événement'],c:1,e:'"Suite à ma visite" = a raíz de mi visita. Estructura: 1) tono positivo (cuisine remarquable, personnel attentionné), 2) critique constructive (niveau sonore), 3) suggestion (isolation acoustique). Es una carta de satisfacción mixta, no una queja pura.'},
  {t:'tf',passage:'Monsieur le Directeur,\n\nJe me permets de vous écrire suite à ma visite dans votre restaurant le 18 mars dernier, à l\'occasion d\'un dîner en famille. Dans l\'ensemble, nous avons passé une très belle soirée : la cuisine était remarquable et le personnel, très attentionné.\n\nToutefois, j\'aimerais vous soumettre une remarque constructive. Le niveau sonore dans la salle était particulièrement élevé ce soir-là, ce qui rendait la conversation difficile. Un peu d\'isolation acoustique ou une disposition différente des tables pourrait améliorer notablement l\'expérience.\n\nJe compte revenir prochainement dans votre établissement et espère que vous prendrez en considération cette suggestion.\n\nCordialement,\nIsabelle Fontaine',q:'Mme Fontaine était accompagnée lors de sa visite au restaurant.',c:true,e:'Vrai. "À l\'occasion d\'un dîner en famille" = con motivo de una cena familiar. "En famille" = en famille/con la familia. No estaba sola. "Nous avons passé" (plural) también confirma que había más personas.'},
  {t:'mc',passage:'Monsieur le Directeur,\n\nJe me permets de vous écrire suite à ma visite dans votre restaurant le 18 mars dernier, à l\'occasion d\'un dîner en famille. Dans l\'ensemble, nous avons passé une très belle soirée : la cuisine était remarquable et le personnel, très attentionné.\n\nToutefois, j\'aimerais vous soumettre une remarque constructive. Le niveau sonore dans la salle était particulièrement élevé ce soir-là, ce qui rendait la conversation difficile. Un peu d\'isolation acoustique ou une disposition différente des tables pourrait améliorer notablement l\'expérience.\n\nJe compte revenir prochainement dans votre établissement et espère que vous prendrez en considération cette suggestion.\n\nCordialement,\nIsabelle Fontaine',q:'Quelle solution Mme Fontaine propose-t-elle pour améliorer l\'expérience ?',a:['Diffuser de la musique douce en fond sonore','Fermer le restaurant les soirs de semaine','Améliorer l\'isolation acoustique ou repositionner les tables','Former davantage le personnel au service'],c:2,e:'"Un peu d\'isolation acoustique" = algo de aislamiento acústico. "Une disposition différente des tables" = una distribución diferente de las mesas. "Améliorer notablement" = mejorar notablemente. Son dos sugerencias concretas para reducir el ruido.'},
  /* ── PASSAGE 5 : Zéro déchet (Q15-17) ── */
  {t:'mc',passage:'De plus en plus de Français adoptent un mode de vie « zéro déchet », une démarche qui vise à réduire au maximum la production de déchets ménagers. Ses adeptes privilégient les achats en vrac, les contenants réutilisables et la confection maison de produits d\'entretien. Si certains y voient une contrainte quotidienne, la majorité de ceux qui s\'y essaient affirment réaliser des économies significatives sur leur budget et retrouver un sentiment de cohérence entre leurs valeurs et leurs actes. Ce mouvement gagne surtout du terrain auprès des moins de 35 ans vivant en milieu urbain.',q:'En quoi consiste principalement le mode de vie « zéro déchet » ?',a:['Trier et recycler la totalité de ses déchets','Réduire au maximum la production de déchets ménagers','Acheter uniquement des produits biologiques','Refuser toute forme de consommation'],c:1,e:'"Viser à réduire au maximum" = tener como objetivo reducir al máximo. "Déchets ménagers" = residuos domésticos. Important: zéro déchet ≠ recycler tout. Il s\'agit de RÉDUIRE la production de déchets en amont, avant même qu\'ils soient créés.'},
  {t:'tf',passage:'De plus en plus de Français adoptent un mode de vie « zéro déchet », une démarche qui vise à réduire au maximum la production de déchets ménagers. Ses adeptes privilégient les achats en vrac, les contenants réutilisables et la confection maison de produits d\'entretien. Si certains y voient une contrainte quotidienne, la majorité de ceux qui s\'y essaient affirment réaliser des économies significatives sur leur budget et retrouver un sentiment de cohérence entre leurs valeurs et leurs actes. Ce mouvement gagne surtout du terrain auprès des moins de 35 ans vivant en milieu urbain.',q:'Tous les partisans du zéro déchet considèrent cette démarche comme une contrainte quotidienne.',c:false,e:'Faux. "Certains y voient une contrainte" (algunos), pero "la majorité affirme réaliser des économies" (la mayoría). La conjunción adversativa "si... (la mayoría)..." establece un contraste. No todos lo ven como una carga.'},
  {t:'mc',passage:'De plus en plus de Français adoptent un mode de vie « zéro déchet », une démarche qui vise à réduire au maximum la production de déchets ménagers. Ses adeptes privilégient les achats en vrac, les contenants réutilisables et la confection maison de produits d\'entretien. Si certains y voient une contrainte quotidienne, la majorité de ceux qui s\'y essaient affirment réaliser des économies significatives sur leur budget et retrouver un sentiment de cohérence entre leurs valeurs et leurs actes. Ce mouvement gagne surtout du terrain auprès des moins de 35 ans vivant en milieu urbain.',q:'Quel groupe adopte principalement ce mode de vie, d\'après l\'article ?',a:['Les retraités des zones rurales','Les familles avec enfants','Les moins de 35 ans en milieu urbain','Les personnes à revenus élevés'],c:2,e:'"Gagner du terrain auprès de" = ganar terreno entre, hacerse popular entre. "Moins de 35 ans" = menores de 35 años. "Milieu urbain" = entorno urbano. El artículo especifica exactamente este perfil demográfico.'},
  /* ── MATCH Q18-Q19 ── */
  {t:'match',q:'Associez chaque connecteur logique à sa fonction.',p:[['Cependant','Opposition'],['En effet','Explication'],['Par conséquent','Conséquence'],['D\'abord','Séquence']],e:'Conectores clave para el TEF B1 CE: "Cependant/Toutefois/Or" = sin embargo (oposición); "En effet/Car/Puisque" = en efecto/porque (explicación); "Par conséquent/Donc/Ainsi" = por lo tanto (consecuencia); "D\'abord/Ensuite/Enfin" = primero/luego/finalmente (secuencia).'},
  {t:'match',q:'Associez chaque type de texte à son objectif principal.',p:[['Un éditorial','Donner une opinion'],['Un mode d\'emploi','Expliquer comment utiliser'],['Une annonce de recrutement','Chercher un employé'],['Un compte-rendu','Résumer des décisions']],e:'"Éditorial" = editorial de opinión. "Mode d\'emploi" = instrucciones de uso. "Annonce de recrutement" = anuncio de trabajo. "Compte-rendu" = acta/resumen de reunión. Reconocer el tipo de texto es clave para el TEF CE B1.'},
  /* ── Q20 standalone ── */
  {t:'mc',q:'Dans un article de presse, l\'expression « selon une étude récente » sert à :',a:['Exprimer l\'opinion personnelle de l\'auteur','Annoncer que l\'auteur invente des données','S\'appuyer sur des recherches pour étayer les faits','Contester les résultats d\'une autre étude'],c:2,e:'"Selon + source" = según + fuente. Esta expresión sirve para citar una fuente externa y dar credibilidad a la información. Otras fórmulas similares: "d\'après une étude", "une enquête révèle que", "les chiffres montrent que". Vocabulaire des sources journalistiques = compétence B1 CE.'},
],

/* ──────────── B1 · CO ──────────── */
CO_B1: [
  /* ── BULLETIN RADIO : Immobilier (Q1-3) ── */
  {t:'mc',audio:'Bonjour à tous. Selon les chiffres publiés ce matin par l\'agence nationale du logement, les prix de l\'immobilier ont augmenté de 8 % en moyenne dans les grandes villes françaises au cours de l\'année écoulée. Paris reste la ville la plus chère, avec un prix moyen de 10 200 euros le mètre carré. À l\'inverse, les zones rurales affichent une légère baisse des prix, de l\'ordre de 2 %. Les experts attribuent cette hausse à un manque de logements disponibles et à une demande toujours soutenue. Les primo-accédants sont les plus touchés par cette situation.',q:'Quel est le sujet principal de ce bulletin radio ?',a:['La réglementation des agences immobilières','L\'évolution des prix de l\'immobilier en France','Les nouvelles constructions dans les grandes villes','La fiscalité sur les propriétés immobilières'],c:1,e:'"L\'immobilier" = el sector inmobiliario. "Les prix de l\'immobilier" = los precios de la vivienda. "Au cours de l\'année écoulée" = durante el año transcurrido. Ce thème est fréquent dans les bulletins radio du TEF CO B1.'},
  {t:'tf',audio:'Bonjour à tous. Selon les chiffres publiés ce matin par l\'agence nationale du logement, les prix de l\'immobilier ont augmenté de 8 % en moyenne dans les grandes villes françaises au cours de l\'année écoulée. Paris reste la ville la plus chère, avec un prix moyen de 10 200 euros le mètre carré. À l\'inverse, les zones rurales affichent une légère baisse des prix, de l\'ordre de 2 %. Les experts attribuent cette hausse à un manque de logements disponibles et à une demande toujours soutenue. Les primo-accédants sont les plus touchés par cette situation.',q:'Les prix ont augmenté de la même manière en ville et en zone rurale.',c:false,e:'Faux. En ville = +8%, mais en zone rurale = -2% (légère baisse). "À l\'inverse" = al contrario, introduce un contraste. "Afficher une baisse" = mostrar una bajada. Cette opposition est le point clé du bulletin.'},
  {t:'mc',audio:'Bonjour à tous. Selon les chiffres publiés ce matin par l\'agence nationale du logement, les prix de l\'immobilier ont augmenté de 8 % en moyenne dans les grandes villes françaises au cours de l\'année écoulée. Paris reste la ville la plus chère, avec un prix moyen de 10 200 euros le mètre carré. À l\'inverse, les zones rurales affichent une légère baisse des prix, de l\'ordre de 2 %. Les experts attribuent cette hausse à un manque de logements disponibles et à une demande toujours soutenue. Les primo-accédants sont les plus touchés par cette situation.',q:'Quelle est la cause principale de la hausse des prix selon les experts ?',a:['L\'afflux de touristes étrangers dans les grandes villes','La hausse des taux d\'intérêt bancaires','Un déséquilibre entre l\'offre et la demande de logements','La construction de trop nombreux logements de luxe'],c:2,e:'"Un manque de logements disponibles" = una falta de viviendas disponibles (= oferta insuficiente). "Une demande toujours soutenue" = una demanda constantemente elevada. Oferta < demanda → subida de precios. Razonamiento económico básico para el TEF CO B1.'},
  /* ── INTERVIEW : Chef cuisinier (Q4-6) ── */
  {t:'mc',audio:'Journaliste : Chef Martineau, vous venez d\'ouvrir votre troisième restaurant. Comment expliquez-vous votre succès ? Chef : Je crois que c\'est avant tout une question de passion et de rigueur. En cuisine, on ne peut pas tricher. Les clients le sentent quand les produits ne sont pas frais ou quand la préparation est bâclée. J\'ai toujours privilégié les producteurs locaux, même quand c\'était plus coûteux. Journaliste : Et les défis ? Chef : Le principal défi, c\'est le personnel. Il est de plus en plus difficile de trouver des cuisiniers motivés. Les horaires sont contraignants, et beaucoup de jeunes préfèrent des métiers avec de meilleures conditions. Nous devons repenser notre façon d\'accueillir les nouveaux talents.',q:'Selon le chef Martineau, quelle est la clé de son succès ?',a:['Le prix accessible de ses menus','La passion et la rigueur','La modernité de ses techniques','Le choix de l\'emplacement de ses restaurants'],c:1,e:'"Avant tout" = ante todo, principalmente. "La passion et la rigueur" = la pasión y el rigor. "Tricher" = hacer trampa. Le chef insiste que la qualité se ressent et qu\'on ne peut pas la simuler. Vocabulaire du monde professionnel fréquent en CO B1.'},
  {t:'tf',audio:'Journaliste : Chef Martineau, vous venez d\'ouvrir votre troisième restaurant. Comment expliquez-vous votre succès ? Chef : Je crois que c\'est avant tout une question de passion et de rigueur. En cuisine, on ne peut pas tricher. Les clients le sentent quand les produits ne sont pas frais ou quand la préparation est bâclée. J\'ai toujours privilégié les producteurs locaux, même quand c\'était plus coûteux. Journaliste : Et les défis ? Chef : Le principal défi, c\'est le personnel. Il est de plus en plus difficile de trouver des cuisiniers motivés. Les horaires sont contraignants, et beaucoup de jeunes préfèrent des métiers avec de meilleures conditions. Nous devons repenser notre façon d\'accueillir les nouveaux talents.',q:'Le chef Martineau a toujours privilégié les fournisseurs locaux, même si cela coûtait plus cher.',c:true,e:'Vrai. "J\'ai toujours privilégié les producteurs locaux, même quand c\'était plus coûteux." = siempre he preferido los productores locales, aunque fuera más caro. "Même quand" = incluso cuando. Admite el coste mayor pero lo asume como principio.'},
  {t:'mc',audio:'Journaliste : Chef Martineau, vous venez d\'ouvrir votre troisième restaurant. Comment expliquez-vous votre succès ? Chef : Je crois que c\'est avant tout une question de passion et de rigueur. En cuisine, on ne peut pas tricher. Les clients le sentent quand les produits ne sont pas frais ou quand la préparation est bâclée. J\'ai toujours privilégié les producteurs locaux, même quand c\'était plus coûteux. Journaliste : Et les défis ? Chef : Le principal défi, c\'est le personnel. Il est de plus en plus difficile de trouver des cuisiniers motivés. Les horaires sont contraignants, et beaucoup de jeunes préfèrent des métiers avec de meilleures conditions. Nous devons repenser notre façon d\'accueillir les nouveaux talents.',q:'Quel est le principal problème mentionné par le chef ?',a:['La concurrence des grandes chaînes de restauration','Le coût élevé des matières premières','La difficulté à recruter et retenir du personnel qualifié','L\'obtention de financements bancaires'],c:2,e:'"Le principal défi, c\'est le personnel" = el principal desafío es el personal. "Trouver des cuisiniers motivés" = encontrar cocineros motivados. "Les horaires sont contraignants" = los horarios son exigentes/poco flexibles. "Repenser notre façon d\'accueillir" = repensar la forma de acoger a los nuevos talentos.'},
  /* ── MESSAGE RÉPONDEUR : Cabinet médical (Q7-9) ── */
  {t:'mc',audio:'Bonjour, vous êtes bien sur le répondeur du cabinet du docteur Leblond. Notre cabinet est ouvert du lundi au vendredi, de 9 heures à 18 heures, et le samedi de 9 heures à midi. Pour prendre rendez-vous, vous pouvez nous rappeler aux heures d\'ouverture au 01 45 67 89 00, ou réserver directement en ligne sur notre site doctolib point fr. En cas d\'urgence médicale, composez le 15. Si votre appel concerne le renouvellement d\'une ordonnance, merci de vous présenter directement à l\'accueil avec votre carte Vitale. Merci de votre appel.',q:'Quels sont les horaires d\'ouverture du cabinet le samedi ?',a:['De 8h à 17h','De 9h à 12h','De 9h à 18h','Le cabinet est fermé le samedi'],c:1,e:'"Le samedi de 9 heures à midi" = el sábado de 9:00 a 12:00. "Midi" = mediodía = 12h. Diferente del horario de semana (9h-18h). En el TEF CO B1, presta atención a los horarios específicos para días distintos.'},
  {t:'tf',audio:'Bonjour, vous êtes bien sur le répondeur du cabinet du docteur Leblond. Notre cabinet est ouvert du lundi au vendredi, de 9 heures à 18 heures, et le samedi de 9 heures à midi. Pour prendre rendez-vous, vous pouvez nous rappeler aux heures d\'ouverture au 01 45 67 89 00, ou réserver directement en ligne sur notre site doctolib point fr. En cas d\'urgence médicale, composez le 15. Si votre appel concerne le renouvellement d\'une ordonnance, merci de vous présenter directement à l\'accueil avec votre carte Vitale. Merci de votre appel.',q:'Le message indique qu\'il est possible de prendre rendez-vous en ligne.',c:true,e:'Vrai. "Réserver directement en ligne sur notre site doctolib.fr" = reservar directamente en línea en el sitio web. Doctolib es la plataforma de citas médicas más usada en Francia. "En ligne" = en línea, por internet.'},
  {t:'mc',audio:'Bonjour, vous êtes bien sur le répondeur du cabinet du docteur Leblond. Notre cabinet est ouvert du lundi au vendredi, de 9 heures à 18 heures, et le samedi de 9 heures à midi. Pour prendre rendez-vous, vous pouvez nous rappeler aux heures d\'ouverture au 01 45 67 89 00, ou réserver directement en ligne sur notre site doctolib point fr. En cas d\'urgence médicale, composez le 15. Si votre appel concerne le renouvellement d\'une ordonnance, merci de vous présenter directement à l\'accueil avec votre carte Vitale. Merci de votre appel.',q:'Que doit faire un patient pour renouveler son ordonnance ?',a:['Appeler le 15','Envoyer un email au cabinet','Se présenter à l\'accueil avec sa carte Vitale','Utiliser uniquement la plateforme en ligne'],c:2,e:'"Se présenter directement à l\'accueil avec votre carte Vitale" = presentarse directamente en recepción con su tarjeta de seguro médico. La Carte Vitale = la tarjeta verde de la Sécurité Sociale francesa. "Ordonnance" = receta médica. "Renouvellement" = renovación.'},
  /* ── PODCAST : Bien-être numérique (Q10-13) ── */
  {t:'mc',audio:'Bienvenue dans La Minute Bien-être. Aujourd\'hui, nous parlons de la déconnexion numérique. Une récente étude révèle que les Français passent en moyenne 6 heures par jour devant leurs écrans, toutes utilisations confondues. Les psychologues alertent sur les effets négatifs d\'une surexposition : troubles du sommeil, difficultés de concentration et sentiment d\'anxiété. La solution préconisée n\'est pas forcément de supprimer tous les écrans, mais d\'adopter des plages de déconnexion intentionnelle — des moments sans téléphone, sans ordinateur. Certaines entreprises expérimentent même le vendredi sans réunion pour permettre à leurs employés de se concentrer sans interruption.',q:'Combien d\'heures les Français passent-ils en moyenne devant leurs écrans par jour ?',a:['3 heures','4 heures et demie','6 heures','8 heures'],c:2,e:'"En moyenne" = en promedio. "6 heures par jour" = 6 horas al día. "Toutes utilisations confondues" = contando todos los usos (trabajo, ocio, redes sociales...). Dato numérico explícito → respuesta directa.'},
  {t:'tf',audio:'Bienvenue dans La Minute Bien-être. Aujourd\'hui, nous parlons de la déconnexion numérique. Une récente étude révèle que les Français passent en moyenne 6 heures par jour devant leurs écrans, toutes utilisations confondues. Les psychologues alertent sur les effets négatifs d\'une surexposition : troubles du sommeil, difficultés de concentration et sentiment d\'anxiété. La solution préconisée n\'est pas forcément de supprimer tous les écrans, mais d\'adopter des plages de déconnexion intentionnelle — des moments sans téléphone, sans ordinateur. Certaines entreprises expérimentent même le vendredi sans réunion pour permettre à leurs employés de se concentrer sans interruption.',q:'Le podcast recommande de supprimer complètement les écrans pour améliorer le bien-être.',c:false,e:'Faux. "La solution préconisée n\'est pas forcément de supprimer tous les écrans" = la solución recomendada no es necesariamente eliminar todas las pantallas. "Pas forcément" = no necesariamente. La solución propuesta es adoptar "plages de déconnexion intentionnelle" = momentos de desconexión intencional.'},
  {t:'mc',audio:'Bienvenue dans La Minute Bien-être. Aujourd\'hui, nous parlons de la déconnexion numérique. Une récente étude révèle que les Français passent en moyenne 6 heures par jour devant leurs écrans, toutes utilisations confondues. Les psychologues alertent sur les effets négatifs d\'une surexposition : troubles du sommeil, difficultés de concentration et sentiment d\'anxiété. La solution préconisée n\'est pas forcément de supprimer tous les écrans, mais d\'adopter des plages de déconnexion intentionnelle — des moments sans téléphone, sans ordinateur. Certaines entreprises expérimentent même le vendredi sans réunion pour permettre à leurs employés de se concentrer sans interruption.',q:'Quelle pratique certaines entreprises mettent-elles en place pour le bien-être numérique ?',a:['Interdire les smartphones au bureau','Instaurer un vendredi sans réunion','Limiter l\'accès à internet à 2 heures par jour','Supprimer les logiciels de messagerie'],c:1,e:'"Le vendredi sans réunion" = el viernes sin reuniones. "Expérimenter" = experimentar/probar. L\'idée est de créer un bloc de temps sans interruptions pour permettre la concentration. "Concentration sans interruption" = concentración sin interrupciones.'},
  {t:'mc',audio:'Bienvenue dans La Minute Bien-être. Aujourd\'hui, nous parlons de la déconnexion numérique. Une récente étude révèle que les Français passent en moyenne 6 heures par jour devant leurs écrans, toutes utilisations confondues. Les psychologues alertent sur les effets négatifs d\'une surexposition : troubles du sommeil, difficultés de concentration et sentiment d\'anxiété. La solution préconisée n\'est pas forcément de supprimer tous les écrans, mais d\'adopter des plages de déconnexion intentionnelle — des moments sans téléphone, sans ordinateur. Certaines entreprises expérimentent même le vendredi sans réunion pour permettre à leurs employés de se concentrer sans interruption.',q:'Quel effet négatif de la surexposition aux écrans est mentionné dans le podcast ?',a:['Les douleurs dorsales et cervicales','La prise de poids','Les troubles du sommeil','La baisse de la créativité'],c:2,e:'"Troubles du sommeil" = trastornos del sueño. La surexposition aux écrans est aussi associée à des "difficultés de concentration" et un "sentiment d\'anxiété". "Alerte sur les effets négatifs" = alerta sobre los efectos negativos. Tres efectos mencionados: sommeil, concentration, anxiété.'},
  /* ── DÉBAT RADIO : Transports en commun (Q14-16) ── */
  {t:'mc',audio:'Présentateur : Notre invitée aujourd\'hui est Marie-Claire Dupont, urbaniste, qui milite pour l\'amélioration des transports en commun dans les villes moyennes françaises. Invitée : Absolument. Le problème est flagrant : les grandes métropoles comme Paris ou Lyon ont des réseaux de transport efficaces, mais les villes de 100 000 à 300 000 habitants sont souvent oubliées. Résultat : les habitants sont contraints d\'utiliser leur voiture, ce qui aggrave la pollution et la congestion. Les investissements doivent être redirigés vers ces villes intermédiaires, sous peine de creuser davantage les inégalités territoriales.',q:'Quelle est la thèse principale de l\'urbaniste Marie-Claire Dupont ?',a:['Les grandes métropoles manquent d\'investissements dans les transports','Les villes moyennes souffrent d\'un réseau de transport insuffisant','Il faut interdire les voitures dans toutes les villes françaises','Le train devrait remplacer complètement la voiture'],c:1,e:'"Milite pour" = milita a favor de, defiende. "Villes moyennes" = ciudades medianas. L\'urbaniste critique l\'oubli des villes de taille intermédiaire (100 000-300 000 hab.) par los inversores. "Flagrant" = flagrante, evidente. Thèse argumentative = compétence clé CO B1.'},
  {t:'tf',audio:'Présentateur : Notre invitée aujourd\'hui est Marie-Claire Dupont, urbaniste, qui milite pour l\'amélioration des transports en commun dans les villes moyennes françaises. Invitée : Absolument. Le problème est flagrant : les grandes métropoles comme Paris ou Lyon ont des réseaux de transport efficaces, mais les villes de 100 000 à 300 000 habitants sont souvent oubliées. Résultat : les habitants sont contraints d\'utiliser leur voiture, ce qui aggrave la pollution et la congestion. Les investissements doivent être redirigés vers ces villes intermédiaires, sous peine de creuser davantage les inégalités territoriales.',q:'Selon l\'invitée, les grandes métropoles françaises disposent d\'un réseau de transport efficace.',c:true,e:'Vrai. "Les grandes métropoles comme Paris ou Lyon ont des réseaux de transport efficaces" = las grandes metrópolis tienen redes de transporte eficaces. L\'invitée lo reconoce antes de contrastar con la situación de las ciudades medianas. Estructura argumentativa: concesión + pero + crítica.'},
  {t:'mc',audio:'Présentateur : Notre invitée aujourd\'hui est Marie-Claire Dupont, urbaniste, qui milite pour l\'amélioration des transports en commun dans les villes moyennes françaises. Invitée : Absolument. Le problème est flagrant : les grandes métropoles comme Paris ou Lyon ont des réseaux de transport efficaces, mais les villes de 100 000 à 300 000 habitants sont souvent oubliées. Résultat : les habitants sont contraints d\'utiliser leur voiture, ce qui aggrave la pollution et la congestion. Les investissements doivent être redirigés vers ces villes intermédiaires, sous peine de creuser davantage les inégalités territoriales.',q:'Quelle conséquence directe de l\'insuffisance des transports en commun dans les villes moyennes est mentionnée ?',a:['L\'augmentation du coût de la vie','L\'abandon de ces villes par leurs habitants','La pollution et la congestion dues à l\'usage de la voiture','La fermeture de commerces de proximité'],c:2,e:'"Les habitants sont contraints d\'utiliser leur voiture" = los habitantes se ven obligados a usar el coche. "Ce qui aggrave la pollution et la congestion" = lo que agrava la contaminación y la congestión. "Aggraver" = agravar, empeorar. "Congestion" = congestión de tráfico.'},
  /* ── MATCH Q17 ── */
  {t:'match',audio:'Je vais décrire quatre professionnels. Un médecin généraliste travaille dans un cabinet médical. Un juge exerce au tribunal. Un pilote de ligne passe ses heures de vol dans le cockpit. Et enfin, un cuisinier professionnel travaille dans une cuisine professionnelle.',q:'Associez chaque professionnel à son lieu de travail principal.',p:[['Un médecin généraliste','Un cabinet médical'],['Un juge','Un tribunal'],['Un pilote','Un cockpit'],['Un cuisinier','Une cuisine professionnelle']],e:'Vocabulaire des professions et lieux de travail : médecin → cabinet médical (también "une clinique"), juge → tribunal (también "palais de justice"), pilote → cockpit (= cabina de mando), cuisinier → cuisine professionnelle (= cocina profesional). Frequent en CO B1 pour les descriptions de métiers.'},
  /* ── Q18-20 standalone ── */
  {t:'mc',audio:'Les primo-accédants sont les acheteurs qui acquièrent leur premier bien immobilier. Ils bénéficient souvent d\'aides spécifiques de l\'État, comme le prêt à taux zéro, pour faciliter cet achat. Cependant, face à la hausse des prix, de nombreux primo-accédants sont contraints de reporter leur projet ou de s\'éloigner des centres-villes.',q:'Que désigne le terme « primo-accédant » ?',a:['Un agent immobilier débutant','Un locataire qui souhaite louer','Une personne qui achète son premier logement','Un investisseur qui achète plusieurs biens'],c:2,e:'"Primo" = premier(ère). "Accédant à la propriété" = acceso a la propiedad. "Primo-accédant" = persona que compra su primera vivienda. "Prêt à taux zéro" = préstamo sin intereses. "Reporter un projet" = aplazar un proyecto.'},
  {t:'tf',audio:'Dans notre émission de ce soir, nous nous intéressons aux habitudes numériques des Français. Selon une enquête menée auprès de 3 000 personnes en France, les 18-35 ans passent en moyenne 4 heures par jour sur les réseaux sociaux. Cette statistique représente une augmentation de 20 % par rapport à l\'année précédente.',q:'L\'enquête mentionnée dans l\'émission porte sur les habitudes numériques des Français.',c:true,e:'Vrai. "Nous nous intéressons aux habitudes numériques des Français" = nos interesamos por los hábitos digitales de los franceses. "Enquête menée auprès de 3 000 personnes en France" = encuesta realizada entre 3.000 personas en Francia. "Habitudes numériques" = hábitos digitales/en línea.'},
  {t:'mc',audio:'Dans l\'interview que nous venons d\'entendre, le chef Martineau explique que son secteur fait face à une crise de recrutement. Les jeunes hésitent à travailler dans la restauration à cause des horaires décalés, des week-ends travaillés et du manque de reconnaissance. Selon lui, la profession doit se réinventer pour attirer les nouvelles générations.',q:'D\'après ce résumé, pourquoi les jeunes hésitent-ils à travailler dans la restauration ?',a:['À cause des faibles salaires et du manque de formation','À cause des horaires difficiles et du manque de reconnaissance','À cause de la concurrence des livraisons à domicile','À cause des mauvaises conditions d\'hygiène'],c:1,e:'"Horaires décalés" = horarios irregulares/partidos. "Week-ends travaillés" = fines de semana trabajados. "Manque de reconnaissance" = falta de reconocimiento. "Se réinventer" = reinventarse. Ces problèmes structurels de la restauration sont un thème récurrent dans les médias français.'},
],


/* ──────────── B1 · EE ──────────── */
EE_B1: [
  /* ── FILL (1-10) ── */
  {t:'ee',mode:'fill',
   q:'Mettez le verbe entre parenthèses au subjonctif présent :\n\n« Il faut que tu ___ (venir) nous voir ce week-end. »',
   a:'viennes',alt:['VIENNES'],
   e:'Subjonctif de VENIR : je vienne, tu VIENNES, il/elle vienne, nous venions, vous veniez, ils viennent. "Il faut que + subjonctif" = es necesario que. Radical irrégulier : vienn-. Le subjonctif exprime la nécessité, le doute, le souhait → très fréquent au TEF B1.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le conditionnel passé du verbe entre parenthèses :\n\n« Si tu avais étudié davantage, tu ___ (réussir) l\'examen. »',
   a:'aurais réussi',alt:['AURAIS RÉUSSI','aurais reussi','AURAIS REUSSI'],
   e:'Conditionnel passé = AVOIR/ÊTRE au conditionnel + participe passé. RÉUSSIR → aurais réussi. Structure de l\'irréel du passé : "Si + plus-que-parfait, conditionnel passé". Compare : irréel du présent = "Si + imparfait, conditionnel présent".'},
  {t:'ee',mode:'fill',
   q:'Conjuguez le verbe au plus-que-parfait :\n\n« Quand je suis arrivé, elle ___ (partir) déjà. »',
   a:'était déjà partie',alt:['ÉTAIT DÉJÀ PARTIE','était partie','ÉTAIT PARTIE','etait partie','etait deja partie'],
   e:'Plus-que-parfait = AVOIR/ÊTRE à l\'imparfait + participe passé. PARTIR (avec ÊTRE) → était partie. Accord : elle → partie (féminin). Le plus-que-parfait exprime une action antérieure à une autre action passée.'},
  {t:'ee',mode:'fill',
   q:'Transformez à la voix passive :\n\n« On a construit cette cathédrale au XIIe siècle.\n→ Cette cathédrale ___ au XIIe siècle. »',
   a:'a été construite',alt:['A ÉTÉ CONSTRUITE','a ete construite','A ETE CONSTRUITE'],
   e:'Voix passive = ÊTRE (conjugué) + participe passé accordé avec le sujet. "Cette cathédrale" est féminin → construite. Le complément d\'agent (introduit par "par") est optionnel ici. Passif au passé composé : a été + pp.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le gérondif du verbe entre parenthèses :\n\n« Elle prend des notes ___ (écouter) le cours. »',
   a:'en écoutant',alt:['EN ÉCOUTANT','en ecoutant','EN ECOUTANT'],
   e:'Gérondif = EN + participe présent (-ANT). ÉCOUTER → en écoutant. Le gérondif exprime la simultanéité ou la manière. "Elle prend des notes EN ÉCOUTANT" = mientras escucha. Attention : le sujet des deux verbes est toujours le même.'},
  {t:'ee',mode:'fill',
   q:'Mettez au discours indirect :\n\n« Elle m\'a dit : "Je viendrai demain." \n→ Elle m\'a dit qu\'elle ___ le lendemain. »',
   a:'viendrait',alt:['VIENDRAIT'],
   e:'Discours indirect au passé : le futur simple → conditionnel présent. "Je viendrai" → elle viendrait. "Demain" → le lendemain (concordance des temps/changement de repère temporel). Autres transformations : maintenant → à ce moment-là, hier → la veille.'},
  {t:'ee',mode:'fill',
   q:'Choisissez le pronom relatif correct :\n\n« C\'est une question ___ je ne sais pas répondre. »\n(à laquelle / dont / que)',
   a:'à laquelle',alt:['À LAQUELLE','a laquelle','A LAQUELLE'],
   e:'"Répondre à quelque chose" → pronom relatif = À LAQUELLE (féminin singulier de "auquel"). Tableau : auquel (masc. sg.), à laquelle (fém. sg.), auxquels (masc. pl.), auxquelles (fém. pl.). Quand le verbe demande "à", on utilise à + lequel.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le mot de négation manquant :\n\n« Je n\'ai ___ cinq minutes pour te parler. »\n(que / rien / jamais)',
   a:'que',alt:['QUE'],
   e:'"Ne… que" = seulement / únicamente. "Je n\'ai QUE cinq minutes" = sólo tengo cinco minutos. Ne…que n\'est pas une vraie négation (aucune idée négative), contrairement à ne…jamais ou ne…rien. Le "que" se place devant l\'élément restreint.'},
  {t:'ee',mode:'fill',
   q:'Conjuguez au subjonctif présent :\n\n« Je doute qu\'il ___ (pouvoir) terminer à temps. »',
   a:'puisse',alt:['PUISSE'],
   e:'Subjonctif de POUVOIR (irrégulier) : je puisse, tu puisses, il PUISSE, nous puissions, vous puissiez, ils puissent. "Douter que + subjonctif" = dudar de que + subjuntivo. Autres déclencheurs : "bien que", "à moins que", "avant que", "pour que".'},
  {t:'ee',mode:'fill',
   q:'Accordez le participe passé :\n\n« Les lettres qu\'il a ___ (écrire) étaient très émouvantes. »',
   a:'écrites',alt:['ÉCRITES','ecrites','ECRITES'],
   e:'Accord du participe passé avec AVOIR : il s\'accorde avec le COD si celui-ci est PLACÉ AVANT le verbe. Ici : "les lettres" (féminin pluriel) est le COD antéposé → ÉCRITES. Si le COD est après : "Il a écrit des lettres" (pas d\'accord).'},
  /* ── WRITE (11-20) ── */
  {t:'ee',mode:'write',
   q:'Vous avez commandé un produit en ligne mais il est arrivé endommagé. Écrivez un email formel au service clientèle pour signaler le problème et demander un remboursement.',
   prompt:'Utilisez le vouvoiement. Incluez : objet du message, description du problème, demande précise et formule de politesse finale.',
   criteria:['Ton formel maintenu tout au long (vouvoiement)','Problème clairement décrit (état du produit)','Demande de remboursement ou remplacement formulée','Formule de politesse de clôture adaptée'],
   model:'Madame, Monsieur,\n\nJe me permets de vous contacter au sujet de ma commande n°12345, reçue le 5 mars. Malheureusement, l\'article est arrivé endommagé : l\'emballage était déchiré et le produit cassé.\n\nJe vous serais reconnaissant(e) de bien vouloir procéder à un remboursement intégral ou à l\'envoi d\'un nouveau produit dans les meilleurs délais.\n\nDans l\'attente de votre réponse, veuillez agréer mes cordiales salutations.\n\n[Prénom Nom]',
   e:'Email formel B1 : vouvoiement obligatoire. Ouverture : "Je me permets de vous contacter au sujet de…". Demande polie : "Je vous serais reconnaissant(e) de bien vouloir + infinitif". Clôture formelle : "Veuillez agréer mes cordiales salutations" (standard) ou "Salutations distinguées" (plus soutenu).'},
  {t:'ee',mode:'write',
   q:'Rédigez un court paragraphe argumentatif (5-7 phrases) donnant votre opinion sur l\'usage excessif des réseaux sociaux chez les adolescents.',
   prompt:'Exprimez clairement votre position, donnez 2 arguments et terminez par une proposition concrète.',
   criteria:['Position clairement exprimée dès le début','Au moins 2 arguments distincts développés','Connecteurs logiques utilisés (cependant, en effet, par conséquent…)','Proposition ou recommandation en conclusion'],
   model:'Selon moi, l\'usage excessif des réseaux sociaux présente de réels risques pour les adolescents. En effet, plusieurs études montrent un lien entre une utilisation prolongée et des troubles du sommeil ainsi qu\'une baisse de concentration. Par ailleurs, les jeunes peuvent être exposés à des contenus néfastes ou à la cyberintimidation. Cependant, il ne s\'agit pas d\'interdire ces outils, mais plutôt d\'apprendre aux jeunes à les utiliser de manière responsable, avec des limites claires fixées en famille.',
   e:'Structure argumentative B1 : thèse (position) + arguments (en effet, par ailleurs) + nuance/concession (cependant) + conclusion/proposition. Connecteurs clés : en effet, par ailleurs, cependant, néanmoins, c\'est pourquoi, ainsi. Éviter les généralités ; préférer des exemples précis.'},
  {t:'ee',mode:'write',
   q:'Rédigez un texte court (5-7 phrases) présentant les avantages ET les inconvénients du télétravail.',
   prompt:'Organisez votre texte en deux parties distinctes : d\'abord les avantages, puis les inconvénients.',
   criteria:['Au moins 2 avantages clairement mentionnés','Au moins 2 inconvénients clairement mentionnés','Structure en deux parties visible','Vocabulaire varié (éviter les répétitions)'],
   model:'Le télétravail offre plusieurs avantages non négligeables. Tout d\'abord, il permet d\'économiser du temps en évitant les trajets quotidiens, et favorise une meilleure conciliation entre vie professionnelle et vie personnelle. De plus, les employés peuvent souvent travailler dans un environnement plus calme et personnalisé.\n\nToutefois, le télétravail présente aussi des inconvénients. L\'isolement social peut nuire à la cohésion d\'équipe et affecter la motivation. En outre, la frontière entre travail et vie privée peut devenir floue, certains salariés ayant du mal à déconnecter en dehors des heures habituelles.',
   e:'Plan pour avantages/inconvénients : Partie 1 (tout d\'abord, de plus, en outre) + Partie 2 (toutefois, en revanche, cependant). Vocabulaire clé : conciliation vie pro/perso, cohésion d\'équipe, isolement, flexibilité, déconnecter, frontière floue. Ce type de texte est très fréquent au TEF EE B1.'},
  {t:'ee',mode:'write',
   q:'Vous postulez pour un poste d\'assistant(e) dans une entreprise francophone. Rédigez un court paragraphe de lettre de motivation (5-6 phrases) expliquant pourquoi vous êtes le/la candidat(e) idéal(e).',
   prompt:'Mentionnez vos compétences, votre expérience pertinente et votre motivation spécifique pour ce poste.',
   criteria:['Ton formel et professionnel maintenu','Compétences ou expériences pertinentes mentionnées','Motivation pour le poste exprimée','Cohérence et clarté du propos'],
   model:'Titulaire d\'un diplôme en administration des affaires et fort(e) de trois ans d\'expérience dans des environnements bilingues, je pense posséder le profil recherché pour ce poste. Rigoureux(se) et organisé(e), j\'ai développé de solides compétences en gestion administrative et en communication interculturelle. Je suis particulièrement attiré(e) par votre entreprise en raison de sa réputation d\'excellence et de ses valeurs qui correspondent aux miennes. C\'est avec enthousiasme et détermination que je souhaite apporter ma contribution à votre équipe.',
   e:'Lettre de motivation B1 : commencer par les atouts (compétences + expérience), puis exprimer l\'intérêt pour l\'entreprise, terminer par la projection dans le poste. Formules utiles : "fort(e) de X ans d\'expérience", "je pense posséder le profil", "je suis particulièrement attiré(e) par", "je souhaite apporter ma contribution".'},
  {t:'ee',mode:'write',
   q:'Votre ami(e) vient d\'échouer à un examen important et se sent découragé(e). Écrivez-lui un message (5-6 phrases) pour le/la soutenir et lui donner des conseils concrets.',
   prompt:'Utilisez le tutoiement. Montrez de l\'empathie, puis proposez au moins 2 conseils pratiques.',
   criteria:['Tutoiement utilisé de façon cohérente','Empathie exprimée dès le début','Au moins 2 conseils pratiques formulés','Ton chaleureux et encourageant'],
   model:'Je comprends que tu te sentes découragé(e) après cet échec, et c\'est tout à fait normal. Mais un examen raté n\'est pas une catastrophe : c\'est une occasion d\'apprendre et de rebondir. Je te conseille d\'abord d\'analyser tes erreurs avec ton professeur pour cibler tes points faibles. Ensuite, pourquoi ne pas établir un planning de révision plus régulier, en commençant dès maintenant ? N\'oublie pas de te ménager des pauses : un esprit reposé apprend mieux. Je suis là si tu as besoin de parler ou d\'aide pour réviser !',
   e:'Message de soutien B1 : registre familier (tutoiement). Exprimer l\'empathie : "Je comprends que tu…", "c\'est tout à fait normal". Conseils pratiques : "je te conseille de", "pourquoi ne pas + infinitif ?", "n\'oublie pas de". Clôture chaleureuse : "Je suis là si tu as besoin". Alterner encouragement et conseil concret.'},
  {t:'ee',mode:'write',
   q:'Donnez votre opinion sur l\'immigration en France en 5-7 phrases. Présentez une vision équilibrée en mentionnant à la fois des bénéfices et des défis.',
   prompt:'Évitez les extrêmes. Utilisez des nuances (certes, néanmoins, il est vrai que…). Concluez avec une idée constructive.',
   criteria:['Position nuancée (ni tout positif ni tout négatif)','Bénéfices de l\'immigration mentionnés','Défis ou difficultés mentionnés','Conclusion constructive ou proposition'],
   model:'L\'immigration est un sujet complexe qui mérite une réflexion nuancée. D\'un côté, les apports culturels et économiques des immigrés sont indéniables : ils enrichissent la société française et contribuent à des secteurs essentiels comme la santé, l\'agriculture et le bâtiment. De l\'autre, l\'intégration représente un défi réel, aussi bien pour les nouveaux arrivants que pour les communautés d\'accueil. Certes, des tensions peuvent apparaître, notamment autour du logement ou de l\'emploi. Néanmoins, avec des politiques d\'intégration adaptées — cours de langue, reconnaissance des diplômes étrangers, lutte contre les discriminations — il est possible de construire une société plus inclusive et cohésive.',
   e:'Sujet de société au TEF EE B1 : structure équilibrée. "D\'un côté… de l\'autre" = por un lado… por otro. Nuances : "certes" (si bien es cierto), "néanmoins" (no obstante), "il est vrai que". Vocabulaire : enrichissement culturel, intégration, politiques publiques, cohésion sociale. Éviter les affirmations non étayées.'},
  {t:'ee',mode:'write',
   q:'Racontez en 5-7 phrases un événement ou une expérience de votre vie qui vous a beaucoup appris ou qui a changé votre façon de voir les choses.',
   prompt:'Utilisez le passé composé et l\'imparfait. Décrivez le contexte, ce qui s\'est passé et ce que vous en avez retenu.',
   criteria:['Passé composé et imparfait utilisés correctement','Contexte de l\'événement décrit','Leçon ou changement de perspective exprimé','Récit cohérent et chronologique'],
   model:'Il y a trois ans, alors que je traversais une période difficile, j\'ai décidé de faire du bénévolat dans une association d\'aide alimentaire. Au début, je n\'y allais que pour m\'occuper, sans vraiment y croire. Mais très vite, j\'ai rencontré des personnes extraordinaires, des bénévoles de tous horizons qui donnaient de leur temps avec générosité et sans attendre de retour. Cette expérience m\'a profondément changé : j\'ai compris que le bonheur ne venait pas de ce qu\'on possède, mais de ce qu\'on donne. Depuis, je m\'engage régulièrement dans cette association et je ne regrette pas cette décision.',
   e:'Récit personnel B1 : alterner passé composé (actions) et imparfait (contexte/description/habitudes passées). "Il y a + durée" = hace X tiempo. "Alors que" = mientras que/en ese momento. Verbes de changement : changer, transformer, prendre conscience, réaliser. Clôture avec une réflexion = marque de B1.'},
  {t:'ee',mode:'write',
   q:'Comparez deux moyens de transport pour se rendre de Montréal à Québec : la voiture et le bus. Lequel recommandez-vous et pourquoi ? (5-6 phrases)',
   prompt:'Mentionnez le coût, la durée, le confort et l\'impact environnemental. Concluez avec une recommandation claire.',
   criteria:['Au moins 2 critères de comparaison abordés','Les deux options comparées équitablement','Recommandation finale clairement exprimée','Connecteurs de comparaison utilisés (en revanche, alors que, par rapport à…)'],
   model:'La voiture et le bus sont tous deux des options courantes pour relier Montréal à Québec (environ 250 km). La voiture offre plus de flexibilité : on part quand on veut et on s\'arrête où l\'on souhaite. Cependant, elle est plus coûteuse (essence, péages) et moins écologique. Le bus, en revanche, est moins cher et réduit l\'empreinte carbone, même si les horaires sont fixes et le confort parfois limité. Personnellement, je recommande le bus pour les voyages seuls ou en couple, car le rapport qualité-prix est meilleur et l\'impact environnemental, plus faible.',
   e:'Comparaison B1 : "alors que" / "en revanche" / "par rapport à" / "contrairement à". Critères typiques : coût (le coût, les frais), durée (le trajet dure), confort (l\'espace, la ponctualité), environnement (l\'empreinte carbone, les émissions de CO₂). Recommandation = "Je recommande… car…" ou "Il vaut mieux… pour…".'},
  {t:'ee',mode:'write',
   q:'Vous avez assisté à un festival de musique dans votre ville. Écrivez un court compte-rendu (5-7 phrases) pour un blog local, en décrivant l\'ambiance, les points forts et ce qui pourrait être amélioré.',
   prompt:'Utilisez des adjectifs variés et des structures de comparaison ou d\'appréciation. Donnez une note globale à la fin.',
   criteria:['Description de l\'ambiance/atmosphère','Au moins un point fort mentionné','Au moins un aspect à améliorer mentionné','Conclusion avec évaluation globale'],
   model:'Le Festival Musiques du Monde, qui s\'est tenu samedi dernier au parc municipal, a réuni plusieurs centaines de spectateurs dans une ambiance chaleureuse et festive. Les concerts étaient d\'excellente qualité, notamment la prestation du groupe Nzinga, dont les rythmes africains ont conquis le public. L\'organisation était globalement bien rodée, avec suffisamment de stands de restauration et une scène bien équipée. Cependant, le manque de places assises a été regretté par de nombreux participants, surtout les personnes âgées. En conclusion, c\'est une belle initiative culturelle qui mériterait quelques améliorations logistiques pour être encore plus accessible. Note : 4/5.',
   e:'Compte-rendu d\'événement B1 : description factuelle + évaluation. Vocabulaire : l\'ambiance (festive, chaleureuse, électrique), la prestation, l\'organisation, le public. Nuance : "globalement bien", "cependant", "mériterait". Registre semi-formel pour blog. Toujours conclure avec une appréciation générale.'},
  {t:'ee',mode:'write',
   q:'Vous répondez à un forum en ligne où quelqu\'un demande : « Comment apprendre le français rapidement et efficacement ? » Rédigez votre réponse en 5-7 phrases.',
   prompt:'Donnez au moins 3 conseils concrets et variés. Justifiez brièvement chaque conseil.',
   criteria:['Au moins 3 conseils distincts et concrets','Justification de chaque conseil','Ton adapté (forum = semi-formel, tutoiement ou vouvoiement possible)','Structure claire et lisible'],
   model:'Pour apprendre le français rapidement, voici quelques conseils qui m\'ont personnellement aidé. Premièrement, immerge-toi dans la langue chaque jour : écoute des podcasts, regarde des séries en version originale sous-titrée. Cette exposition régulière permet d\'intérioriser les structures naturellement. Deuxièmement, parle sans craindre les fautes : trouver un partenaire de conversation ou rejoindre un tandem linguistique accélère considérablement les progrès. Troisièmement, tiens un carnet de vocabulaire thématique et révise-le régulièrement avec des flashcards. Enfin, fixe-toi des objectifs précis et mesurables, comme regarder un film en français par semaine. La régularité prime sur l\'intensité !',
   e:'Conseils au forum B1 : "Premièrement / Deuxièmement / Enfin" pour structurer. Registre semi-formel. Justifier : "Cette exposition permet de…", "ce qui accélère…". Vocabulaire de l\'apprentissage : s\'immerger, intérioriser, un tandem linguistique, des flashcards, régulièrement. La dernière phrase de synthèse est une marque de style B1.'},
],

/* ──────────── B1 · EO ──────────── */
EO_B1: [
  /* ── REPEAT (1-8) ── */
  {t:'eo',mode:'repeat',q:'Répétez cette phrase complexe à voix haute en articulant clairement :',model:'Bien que la situation soit difficile, je suis convaincu(e) qu\'il est possible de trouver une solution satisfaisante pour tout le monde.',keywords:['bien que','situation','convaincu','solution','satisfaisante'],e:'"Bien que + subjonctif" = aunque + subjuntivo. "Soit" = subjonctif de ÊTRE. "Convaincu(e)" = convencido/a. "Satisfaisante" = satisfactoria. Structure concessive très utilisée à l\'oral B1 pour nuancer ses propos. Prononciation : "bien que" /bjɛ̃kə/, "convaincu" /kɔ̃vɛ̃ky/.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase au conditionnel passé, en marquant bien les liaisons :',model:'Si j\'avais su que la réunion était annulée, je ne serais pas venu(e) aussi tôt ce matin-là.',keywords:['avais su','annulée','serais','venu','matin-là'],e:'Conditionnel passé (irréel du passé) : "je ne serais pas venu(e)" = je suis (conditionnel) + participe passé avec ÊTRE. Liaison obligatoire : "serais_arrivé". "Ce matin-là" = esa mañana. "Annulée" (féminin, "la réunion"). Registre soutenu mais naturel à l\'oral B1.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase à la voix passive en articulant les formes verbales :',model:'La décision a été prise par la direction après plusieurs semaines de négociations avec les représentants du personnel.',keywords:['décision','prise','direction','négociations','représentants'],e:'Voix passive : "a été prise" = passé composé passif de PRENDRE. Accord : "la décision" (féminin) → prise. "Le personnel" = el personal. "Les représentants du personnel" = los representantes del personal/sindicato. Articuler clairement les groupes nominaux longs.'},
  {t:'eo',mode:'repeat',q:'Répétez cet énoncé avec une intonation naturelle, comme dans un débat :',model:'Je comprends votre point de vue, cependant je pense que la situation est plus complexe qu\'il n\'y paraît et mérite une analyse plus approfondie.',keywords:['comprends','cependant','complexe','paraît','approfondie'],e:'"Je comprends votre point de vue" = entiendo su punto de vista. "Cependant" = sin embargo. "Plus complexe qu\'il n\'y paraît" = más complejo de lo que parece ("n\'y" est explétif). "Mériter" = merecer. Formule de débat oral très utile : concession + contre-argument.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase en discours rapporté en articulant bien :',model:'Elle m\'a expliqué qu\'elle aurait aimé partir plus tôt, mais qu\'elle avait dû attendre la fin de la réunion.',keywords:['expliqué','aurait aimé','avait dû','attendre','réunion'],e:'"Aurait aimé" = conditionnel passé de AIMER (aurait + aimé). "Avait dû" = plus-que-parfait de DEVOIR (avait + dû). Concordance des temps en discours indirect passé : conditionnel passé et plus-que-parfait. "Dû" = participe passé de devoir.'},
  {t:'eo',mode:'repeat',q:'Répétez ce proverbe en français standard, en marquant les groupes rythmiques :',model:'Mieux vaut prévenir que guérir, car les problèmes non résolus finissent toujours par ressurgir au moment le plus inopportun.',keywords:['prévenir','guérir','résolus','ressurgir','inopportun'],e:'"Mieux vaut + infinitif que + infinitif" = más vale + infinitivo que. "Prévenir" = prevenir/advertir. "Guérir" = curar/sanar. "Inopportun" = inoportuno. "Ressurgir" = resurgir. Proverbe classique : más vale prevenir que curar. Groupes rythmiques en français : 2-3 syllabes par groupe.'},
  {t:'eo',mode:'repeat',q:'Répétez cette description orale en maintenant un rythme fluide :',model:'Le quartier dans lequel j\'habite est à la fois calme et bien desservi par les transports en commun, ce qui en fait un endroit très agréable à vivre au quotidien.',keywords:['quartier','lequel','desservi','transports','quotidien'],e:'"Dans lequel" = pronom relatif composé (en el cual). "Bien desservi" = bien comunicado/con buena conexión de transporte. "Ce qui en fait" = lo que lo convierte en. "Au quotidien" = en el día a día. Rythme : ne pas hésiter entre les groupes nominaux, maintenir la fluidité.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase avec une négation complexe en articulant clairement :',model:'Non seulement le projet n\'a pas été approuvé, mais en plus les délais ont été repoussés de plusieurs semaines sans aucune explication officielle.',keywords:['seulement','approuvé','délais','repoussés','explication'],e:'"Non seulement… mais en plus" = no solo… sino también/encima. Structure d\'insistance/accumulation. "Approuvé" = aprobado. "Délais repoussés" = plazos aplazados. "Sans aucune explication" = sin ninguna explicación. Très expressif à l\'oral pour souligner plusieurs problèmes.'},
  /* ── ANSWER (9-15) ── */
  {t:'eo',mode:'answer',q:'Parlez d\'une expérience professionnelle ou d\'un stage que vous avez fait. Qu\'avez-vous appris et qu\'est-ce qui vous a le plus marqué(e) ?',model:'Lors de mon stage chez [entreprise], j\'étais chargé(e) de... Ce qui m\'a le plus marqué(e), c\'est... J\'ai appris à... Cette expérience m\'a permis de...',keywords:['stage','chargé','appris','marqué','expérience'],e:'Vocabulaire du monde professionnel : "être chargé(e) de" = ser responsable de, "travailler en équipe", "acquérir des compétences", "gérer un projet". Temps verbaux : passé composé (actions), imparfait (contexte). "Ce qui m\'a le plus marqué(e)" = subordonnée relative avec ce + qui. Marque de B1 : développer une réflexion personnelle.'},
  {t:'eo',mode:'answer',q:'Quels sont, selon vous, les principaux avantages des transports en commun par rapport à la voiture individuelle ? Donnez au moins deux arguments.',model:'Selon moi, les transports en commun présentent plusieurs avantages... D\'abord... De plus... En outre, ils permettent de...',keywords:['transports','avantages','pollution','coût','environnement'],e:'Argumentaire oral B1 : "D\'abord... De plus... En outre..." = Primero... Además... Por otro parte... Arguments types : réduction de la pollution, coût moins élevé, réduction de la congestion, temps de trajet utilisable (lecture, etc.). "Par rapport à" = en comparación con. Exprimer une opinion : "selon moi", "à mon avis", "je pense que".'},
  {t:'eo',mode:'answer',q:'Décrivez la ville ou le pays idéal dans lequel vous aimeriez vivre. Parlez du climat, de l\'environnement, des infrastructures et de la qualité de vie.',model:'La ville idéale pour moi serait... Elle se trouverait... Le climat y serait... En ce qui concerne les infrastructures, il y aurait...',keywords:['idéale','serait','climat','infrastructures','qualité'],e:'Conditionnel présent pour exprimer l\'hypothèse/idéal : "serait", "y aurait", "je pourrais". Vocabulaire urbain : des espaces verts, bien desservi, sécurisé, des services de qualité, la mixité sociale. "En ce qui concerne" = en lo que respecta a. "La qualité de vie" = la calidad de vida. Connecteurs de thème : "Pour ce qui est de", "Quant à".'},
  {t:'eo',mode:'answer',q:'Donnez votre opinion sur l\'impact des smartphones sur les relations humaines. Pensez-vous qu\'ils rapprochent ou éloignent les gens ? Justifiez votre réponse.',model:'À mon avis, les smartphones ont un impact contradictoire sur les relations humaines. D\'un côté... De l\'autre... Cependant, je pense que...',keywords:['smartphones','relations','côté','rapprochent','éloignent'],e:'Opinion nuancée B1 : "D\'un côté... de l\'autre" = por un lado... por otro. "Je pense que" + indicatif. "Il me semble que" + indicatif. "Je doute que" + subjonctif. Arguments : rapprocher les gens à distance mais créer une distance physique dans la vie réelle. Vocabulaire : addiction, isolement, communication virtuelle, présence physique.'},
  {t:'eo',mode:'answer',q:'Comment vous préparez-vous habituellement à un examen important ? Décrivez votre méthode de travail étape par étape.',model:'Pour me préparer à un examen, je commence généralement par... Ensuite, je... Je consacre également du temps à... La veille de l\'examen, je...',keywords:['préparez','méthode','réviser','étape','veille'],e:'Description d\'un processus : "D\'abord... Ensuite... Puis... Enfin..." = Primero... Luego... Después... Finalmente. "La veille" = la víspera/el día anterior. Vocabulaire : réviser, mémoriser, faire des fiches, s\'entraîner sur des exercices, gérer le stress. "Je consacre du temps à" = dedico tiempo a. Exprimer la fréquence : "généralement", "habituellement", "en règle générale".'},
  {t:'eo',mode:'answer',q:'Parlez d\'une tradition ou d\'une coutume typique de votre pays ou de votre culture. Expliquez son origine (si vous la connaissez) et son importance pour vous.',model:'Dans ma culture, une tradition importante est... Elle se déroule généralement... Son origine remonte à... Pour moi, cette tradition représente...',keywords:['tradition','culture','déroule','origine','représente'],e:'Décrire une tradition B1 : "se dérouler" = tener lugar/desarrollarse. "Remonter à" = remontarse a. "Marquer" = marcar/significar. Vocabulaire culturel : une fête traditionnelle, une coutume ancestrale, un rite de passage, transmettre des valeurs. "Cette tradition représente pour moi..." = estructura personal para dar significado.'},
  {t:'eo',mode:'answer',q:'Un(e) ami(e) vous demande si vous préférez vivre en ville ou à la campagne. Expliquez votre préférence avec des arguments précis.',model:'Personnellement, je préfère vivre en [ville/campagne], et ce pour plusieurs raisons. Premièrement... De plus... Certes, [inconvénient], mais...',keywords:['préfère','ville','campagne','raisons','certes'],e:'Exprimer une préférence motivée B1 : "Je préfère X à Y parce que…". Concession : "Certes, la ville peut être bruyante, mais elle offre…". Vocabulaire ville/campagne : les animations culturelles, les espaces naturels, la pollution, la tranquillité, l\'isolement, les commodités. "Et ce pour plusieurs raisons" = y esto por varias razones (structure emphatique).'},
  /* ── PRODUCE (16-20) ── */
  {t:'eo',mode:'produce',q:'Présentez à voix haute un problème de société qui vous préoccupe (environnement, inégalités, santé publique…). Expliquez le problème, ses causes et proposez une solution.',model:'Le problème qui me préoccupe le plus est... En effet, [causes]... Les conséquences sont... Pour résoudre ce problème, il faudrait...',keywords:['problème','causes','conséquences','résoudre','faudrait'],e:'Structure de présentation de problème B1 : Définition → Causes → Conséquences → Solutions. "Il faudrait que + subjonctif" = habría que. "Il serait nécessaire de" = sería necesario. "En effet" = en efecto (explication). "Par conséquent" = por lo tanto. "Prendre des mesures" = tomar medidas. Registre semi-formel, clair, structuré.'},
  {t:'eo',mode:'produce',q:'Défendez à voix haute le point de vue suivant : « Il faudrait rendre les transports en commun gratuits dans toutes les grandes villes. » Utilisez au moins 3 arguments.',model:'Je suis favorable à la gratuité des transports en commun pour plusieurs raisons. Premièrement... Deuxièmement... Enfin...',keywords:['favorable','gratuité','transports','premièrement','enfin'],e:'Défendre une thèse B1 : "Je suis favorable/opposé(e) à" + nom. "Pour plusieurs raisons" = por varias razones. Arguments type : réduction de la pollution, lutte contre les inégalités sociales, désengorgement du trafic routier, amélioration de la qualité de l\'air. Contrer une objection : "Certes cela a un coût, mais…". "Désengorgement" = descongestión.'},
  {t:'eo',mode:'produce',q:'Décrivez à voix haute votre parcours scolaire ou professionnel en détail. Parlez de vos études, de vos expériences et de vos projets d\'avenir.',model:'J\'ai commencé mes études de... après avoir obtenu mon... Ensuite, j\'ai... Mon expérience la plus marquante a été... À l\'avenir, j\'aimerais...',keywords:['études','obtenu','expérience','marquante','aimerais'],e:'Récit de parcours B1 : Chronologie avec passé composé + imparfait. "Après avoir + participe passé" = infinitif passé (après avoir obtenu). "À l\'avenir" + conditionnel : "j\'aimerais", "je souhaiterais". Vocabulaire : un diplôme, une licence/maîtrise, une spécialisation, acquérir de l\'expérience, se reconvertir. Longueur cible : 1 à 2 minutes.'},
  {t:'eo',mode:'produce',q:'Donnez à voix haute des conseils à quelqu\'un qui vient d\'arriver dans un nouveau pays et doit s\'intégrer. Proposez au moins 4 conseils concrets et justifiez-les.',model:'Si vous venez d\'arriver dans un nouveau pays, voici quelques conseils. D\'abord, je vous conseille de... parce que... Ensuite... Il est aussi important de...',keywords:['conseils','intégrer','recommande','langue','communauté'],e:'Donner des conseils à l\'oral B1 : "Je vous conseille de", "Je vous recommande de", "Il est important de", "Pensez à", "N\'hésitez pas à". Subjonctif après expressions de conseil : "Il faut que vous". Vocabulaire de l\'intégration : apprendre la langue locale, s\'ouvrir aux autres cultures, rejoindre des associations, tisser des liens. "Tisser des liens" = crear vínculos/lazos.'},
  {t:'eo',mode:'produce',q:'Racontez à voix haute un moment de votre vie où vous avez dû surmonter un obstacle ou une difficulté. Que vous a-t-il appris sur vous-même ?',model:'Il y a quelque temps, j\'ai traversé une période difficile quand... Au début, je ne savais pas comment... Mais j\'ai décidé de... Cette expérience m\'a appris que...',keywords:['surmonter','obstacle','traversé','appris','décidé'],e:'Récit personnel B1 avec réflexion : "Surmonter un obstacle" = superar un obstáculo. "Faire face à" = hacer frente a. "J\'ai décidé de" = decidí. "Cette expérience m\'a appris que…" = esta experiencia me enseñó que. Alterner passé composé (actions) et imparfait (état d\'esprit à l\'époque). Conclure avec une leçon de vie → marque de niveau B1.'},
],


/* ──────────── B2 · CE ──────────── */
CE_B2: [
  /* ── PASSAGE 1 : IA et emploi (Q1-4) ── */
  {t:'mc',passage:'L\'intelligence artificielle suscite des interrogations croissantes quant à son impact sur le marché du travail. Si certains économistes prédisent une destruction massive d\'emplois, d\'autres soulignent que chaque révolution technologique a historiquement généré autant de postes qu\'elle en a supprimés. La réalité est probablement plus nuancée : les tâches routinières et répétitives seront les plus touchées, tandis que les métiers exigeant créativité, empathie et pensée critique résisteront mieux. Néanmoins, la question de la transition — comment reconvertir rapidement des millions de travailleurs — demeure un défi politique majeur que les gouvernements ne peuvent se permettre d\'ignorer.',q:'Quelle est la position de l\'auteur sur l\'impact de l\'IA sur l\'emploi ?',a:['L\'IA détruira inévitablement la majorité des emplois','L\'IA ne représente aucun danger réel','La situation est complexe et réclame une gestion politique active','Les économistes sont unanimes sur les effets négatifs de l\'IA'],c:2,e:'"La réalité est probablement plus nuancée" = la realidad es probablemente más matizada. L\'auteur adopte une position médiane entre catastrophisme et optimisme, et appelle à une politique de reconversion. Position modérée + urgence politique = marque stylistique d\'un article analytique B2.'},
  {t:'mc',passage:'L\'intelligence artificielle suscite des interrogations croissantes quant à son impact sur le marché du travail. Si certains économistes prédisent une destruction massive d\'emplois, d\'autres soulignent que chaque révolution technologique a historiquement généré autant de postes qu\'elle en a supprimés. La réalité est probablement plus nuancée : les tâches routinières et répétitives seront les plus touchées, tandis que les métiers exigeant créativité, empathie et pensée critique résisteront mieux. Néanmoins, la question de la transition — comment reconvertir rapidement des millions de travailleurs — demeure un défi politique majeur que les gouvernements ne peuvent se permettre d\'ignorer.',q:'Selon le texte, quels emplois résisteront le mieux à l\'automatisation ?',a:['Les postes de direction','Les métiers exigeant créativité, empathie et pensée critique','Les emplois industriels physiques','Les professions médicales uniquement'],c:1,e:'"Exigeant" (participe présent adjectival) = que requieren. Le texte oppose "tâches routinières et répétitives" (vulnérables) à "créativité, empathie, pensée critique" (résistantes). Repérer les oppositions binaires dans les textes analytiques = compétence clé CE B2.'},
  {t:'tf',passage:'L\'intelligence artificielle suscite des interrogations croissantes quant à son impact sur le marché du travail. Si certains économistes prédisent une destruction massive d\'emplois, d\'autres soulignent que chaque révolution technologique a historiquement généré autant de postes qu\'elle en a supprimés. La réalité est probablement plus nuancée : les tâches routinières et répétitives seront les plus touchées, tandis que les métiers exigeant créativité, empathie et pensée critique résisteront mieux. Néanmoins, la question de la transition — comment reconvertir rapidement des millions de travailleurs — demeure un défi politique majeur que les gouvernements ne peuvent se permettre d\'ignorer.',q:'Le texte affirme que toutes les révolutions technologiques passées ont entraîné une perte nette d\'emplois.',c:false,e:'Faux. "D\'autres soulignent que chaque révolution technologique a historiquement généré autant de postes qu\'elle en a supprimés." Cet argument de la compensation historique est présenté comme la position de certains économistes — pas comme une réalité indiscutable.'},
  {t:'mc',passage:'L\'intelligence artificielle suscite des interrogations croissantes quant à son impact sur le marché du travail. Si certains économistes prédisent une destruction massive d\'emplois, d\'autres soulignent que chaque révolution technologique a historiquement généré autant de postes qu\'elle en a supprimés. La réalité est probablement plus nuancée : les tâches routinières et répétitives seront les plus touchées, tandis que les métiers exigeant créativité, empathie et pensée critique résisteront mieux. Néanmoins, la question de la transition — comment reconvertir rapidement des millions de travailleurs — demeure un défi politique majeur que les gouvernements ne peuvent se permettre d\'ignorer.',q:'« La question de la transition » désigne dans ce texte :',a:['Le passage d\'une économie agricole vers industrielle','Le changement de gouvernement lors des élections','La reconversion professionnelle des travailleurs déplacés par l\'IA','La migration des entreprises vers les pays à bas coûts'],c:2,e:'"La transition" = el período de cambio entre la economía actual y la automatizada. "Reconvertir des travailleurs" = reciclar/reconvertir trabajadores. "Défi politique majeur" = reto político mayor. L\'auteur souligne que c\'est une urgence politique, pas seulement économique.'},
  /* ── PASSAGE 2 : Extrait littéraire (Q5-7) ── */
  {t:'mc',passage:'Il avait cette façon particulière de traverser une pièce comme si les murs n\'existaient pas, comme si le monde entier était fait pour lui céder le passage. On ne savait jamais s\'il vous avait vu ou s\'il regardait à travers vous. Les femmes trouvaient cela fascinant ; les hommes, plus prosaïquement, appelaient ça de l\'arrogance. Lui, il n\'aurait su dire. Il vivait dans cette bulle de certitudes que confère parfois une enfance trop protégée, et dont on ne sort, en général, que par l\'épreuve.',q:'Quelle impression générale le personnage crée-t-il sur son entourage ?',a:['Il est admiré unanimement pour sa modestie','Il provoque des réactions contrastées selon les personnes','Il est unanimement rejeté par son entourage','Il passe complètement inaperçu'],c:1,e:'"Prosaïquement" = prosaicamente, sin romanticismo. Les femmes : fascination. Les hommes : "arrogance". Deux lectures opposées du même comportement. En littérature B2 : analyser comment un auteur construit un personnage par le regard contradictoire des autres.'},
  {t:'tf',passage:'Il avait cette façon particulière de traverser une pièce comme si les murs n\'existaient pas, comme si le monde entier était fait pour lui céder le passage. On ne savait jamais s\'il vous avait vu ou s\'il regardait à travers vous. Les femmes trouvaient cela fascinant ; les hommes, plus prosaïquement, appelaient ça de l\'arrogance. Lui, il n\'aurait su dire. Il vivait dans cette bulle de certitudes que confère parfois une enfance trop protégée, et dont on ne sort, en général, que par l\'épreuve.',q:'Le narrateur adopte un regard entièrement admiratif envers ce personnage.',c:false,e:'Faux. Le narrateur use de termes légèrement critiques ou ironiques : "arrogance", "enfance trop protégée", "dont on ne sort que par l\'épreuve" (le personnage a encore des leçons à apprendre). Ton : nuancé, légèrement distancié, pas admiratif.'},
  {t:'mc',passage:'Il avait cette façon particulière de traverser une pièce comme si les murs n\'existaient pas, comme si le monde entier était fait pour lui céder le passage. On ne savait jamais s\'il vous avait vu ou s\'il regardait à travers vous. Les femmes trouvaient cela fascinant ; les hommes, plus prosaïquement, appelaient ça de l\'arrogance. Lui, il n\'aurait su dire. Il vivait dans cette bulle de certitudes que confère parfois une enfance trop protégée, et dont on ne sort, en général, que par l\'épreuve.',q:'« Cette bulle de certitudes » suggère que le personnage :',a:['Possède une grande intelligence analytique','Vit isolé dans ses convictions, coupé de la réalité','Mène une vie sociale épanouissante','A développé sa confiance grâce à ses épreuves'],c:1,e:'"Bulle" = burbuja (metáfora de aislamiento de la realidad). "Certitudes" = certezas inamovibles. "Que confère une enfance trop protégée" = que otorga una infancia sobreprotegida. "Dont on ne sort que par l\'épreuve" = de la que solo se sale mediante la adversidad. Métaphore de l\'isolement + immaturité = analyse littéraire B2.'},
  /* ── PASSAGE 3 : Système éducatif (Q8-11) ── */
  {t:'mc',passage:'Le système éducatif français, souvent présenté comme le gardien de l\'égalité républicaine, peine pourtant à remplir sa promesse fondatrice. Les études comparatives internationales révèlent régulièrement que la France figure parmi les pays de l\'OCDE où l\'origine socioéconomique des élèves détermine le plus fortement leur réussite scolaire. Loin d\'effacer les inégalités, l\'école les reproduit parfois avec une redoutable efficacité. Face à ce constat, les partisans d\'une refonte en profondeur s\'affrontent aux défenseurs d\'un modèle dont les imperfections n\'empêcheraient pas l\'excellence — comme en témoigne le rang des grandes écoles françaises dans les classements mondiaux. Le débat, clivant, dit en creux beaucoup de choses sur la conception française de la méritocratie.',q:'Quelle est la thèse centrale de cet article ?',a:['Le système éducatif français est le meilleur au monde','La France doit copier le modèle scandinave','L\'école française ne tient pas sa promesse d\'égalité, malgré son prestige','Les grandes écoles constituent le cœur du problème'],c:2,e:'"Peine à remplir sa promesse fondatrice" = le cuesta cumplir su promesa fundamental. "Gardien de l\'égalité républicaine" = guardián de la igualdad republicana. L\'auteur démontre l\'écart entre idéal républicain et réalité statistique internationale. "Loin d\'effacer les inégalités, l\'école les reproduit" = structure rhétorique d\'inversion/réfutation.'},
  {t:'tf',passage:'Le système éducatif français, souvent présenté comme le gardien de l\'égalité républicaine, peine pourtant à remplir sa promesse fondatrice. Les études comparatives internationales révèlent régulièrement que la France figure parmi les pays de l\'OCDE où l\'origine socioéconomique des élèves détermine le plus fortement leur réussite scolaire. Loin d\'effacer les inégalités, l\'école les reproduit parfois avec une redoutable efficacité. Face à ce constat, les partisans d\'une refonte en profondeur s\'affrontent aux défenseurs d\'un modèle dont les imperfections n\'empêcheraient pas l\'excellence — comme en témoigne le rang des grandes écoles françaises dans les classements mondiaux. Le débat, clivant, dit en creux beaucoup de choses sur la conception française de la méritocratie.',q:'L\'article défend sans réserve que les grandes écoles prouvent l\'excellence du système éducatif.',c:false,e:'Faux. L\'argument des grandes écoles est rapporté comme celui des "défenseurs du modèle existant" — l\'auteur le cite mais ne l\'endosse pas : "le débat, clivant, dit en creux..." révèle une position réservée. Repérer le discours rapporté vs la position de l\'auteur = compétence fondamentale CE B2.'},
  {t:'mc',passage:'Le système éducatif français, souvent présenté comme le gardien de l\'égalité républicaine, peine pourtant à remplir sa promesse fondatrice. Les études comparatives internationales révèlent régulièrement que la France figure parmi les pays de l\'OCDE où l\'origine socioéconomique des élèves détermine le plus fortement leur réussite scolaire. Loin d\'effacer les inégalités, l\'école les reproduit parfois avec une redoutable efficacité. Face à ce constat, les partisans d\'une refonte en profondeur s\'affrontent aux défenseurs d\'un modèle dont les imperfections n\'empêcheraient pas l\'excellence — comme en témoigne le rang des grandes écoles françaises dans les classements mondiaux. Le débat, clivant, dit en creux beaucoup de choses sur la conception française de la méritocratie.',q:'Que signifie « dit en creux » dans la dernière phrase ?',a:['Dit de manière directe et explicite','Révèle quelque chose par ce qui est implicite ou absent','Dit de façon confuse et contradictoire','Dit par des voix marginales'],c:1,e:'"En creux" = en negativo / por lo que no se dice (como el molde negativo que revela la forma). Ce débat révèle IMPLICITEMENT la vision française de la méritocratie sans jamais la nommer directement. Maîtrise du sens figuré et de l\'implicite = compétence stylistique B2.'},
  {t:'mc',passage:'Le système éducatif français, souvent présenté comme le gardien de l\'égalité républicaine, peine pourtant à remplir sa promesse fondatrice. Les études comparatives internationales révèlent régulièrement que la France figure parmi les pays de l\'OCDE où l\'origine socioéconomique des élèves détermine le plus fortement leur réussite scolaire. Loin d\'effacer les inégalités, l\'école les reproduit parfois avec une redoutable efficacité. Face à ce constat, les partisans d\'une refonte en profondeur s\'affrontent aux défenseurs d\'un modèle dont les imperfections n\'empêcheraient pas l\'excellence — comme en témoigne le rang des grandes écoles françaises dans les classements mondiaux. Le débat, clivant, dit en creux beaucoup de choses sur la conception française de la méritocratie.',q:'L\'auteur conclut que ce débat sur l\'éducation :',a:['A été résolu par les réformes récentes','Révèle implicitement la conception française de la méritocratie','N\'intéresse plus les citoyens','Prouve la supériorité du système français'],c:1,e:'"La conception française de la méritocratie" = la concepción francesa de la meritocracia. La France valorise officiellement le mérite individuel, mais le débat révèle que ce mérite reste conditionné par l\'origine sociale. Tension méritocratie/reproduction sociale = débat sociologique majeur en France.'},
  /* ── PASSAGE 4 : Neurosciences du sommeil (Q12-14) ── */
  {t:'mc',passage:'Longtemps considéré comme un état passif d\'inaction cérébrale, le sommeil est aujourd\'hui reconnu par la neurologie comme une phase d\'activité intense et indispensable. Durant les cycles de sommeil paradoxal, le cerveau consolide les apprentissages de la journée, élimine les toxines accumulées et renforce les connexions neuronales jugées pertinentes. La privation chronique de sommeil n\'est plus considérée comme un simple inconfort : elle est désormais associée à des risques accrus de maladies cardiovasculaires, de diabète de type 2 et de troubles cognitifs. Pourtant, dans des sociétés qui valorisent la performance et la productivité, l\'image du « dormeur » reste paradoxalement stigmatisée.',q:'Quelle idée reçue ce texte cherche-t-il à remettre en question ?',a:['L\'idée que la neurologie est une science récente','L\'idée que le sommeil est un état passif et non essentiel','L\'idée que les maladies cardiovasculaires sont liées au stress','L\'idée que les sociétés valorisent la santé avant la productivité'],c:1,e:'Structure argumentative de réfutation : "Longtemps considéré comme X... est aujourd\'hui reconnu comme Y". L\'auteur réfute l\'idée reçue ("état passif d\'inaction") grâce aux découvertes récentes. "Remettre en question" = cuestionar una idea establecida. Structure classique : idée reçue → réalité scientifique → paradoxe social.'},
  {t:'tf',passage:'Longtemps considéré comme un état passif d\'inaction cérébrale, le sommeil est aujourd\'hui reconnu par la neurologie comme une phase d\'activité intense et indispensable. Durant les cycles de sommeil paradoxal, le cerveau consolide les apprentissages de la journée, élimine les toxines accumulées et renforce les connexions neuronales jugées pertinentes. La privation chronique de sommeil n\'est plus considérée comme un simple inconfort : elle est désormais associée à des risques accrus de maladies cardiovasculaires, de diabète de type 2 et de troubles cognitifs. Pourtant, dans des sociétés qui valorisent la performance et la productivité, l\'image du « dormeur » reste paradoxalement stigmatisée.',q:'Dans les sociétés modernes décrites dans le texte, bien dormir est socialement valorisé.',c:false,e:'Faux. "L\'image du « dormeur » reste paradoxalement stigmatisée" = la imagen del que duerme mucho sigue paradójicamente estigmatizada. "Paradoxalement" : la science prouve l\'importance du sommeil, mais la norme sociale le condamne. "Stigmatiser" = estigmatizar.'},
  {t:'mc',passage:'Longtemps considéré comme un état passif d\'inaction cérébrale, le sommeil est aujourd\'hui reconnu par la neurologie comme une phase d\'activité intense et indispensable. Durant les cycles de sommeil paradoxal, le cerveau consolide les apprentissages de la journée, élimine les toxines accumulées et renforce les connexions neuronales jugées pertinentes. La privation chronique de sommeil n\'est plus considérée comme un simple inconfort : elle est désormais associée à des risques accrus de maladies cardiovasculaires, de diabète de type 2 et de troubles cognitifs. Pourtant, dans des sociétés qui valorisent la performance et la productivité, l\'image du « dormeur » reste paradoxalement stigmatisée.',q:'Le terme « paradoxalement » dans la dernière phrase souligne :',a:['La contradiction entre valeur scientifique du sommeil et son image sociale négative','Le désaccord entre scientifiques sur les bienfaits du sommeil','L\'idée que dormir beaucoup rend les gens plus productifs','La difficulté à mesurer la qualité du sommeil en laboratoire'],c:0,e:'"Paradoxalement" = paradójicamente. Le paradoxe : (1) la science prouve que le sommeil est vital, (2) la société stigmatise ceux qui dorment beaucoup. Reconnaître la fonction rhétorique des adverbes de modalité (paradoxalement, étrangement, curieusement) = compétence stylistique CE B2.'},
  /* ── MATCH + standalone (Q15-20) ── */
  {t:'match',q:'Associez chaque connecteur soutenu à sa valeur logique.',p:[['Bien que','Concession (+ subjonctif)'],['Or','Transition inattendue (+ indicatif)'],['Quoique','Concession (+ subjonctif)'],['Partant','Conséquence (registre soutenu)']],e:'"Bien que / quoique" + subjonctif = aunque. "Or" = pues bien / ahora bien (introduce un hecho que matiza lo anterior). "Partant" = por tanto / en consecuencia (muy formal). Ces connecteurs distinguent le niveau B2 du B1 dans la lecture de textes académiques ou littéraires.'},
  {t:'mc',q:'Dans un article d\'analyse, que signifie « se permettre d\'ignorer » (comme dans : « les gouvernements ne peuvent se permettre d\'ignorer ») ?',a:['Oublier involontairement','Refuser intentionnellement de tenir compte de quelque chose','Décider de pardonner une erreur','Autoriser quelqu\'un à ne pas respecter les règles'],c:1,e:'"Se permettre de + infinitif" = permitirse + infinitivo. Utilisé à la forme négative, il signifie "no pueden ignorarlo" = ne pas avoir le luxe de l\'ignorer. Tour idiomatique fréquent dans les textes formels et analytiques pour exprimer une obligation implicite.'},
  {t:'tf',q:'Dans un texte littéraire en français, la construction « comme si + imparfait » exprime une comparaison avec quelque chose de réel et avéré.',c:false,e:'Faux. "Comme si + imparfait/plus-que-parfait" = como si + subjuntivo → exprime une HYPOTHÈSE irréelle ou une COMPARAISON fictive. Ex : "Il marchait comme si le monde lui appartenait" = irréel, pas une réalité. Structure littéraire fréquente pour créer des images et caractériser des personnages.'},
  {t:'mc',q:'Dans un article d\'opinion, l\'expression « loin de + infinitif » sert à :',a:['Exprimer une grande distance géographique','Nier l\'idée exprimée par l\'infinitif et affirmer le contraire','Introduire un exemple positif','Formuler une hypothèse incertaine'],c:1,e:'"Loin de + infinitif" = lejos de + infinitivo → niega la acción y la invierte. "Loin d\'effacer les inégalités, l\'école les reproduit" = lejos de borrar las desigualdades, las reproduce. Marque d\'inversion rhétorique. Synonymes : "au lieu de", "contrairement à ce que l\'on pourrait croire".'},
  {t:'mc',q:'Laquelle de ces expressions appartient au registre le plus soutenu (littéraire/académique) ?',a:['"C\'est vachement bien expliqué"','"C\'est assez bien expliqué"','"C\'est bien expliqué"','"Cela est exposé avec une redoutable clarté"'],c:3,e:'"Vachement" = très familier. "Assez bien / bien" = neutre/standard. "Exposé avec une redoutable clarté" = registre soutenu/académique. "Redoutable" = formidable/implacable (registre formel). "Exposer" vs "expliquer" : choix lexical qui marque le niveau de langue. Reconnaître les registres de langue = compétence B2 CE.'},
  {t:'mc',q:'Dans un texte analytique, laquelle de ces phrases exprime le mieux une nuance concessive ?',a:['"Le télétravail est mauvais pour les entreprises."','"Certes, le télétravail favorise l\'autonomie, mais il peut fragiliser la cohésion d\'équipe."','"Le télétravail n\'a aucun avantage connu."','"Tout le monde aime le télétravail sans exception."'],c:1,e:'"Certes... mais" = la structure concessive par excellence au niveau B2. Elle reconnaît la validité partielle d\'un argument (thèse adverse) avant d\'introduire la réserve principale (antithèse). "Fragiliser" = debilitar. "Cohésion d\'équipe" = cohesión de equipo. Reconnaître et produire cette structure = marque de maturité argumentative B2.'},
],

/* ──────────── B2 · CO ──────────── */
CO_B2: [
  /* ── CONFÉRENCE : Démocratie numérique (Q1-4) ── */
  {t:'mc',audio:'Mesdames et Messieurs, je voudrais vous poser une question fondamentale : les démocraties modernes sont-elles équipées pour faire face aux défis de la désinformation numérique ? Nous vivons à une époque où un faux article peut être partagé un million de fois avant qu\'un démenti officiel ne soit publié. Les algorithmes des plateformes récompensent l\'engagement émotionnel, favorisant ainsi les contenus outranciers au détriment de l\'information nuancée. Certains politologues parlent d\'une infodémie — une épidémie de fausses informations — qui ronge le tissu démocratique de l\'intérieur. Ma thèse est simple : sans une éducation aux médias massifiée et obligatoire, nos démocraties seront de plus en plus vulnérables.',q:'Quelle est la thèse principale de cet orateur ?',a:['Internet doit être entièrement régulé par les gouvernements','La désinformation est un problème uniquement occidental','L\'éducation aux médias est indispensable pour protéger la démocratie','Les plateformes numériques devraient être fermées'],c:2,e:'"Ma thèse est simple" = annonce directe de la position. "Sans une éducation aux médias massifiée et obligatoire" = sine qua non de la démocratie saine. "Ronger" = corroer. "Le tissu démocratique" = el tejido democrático. Structure B2 : ouverture rhétorique (question) → constat → thèse.'},
  {t:'tf',audio:'Mesdames et Messieurs, je voudrais vous poser une question fondamentale : les démocraties modernes sont-elles équipées pour faire face aux défis de la désinformation numérique ? Nous vivons à une époque où un faux article peut être partagé un million de fois avant qu\'un démenti officiel ne soit publié. Les algorithmes des plateformes récompensent l\'engagement émotionnel, favorisant ainsi les contenus outranciers au détriment de l\'information nuancée. Certains politologues parlent d\'une infodémie — une épidémie de fausses informations — qui ronge le tissu démocratique de l\'intérieur. Ma thèse est simple : sans une éducation aux médias massifiée et obligatoire, nos démocraties seront de plus en plus vulnérables.',q:'Selon l\'orateur, les plateformes numériques favorisent les contenus nuancés et équilibrés.',c:false,e:'Faux. "Les algorithmes récompensent l\'engagement émotionnel, favorisant les contenus outranciers au DÉTRIMENT de l\'information nuancée." "Au détriment de" = en detrimento de. "Outrancier" = exagerado, extremista. Les algorithmes sont conçus pour maximiser l\'engagement, pas l\'exactitude.'},
  {t:'mc',audio:'Mesdames et Messieurs, je voudrais vous poser une question fondamentale : les démocraties modernes sont-elles équipées pour faire face aux défis de la désinformation numérique ? Nous vivons à une époque où un faux article peut être partagé un million de fois avant qu\'un démenti officiel ne soit publié. Les algorithmes des plateformes récompensent l\'engagement émotionnel, favorisant ainsi les contenus outranciers au détriment de l\'information nuancée. Certains politologues parlent d\'une infodémie — une épidémie de fausses informations — qui ronge le tissu démocratique de l\'intérieur. Ma thèse est simple : sans une éducation aux médias massifiée et obligatoire, nos démocraties seront de plus en plus vulnérables.',q:'Que désigne le terme « infodémie » dans ce discours ?',a:['Un virus informatique qui bloque les réseaux','La propagation massive de fausses informations','Un système d\'IA de surveillance des médias','Une plateforme d\'information médicale'],c:1,e:'"Infodémie" = "info" + "démie" (como en pandemia). L\'orateur le définit : "une épidémie de fausses informations". Terme popularisé par l\'OMS lors de la pandémie de COVID-19. Comprendre les néologismes par décomposition morphologique + contexte = compétence CO B2.'},
  {t:'mc',audio:'Mesdames et Messieurs, je voudrais vous poser une question fondamentale : les démocraties modernes sont-elles équipées pour faire face aux défis de la désinformation numérique ? Nous vivons à une époque où un faux article peut être partagé un million de fois avant qu\'un démenti officiel ne soit publié. Les algorithmes des plateformes récompensent l\'engagement émotionnel, favorisant ainsi les contenus outranciers au détriment de l\'information nuancée. Certains politologues parlent d\'une infodémie — une épidémie de fausses informations — qui ronge le tissu démocratique de l\'intérieur. Ma thèse est simple : sans une éducation aux médias massifiée et obligatoire, nos démocraties seront de plus en plus vulnérables.',q:'Le registre de ce discours est principalement :',a:['Pessimiste et résigné, sans proposition concrète','Alarmiste mais constructif, débouchant sur une recommandation','Enthousiaste face aux bénéfices du numérique','Neutre et exclusivement factuel'],c:1,e:'Alarmiste : "nos démocraties seront de plus en plus vulnérables". Constructif : il propose "une éducation aux médias massifiée et obligatoire". Reconnaître la tonalité d\'un discours (alarmiste/optimiste/constructif/polémique) et sa nuance = compétence clé CO B2.'},
  /* ── DÉBAT : Revenu universel de base (Q5-8) ── */
  {t:'mc',audio:'Journaliste : Le revenu universel de base est-il utopie ou nécessité ? Économiste Leconte : Avec l\'automatisation croissante, des millions de travailleurs risquent de se retrouver sans filet de sécurité. Le RUB offrirait une base stable, permettant aussi des prises de risques entrepreneuriales. Les expérimentations en Finlande et au Kenya ont montré des effets positifs. Monsieur Faure : Je suis opposé. Le coût fiscal serait astronomique. Donner de l\'argent sans condition risque de décourager le travail. Je préfère cibler les aides sur les personnes véritablement dans le besoin.',q:'Quel argument avance l\'économiste Leconte pour défendre le RUB ?',a:['Il permettrait de financer les retraites','Il protégerait contre l\'automatisation et encouragerait l\'entrepreneuriat','Il remplacerait entièrement la protection sociale','Il réduirait la bureaucratie'],c:1,e:'"Filet de sécurité" = red de seguridad. "Prises de risques entrepreneuriales" = iniciativas empresariales audaces. Le RUB = amortiguador ante la automatización + liberación para emprender. Deux arguments distincts : protection + incentivo económico.'},
  {t:'tf',audio:'Journaliste : Le revenu universel de base est-il utopie ou nécessité ? Économiste Leconte : Avec l\'automatisation croissante, des millions de travailleurs risquent de se retrouver sans filet de sécurité. Le RUB offrirait une base stable, permettant aussi des prises de risques entrepreneuriales. Les expérimentations en Finlande et au Kenya ont montré des effets positifs. Monsieur Faure : Je suis opposé. Le coût fiscal serait astronomique. Donner de l\'argent sans condition risque de décourager le travail. Je préfère cibler les aides sur les personnes véritablement dans le besoin.',q:'Monsieur Faure est opposé à toute forme d\'aide sociale, quelle qu\'elle soit.',c:false,e:'Faux. Faure dit "Je préfère cibler les aides sur les personnes dans le besoin" → il est POUR les aides ciblées, contre le RUB universel. Position : aide conditionnelle ≠ pas d\'aide du tout. Nuance fondamentale à saisir en CO B2 : distinguer la position défendue de ce qu\'elle n\'implique pas.'},
  {t:'mc',audio:'Journaliste : Le revenu universel de base est-il utopie ou nécessité ? Économiste Leconte : Avec l\'automatisation croissante, des millions de travailleurs risquent de se retrouver sans filet de sécurité. Le RUB offrirait une base stable, permettant aussi des prises de risques entrepreneuriales. Les expérimentations en Finlande et au Kenya ont montré des effets positifs. Monsieur Faure : Je suis opposé. Le coût fiscal serait astronomique. Donner de l\'argent sans condition risque de décourager le travail. Je préfère cibler les aides sur les personnes véritablement dans le besoin.',q:'Quels pays sont cités comme ayant expérimenté le RUB ?',a:['La France et le Canada','Les États-Unis et l\'Allemagne','La Finlande et le Kenya','La Suède et le Brésil'],c:2,e:'Donnée explicite : "Les expérimentations en Finlande et au Kenya." Finlande (2017-2018) = expérience en pays développé. Kenya = expérience en pays en développement (GiveDirectly). Deux contextes très différents = argument en faveur de l\'universalité du concept.'},
  {t:'mc',audio:'Journaliste : Le revenu universel de base est-il utopie ou nécessité ? Économiste Leconte : Avec l\'automatisation croissante, des millions de travailleurs risquent de se retrouver sans filet de sécurité. Le RUB offrirait une base stable, permettant aussi des prises de risques entrepreneuriales. Les expérimentations en Finlande et au Kenya ont montré des effets positifs. Monsieur Faure : Je suis opposé. Le coût fiscal serait astronomique. Donner de l\'argent sans condition risque de décourager le travail. Je préfère cibler les aides sur les personnes véritablement dans le besoin.',q:'Quel double argument Monsieur Faure avance-t-il contre le RUB ?',a:['La corruption et l\'inefficacité administrative','Le coût fiscal élevé et le risque de désincitatif au travail','L\'impossibilité technique et le risque d\'inflation','L\'aggravation des inégalités régionales'],c:1,e:'"Le coût fiscal serait astronomique" = el costo fiscal sería astronómico. "Risque de décourager le travail" = riesgo de desincentivo laboral. Deux arguments structurés : contrainte budgétaire + effet pervers comportemental. "Astronomique" = adjectif expressif pour l\'ampleur du coût.'},
  /* ── REPORTAGE : Overtourisme (Q9-11) ── */
  {t:'mc',audio:'Venise, Barcelone, Kyoto — ces villes emblématiques font face à un paradoxe cruel : attirer des millions de touristes est devenu une menace pour leur identité même. Chaque année, Venise accueille 30 millions de visiteurs pour une population permanente de 250 000 habitants. Les logements locaux se transforment en locations touristiques, les commerces cèdent la place aux boutiques de souvenirs, et les habitants fuient une ville devenue une sorte de parc d\'attractions grandeur nature. Ce phénomène, baptisé overtourisme, soulève une question éthique fondamentale : a-t-on le droit de visiter un lieu que l\'on risque de contribuer à détruire ?',q:'Quel paradoxe le reportage met-il en évidence ?',a:['Les villes touristiques perdent des revenus malgré les visiteurs','Le succès touristique détruit l\'identité et le tissu social des villes','Les habitants sont favorables au tourisme de masse','Les plateformes de location dégradent uniquement les périphéries'],c:1,e:'"Paradoxe cruel" = paradoja cruel. La popularité touristique menace l\'identité même des villes. Ironie : le touriste vient admirer une ville authentique, mais sa venue contribue à effacer cette authenticité. "Overtourisme" = surtourisme : phénomène documenté à Venise, Barcelone, Amsterdam, Kyoto.'},
  {t:'tf',audio:'Venise, Barcelone, Kyoto — ces villes emblématiques font face à un paradoxe cruel : attirer des millions de touristes est devenu une menace pour leur identité même. Chaque année, Venise accueille 30 millions de visiteurs pour une population permanente de 250 000 habitants. Les logements locaux se transforment en locations touristiques, les commerces cèdent la place aux boutiques de souvenirs, et les habitants fuient une ville devenue une sorte de parc d\'attractions grandeur nature. Ce phénomène, baptisé overtourisme, soulève une question éthique fondamentale : a-t-on le droit de visiter un lieu que l\'on risque de contribuer à détruire ?',q:'Selon le reportage, Venise compte plus d\'habitants permanents que de touristes annuels.',c:false,e:'Faux. 30 millions de touristes par an pour 250 000 habitants = ratio de 120 touristes par habitant et par an. Ce déséquilibre extrême illustre précisément le phénomène d\'overtourisme. "Population permanente" = población residente permanente ≠ touristes de passage.'},
  {t:'mc',audio:'Venise, Barcelone, Kyoto — ces villes emblématiques font face à un paradoxe cruel : attirer des millions de touristes est devenu une menace pour leur identité même. Chaque année, Venise accueille 30 millions de visiteurs pour une population permanente de 250 000 habitants. Les logements locaux se transforment en locations touristiques, les commerces cèdent la place aux boutiques de souvenirs, et les habitants fuient une ville devenue une sorte de parc d\'attractions grandeur nature. Ce phénomène, baptisé overtourisme, soulève une question éthique fondamentale : a-t-on le droit de visiter un lieu que l\'on risque de contribuer à détruire ?',q:'La question finale du reportage a principalement pour fonction de :',a:['Proposer une loi internationale sur le tourisme','Interpeller la conscience éthique de l\'auditeur','Critiquer les compagnies aériennes low-cost','Présenter les politiques municipales anti-tourisme'],c:1,e:'Question rhétorique ouverte sans réponse fournie : "a-t-on le droit de se rendre dans un lieu qu\'on risque de contribuer à détruire ?" Vise à interpeller la responsabilité individuelle du voyageur. Reconnaître la fonction d\'une question de clôture (interpellation éthique) = compétence B2 CO.'},
  /* ── INTERVIEW : Créativité (Q12-14) ── */
  {t:'mc',audio:'Intervieweur : Professeur Marchal, peut-on apprendre à être créatif ? Professeur : La créativité était longtemps associée au génie inné. Nos recherches montrent que c\'est une compétence cognitive : pensée divergente, connexions inattendues, tolérance à l\'ambiguïté. Ces processus s\'entraînent comme un muscle. Ce qui bloque souvent la créativité, c\'est l\'autocensure — la peur du jugement. Intervieweur : Des conseils pratiques ? Professeur : Diversifier ses expériences, méditer pour réduire l\'autocensure, et surtout accepter l\'échec comme partie intégrante du processus.',q:'Selon le Professeur Marchal, la créativité est :',a:['Exclusivement un don génétique','Une compétence cognitive qui peut être développée','Réservée aux disciplines artistiques','Une capacité qui diminue avec l\'âge'],c:1,e:'"Compétence cognitive" = competencia cognitiva (≠ don inné). "S\'entraîner comme un muscle" = metáfora para expresar que se puede desarrollar. Le professeur opère un changement de paradigme : du génie inné → à la compétence entraînable. "Pensée divergente" = pensamiento divergente (generar múltiples soluciones).'},
  {t:'tf',audio:'Intervieweur : Professeur Marchal, peut-on apprendre à être créatif ? Professeur : La créativité était longtemps associée au génie inné. Nos recherches montrent que c\'est une compétence cognitive : pensée divergente, connexions inattendues, tolérance à l\'ambiguïté. Ces processus s\'entraînent comme un muscle. Ce qui bloque souvent la créativité, c\'est l\'autocensure — la peur du jugement. Intervieweur : Des conseils pratiques ? Professeur : Diversifier ses expériences, méditer pour réduire l\'autocensure, et surtout accepter l\'échec comme partie intégrante du processus.',q:'Selon le professeur, la peur du jugement stimule le développement créatif.',c:false,e:'Faux. "Ce qui bloque souvent la créativité, c\'est l\'autocensure — la peur du jugement." La peur du jugement BLOQUE la créativité. La recommandation : "méditer pour RÉDUIRE l\'autocensure" → il faut la diminuer.'},
  {t:'mc',audio:'Intervieweur : Professeur Marchal, peut-on apprendre à être créatif ? Professeur : La créativité était longtemps associée au génie inné. Nos recherches montrent que c\'est une compétence cognitive : pensée divergente, connexions inattendues, tolérance à l\'ambiguïté. Ces processus s\'entraînent comme un muscle. Ce qui bloque souvent la créativité, c\'est l\'autocensure — la peur du jugement. Intervieweur : Des conseils pratiques ? Professeur : Diversifier ses expériences, méditer pour réduire l\'autocensure, et surtout accepter l\'échec comme partie intégrante du processus.',q:'Quelle recommandation le professeur ne mentionne PAS ?',a:['Diversifier ses expériences','Pratiquer la méditation','Suivre des cours de dessin ou de musique','Accepter l\'échec'],c:2,e:'Trois recommandations citées : 1) diversifier ses expériences, 2) méditer, 3) accepter l\'échec. Cours d\'art ou de musique = non mentionné. Question-piège de type "négation" : fréquente dans le TEF CO B2 pour tester une écoute précise et sélective.'},
  /* ── MATCH + standalone Q15-20 ── */
  {t:'match',audio:'Voici quatre termes-clés issus de nos documents. L\'infodémie désigne la propagation massive de fausses informations en ligne. Un algorithme est un programme informatique qui sélectionne et classe le contenu vu par les utilisateurs. La pensée divergente est la capacité cognitive à générer de multiples solutions créatives à un problème. L\'autocensure est le fait de se freiner soi-même dans son expression par peur du jugement des autres.',q:'Associez chaque terme à sa définition.',p:[['Infodémie','Propagation de fausses informations'],['Algorithme','Programme qui sélectionne le contenu en ligne'],['Pensée divergente','Générer de multiples solutions créatives'],['Autocensure','Se freiner par peur du jugement']],e:'Vocabulaire médiatique et cognitif B2 : "infodémie" (néologisme OMS 2020), "algorithme" (terme tech devenu courant), "pensée divergente" (psychologie cognitive, Guilford 1950), "autocensure" (phénomène psychosocial). Reconnaître ces termes dans des contextes audio variés = compétence CO B2.'},
  {t:'mc',audio:'Dans le reportage sur l\'overtourisme, le journaliste a utilisé une métaphore marquante pour décrire ce que Venise est devenue. La ville est comparée à un parc d\'attractions grandeur nature pour exprimer la perte d\'authenticité.',q:'À quoi Venise est-elle comparée dans le reportage ?',a:['À un musée à ciel ouvert abandonné','À un parc d\'attractions grandeur nature','À une ville fantôme','À une destination réservée aux élites'],c:1,e:'"Une sorte de parc d\'attractions grandeur nature" = una especie de parque de atracciones a escala real. Métaphore critique : la ville réelle devient un spectacle artificiel. "Grandeur nature" = a tamaño real (expression ironique ici). Mémoriser les images et métaphores dans un document audio = compétence CO B2.'},
  {t:'tf',audio:'Dans le débat sur le revenu universel, bien que les deux intervenants défendent des positions opposées sur le RUB lui-même, ils partagent implicitement la même préoccupation de base : protéger les plus vulnérables économiquement.',q:'Les deux intervenants du débat partagent au fond la même préoccupation pour les personnes économiquement vulnérables.',c:true,e:'Vrai (implicite). Leconte : protéger les travailleurs déplacés par l\'automatisation. Faure : "cibler les aides sur les personnes dans le besoin". Les deux veulent aider les vulnérables — ils divergent sur la méthode (universelle vs ciblée). Saisir le consensus implicite derrière un désaccord apparent = compétence d\'inférence B2 CO.'},
  {t:'mc',audio:'Réfléchissons maintenant à ce que ces quatre documents ont en commun. La conférence sur la démocratie, le débat sur le RUB, le reportage sur l\'overtourisme et l\'interview sur la créativité partagent tous une même structure argumentative : ils identifient un problème contemporain, en analysent les causes, et proposent ou débattent des solutions.',q:'Quel fil conducteur unit structurellement ces quatre documents ?',a:['Ils critiquent tous les mêmes politiques gouvernementales','Ils suivent tous la structure : problème → analyse → solution(s)','Ils concluent tous sur une note entièrement optimiste','Ils sont tous fondés uniquement sur des données statistiques'],c:1,e:'"Fil conducteur" = hilo conductor. Structure argumentative partagée : problème → causes → solutions/débat. Reconnaître les structures discursives à travers plusieurs documents = compétence de synthèse et méta-compréhension CO B2. Niveau d\'abstraction requis : analyser non le contenu mais la forme.'},
  {t:'mc',audio:'La désinformation, l\'automatisation économique, le surtourisme et l\'autocensure créative sont des défis qui touchent des millions de personnes dans le monde francophone. Qu\'ils soient canadiens, français, belges ou suisses, les locuteurs de français sont confrontés à ces réalités globales avec des nuances culturelles locales.',q:'Quelle conclusion générale peut-on tirer de l\'ensemble de ces documents audio ?',a:['Les défis contemporains sont spécifiques à la France et ne touchent pas le reste du monde francophone','Ces défis sont globaux mais vécus avec des nuances locales dans l\'espace francophone','Les solutions proposées sont toutes identiques dans chaque document','Ces problèmes ne concernent que les pays développés'],c:1,e:'Synthèse : "défis globaux" (désinformation, automatisation, overtourisme, créativité) + "nuances culturelles locales" (comment chaque pays francophone les vit différemment). Compétence de synthèse transversale CO B2 : tirer une conclusion générale à partir de plusieurs documents sans la surinterprétation ou la généralisation abusive.'},
  {t:'tf',audio:'Dans tous les documents étudiés, les intervenants s\'accordent sur l\'idée que l\'expertise individuelle — qu\'elle soit scientifique, économique ou artistique — doit primer sur le débat collectif.',q:'Tous les intervenants des documents défendent la primauté de l\'expertise individuelle sur le débat collectif.',c:false,e:'Faux. Aucun des intervenants ne défend explicitement cette idée. Au contraire : le conférencier appelle à une éducation COLLECTIVE aux médias, le débat sur le RUB implique une délibération POLITIQUE, et l\'interview sur la créativité valorise les expériences PARTAGÉES. La CO B2 exige de résister aux généralisations abusives non fondées dans les textes.'},
],


/* ──────────── B2 · EE ──────────── */
EE_B2: [
  /* ── FILL (1-10) ── */
  {t:'ee',mode:'fill',
   q:'Transformez en proposition subordonnée avec le subjonctif :\n\n« Il est indispensable ___ (prendre) des mesures urgentes face à ce problème. »\n(que + sujet + subjonctif)',
   a:'qu\'on prenne',alt:['QU\'ON PRENNE','que l\'on prenne','QUE L\'ON PRENNE','qu\'il prenne','QU\'IL PRENNE'],
   e:'"Il est indispensable que + subjonctif" = es indispensable que + subjuntivo. PRENDRE au subjonctif : que je prenne, tu prennes, il/on PRENNE. Avec "on" (sujet indéfini) : qu\'on prenne. Équivalent de "que l\'on prenne" (plus soutenu). Expressions impersonnelles + que + subjonctif = structure clé B2.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le participe passé accordé correctement :\n\n« Les arguments qu\'elle a ___ (avancer) dans son discours étaient convaincants. »',
   a:'avancés',alt:['AVANCÉS','avances','AVANCES'],
   e:'Accord du participe passé avec AVOIR : il s\'accorde avec le COD si celui-ci est ANTÉPOSÉ. "Les arguments" (masc. pl.) = COD antéposé → AVANCÉS (masc. pl.). AVANCER → avancé + s. Piège B2 : avec AVOIR, l\'accord n\'est PAS systématique, seulement si le COD précède le verbe.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec la forme correcte du subjonctif passé :\n\n« Je regrette qu\'il n\'___ pas ___ (venir) à la conférence. »',
   a:'soit venu',alt:['SOIT VENU','soit venue','SOIT VENU(E)'],
   e:'Subjonctif passé = subjonctif de AVOIR/ÊTRE + participe passé. VENIR (avec ÊTRE) → qu\'il soit venu. Utilisé quand l\'action subordonnée est ANTÉRIEURE à celle de la principale. "Je regrette que…" → déclencheur du subjonctif. "Ne pas + subjonctif passé" = ne... pas + soit venu.'},
  {t:'ee',mode:'fill',
   q:'Reformulez avec la voix passive au plus-que-parfait :\n\n« Le comité avait approuvé cette décision avant la réunion.\n→ Cette décision ___ avant la réunion. »',
   a:'avait été approuvée',alt:['AVAIT ÉTÉ APPROUVÉE','avait ete approuvee','AVAIT ETE APPROUVEE'],
   e:'Voix passive au plus-que-parfait = AVOIR à l\'imparfait + ÉTÉ + participe passé. "Avait été approuvée" (féminin : "cette décision"). Passif + plus-que-parfait = antériorité + passivité. Structure : auxiliaire AVOIR (imparfait) + ÉTÉ + pp accordé avec le sujet.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le pronom relatif composé correct :\n\n« C\'est une entreprise pour ___ je travaille depuis cinq ans. »',
   a:'laquelle',alt:['LAQUELLE'],
   e:'"Travailler pour quelque chose" → pronom relatif = POUR + LEQUEL/LAQUELLE. "Une entreprise" = féminin singulier → LAQUELLE. Tableau complet : pour lequel (m.sg.), pour laquelle (f.sg.), pour lesquels (m.pl.), pour lesquelles (f.pl.). En B2, maîtrise de tous les pronoms relatifs composés = essentiel.'},
  {t:'ee',mode:'fill',
   q:'Mettez au discours indirect passé :\n\n« Il a dit : "Je serai là demain matin." \n→ Il a dit qu\'il ___ là le lendemain matin. »',
   a:'serait',alt:['SERAIT'],
   e:'Discours indirect passé : futur simple → conditionnel présent. "Je serai" → il serait. "Demain" → le lendemain. Transformations temporelles : demain → le lendemain, hier → la veille, maintenant → à ce moment-là, la semaine prochaine → la semaine suivante.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec la négation restrictive appropriée :\n\n« Ce chercheur ne publie ___ des articles peer-reviewed ; il refuse tout autre format. »',
   a:'que',alt:['QUE'],
   e:'"Ne… que" = seulement / únicamente. "Ne publie QUE des articles peer-reviewed" = sólo publica artículos revisados por pares. Ne…que n\'est pas une vraie négation mais une restriction. "Peer-reviewed" = soumis à révision par les pairs (terme académique). Niveau B2 : utiliser ne…que dans des contextes formels et académiques.'},
  {t:'ee',mode:'fill',
   q:'Transformez en proposition participiale :\n\n« Comme il avait oublié son passeport, il n\'a pas pu embarquer.\n→ ___ son passeport, il n\'a pas pu embarquer. »',
   a:'Ayant oublié',alt:['AYANT OUBLIÉ','Ayant oublie','AYANT OUBLIE'],
   e:'Proposition participiale passée = AYANT + participe passé (indique l\'antériorité). "Ayant oublié" remplace "Comme il avait oublié" (cause antérieure). Le sujet de la participiale = sujet de la principale. Registre formel/littéraire. Équivalent : "Après avoir oublié" (moins soutenu).'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le mode correct :\n\n« Quoi qu\'il ___ (faire), il ne satisfera jamais tout le monde. »',
   a:'fasse',alt:['FASSE'],
   e:'"Quoi que + subjonctif" = haga lo que haga / pase lo que pase (concession totale). FAIRE au subjonctif = fasse. "Quoi que" ≠ "quoique" (= bien que). Locutions concessives + subjonctif au B2 : "quoi que", "où que", "quel(le) que", "qui que". Très utilisé dans les textes argumentatifs soutenu.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le mot de liaison soutenu correct :\n\n« Les résultats sont positifs ; ___, certaines limites méthodologiques doivent être signalées. »\n(toutefois / bien que / afin que)',
   a:'toutefois',alt:['TOUTEFOIS'],
   e:'"Toutefois" = sin embargo, no obstante (connecteur d\'opposition en début de phrase indépendante). "Bien que" et "afin que" exigent le subjonctif dans une subordonnée. Ici, la phrase suivante est une proposition indépendante → "toutefois" (connecteur de coordination) est le seul correct. Usage académique très fréquent dans les articles de recherche.'},
  /* ── WRITE (11-20) ── */
  {t:'ee',mode:'write',
   q:'Rédigez un essai court (7-9 phrases) argumentant POUR ou CONTRE l\'affirmation suivante : « Les réseaux sociaux nuisent davantage à la démocratie qu\'ils ne la renforcent. »',
   prompt:'Choisissez une position claire et défendez-la avec 3 arguments structurés. Utilisez des exemples concrets et des connecteurs logiques de niveau B2.',
   criteria:['Position clairement annoncée dès l\'introduction','3 arguments distincts et développés','Exemples concrets ou références à des faits','Connecteurs de niveau B2 (or, néanmoins, partant, il s\'ensuit que…)','Conclusion cohérente qui synthétise la thèse'],
   model:'Les réseaux sociaux constituent aujourd\'hui une menace réelle pour les démocraties libérales, et ce pour trois raisons majeures. Premièrement, ils favorisent la création de "chambres d\'écho" où les citoyens ne sont exposés qu\'à des opinions similaires aux leurs, appauvrissant ainsi le débat public. Or, une démocratie saine suppose précisément la confrontation d\'idées diverses. Deuxièmement, la viralité des contenus émotionnels — notamment les fausses informations — érode la confiance dans les institutions et les médias traditionnels. À titre d\'exemple, les élections de plusieurs pays ont été perturbées par des campagnes de désinformation coordonnées. Enfin, la concentration du pouvoir entre les mains de quelques entreprises technologiques privées soulève des questions fondamentales de gouvernance démocratique. Partant, si des régulations strictes ne sont pas mises en place, les dérives actuelles risquent de s\'amplifier.',
   e:'Essai argumentatif B2 : Introduction (thèse) + 3 arguments + conclusion. Connecteurs B2 : "or" (transition inattendue), "partant" (conséquence formelle), "à titre d\'exemple" (illustration), "il s\'ensuit que" (conséquence). Vocabulaire : chambre d\'écho, désinformation, viralité, gouvernance, régulation. Pas de répétition du même connecteur.'},
  {t:'ee',mode:'write',
   q:'Vous êtes journaliste. Rédigez le premier paragraphe d\'un article de fond (7-8 phrases) sur l\'impact environnemental du tourisme spatial, récemment inauguré par des entreprises privées.',
   prompt:'Soignez l\'accroche (première phrase percutante), développez le problème et terminez par une question ouverte ou une citation fictive d\'expert.',
   criteria:['Accroche percutante (statistique, question rhétorique ou fait marquant)','Problème environnemental clairement exposé','Ton journalistique : objectif mais engagé','Question ouverte ou citation fictive en clôture','Vocabulaire spécialisé approprié (émissions, empreinte carbone…)'],
   model:'En 2023, un seul vol spatial de 10 minutes a produit l\'équivalent de 100 tonnes de CO₂ — autant qu\'un vol transatlantique pour 80 passagers. Alors que le tourisme spatial privé se développe à toute vitesse, porté par des milliardaires visionnaires et des entreprises comme SpaceX ou Blue Origin, une question brûlante émerge : qui assumera les coûts environnementaux de cette nouvelle industrie du luxe ? Les scientifiques alertent en effet sur les effets durables des particules de suie projetées dans la stratosphère, là où elles peuvent persister des années. Contrairement aux émissions au sol, ces polluants stratosphériques sont particulièrement difficiles à neutraliser. "Nous sommes en train de créer un problème que nos technologies actuelles ne savent pas résoudre", avertit le climatologue fictif Marc Delvaux.',
   e:'Accroche journalistique B2 : statistique choc, question rhétorique ou fait paradoxal. Ton : objectif (chiffres, sources) + engagé (sélection des faits). Vocabulaire : émissions de CO₂, empreinte carbone, stratosphère, particules de suie, polluants stratosphériques. Citation fictive = "Montre l\'expert + verbe de parole + guillemets". Structure : fait → enjeu → analyse → clôture ouverte.'},
  {t:'ee',mode:'write',
   q:'Rédigez une lettre ouverte (7-9 phrases) à un décideur politique pour l\'appeler à agir sur l\'accès à l\'eau potable dans les régions défavorisées. Adoptez un registre formel et engagé.',
   prompt:'Présentez le problème avec des données précises (inventez des chiffres crédibles), exprimez l\'urgence et formulez une demande concrète.',
   criteria:['Registre formel maintenu tout au long','Problème exposé avec données chiffrées','Urgence clairement exprimée','Demande concrète et réaliste formulée','Formule de clôture adaptée à une lettre ouverte'],
   model:'Monsieur le Ministre,\n\nJe me permets de vous écrire au nom de milliers de citoyens préoccupés par une crise silencieuse qui frappe nos territoires : l\'accès insuffisant à l\'eau potable dans les zones rurales défavorisées. Selon les données publiées récemment par l\'Observatoire national de la ressource en eau, près de 2,5 millions de personnes en France n\'ont pas accès à une eau conforme aux normes sanitaires européennes. Ce constat est d\'autant plus alarmant que le changement climatique aggrave la situation chaque année. Face à l\'urgence, nous vous demandons instamment d\'allouer des fonds spécifiques à la rénovation des infrastructures hydrauliques vieillissantes, et ce, dans un délai maximal de cinq ans. Il en va de la dignité de nos concitoyens et de la cohérence de nos engagements en matière d\'égalité territoriale.\n\nDans l\'espoir d\'une réponse rapide, je vous adresse mes respectueuses salutations.',
   e:'Lettre ouverte B2 : plus argumentée et engagée qu\'une lettre formelle classique. "Je me permets de vous écrire au nom de..." = légitime l\'auteur. Données chiffrées = crédibilité. "Nous vous demandons instamment de" = demande formelle urgente. "Il en va de" = es cuestión de. "Il en va de + nom" = estructura de apelación retórica muy formal.'},
  {t:'ee',mode:'write',
   q:'Rédigez un commentaire de texte court (7-8 phrases) sur la phrase suivante, extraite d\'un roman : « Il vivait dans cette bulle de certitudes que confère parfois une enfance trop protégée, et dont on ne sort, en général, que par l\'épreuve. »',
   prompt:'Analysez le sens littéral et figuré, commentez les choix stylistiques de l\'auteur et proposez une interprétation personnelle.',
   criteria:['Sens littéral et figuré de la métaphore expliqués','Au moins un commentaire stylistique précis','Interprétation personnelle nuancée','Registre de commentaire littéraire maintenu','Cohérence et progression de l\'analyse'],
   model:'Cette phrase de la romancière [auteure fictive] met en scène un personnage prisonnier de ses certitudes, incapable de voir le monde tel qu\'il est réellement. La métaphore de la "bulle" est particulièrement efficace : elle évoque à la fois la fragilité (une bulle peut éclater) et l\'isolement (on ne peut pas communiquer facilement depuis l\'intérieur d\'une bulle). L\'expression "confère une enfance trop protégée" établit un lien causal entre la surprotection parentale et l\'incapacité à affronter la complexité du réel. Sur le plan stylistique, l\'emploi de "en général" introduit une nuance : l\'auteure reconnaît que d\'autres chemins existent, même si l\'épreuve est la voie la plus commune. La clausule "dont on ne sort que par l\'épreuve" donne à la phrase une résonance universelle et presque sentencieuse, presque proverbiale. On peut y lire une réflexion sur la condition humaine : la souffrance comme condition de la maturité.',
   e:'Commentaire littéraire B2 : analyser la métaphore (sens littéral + figuré), le style (choix lexicaux, structures) et le sens profond. Verbes utiles : "met en scène", "évoque", "établit", "introduit une nuance", "donne une résonance". Registre analytique : "particulièrement efficace", "sur le plan stylistique", "on peut y lire". Éviter le paraphrase pure → toujours interpréter.'},
  {t:'ee',mode:'write',
   q:'Rédigez une synthèse de 7-8 phrases comparant les avantages et les inconvénients de deux systèmes d\'éducation que vous connaissez (ex. : franco-canadien et québécois, ou français et espagnol).',
   prompt:'Structurez en deux parties équilibrées. Concluez avec une recommandation ou une réflexion sur ce que chaque système peut apprendre de l\'autre.',
   criteria:['Deux systèmes clairement identifiés et comparés','Structure équilibrée (avantages de l\'un + limites, et vice-versa)','Critères de comparaison explicitées (égalité des chances, résultats, flexibilité…)','Conclusion avec recommandation ou ouverture','Registre formel et analytique'],
   model:'Le système éducatif français et le modèle québécois présentent des philosophies distinctes qui méritent d\'être confrontées. Le système français, centralisé et exigeant, valorise la rigueur académique et produit d\'excellents résultats dans les matières abstraites comme les mathématiques. Cependant, il est souvent critiqué pour son caractère élitiste : l\'origine socioéconomique y détermine encore fortement la réussite scolaire. À l\'inverse, le modèle québécois privilégie l\'épanouissement de l\'élève, la pédagogie participative et la valorisation des compétences pratiques. Mais certains reprochent à ce système un manque de rigueur et un nivellement par le bas dans certaines disciplines. Une synthèse féconde consisterait à combiner la rigueur académique française avec la pédagogie différenciée et bienveillante du Québec, afin de former des citoyens à la fois compétents et épanouis.',
   e:'Synthèse comparative B2 : critères de comparaison explicites (rigueur, égalité, résultats, épanouissement). Connecteurs : "cependant", "à l\'inverse", "certes... mais", "néanmoins". Conclusion : recommandation ou synthèse convergente ("une approche hybride"). Registre analytique : "valorise", "privilégie", "est souvent critiqué pour", "méritent d\'être confrontés".'},
  {t:'ee',mode:'write',
   q:'Vous êtes consultant(e) en communication. Rédigez une note interne courte (6-8 phrases) à votre équipe pour expliquer les nouvelles règles de communication sur les réseaux sociaux de l\'entreprise.',
   prompt:'Ton professionnel mais clair. Incluez : le contexte du changement, les nouvelles règles (au moins 3) et les conséquences en cas de non-respect.',
   criteria:['Ton professionnel et direct maintenu','Contexte du changement expliqué brièvement','Au moins 3 règles concrètes énoncées','Conséquences du non-respect mentionnées','Structure claire : objet, corps, conclusion'],
   model:'Objet : Nouvelles directives de communication sur les réseaux sociaux\n\nÀ toute l\'équipe,\n\nSuite à plusieurs incidents récents impliquant des publications inappropriées liées à notre entreprise, la direction a décidé de mettre en place des règles claires concernant l\'utilisation des réseaux sociaux à titre professionnel.\n\nÀ compter du 1er avril, les règles suivantes s\'appliquent :\n1. Toute publication mentionnant l\'entreprise, ses clients ou ses projets doit être préalablement approuvée par le service communication.\n2. Il est strictement interdit de partager des informations confidentielles, même de manière indirecte.\n3. Les prises de position politiques ou polémiques au nom de l\'entreprise sont prohibées.\n\nTout manquement à ces règles pourra faire l\'objet d\'une procédure disciplinaire.\n\nMerci de votre coopération.\nLa Direction',
   e:'Note interne B2 : format structuré (objet + corps + clôture). Verbes de modalité professionnelle : "doit être", "il est strictement interdit de", "pourra faire l\'objet de". "À compter du" = a partir del. "Préalablement approuvée" = previamente aprobada. "Procédure disciplinaire" = procedimiento disciplinario. Registre directif mais non agressif.'},
  {t:'ee',mode:'write',
   q:'Rédigez un texte de 7-8 phrases exprimant votre point de vue sur cette affirmation : « La connaissance d\'une langue étrangère change la façon dont on perçoit le monde. »',
   prompt:'Appuyez-vous sur votre expérience personnelle ET sur des exemples plus généraux. Utilisez des structures de niveau B2 (subjonctif, conditionnel, propositions participiales…).',
   criteria:['Point de vue clairement exprimé et défendu','Expérience personnelle intégrée','Exemple général ou référence intellectuelle','Au moins une structure B2 (subjonctif, participe, proposition inversée…)','Réflexion approfondie sur le lien langue-pensée'],
   model:'Il me semble indiscutable que l\'apprentissage d\'une langue étrangère modifie en profondeur notre rapport au monde. En apprenant le français, j\'ai ainsi découvert que certains concepts n\'ont pas d\'équivalent exact dans ma langue maternelle — et inversement. Ce constat m\'a amené(e) à prendre conscience que les langues ne sont pas de simples outils de communication, mais de véritables fenêtres conceptuelles sur le réel. Ayant étudié deux langues étrangères pendant plusieurs années, je puis affirmer que chaque langue active des modes de pensée légèrement différents. L\'hypothèse de la relativité linguistique — formulée par Sapir et Whorf — suggère d\'ailleurs que la structure d\'une langue influence la manière dont ses locuteurs catégorisent le réel. Quoi qu\'il en soit, même si cette thèse reste débattue, l\'expérience subjective de l\'apprentissage d\'une langue étrangère est invariablement enrichissante et transformatrice.',
   e:'Réflexion intellectuelle B2 : intégrer une référence (Sapir-Whorf), une expérience personnelle ("j\'ai ainsi découvert") et une nuance ("même si cette thèse reste débattue"). Structures B2 : "il me semble indiscutable que", "ayant étudié" (proposition participiale), "quoi qu\'il en soit" (concession). Vocabulaire : relativité linguistique, concepts, locuteurs, catégoriser le réel.'},
  {t:'ee',mode:'write',
   q:'Rédigez une critique courte (7-8 phrases) d\'un film, d\'un livre ou d\'un spectacle que vous avez apprécié. Adressez-vous à un lecteur cultivé.',
   prompt:'Présentez brièvement l\'œuvre, analysez ses points forts sur le plan artistique, mentionnez une limite et concluez avec une recommandation nuancée.',
   criteria:['Présentation claire de l\'œuvre (titre, auteur, genre)','Analyse d\'au moins 2 points forts artistiques','Une limite ou point discutable mentionné(e)','Recommandation finale nuancée','Registre critique et cultivé maintenu'],
   model:'Le roman "La Honte" d\'Annie Ernaux (1997) constitue l\'un des témoignages les plus saisissants de la littérature française contemporaine sur la domination sociale et la honte de classe. Ernaux y retrace avec une précision clinique le souvenir d\'une scène de violence domestique survenue durant son enfance, qu\'elle analyse comme le point de bascule de sa conscience de classe. Sur le plan stylistique, l\'auteure déploie une écriture blanche, dépouillée de tout effet rhétorique superflu, ce qui confère au texte une puissance émotionnelle décuplée. On appréciera également la dimension sociologique de l\'œuvre, qui transcende le simple récit autobiographique pour toucher à des questions universelles d\'identité et d\'appartenance. Cependant, certains lecteurs pourront trouver le texte hermétique par moments, en raison de sa densité conceptuelle. Il n\'en demeure pas moins que ce livre est une lecture indispensable pour quiconque s\'intéresse aux rapports entre littérature, mémoire et sociologie.',
   e:'Critique littéraire B2 : "constitue l\'un des... les plus" = superlatif relatif. "Déploie une écriture blanche" = registre critique littéraire. "Ce qui confère" = relative consécutive. "Il n\'en demeure pas moins que" = no obstante / sin embargo (très formel). "Quiconque" = cualquiera que (pronom indéfini soutenu). Structure : présentation → points forts → limite → recommandation.'},
  {t:'ee',mode:'write',
   q:'Rédigez un rapport court (7-8 phrases) analysant les résultats d\'une enquête fictive : « 68 % des employés d\'une entreprise se disent insatisfaits de la communication interne. »',
   prompt:'Identifiez des causes probables, proposez 3 recommandations concrètes et concluez sur les bénéfices attendus si des mesures sont prises.',
   criteria:['Causes probables de l\'insatisfaction analysées','3 recommandations concrètes et réalistes','Bénéfices attendus des mesures décrits','Ton objectif et professionnel','Structure de rapport : constats → analyse → recommandations → conclusion'],
   model:'L\'enquête révèle un niveau d\'insatisfaction préoccupant : 68 % des employés jugent insuffisante la communication interne de l\'entreprise. Plusieurs facteurs expliquent ce résultat. D\'abord, l\'absence de canaux de communication ascendants prive les employés de moyens formels pour exprimer leurs préoccupations. Ensuite, les informations stratégiques circulent souvent de manière fragmentée, créant des rumeurs et une perte de confiance. Enfin, les managers de proximité manquent parfois de formation en communication interpersonnelle. Pour remédier à cette situation, nous recommandons : 1) d\'instaurer des réunions d\'équipe hebdomadaires avec un ordre du jour partagé, 2) de former les cadres intermédiaires à la communication non violente, et 3) de mettre en place une boîte à idées anonyme accessible à tous les employés. Si ces mesures sont correctement mises en œuvre, on peut s\'attendre à une amélioration significative du climat de confiance et de l\'engagement des collaborateurs.',
   e:'Rapport professionnel B2 : structure rigoureuse. Constats : "L\'enquête révèle". Analyse causale : "D\'abord… Ensuite… Enfin". Recommandations : liste numérotée, verbes à l\'infinitif. Bénéfices : "on peut s\'attendre à". Vocabulaire RH : communication ascendante/descendante, managers de proximité, communication non violente, climat de confiance, engagement des collaborateurs.'},
  {t:'ee',mode:'write',
   q:'Rédigez une réflexion personnelle (7-8 phrases) sur le rôle de la culture dans la construction de l\'identité individuelle. Faites référence à au moins une expérience personnelle.',
   prompt:'Construisez une argumentation qui mêle le général (thèse sur la culture et l\'identité) et le particulier (votre expérience). Utilisez des structures abstraites et des exemples concrets.',
   criteria:['Thèse générale sur culture et identité clairement formulée','Au moins une expérience personnelle intégrée et développée','Lien explicite entre l\'expérience et la thèse générale','Structures abstraites (subjonctif, conditionnel, relative complexe…)','Conclusion qui élargit la réflexion'],
   model:'La culture dans laquelle on grandit façonne profondément notre manière d\'être au monde, nos valeurs et notre rapport à l\'autre — souvent à notre insu. Pour ma part, avoir grandi entre deux cultures m\'a permis de comprendre que l\'identité n\'est pas une donnée fixe, mais une construction dynamique et continue. En observant comment mes parents naviguaient entre leurs traditions d\'origine et les normes de leur pays d\'adoption, j\'ai pris conscience que la culture n\'est pas un carcan, mais un réservoir de ressources symboliques dans lequel on puise selon les contextes. Il serait simpliste de croire qu\'une seule culture peut entièrement "expliquer" un individu : l\'être humain est toujours plus complexe que ses origines. C\'est peut-être là que réside la beauté du dialogue interculturel : il nous oblige à réviser nos certitudes et à enrichir notre propre identité au contact de l\'altérité. Quoi qu\'on pense de la mondialisation, celle-ci a au moins rendu cette rencontre des cultures plus accessible que jamais.',
   e:'Réflexion identitaire B2 : mêler thèse générale + témoignage personnel. "À notre insu" = sin que nos demos cuenta. "Carcan" = corsé/jaula (imagen metafórica). "Réservoir de ressources symboliques" = registre sociologique/anthropologique. "Puiser" = extraer/sacar. "Altérité" = alteridad (lo que es diferente de uno mismo). Structures : "ayant grandi" (participiale), "il serait simpliste de croire que" (conditionnel + subjonctif).'},
],

/* ──────────── B2 · EO ──────────── */
EO_B2: [
  /* ── REPEAT (1-8) ── */
  {t:'eo',mode:'repeat',q:'Répétez cet énoncé philosophique en articulant clairement chaque groupe nominal complexe :',model:'Il est généralement admis que la liberté d\'expression, aussi fondamentale soit-elle, ne saurait constituer un droit absolu dans une société démocratique plurielle.',keywords:['liberté','expression','fondamentale','saurait','absolu'],e:'"Aussi fondamentale soit-elle" = por fundamental que sea (concesión con subjuntivo invertido). "Ne saurait + infinitif" = no podría (condicional negativo de saber, muy formal). "Société démocratique plurielle" = sociedad democrática plural. Structure B2 : concession inversée + négation de modalité. Prononciation soignée des groupes nominaux longs.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase complexe issue d\'un débat académique, en respectant la structure intonative :',model:'Quoi que l\'on puisse penser de la mondialisation, force est de constater que ses effets sur les inégalités mondiales demeurent profondément ambivalents et difficiles à démêler.',keywords:['quoi','mondialisation','force','inégalités','ambivalents'],e:'"Quoi que + subjonctif" = haga lo que se haga / piense lo que se piense. "Force est de constater que" = es forzoso constatar que (expresión muy formal para admitir un hecho). "Ambivalents" = ambivalentes. "Démêler" = desenredar. Intonation : descente progressive sur les groupes longs en fin de phrase.'},
  {t:'eo',mode:'repeat',q:'Répétez cette critique littéraire à voix haute en marquant bien les accents d\'intensité :',model:'L\'écriture d\'Ernaux se distingue par une sobriété stylistique radicale qui, loin d\'appauvrir le propos, lui confère une densité émotionnelle et une portée universelle que peu d\'auteurs contemporains atteignent.',keywords:['écriture','sobriété','appauvrir','confère','universelle'],e:'"Sobriété stylistique radicale" = sobriedad estilística radical. "Loin d\'appauvrir le propos" = lejos de empobrecer el tema (négation rhétorique). "Confère" = otorga / confiere (registre littéraire). "Portée universelle" = alcance universal. Accent d\'intensité en français : sur la DERNIÈRE syllabe du groupe rythmique.'},
  {t:'eo',mode:'repeat',q:'Répétez cet extrait de discours politique en soignant la fluidité :',model:'Nous nous trouvons à un carrefour décisif : soit nous choisissons de relever collectivement les défis environnementaux avec ambition et cohérence, soit nous léguons à nos enfants un monde appauvri dont nous porterons l\'entière responsabilité.',keywords:['carrefour','décisif','relever','léguons','responsabilité'],e:'"Carrefour décisif" = encrucijada decisiva (metáfora de la decisión). "Relever un défi" = afrontar un reto. "Léguer" = legar/transmitir (a las generaciones futuras). "Dont nous porterons la responsabilité" = de lo cual asumiremos la responsabilidad. Structure rhétorique : "soit... soit..." = o bien... o bien (disjonction binaire).'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase en discours indirect libre, en articulant les nuances modales :',model:'Elle se demandait si tout cela en valait vraiment la peine, si les sacrifices consentis au fil des années n\'auraient pas pu être évités, si une autre voie n\'avait pas été possible dès le départ.',keywords:['demandait','valait','sacrifices','consentis','évités'],e:'Discours indirect libre = mélange du discours indirect et du flux de conscience (style littéraire). "En valoir la peine" = valer la pena. "Consentis" = consentidos/aceptados (participio de consentir). "Au fil des années" = a lo largo de los años. Triplication de "si" = anaphore pour exprimer le doute intérieur.'},
  {t:'eo',mode:'repeat',q:'Répétez cet argument de débat contradictoire en gardant un débit naturel :',model:'Permettez-moi de vous rappeler, avec tout le respect que je vous dois, que les faits que vous venez d\'avancer ne reposent sur aucune étude scientifique sérieuse et méritent d\'être vérifiés avant d\'être présentés comme acquis.',keywords:['permettez','respect','avancer','reposent','acquis'],e:'"Permettez-moi de vous rappeler" = permítame recordarle (fórmula de debate cortés). "Avec tout le respect que je vous dois" = con todo el respeto que le debo (fórmula de cortesía formal). "Reposer sur" = basarse en. "Présentés comme acquis" = presentados como hechos establecidos. Ton : formel, courtois mais ferme.'},
  {t:'eo',mode:'repeat',q:'Répétez cette phrase avec une structure participiale complexe :',model:'Ayant pris connaissance des résultats de l\'enquête, et conscient(e) des implications sociales qu\'ils révèlent, le conseil d\'administration a décidé de mandater un groupe de travail chargé d\'élaborer des recommandations concrètes d\'ici six mois.',keywords:['pris connaissance','conscient','implications','mandater','élaborer'],e:'"Ayant pris connaissance de" = habiendo tomado conocimiento de / una vez conocidos. "Mandater" = encargar/designar formalmente. "Chargé d\'élaborer" = encargado de elaborar. "D\'ici six mois" = en un plazo de seis meses. Structure : deux participiales (ayant pris + conscient) + principale longue = registre de compte-rendu de réunion.'},
  {t:'eo',mode:'repeat',q:'Répétez ce proverbe développé en registre soutenu :',model:'Si l\'on admet, comme le voulait Voltaire, que le mieux est l\'ennemi du bien, on comprend mieux pourquoi tant de réformes louables dans leurs intentions finissent par produire des effets contraires à ceux qu\'elles visaient initialement.',keywords:['admet','Voltaire','ennemi','réformes','initialement'],e:'"Le mieux est l\'ennemi du bien" (Voltaire) = lo mejor es el enemigo de lo bueno. "Comme le voulait Voltaire" = según decía Voltaire (referencia culturelle). "Louables dans leurs intentions" = loables en sus intenciones. "Finissent par + infinitif" = terminan por. "Ceux qu\'elles visaient" = los que perseguían.'},
  /* ── ANSWER (9-15) ── */
  {t:'eo',mode:'answer',q:'Analysez oralement les avantages et les risques de l\'intelligence artificielle dans le domaine de la médecine. Appuyez-vous sur des exemples concrets et structurez votre réponse.',model:'D\'un côté, l\'IA permet de... notamment en... De l\'autre, les risques sont réels : d\'abord... ensuite... La question éthique fondamentale est de savoir si...',keywords:['diagnostic','algorithme','données','éthique','erreur'],e:'Structure B2 oral : "D\'un côté... de l\'autre" + exemples concrets. Avantages IA médicale : détection précoce de cancers, analyse d\'images médicales, personnalisation des traitements. Risques : biais algorithmiques, déshumanisation, confidentialité des données, erreurs de diagnostic. Question éthique : responsabilité en cas d\'erreur (médecin ou système ?). Vocabulaire : diagnostic, algorithme, données de santé, responsabilité, consentement.'},
  {t:'eo',mode:'answer',q:'Développez oralement votre opinion sur la phrase suivante : « Voyager, c\'est apprendre à se remettre en question. » Utilisez des exemples personnels et des références culturelles.',model:'Cette affirmation me semble profondément juste, et ce pour plusieurs raisons. Personnellement... D\'un point de vue plus général... Cependant, il faut nuancer...',keywords:['voyager','remettre','question','altérité','perspectives'],e:'Opinion développée B2 : thèse + arguments personnels + exemples culturels + nuance. "Se remettre en question" = cuestionarse a uno mismo. "Altérité" = lo diferente de uno mismo. Références possibles : Albert Camus, "Il faut voyager, si on veut rester chez soi" (paraphrase). Nuance : le voyage de luxe sans immersion ne remet pas nécessairement en question. "Immersion" = inmersión cultural.'},
  {t:'eo',mode:'answer',q:'Débattez oralement de la question suivante : « Faut-il instaurer des quotas de représentation féminine dans les conseils d\'administration des grandes entreprises ? » Présentez deux positions et défendez la vôtre.',model:'Cette question divise profondément. Ceux qui soutiennent les quotas font valoir que... À l\'inverse, les adversaires arguent que... Pour ma part, je pense que...',keywords:['quotas','parité','représentation','mérite','inégalités'],e:'Débat B2 oral : présenter deux positions avant de défendre la sienne. Pour les quotas : corriger les inégalités structurelles, augmenter la diversité des décisions, effet symbole. Contre : risque de stigmatisation, insuffisant sans changement culturel, mérite vs parité imposée. "Faire valoir" = hacer valer (argumento). "Arguer que" = argumentar que. Vocabulaire : parité, diversité, stéréotypes, plafond de verre.'},
  {t:'eo',mode:'answer',q:'Présentez oralement un défi contemporain de votre choix lié à la transition écologique. Expliquez sa complexité, ses causes et esquissez des solutions, en montrant les tensions entre les différents acteurs concernés.',model:'Le défi que je souhaite aborder est... Il est particulièrement complexe parce que... Les acteurs en jeu sont... Les solutions envisageables sont... Mais des tensions existent entre...',keywords:['transition','écologique','acteurs','tension','solutions'],e:'Présentation structurée B2 : problème → complexité → causes → acteurs → solutions → tensions. "Esquisser des solutions" = bosquejar soluciones. "Acteurs en jeu" = actores implicados. Tensions typiques : croissance économique vs environnement, pays riches vs pays en développement, court terme vs long terme. Vocabulaire : transition énergétique, décarbonation, sobriété, lobbying, accord climatique.'},
  {t:'eo',mode:'answer',q:'Commentez oralement cette citation de Simone de Beauvoir : « On ne naît pas femme, on le devient. » Situez-la dans son contexte, expliquez son sens et donnez votre interprétation.',model:'Cette citation, extraite du "Deuxième Sexe" (1949), affirme que... Le contexte dans lequel elle a été écrite est... Son sens est... Ma propre interprétation est que...',keywords:['Beauvoir','genre','construction','social','identité'],e:'"On ne naît pas femme, on le devient" = no se nace mujer, se llega a serlo. Contexte : existentialisme + féminisme de Beauvoir (1949). Sens : le genre est une construction sociale, pas une essence naturelle. Concepte-clé : distinction sexe (biologique) / genre (social). Prolongement actuel : études de genre, mouvements féministes contemporains. "Construction sociale" = construcción social.'},
  {t:'eo',mode:'answer',q:'Vous participez à un débat sur la mondialisation culturelle. Développez oralement la thèse suivante : « La mondialisation n\'homogénéise pas les cultures, elle crée de nouvelles hybridités. » Donnez des exemples précis.',model:'Je soutiens cette thèse pour plusieurs raisons. Premièrement, si l\'on observe... Deuxièmement, des phénomènes comme... montrent que... Certes, certains craignent l\'homogénéisation, mais...',keywords:['mondialisation','hybridité','cultures','homogénéisation','métissage'],e:'"Homogénéiser" = homogeneizar. "Hybridité" = hibridez cultural. Exemples d\'hybridités : la K-pop qui incorpore des éléments hip-hop américains + éléments coréens, la cuisine fusion, le créole linguistique. Théorie culturelle : Homi Bhabha (hybridité), García Canclini (cultures hybrides). "Métissage" = mestizaje cultural. "Glocalisation" = adaptación de lo global a lo local.'},
  {t:'eo',mode:'answer',q:'Présentez oralement votre analyse d\'un problème social contemporain que vous jugez sous-estimé par les médias et les politiques. Justifiez pourquoi il mériterait plus d\'attention.',model:'Le problème que je juge sous-estimé est... Les raisons pour lesquelles les médias l\'ignorent partiellement sont... Son impact réel est pourtant... Je pense que pour y remédier, il faudrait...',keywords:['sous-estimé','médias','impact','remédier','politique'],e:'Analyse critique B2 oral : "sous-estimé" = subestimado. "Médias" = medios de comunicación. Problèmes potentiels : isolement des personnes âgées, santé mentale des jeunes, précarité des travailleurs informels, pollution lumineuse, déserts médicaux. "Désert médical" = área sin acceso a médicos. Montrer la complexité et les solutions systémiques = marque de B2 oral.'},
  /* ── PRODUCE (16-20) ── */
  {t:'eo',mode:'produce',q:'Présentez oralement une analyse de 2-3 minutes sur un aspect de la société contemporaine que vous jugez paradoxal. Structurez votre propos : définition du paradoxe, exemples, causes, réflexion personnelle.',model:'Le paradoxe que je souhaite explorer est... D\'un côté... De l\'autre... Ce qui est particulièrement frappant, c\'est que... En examinant les causes, on réalise que... Ma réflexion personnelle me conduit à penser que...',keywords:['paradoxe','frappant','causes','réflexion','contemporain'],e:'Présentation analytique B2 oral : "Paradoxe" = contradiction apparente dans la réalité. Structure : définition → illustration → analyse causale → réflexion. Exemples de paradoxes : société d\'information + désinformation croissante, bien-être matériel + hausse de l\'anxiété, connectivité numérique + solitude sociale. Vocabulaire : "frappant" = llamativo, "il est symptomatique que" = es sintomático que.'},
  {t:'eo',mode:'produce',q:'Débattez oralement pendant 2-3 minutes de la question : « L\'art a-t-il une responsabilité sociale ? » Défendez une position nuancée en mobilisant des exemples d\'artistes ou d\'œuvres.',model:'Je défendrais l\'idée que l\'art n\'a pas de responsabilité au sens strict, mais qu\'il exerce inévitablement une influence sociale... D\'un côté... De l\'autre... Des exemples comme... illustrent...',keywords:['art','responsabilité','sociale','influence','artiste'],e:'"Responsabilité sociale" = responsabilidad social. Positions : art pour l\'art (Oscar Wilde) vs art engagé (Brecht, Picasso/Guernica, Zola/J\'accuse). "Exercer une influence" = ejercer una influencia. "Art engagé" = art committed. Nuance : même sans intention, l\'art reflète et influence la société. "Inévitablement" = inevitablemente. Références culturelles francophones = marque du B2.'},
  {t:'eo',mode:'produce',q:'Présentez oralement une analyse comparative (2-3 minutes) entre votre culture d\'origine et la culture française ou québécoise sur un aspect précis (rapport au travail, à la famille, à la nourriture, à l\'autorité…)',model:'Je vais comparer le rapport [au travail/à la famille/à la nourriture] dans ma culture d\'origine et en France/au Québec. Dans ma culture... En France/au Québec... Ce qui est frappant dans cette différence, c\'est que... Cette comparaison me permet de réfléchir à...',keywords:['comparer','culture','rapport','frappant','différence'],e:'Comparaison interculturelle B2 : éviter les stéréotypes, nuancer. "Rapport au travail" = relación con el trabajo. "Rapport à l\'autorité" = relación con la autoridad. Dimensions culturelles de Hofstede : individualisme/collectivisme, distance hiérarchique, orientation court/long terme. Clé : tirer une réflexion de la comparaison, ne pas simplement décrire les différences.'},
  {t:'eo',mode:'produce',q:'Imaginez que vous présentez un TED Talk de 2-3 minutes sur l\'idée suivante : « L\'échec est la condition indispensable du succès durable. » Structurez votre discours avec une accroche, un développement et une conclusion mémorable.',model:'Imaginez un monde où tout le monde réussit du premier coup. Ce monde serait-il vraiment meilleur ? [pause] Je ne le crois pas. Voici pourquoi l\'échec est, selon moi, la condition indispensable... Premièrement... Deuxièmement... Je conclurai par...',keywords:['échec','succès','condition','accroche','mémorable'],e:'Format TED Talk B2 oral : accroche percutante (question rhétorique, anecdote, statistique choc) + développement structuré (3 points max) + conclusion mémorable (appel à l\'action ou formule résumante). "Accroche" = gancho/apertura. "Mémorable" = memorable. "Appel à l\'action" = llamada a la acción. Exemples d\'échecs célèbres : J.K. Rowling refusée 12 fois, Einstein renvoyé de l\'école. Vocabulaire : résilience, itération, apprentissage par l\'erreur.'},
  {t:'eo',mode:'produce',q:'Présentez oralement (2-3 minutes) votre vision personnelle de ce que signifie "bien vivre" dans la société contemporaine. Défendez une conception originale en la distinguant des idées reçues.',model:'La notion de "bien vivre" est souvent réduite à... Mais je propose une conception différente, qui s\'articule autour de... Cette vision implique de... Ce qui la distingue des idées reçues, c\'est...',keywords:['bien vivre','conception','idées reçues','distingue','implique'],e:'"Bien vivre" = buen vivir / bienvivencia. "Idées reçues" = ideas preconcebidas / tópicos. Conceptions alternatives : slow living, décroissance, ikigai (japonais), Ubuntu (africain), Buen Vivir (andino). "S\'articuler autour de" = articularse en torno a. "Ce qui la distingue" = lo que la distingue. Vision personnelle originale + réfutation des idées reçues = exercice oral B2 de haut niveau.'},
],


/* ──────────── C1 · CE ──────────── */
CE_C1: [
  /* ── PASSAGE 1 : Philosophie politique — Espace public et démocratie (Q1-4) ── */
  {t:'mc',passage:'Hannah Arendt distingue, dans « La Condition de l\'homme moderne », trois activités fondamentales de la vita activa : le travail, l\'œuvre et l\'action. L\'action, seule activité qui se déroule directement entre les hommes sans la médiation de choses matérielles, est pour elle le lieu par excellence de la politique. L\'espace public est cet espace de l\'apparence où les hommes se révèlent les uns aux autres par leur parole et leurs actes. Or, la modernité, selon Arendt, menace cet espace en substituant au citoyen actif l\'animal laborans — l\'être humain réduit à ses besoins biologiques et économiques — et en transformant la politique en administration de choses plutôt qu\'en gouvernement des hommes. Le rétrécissement de l\'espace public est ainsi pour elle le symptôme d\'une crise de la liberté.',q:'Selon Arendt telle qu\'elle est présentée dans ce texte, quelle activité est au fondement de la politique ?',a:['Le travail productif qui satisfait les besoins biologiques','L\'œuvre qui laisse des traces durables dans le monde','L\'action directe entre les hommes par la parole et les actes','L\'administration rationnelle des ressources collectives'],c:2,e:'"L\'action" = acción (≠ travail ni œuvre). "Se déroule directement entre les hommes sans médiation" = ocurre directamente entre los hombres sin mediación. "Espace de l\'apparence" = donde los hombres se revelan a través de la palabra y el acto. Arendt (1906-1975) : philosophe politique, auteure de "Les Origines du totalitarisme". Trier les trois catégories (travail/œuvre/action) = compétence analytique C1 CE.'},
  {t:'tf',passage:'Hannah Arendt distingue, dans « La Condition de l\'homme moderne », trois activités fondamentales de la vita activa : le travail, l\'œuvre et l\'action. L\'action, seule activité qui se déroule directement entre les hommes sans la médiation de choses matérielles, est pour elle le lieu par excellence de la politique. L\'espace public est cet espace de l\'apparence où les hommes se révèlent les uns aux autres par leur parole et leurs actes. Or, la modernité, selon Arendt, menace cet espace en substituant au citoyen actif l\'animal laborans — l\'être humain réduit à ses besoins biologiques et économiques — et en transformant la politique en administration de choses plutôt qu\'en gouvernement des hommes. Le rétrécissement de l\'espace public est ainsi pour elle le symptôme d\'une crise de la liberté.',q:'Selon le texte, Arendt considère que la modernité enrichit l\'espace public en favorisant la participation citoyenne.',c:false,e:'Faux. Arendt critique la modernité : elle MENACE l\'espace public en substituant le "citoyen actif" par "l\'animal laborans" (l\'être réduit à ses besoins économiques). "Rétrécissement de l\'espace public" = réduction du lieu de liberté politique. La modernité = administration de CHOSES plutôt que gouvernement des HOMMES.'},
  {t:'mc',passage:'Hannah Arendt distingue, dans « La Condition de l\'homme moderne », trois activités fondamentales de la vita activa : le travail, l\'œuvre et l\'action. L\'action, seule activité qui se déroule directement entre les hommes sans la médiation de choses matérielles, est pour elle le lieu par excellence de la politique. L\'espace public est cet espace de l\'apparence où les hommes se révèlent les uns aux autres par leur parole et leurs actes. Or, la modernité, selon Arendt, menace cet espace en substituant au citoyen actif l\'animal laborans — l\'être humain réduit à ses besoins biologiques et économiques — et en transformant la politique en administration de choses plutôt qu\'en gouvernement des hommes. Le rétrécissement de l\'espace public est ainsi pour elle le symptôme d\'une crise de la liberté.',q:'Que désigne le concept d\'« animal laborans » dans l\'argumentation d\'Arendt ?',a:['L\'artisan qui crée des œuvres durables et significatives','L\'être humain réduit à ses fonctions biologiques et économiques','Le citoyen engagé dans la délibération politique','L\'animal domestiqué qui travaille pour ses maîtres'],c:1,e:'"Animal laborans" (latin) = animal qui travaille. Arendt oppose l\'animal laborans (mu par les besoins biologiques et économiques) au "citoyen actif" (mu par l\'action politique libre). La modernité favorise le premier au détriment du second. Notion fondamentale pour comprendre la critique arendtienne de la société de consommation.'},
  {t:'mc',passage:'Hannah Arendt distingue, dans « La Condition de l\'homme moderne », trois activités fondamentales de la vita activa : le travail, l\'œuvre et l\'action. L\'action, seule activité qui se déroule directement entre les hommes sans la médiation de choses matérielles, est pour elle le lieu par excellence de la politique. L\'espace public est cet espace de l\'apparence où les hommes se révèlent les uns aux autres par leur parole et leurs actes. Or, la modernité, selon Arendt, menace cet espace en substituant au citoyen actif l\'animal laborans — l\'être humain réduit à ses besoins biologiques et économiques — et en transformant la politique en administration de choses plutôt qu\'en gouvernement des hommes. Le rétrécissement de l\'espace public est ainsi pour elle le symptôme d\'une crise de la liberté.',q:'Dans ce texte, « l\'espace de l\'apparence » désigne :',a:['L\'espace médiatique où les politiciens construisent leur image publique','Le lieu où les humains se révèlent mutuellement par leur parole et leurs actes','L\'illusion créée par les médias de masse','L\'espace architectural des places publiques et des forums'],c:1,e:'"Espace de l\'apparence" (Erscheinungsraum) = espacio de la apariencia. Chez Arendt, "apparaître" ne signifie pas "paraître" (sembler) mais "se révéler" à autrui dans sa singularité par la parole et l\'action. C\'est l\'espace intersubjectif de la politique. Maîtriser la polysémie de termes philosophiques en contexte = compétence C1 CE.'},
  /* ── PASSAGE 2 : Sociologie — Précarité contemporaine (Q5-8) ── */
  {t:'mc',passage:'La précarité, longtemps cantonnée aux marges du marché du travail, s\'est étendue jusqu\'au cœur des classes moyennes. Ce n\'est plus seulement la pauvreté matérielle qui frappe : c\'est l\'instabilité chronique qui ronge l\'existence — emplois à durée déterminée, ruptures de parcours, sentiment d\'une vie perpétuellement provisoire. Le sociologue Robert Castel a décrit ce phénomène comme une « désaffiliation » progressive : le délitement des liens sociaux qui donnaient autrefois aux individus un socle de sécurité. Mais ce que Castel n\'avait peut-être pas pleinement anticipé, c\'est la dimension subjective de cette précarisation : de nombreux individus intériorisent l\'instabilité au point d\'en faire une norme, voire de la revendiquer comme une forme d\'autonomie et de flexibilité choisie. La précarité se mue alors en idéologie.',q:'Quelle évolution majeure de la précarité le texte décrit-il ?',a:['Elle a reculé grâce aux politiques sociales récentes','Elle s\'est étendue des marges vers le cœur des classes moyennes','Elle ne concerne plus que les travailleurs manuels','Elle a été remplacée par une forme de pauvreté numérique'],c:1,e:'"Cantonnée aux marges" → "étendue jusqu\'au cœur des classes moyennes" = de la periferia al centro. La précarité n\'est plus l\'exception mais tend à devenir la norme. "Instabilité chronique" = inestabilidad crónica. "Perpétuellement provisoire" = perpetuamente provisional. Vocabulaire sociologique C1 : maîtriser les notions de mobilité sociale et de stratification.'},
  {t:'tf',passage:'La précarité, longtemps cantonnée aux marges du marché du travail, s\'est étendue jusqu\'au cœur des classes moyennes. Ce n\'est plus seulement la pauvreté matérielle qui frappe : c\'est l\'instabilité chronique qui ronge l\'existence — emplois à durée déterminée, ruptures de parcours, sentiment d\'une vie perpétuellement provisoire. Le sociologue Robert Castel a décrit ce phénomène comme une « désaffiliation » progressive : le délitement des liens sociaux qui donnaient autrefois aux individus un socle de sécurité. Mais ce que Castel n\'avait peut-être pas pleinement anticipé, c\'est la dimension subjective de cette précarisation : de nombreux individus intériorisent l\'instabilité au point d\'en faire une norme, voire de la revendiquer comme une forme d\'autonomie et de flexibilité choisie. La précarité se mue alors en idéologie.',q:'Selon le texte, Robert Castel avait entièrement prévu la dimension subjective de la précarisation.',c:false,e:'Faux. "Ce que Castel n\'avait peut-être pas pleinement anticipé, c\'est la dimension subjective de cette précarisation." = lo que Castel quizá no había previsto plenamente es la dimensión subjetiva. L\'auteur reconnaît la contribution de Castel mais note une limite de son analyse. "N\'avait pas anticipé" → la psychologisation de la précarité (intériorisation comme norme) est un développement ultérieur.'},
  {t:'mc',passage:'La précarité, longtemps cantonnée aux marges du marché du travail, s\'est étendue jusqu\'au cœur des classes moyennes. Ce n\'est plus seulement la pauvreté matérielle qui frappe : c\'est l\'instabilité chronique qui ronge l\'existence — emplois à durée déterminée, ruptures de parcours, sentiment d\'une vie perpétuellement provisoire. Le sociologue Robert Castel a décrit ce phénomène comme une « désaffiliation » progressive : le délitement des liens sociaux qui donnaient autrefois aux individus un socle de sécurité. Mais ce que Castel n\'avait peut-être pas pleinement anticipé, c\'est la dimension subjective de cette précarisation : de nombreux individus intériorisent l\'instabilité au point d\'en faire une norme, voire de la revendiquer comme une forme d\'autonomie et de flexibilité choisie. La précarité se mue alors en idéologie.',q:'Que signifie « la précarité se mue en idéologie » dans la conclusion du texte ?',a:['La précarité devient un outil de propagande gouvernementale','L\'instabilité, intériorisée, est revendiquée comme un style de vie et un choix','La précarité est désormais théorisée par les économistes libéraux','L\'instabilité économique produit des idéologies politiques extrêmes'],c:1,e:'"Se muer en" = transformarse en. "Idéologie" = sistema de ideas que naturaliza una realidad. Quand la précarité est revendiquée comme "autonomie et flexibilité", elle n\'est plus perçue comme une contrainte structurelle mais comme un choix individuel → elle devient une idéologie qui masque ses propres conditions de production. Pensée critique C1 : déconstruire la naturalisation des phénomènes sociaux.'},
  {t:'mc',passage:'La précarité, longtemps cantonnée aux marges du marché du travail, s\'est étendue jusqu\'au cœur des classes moyennes. Ce n\'est plus seulement la pauvreté matérielle qui frappe : c\'est l\'instabilité chronique qui ronge l\'existence — emplois à durée déterminée, ruptures de parcours, sentiment d\'une vie perpétuellement provisoire. Le sociologue Robert Castel a décrit ce phénomène comme une « désaffiliation » progressive : le délitement des liens sociaux qui donnaient autrefois aux individus un socle de sécurité. Mais ce que Castel n\'avait peut-être pas pleinement anticipé, c\'est la dimension subjective de cette précarisation : de nombreux individus intériorisent l\'instabilité au point d\'en faire une norme, voire de la revendiquer comme une forme d\'autonomie et de flexibilité choisie. La précarité se mue alors en idéologie.',q:'Quelle est la contribution théorique de Robert Castel mentionnée dans le texte ?',a:['Il a quantifié le nombre de précaires dans la société française','Il a introduit le concept de "désaffiliation" pour désigner le délitement des liens sociaux','Il a développé le concept d\'idéologie de la flexibilité','Il a prouvé que la précarité était un phénomène exclusivement économique'],c:1,e:'"Désaffiliation" = désafiliación : rupture progressive des liens d\'appartenance sociale (famille, travail, communauté) qui assuraient la sécurité. Robert Castel (1933-2013) = sociologue français, auteur de "Les Métamorphoses de la question sociale" (1995). La désaffiliation ≠ exclusion brutale : c\'est un processus graduel.'},
  /* ── PASSAGE 3 : Sciences cognitives — Biais de confirmation (Q9-11) ── */
  {t:'mc',passage:'Le biais de confirmation est l\'une des distorsions cognitives les mieux documentées par la psychologie expérimentale. Il désigne la tendance à rechercher, interpréter et mémoriser les informations de manière à confirmer ses croyances préexistantes, tout en négligeant ou en déformant les éléments qui les contredisent. Ce phénomène, décrit initialement par Peter Wason en 1960 à travers son célèbre test « 2-4-6 », a depuis été observé dans des domaines aussi variés que la médecine diagnostique, les marchés financiers et la délibération démocratique. Son implication pour l\'épistémologie est profonde : si notre quête de connaissance est structurellement biaisée vers la confirmation, comment pouvons-nous prétendre atteindre une vérité objective ? La réponse scientifique à ce défi est la falsifiabilité poppérienne : une théorie n\'est scientifique que si elle peut être contredite par l\'expérience.',q:'Quel philosophe ou scientifique est mobilisé pour répondre au défi du biais de confirmation ?',a:['Peter Wason, par le test 2-4-6','Karl Popper, par le critère de falsifiabilité','Thomas Kuhn, par la notion de paradigme','René Descartes, par le doute méthodique'],c:1,e:'"Falsifiabilité poppérienne" = falsabilidad popperiana. Karl Popper (1902-1994) : "une théorie n\'est scientifique que si elle peut être réfutée par l\'expérience". Antidote au biais de confirmation : chercher activement à RÉFUTER ses hypothèses plutôt qu\'à les CONFIRMER. "Poppérien" = adjectif dérivé de Popper. Distinguer Wason (description du biais) de Popper (solution épistémologique) = C1 CE.'},
  {t:'tf',passage:'Le biais de confirmation est l\'une des distorsions cognitives les mieux documentées par la psychologie expérimentale. Il désigne la tendance à rechercher, interpréter et mémoriser les informations de manière à confirmer ses croyances préexistantes, tout en négligeant ou en déformant les éléments qui les contredisent. Ce phénomène, décrit initialement par Peter Wason en 1960 à travers son célèbre test « 2-4-6 », a depuis été observé dans des domaines aussi variés que la médecine diagnostique, les marchés financiers et la délibération démocratique. Son implication pour l\'épistémologie est profonde : si notre quête de connaissance est structurellement biaisée vers la confirmation, comment pouvons-nous prétendre atteindre une vérité objective ? La réponse scientifique à ce défi est la falsifiabilité poppérienne : une théorie n\'est scientifique que si elle peut être contredite par l\'expérience.',q:'Le texte affirme que le biais de confirmation est un phénomène limité à la psychologie individuelle.',c:false,e:'Faux. "Observé dans des domaines aussi variés que la médecine diagnostique, les marchés financiers et la délibération démocratique" = documentado en ámbitos tan variados como la medicina diagnóstica, los mercados financieros y la deliberación democrática. Le biais est transversal, institutionnel et collectif, pas seulement individuel.'},
  {t:'mc',passage:'Le biais de confirmation est l\'une des distorsions cognitives les mieux documentées par la psychologie expérimentale. Il désigne la tendance à rechercher, interpréter et mémoriser les informations de manière à confirmer ses croyances préexistantes, tout en négligeant ou en déformant les éléments qui les contredisent. Ce phénomène, décrit initialement par Peter Wason en 1960 à travers son célèbre test « 2-4-6 », a depuis été observé dans des domaines aussi variés que la médecine diagnostique, les marchés financiers et la délibération démocratique. Son implication pour l\'épistémologie est profonde : si notre quête de connaissance est structurellement biaisée vers la confirmation, comment pouvons-nous prétendre atteindre une vérité objective ? La réponse scientifique à ce défi est la falsifiabilité poppérienne : une théorie n\'est scientifique que si elle peut être contredite par l\'expérience.',q:'Dans ce texte, « épistémologie » désigne :',a:['L\'étude des épidémies et de leur propagation','La branche de la philosophie qui étudie la nature et les limites de la connaissance','La psychologie des processus cognitifs inconscients','La théorie politique du pouvoir'],c:1,e:'"Épistémologie" = epistemología : branche de la philosophie qui s\'interroge sur la nature, les sources et les limites de la connaissance humaine. Distinguer de "empirisme" (méthode), "ontologie" (étude de l\'être), "méthodologie" (outils de recherche). Reconnaître les termes philosophiques dans leurs contextes précis = compétence C1.'},
  /* ── STANDALONE Q12-16 ── */
  {t:'match',q:'Associez chaque concept philosophique ou sociologique à sa définition concise.',p:[['Désaffiliation (Castel)','Délitement progressif des liens sociaux protecteurs'],['Falsifiabilité (Popper)','Critère selon lequel une théorie peut être réfutée empiriquement'],['Biais de confirmation','Tendance à privilégier les informations qui confirment ses croyances'],['Animal laborans (Arendt)','Être humain réduit à ses besoins biologiques et économiques']],e:'Vocabulaire conceptuel C1 : quatre notions clés de la philosophie et des sciences sociales contemporaines. "Désaffiliation" (Castel) ≠ exclusion brutale. "Falsifiabilité" (Popper) = critère de scientificité. "Biais de confirmation" (Wason) = tendance cognitive. "Animal laborans" (Arendt) = figure critique de la modernité.'},
  {t:'mc',q:'Laquelle de ces constructions syntaxiques est caractéristique du registre académique et littéraire en français ?',a:['"Il faut que tout le monde soit d\'accord."','"Qu\'on le veuille ou non, le changement est inévitable."','"On doit faire quelque chose."','"C\'est clair que ça va changer."'],c:1,e:'"Qu\'on le veuille ou non" = se quiera o no → subjonctif en proposition concessive sans conjonction (inversion). Structure soutenue = marque C1 syntaxique. Les autres sont courantes ou familières. Reconnaître les structures concessives implicites en français académique = compétence C1 CE.'},
  {t:'tf',q:'En français soutenu, l\'expression « ne… que » est une négation totale équivalente à « ne… pas ».',c:false,e:'Faux. "Ne… que" = seulement / únicamente (restrictif, pas négatif total). Ex : "Il ne lit que des essais" = il lit UNIQUEMENT des essais (pas d\'autres). ≠ "Il ne lit pas" (ne lit rien). "Ne… que" = restriction. "Ne… pas" = négation. Erreur fréquente en lecture de textes C1.'},
  {t:'mc',q:'Dans un texte critique, la phrase « loin que + subjonctif » introduit :',a:['Une conséquence logique de ce qui précède','Une contradiction avec ce qu\'on pourrait attendre','Une condition nécessaire à la réalisation d\'un fait','Une comparaison entre deux situations similaires'],c:1,e:'"Loin que + subjonctif" = lejos de que + subjuntivo → introduce lo contrario de lo esperado. Ex : "Loin qu\'elle résolve le problème, cette mesure l\'aggrave" = lejos de resolver el problema, esta medida lo agrava. Synonymes : "loin de + infinitif", "plutôt que de + infinitif". Structure concessive C1 = distingue le niveau C des niveaux B.'},
  {t:'mc',q:'Lequel de ces procédés stylistiques est illustré dans la phrase suivante : « L\'espace public rétrécit ; la liberté se vide » ?',a:['La métaphore filée','Le parallélisme (isocolon)','La litote','L\'hyperbole'],c:1,e:'"L\'espace public rétrécit ; la liberté se vide" = dos cláusulas de estructura paralela (sujeto + verbo) → ISOCOLON / parallélisme. "Rétrécir" et "se vider" sont deux métaphores, mais la figure principale est le parallélisme syntaxique. "Isocolon" = membres de phrase de longueur et structure similaires. Identifier les procédés rhétoriques dans les textes analytiques = compétence stylistique C1.'},
  {t:'mc',q:'Quelle est la valeur de la locution « à cet égard » dans un texte argumentatif ?',a:['Elle marque une opposition entre deux idées contradictoires','Elle renvoie à ce qui vient d\'être dit pour y apporter un développement','Elle introduit une hypothèse contrefactuelle','Elle signale la fin d\'un paragraphe argumentatif'],c:1,e:'"À cet égard" = al respecto / en este sentido → connecteur de référence anaphorique. Il pointe vers ce qui précède pour y ajouter un développement ou une précision. Synonymes : "à ce sujet", "en ce sens", "sur ce point". ≠ "en revanche" (opposition), "par conséquent" (conséquence). Maîtriser la valeur des connecteurs = compétence C1 CE fondamentale.'},
  {t:'mc',q:'Dans quel type de texte rencontrerait-on le plus naturellement cette formulation : « Il convient de distinguer deux acceptions du terme "culture" » ?',a:['Un SMS entre amis','Un article journalistique de faits divers','Un essai ou texte académique','Un forum de discussion informel en ligne'],c:2,e:'"Il convient de + infinitif" = es conveniente / procede (registre académique soutenu). "Acceptions" = acepciones (pluriel de signification d\'un mot). "Distinguer deux acceptions" = opération définitionnelle typique des textes académiques, essais, dissertations, introductions de thèse. Reconnaître le registre académique = compétence de base C1 CE.'},
  {t:'mc',q:'Le terme « épistémique » (comme dans « incertitude épistémique ») renvoie à :',a:['Ce qui concerne les émotions et les affects','Ce qui relève de la connaissance et de ses limites','Ce qui appartient au domaine juridique','Ce qui concerne la structure du pouvoir'],c:1,e:'"Épistémique" = epistémico : relatif à la connaissance, aux croyances justifiées et à leurs limites. "Incertitude épistémique" = incerteza sobre lo que podemos saber (vs incertitude aléatoire). Famille lexicale : épistémologie, épistémique, épistémologiquement. Vocabulaire transdisciplinaire C1 (philosophie, sciences cognitives, théorie politique).'},
  {t:'match',q:'Associez chaque figure de style C1 à son exemple illustratif.',p:[['Oxymore','Un silence éloquent'],['Chiasme','La vie pour vivre, vivre pour la vie'],['Anacoluthe','Lui parti, tout s\'écroule — sans verbe principal'],['Zeugme','Elle perdit ses illusions et son portefeuille']],e:'Figures C1 : Oxymore = alliance de termes contradictoires (silencio elocuente). Chiasme = structure croisée AB-BA (vivre/vie / vie/vivre). Anacoluthe = rupture syntaxique qui crée une ellipse. Zeugme = un verbe gouverne deux compléments de nature différente (illusions=abstrait + portefeuille=concret). Ces figures caractérisent les textes littéraires et philosophiques de niveau C1-C2.'},
],

/* ──────────── C1 · CO ──────────── */
CO_C1: [
  /* ── CONFÉRENCE : Mondialisation culturelle et hybridité (Q1-4) ── */
  {t:'mc',audio:'L\'anthropologue Arjun Appadurai a proposé le concept de « scapes » — mediascapes, ethnoscapes, technoscapes — pour rendre compte des flux globaux qui traversent et reconfigurent les cultures locales. L\'idée centrale est que la mondialisation ne produit pas une homogénéisation culturelle uniforme, contrairement à la thèse de l\'américanisation, mais une série d\'hybridations imprévisibles. Un exemple : la diffusion mondiale du K-pop sud-coréen, qui intègre des esthétiques afro-américaines, des structures rythmiques d\'origine européenne et des codes visuels proprement asiatiques. La culture globalisée n\'est donc pas une culture unique exportée depuis un centre dominant, mais une mosaïque de trajectoires croisées et d\'appropriations mutuelles qui redéfinissent perpétuellement les frontières de l\'identité culturelle.',q:'Quelle est la thèse principale de cette conférence ?',a:['La mondialisation produit une culture américaine universelle','La mondialisation génère des hybridations culturelles imprévisibles plutôt qu\'une homogénéisation','Le K-pop est l\'exemple parfait de l\'américanisation culturelle','Les cultures locales disparaissent face à la mondialisation'],c:1,e:'"Hybridation" = hibridación (≠ homogénéisation). Appadurai (1949-) : anthropologue indo-américain. "Scapes" = flujos culturales transnacionales. La thèse réfute l\'américanisation au profit du concept d\'hybridité. Le K-pop = contre-exemple : centre de diffusion = Corée du Sud (non-occidental). Comprendre une thèse complexe contre-intuitive = compétence C1 CO.'},
  {t:'tf',audio:'L\'anthropologue Arjun Appadurai a proposé le concept de « scapes » — mediascapes, ethnoscapes, technoscapes — pour rendre compte des flux globaux qui traversent et reconfigurent les cultures locales. L\'idée centrale est que la mondialisation ne produit pas une homogénéisation culturelle uniforme, contrairement à la thèse de l\'américanisation, mais une série d\'hybridations imprévisibles. Un exemple : la diffusion mondiale du K-pop sud-coréen, qui intègre des esthétiques afro-américaines, des structures rythmiques d\'origine européenne et des codes visuels proprement asiatiques. La culture globalisée n\'est donc pas une culture unique exportée depuis un centre dominant, mais une mosaïque de trajectoires croisées et d\'appropriations mutuelles qui redéfinissent perpétuellement les frontières de l\'identité culturelle.',q:'Selon la conférence, la mondialisation produit nécessairement une culture uniforme d\'origine américaine.',c:false,e:'Faux. La conférence réfute explicitement "la thèse de l\'américanisation" : "contrairement à la thèse de l\'américanisation". L\'orateur défend l\'hybridation et la mosaïque culturelle. Le K-pop en est l\'illustration : origine coréenne avec influences multiples.'},
  {t:'mc',audio:'L\'anthropologue Arjun Appadurai a proposé le concept de « scapes » — mediascapes, ethnoscapes, technoscapes — pour rendre compte des flux globaux qui traversent et reconfigurent les cultures locales. L\'idée centrale est que la mondialisation ne produit pas une homogénéisation culturelle uniforme, contrairement à la thèse de l\'américanisation, mais une série d\'hybridations imprévisibles. Un exemple : la diffusion mondiale du K-pop sud-coréen, qui intègre des esthétiques afro-américaines, des structures rythmiques d\'origine européenne et des codes visuels proprement asiatiques. La culture globalisée n\'est donc pas une culture unique exportée depuis un centre dominant, mais une mosaïque de trajectoires croisées et d\'appropriations mutuelles qui redéfinissent perpétuellement les frontières de l\'identité culturelle.',q:'Comment le K-pop est-il utilisé dans l\'argumentation de la conférence ?',a:['Comme preuve de la domination culturelle américaine','Comme contre-exemple illustrant l\'hybridation multi-origine','Comme exemple d\'une culture locale qui résiste à la mondialisation','Comme modèle d\'exportation culturelle imposé par un État autoritaire'],c:1,e:'Le K-pop = contre-exemple à l\'américanisation : il mélange esthétiques afro-américaines + rythmes européens + codes visuels asiatiques, mais provient de Corée du Sud. Il illustre l\'hybridation imprévisible : ni uniforme, ni uniquement américain. Reconnaître la fonction rhétorique d\'un exemple dans une argumentation = compétence C1 CO.'},
  {t:'mc',audio:'L\'anthropologue Arjun Appadurai a proposé le concept de « scapes » — mediascapes, ethnoscapes, technoscapes — pour rendre compte des flux globaux qui traversent et reconfigurent les cultures locales. L\'idée centrale est que la mondialisation ne produit pas une homogénéisation culturelle uniforme, contrairement à la thèse de l\'américanisation, mais une série d\'hybridations imprévisibles. Un exemple : la diffusion mondiale du K-pop sud-coréen, qui intègre des esthétiques afro-américaines, des structures rythmiques d\'origine européenne et des codes visuels proprement asiatiques. La culture globalisée n\'est donc pas une culture unique exportée depuis un centre dominant, mais une mosaïque de trajectoires croisées et d\'appropriations mutuelles qui redéfinissent perpétuellement les frontières de l\'identité culturelle.',q:'À quoi renvoie le concept de « scapes » selon la conférence ?',a:['Des paysages naturels préservés par les politiques culturelles','Des flux globaux qui traversent et reconfigurent les cultures locales','Des catégories linguistiques servant à classer les langues','Des territoires culturels délimités par des frontières nationales'],c:1,e:'"Scapes" (mediascapes, ethnoscapes, technoscapes) = flujos globales (mediáticos, humanos, tecnológicos). Concept d\'Appadurai issu de "Modernity at Large" (1996). "Traversent et reconfigurent" = atraviesan y reconfiguran. Mémoriser une définition conceptuelle à travers un discours oral dense = compétence C1 CO.'},
  /* ── DÉBAT ACADÉMIQUE : Principe de précaution (Q5-8) ── */
  {t:'mc',audio:'Animatrice : Le principe de précaution est-il un frein à l\'innovation ? Professeur Hélène Vidal : Je pense que cette opposition est un faux débat. Le principe de précaution ne s\'applique pas à tout risque, mais uniquement aux risques graves, irréversibles et scientifiquement incertains. Il ne dit pas « ne faites rien », il dit « agissez prudemment en l\'absence de certitude ». La vraie question est : qui assume les coûts des risques mal évalués ? Historiquement, c\'est la société qui paie — le scandale de l\'amiante, la thalidomide, le glyphosate. Professeur André Morin : Le problème est que le principe est appliqué de manière asymétrique. On invoque la précaution pour les nouvelles technologies, mais jamais pour le statu quo. Or, ne pas innover a aussi un coût : des maladies non traitées, des inefficacités énergétiques perpétuées, des inégalités technologiques qui s\'aggravent.',q:'Quelle est la position de la Professeure Vidal sur le principe de précaution ?',a:['Il doit être abandonné car il freine l\'innovation','Il s\'applique uniquement aux risques graves, irréversibles et incertains, et non à tout risque','Il doit s\'appliquer à toutes les décisions technologiques sans exception','Il est inutile car la science peut toujours anticiper les risques'],c:1,e:'"Le principe de précaution ne s\'applique pas à tout risque, mais uniquement aux risques graves, irréversibles et scientifiquement incertains" = criterios de aplicación: gravedad + irreversibilidad + incerteza científica. Vidal réfute l\'idée que le principe = inaction. "Ne pas faire" ≠ "faire prudemment". Saisir une distinction conceptuelle dans un débat oral = C1 CO.'},
  {t:'tf',audio:'Animatrice : Le principe de précaution est-il un frein à l\'innovation ? Professeur Hélène Vidal : Je pense que cette opposition est un faux débat. Le principe de précaution ne s\'applique pas à tout risque, mais uniquement aux risques graves, irréversibles et scientifiquement incertains. Il ne dit pas « ne faites rien », il dit « agissez prudemment en l\'absence de certitude ». La vraie question est : qui assume les coûts des risques mal évalués ? Historiquement, c\'est la société qui paie — le scandale de l\'amiante, la thalidomide, le glyphosate. Professeur André Morin : Le problème est que le principe est appliqué de manière asymétrique. On invoque la précaution pour les nouvelles technologies, mais jamais pour le statu quo. Or, ne pas innover a aussi un coût : des maladies non traitées, des inefficacités énergétiques perpétuées, des inégalités technologiques qui s\'aggravent.',q:'Selon le Professeur Morin, le principe de précaution est appliqué de manière symétrique aux nouvelles technologies et au statu quo.',c:false,e:'Faux. Morin critique précisément l\'ASYMÉTRIE : "On invoque la précaution pour les nouvelles technologies, mais jamais pour le statu quo." Le statu quo (ne pas innover) a aussi des risques (maladies non traitées, etc.) mais on ne lui applique pas le même principe. "Asymétrique" = asimétrico. Critique de la logique d\'application sélective.'},
  {t:'mc',audio:'Animatrice : Le principe de précaution est-il un frein à l\'innovation ? Professeur Hélène Vidal : Je pense que cette opposition est un faux débat. Le principe de précaution ne s\'applique pas à tout risque, mais uniquement aux risques graves, irréversibles et scientifiquement incertains. Il ne dit pas « ne faites rien », il dit « agissez prudemment en l\'absence de certitude ». La vraie question est : qui assume les coûts des risques mal évalués ? Historiquement, c\'est la société qui paie — le scandale de l\'amiante, la thalidomide, le glyphosate. Professeur André Morin : Le problème est que le principe est appliqué de manière asymétrique. On invoque la précaution pour les nouvelles technologies, mais jamais pour le statu quo. Or, ne pas innover a aussi un coût : des maladies non traitées, des inefficacités énergétiques perpétuées, des inégalités technologiques qui s\'aggravent.',q:'Quels exemples historiques la Professeure Vidal cite-t-elle pour illustrer le coût des risques mal évalués ?',a:['L\'amiante, la thalidomide et le glyphosate','Le DDT, le mercure et le plomb dans l\'essence','L\'énergie nucléaire, les OGM et les pesticides','L\'alcool, le tabac et les médicaments opioïdes'],c:0,e:'Exemples cités explicitement : "le scandale de l\'amiante, la thalidomide, le glyphosate". Amiante = cancérigène utilisé massivement avant interdiction. Thalidomide = médicament cause de malformations fœtales dans les années 1960. Glyphosate = herbicide controversé. Trois scandales sanitaires liés à une évaluation des risques insuffisante.'},
  {t:'mc',audio:'Animatrice : Le principe de précaution est-il un frein à l\'innovation ? Professeur Hélène Vidal : Je pense que cette opposition est un faux débat. Le principe de précaution ne s\'applique pas à tout risque, mais uniquement aux risques graves, irréversibles et scientifiquement incertains. Il ne dit pas « ne faites rien », il dit « agissez prudemment en l\'absence de certitude ». La vraie question est : qui assume les coûts des risques mal évalués ? Historiquement, c\'est la société qui paie — le scandale de l\'amiante, la thalidomide, le glyphosate. Professeur André Morin : Le problème est que le principe est appliqué de manière asymétrique. On invoque la précaution pour les nouvelles technologies, mais jamais pour le statu quo. Or, ne pas innover a aussi un coût : des maladies non traitées, des inefficacités énergétiques perpétuées, des inégalités technologiques qui s\'aggravent.',q:'Quel est le point commun entre les positions de Vidal et de Morin ?',a:['Ils s\'accordent sur la nécessité d\'abandonner le principe de précaution','Ils reconnaissent tous les deux que l\'inaction a un coût','Ils défendent tous les deux la priorité absolue à l\'innovation','Ils refusent tous les deux de citer des exemples historiques'],c:1,e:'Implicitement : Vidal dit que "ne pas agir prudemment" a un coût (scandales sanitaires) ; Morin dit que "ne pas innover" a aussi un coût (maladies, inégalités). Les deux reconnaissent que l\'INACTION ou la prudence excessive coûte quelque chose. Accord implicite sous désaccord apparent = compétence d\'inférence C1 CO.'},
  /* ── REPORTAGE : Économie circulaire (Q9-11) ── */
  {t:'mc',audio:'Dans un monde aux ressources limitées, l\'économie linéaire — extraire, produire, consommer, jeter — est un modèle à bout de souffle. L\'économie circulaire propose une rupture paradigmatique : concevoir les déchets comme des ressources, les fins de vie de produits comme des points de départ de nouveaux cycles. En pratique, cela implique l\'écoconception dès la fabrication, des filières de réparation et de réemploi, et des boucles de recyclage fermées où rien ne se perd. Les exemples pionniers existent : la ville d\'Amsterdam s\'est engagée à devenir une ville circulaire d\'ici 2050 ; des start-ups françaises transforment les marc de café en isolants thermiques ou les filets de pêche usagés en textiles. Mais l\'enjeu systémique dépasse de loin ces initiatives symboliques : il s\'agit de repenser l\'ensemble du système économique.',q:'Quelle image est utilisée dans le reportage pour décrire l\'économie linéaire ?',a:['"Un modèle à bout de souffle" qui n\'est plus viable','"Un système en plein essor qui doit être préservé"','"Un moteur de l\'innovation technologique mondiale"','"Un système équilibré mais perfectible"'],c:0,e:'"À bout de souffle" = sin aliento / agotado. L\'image évoque un système épuisé, en fin de course, qui ne peut plus fonctionner. Métaphore somatique (le corps à l\'agonie) appliquée à un système économique. "Rupture paradigmatique" = cambio de paradigma. Reconnaître et interpréter les métaphores dans les discours argumentatifs = C1 CO.'},
  {t:'tf',audio:'Dans un monde aux ressources limitées, l\'économie linéaire — extraire, produire, consommer, jeter — est un modèle à bout de souffle. L\'économie circulaire propose une rupture paradigmatique : concevoir les déchets comme des ressources, les fins de vie de produits comme des points de départ de nouveaux cycles. En pratique, cela implique l\'écoconception dès la fabrication, des filières de réparation et de réemploi, et des boucles de recyclage fermées où rien ne se perd. Les exemples pionniers existent : la ville d\'Amsterdam s\'est engagée à devenir une ville circulaire d\'ici 2050 ; des start-ups françaises transforment les marc de café en isolants thermiques ou les filets de pêche usagés en textiles. Mais l\'enjeu systémique dépasse de loin ces initiatives symboliques : il s\'agit de repenser l\'ensemble du système économique.',q:'Le reportage suggère que les exemples de start-ups cités suffisent à réaliser la transition vers l\'économie circulaire.',c:false,e:'Faux. "L\'enjeu systémique dépasse de loin ces initiatives symboliques" = el desafío sistémico supera con creces estas iniciativas simbólicas. Le mot "symboliques" minimise la portée des exemples cités : ils sont positifs mais insuffisants. L\'enjeu réel = repenser l\'ensemble du système. Saisir la nuance entre illustration et solution = compétence C1 CO.'},
  {t:'mc',audio:'Dans un monde aux ressources limitées, l\'économie linéaire — extraire, produire, consommer, jeter — est un modèle à bout de souffle. L\'économie circulaire propose une rupture paradigmatique : concevoir les déchets comme des ressources, les fins de vie de produits comme des points de départ de nouveaux cycles. En pratique, cela implique l\'écoconception dès la fabrication, des filières de réparation et de réemploi, et des boucles de recyclage fermées où rien ne se perd. Les exemples pionniers existent : la ville d\'Amsterdam s\'est engagée à devenir une ville circulaire d\'ici 2050 ; des start-ups françaises transforment les marc de café en isolants thermiques ou les filets de pêche usagés en textiles. Mais l\'enjeu systémique dépasse de loin ces initiatives symboliques : il s\'agit de repenser l\'ensemble du système économique.',q:'Quelle transformation est opérée dans les deux exemples français cités dans le reportage ?',a:['Des déchets alimentaires et marins sont reconvertis en matériaux utiles','Des eaux usées sont purifiées pour l\'agriculture urbaine','Des véhicules hors d\'usage sont transformés en mobilier urbain','Des textiles synthétiques sont biodégradés en engrais'],c:0,e:'Marc de café → isolants thermiques. Filets de pêche usagés → textiles. Dans les deux cas : déchet → ressource. Principe central de l\'économie circulaire illustré par des exemples concrets et mémorables.'},
  /* ── STANDALONE Q12-20 ── */
  {t:'match',audio:'Ces quatre expressions sont extraites de discours académiques et journalistiques enregistrés. "À cet égard" introduit un développement sur ce qui précède. "Or" marque une transition vers un fait qui modifie l\'analyse. "Quant à" isole un élément pour en faire l\'objet d\'un commentaire distinct. "Partant" exprime une conséquence de niveau soutenu.',q:'Associez chaque expression à sa valeur discursive.',p:[['À cet égard','Référence et développement thématique'],['Or','Transition inattendue / réorientation'],['Quant à','Isolation d\'un élément pour le commenter'],['Partant','Conséquence (registre académique soutenu)']],e:'Connecteurs C1 indispensables : "À cet égard" = al respecto (anaphorique). "Or" = ahora bien / pues bien (transition). "Quant à" = en cuanto a / por lo que respecta a (isolation). "Partant" = por lo tanto / en consecuencia (soutenu). Ces quatre connecteurs structurent les discours académiques et doivent être reconnus à l\'oral C1.'},
  {t:'mc',audio:'Pour conclure cet exposé, je souhaite souligner que les enjeux que nous avons évoqués — pluralisme culturel, précaution technologique, économie circulaire — ne sont pas des questions sectorielles mais des dimensions d\'une seule et même question : comment habiter le monde de façon juste et durable ? Cette question n\'est pas uniquement politique ou économique ; elle est aussi, et peut-être avant tout, éthique.',q:'Quelle est la fonction principale de cette conclusion ?',a:['Résumer exhaustivement tous les arguments développés','Unifier les thèmes traités sous une question éthique commune','Introduire une nouvelle problématique non évoquée auparavant','Critiquer les approches sectorielles adoptées par les intervenants précédents'],c:1,e:'La conclusion opère une SYNTHÈSE TRANSVERSALE : relie les thèmes pluralisme + précaution + économie circulaire sous une seule question-cadre. "Question éthique" = dimension normative (≠ sectorielle). "Dimension d\'une seule et même question" = unification. Reconnaître la fonction d\'une conclusion rhétorique dans un exposé académique = C1 CO.'},
  {t:'tf',audio:'En linguistique, on distingue la compétence — la connaissance implicite et abstraite d\'une langue — de la performance — l\'usage réel, contextualisé et parfois erroné que l\'on fait de cette compétence dans des situations concrètes. Cette distinction, introduite par Noam Chomsky, a profondément influencé la didactique des langues.',q:'Selon cette définition, la compétence linguistique désigne l\'usage réel et contextualisé d\'une langue dans des situations précises.',c:false,e:'Faux. La COMPÉTENCE = connaissance implicite et abstraite (≠ usage réel). L\'usage réel = PERFORMANCE. Erreur classique d\'inversion. Chomsky (1928-) : linguiste américain, "Syntactic Structures" (1957). Distinction compétence/performance = fondement de la linguistique générative.'},
  {t:'mc',audio:'Lors d\'un colloque sur l\'intelligence artificielle, un intervenant a affirmé : « L\'IA ne peut pas être créative car elle ne fait que combiner des patterns existants. » Un autre a répondu : « Mais l\'être humain lui-même ne crée jamais ex nihilo — il recombine, transforme et réinterprète ce qui existe. Si cette critique s\'applique à l\'IA, elle s\'applique aussi à l\'humain. »',q:'Quelle stratégie argumentative le deuxième intervenant utilise-t-il ?',a:['Il refuse la prémisse et propose une définition alternative de l\'IA','Il retourne l\'argument contre son auteur en montrant qu\'il s\'applique aussi aux humains','Il cite des exemples empiriques de créativité artificielle','Il invoque l\'autorité de chercheurs en sciences cognitives'],c:1,e:'Stratégie : RETORSION de l\'argument (retourner l\'argument contre son auteur). Si "combiner des patterns = pas créatif" → l\'humain aussi combine des éléments → l\'humain non plus ne serait pas créatif. L\'argument du premier se contredit donc lui-même. "Ex nihilo" = de la nada. Reconnaître les stratégies argumentatives dans un échange oral = C1 CO.'},
  {t:'mc',audio:'Le philosophe Paul Ricœur distingue deux niveaux de l\'identité personnelle : l\'identité-idem (la mêmeté) — ce qui reste stable et identique à travers le temps — et l\'identité-ipse (l\'ipséité) — ce que l\'on est en tant que sujet capable de promesses et d\'engagement. La première est une permanence de fait ; la seconde est une permanence de droit, une fidélité à soi-même librement assumée.',q:'Selon Ricœur tel que présenté ici, l\'identité-ipse se distingue de l\'identité-idem principalement parce que :',a:['Elle est biologique et héréditaire','Elle est fondée sur un engagement éthique librement assumé','Elle correspond aux traits physiques stables d\'un individu','Elle désigne la mémoire involontaire d\'un sujet'],c:1,e:'Identité-idem = permanence de FAIT (ce qui ne change pas physiquement/biologiquement). Identité-ipse = permanence de DROIT : "je tiendrai ma promesse même si je ne suis plus le même qu\'avant" = fidélité à soi-même = engagement éthique. Paul Ricœur (1913-2005) : "Soi-même comme un autre" (1990). Distinguer deux concepts proches par leur fonction respective = compétence conceptuelle C1.'},
  {t:'mc',audio:'Dans un entretien sur la démocratie délibérative, Jürgen Habermas a expliqué que la légitimité des décisions politiques ne dérive pas du consensus lui-même, mais de la qualité du processus délibératif qui y mène : un processus ouvert, inclusif, fondé sur l\'argument et non sur la rhétorique persuasive ou la domination.',q:'Selon Habermas tel qu\'il est présenté ici, qu\'est-ce qui légitime une décision politique ?',a:['La majorité numérique obtenue par vote','La qualité du processus de délibération qui la précède','Le consensus final atteint entre tous les participants','L\'expertise des décideurs qui la prennent'],c:1,e:'"La légitimité dérive de la QUALITÉ DU PROCESSUS délibératif" : ouvert, inclusif, fondé sur l\'argument. Habermas (1929-) : "L\'espace public" (1962), "Théorie de l\'agir communicationnel" (1981). "Démocratie délibérative" ≠ démocratie représentative (vote seul) → la légitimité = processus + qualité des échanges. Concept central pour le droit et la philosophie politique francophone.'},
  {t:'tf',audio:'La notion de "capital social", développée par Pierre Bourdieu et James Coleman de manière indépendante, désigne l\'ensemble des ressources actuelles ou potentielles liées à la possession d\'un réseau durable de relations de connaissance ou de reconnaissance mutuelles.',q:'La notion de capital social a été développée simultanément par Bourdieu et Coleman, qui travaillaient en collaboration.',c:false,e:'Faux. "De manière indépendante" = de manera independiente. Ils ont développé des concepts similaires mais séparément, sans collaboration. Bourdieu : capital social comme ressource liée au réseau de relations (champ social). Coleman : capital social comme facilité de l\'action collective. Lire "de manière indépendante" avec attention = C1 CO (distinguer "simultanément" de "en collaboration").'},
  {t:'mc',audio:'Un historien spécialisé dans les phénomènes migratoires a déclaré lors d\'une conférence : « Les grandes vagues migratoires ne se comprennent pas uniquement comme des déplacements de populations, mais comme des transferts de savoirs, de pratiques et de représentations qui reconfigurent les deux sociétés en contact — la société d\'accueil et la société d\'origine. La migration est une transformation réciproque. »',q:'Quelle conception de la migration l\'historien défend-il ?',a:['Une vision exclusivement économique : les migrants déplacent du travail et du capital','Une vision bilatérale et culturelle : la migration transforme mutuellement les deux sociétés','Une vision démographique : la migration est une réponse à la dénatalité','Une vision sécuritaire : la migration pose des défis à la cohésion nationale'],c:1,e:'"Transformation réciproque" = transformación recíproca. La migration ≠ simple déplacement de personnes → transfert de savoirs, pratiques, représentations, dans LES DEUX SENS. Société d\'accueil transformée par les migrants ET société d\'origine transformée par l\'émigration. Vision bilatérale et culturaliste de la migration = approche des cultural studies et de l\'histoire connectée. C1 CO : saisir une thèse nuancée à partir d\'un seul extrait.'},
  {t:'match',audio:'Quatre penseurs apparaissent dans les extraits étudiés. Arjun Appadurai est anthropologue, connu pour la notion de "scapes" et la mondialisation culturelle. Jürgen Habermas est philosophe, connu pour la démocratie délibérative et l\'espace public. Paul Ricœur est philosophe, connu pour la distinction identité-idem et identité-ipse. Pierre Bourdieu est sociologue, connu pour la notion de capital social et de champ.',q:'Associez chaque penseur à son domaine ou concept principal.',p:[['Appadurai','Mondialisation culturelle et hybridité (scapes)'],['Habermas','Démocratie délibérative et légitimité'],['Ricœur','Identité narrative et herméneutique'],['Bourdieu','Capital social et reproduction sociale']],e:'Quatre références incontournables du niveau C1 CO francophone : Appadurai (anthropologie), Habermas (philosophie politique), Ricœur (herméneutique), Bourdieu (sociologie critique). Reconnaître et distinguer les auteurs et leurs concepts dans des contextes oraux variés = compétence C1 CO.'},
],

/* ──────────── C1 · EE ──────────── */
EE_C1: [
  /* ── FILL (1-10) ── */
  {t:'ee',mode:'fill',q:'Complétez avec la forme correcte du subjonctif passé :\n\n« Bien qu\'il ___ (partir) sans prévenir, nous avons décidé de lui pardonner. »',a:'soit parti',alt:['SOIT PARTI','soit parti(e)'],e:'"Bien que + subjonctif" = aunque. Subjonctif PASSÉ = ÊTRE ou AVOIR au subjonctif présent + participe passé. "Partir" → ÊTRE → il SOIT parti. Comparer : subjonctif présent "bien qu\'il parte" (maintenant) vs passé "bien qu\'il soit parti" (avant). Accord : parti/e selon le sujet.'},
  {t:'ee',mode:'fill',q:'Conjuguez "se souvenir" au plus-que-parfait :\n\n« Si elle ___ de son rendez-vous, elle ne serait pas en retard. »',a:'s\'était souvenue',alt:["s'était souvenu",'s\'était souvenu(e)','SÉTAIT SOUVENUE'],e:'Plus-que-parfait des pronominaux : SE + ÊTRE à l\'imparfait + participe passé. "S\'était souvenu(e)" — accord avec le sujet féminin "elle" → souvenu-E. Structure du conditionnel passé irréel : "Si + plus-que-parfait → conditionnel passé". Niveau C1 : maîtrise du système hypothétique complexe.'},
  {t:'ee',mode:'fill',q:'Complétez avec le gérondif de "réfléchir" :\n\n« C\'est ___ à la question qu\'il a trouvé la solution. »',a:'en réfléchissant',alt:['EN RÉFLÉCHISSANT'],e:'Gérondif = EN + participe présent. "Réfléchir" → participe présent : "réfléchissant" → gérondif : "en réfléchissant". Valeur : simultanéité ou moyen. "C\'est en forgeant qu\'on devient forgeron" = estructura proverbial del gérondif. ≠ participe présent seul (sans EN).'},
  {t:'ee',mode:'fill',q:'Accordez correctement le participe passé :\n\n« Les décisions que le gouvernement ___ (prendre) ont suscité la polémique. »',a:'a prises',alt:['A PRISES','a pris'],e:'Accord du participe passé avec AVOIR : accord avec le COD si le COD est AVANT le verbe. "Les décisions que" = COD placé avant → accord : pris → PRISES (féminin pluriel). "Le gouvernement a prises" = accord requis. Règle C1 : repérer l\'antécédent du pronom relatif et l\'accorder.'},
  {t:'ee',mode:'fill',q:'Complétez avec la forme correcte du conditionnel passé :\n\n« Sans votre aide, nous n\'___ jamais ___ (réussir) à temps. »',a:'aurions réussi',alt:['AURIONS RÉUSSI'],e:'Conditionnel passé = AVOIR ou ÊTRE au conditionnel présent + participe passé. "Réussir" → AVOIR → "n\'aurions jamais réussi". "Sans + groupe nominal" remplace la proposition hypothétique en "si". Structure : "Sans X, nous aurions fait Y" = Si X n\'avait pas existé, nous aurions fait Y.'},
  {t:'ee',mode:'fill',q:'Transformez en voix passive :\n\n« Le comité ___ (approuver) le projet hier. » [voix passive au passé composé]',a:'a approuvé → a été approuvé',alt:['a été approuvé','A ÉTÉ APPROUVÉ'],e:'Voix passive au passé composé : ÊTRE (au passé composé) + participe passé. "Approuver" → passif = "a été approuvé". "Le projet A ÉTÉ APPROUVÉ par le comité hier." Accord du PP avec le sujet : projet (masc. sing.) → approuvé. C1 : maîtrise de la voix passive dans tous les temps.'},
  {t:'ee',mode:'fill',q:'Complétez avec la locution adverbiale correcte pour marquer une opposition forte :\n\n« Il prétend défendre les droits sociaux ; ___, ses votes au Parlement racontent une tout autre histoire. »',a:'or',alt:['Or','OR'],e:'"Or" = pues bien / ahora bien → introduce un hecho que contradice o matiza lo anterior. Valeur : transition vers une réalité qui invalide ou complique la thèse précédente. ≠ "cependant" (concession simple), ≠ "donc" (conséquence). "Or" est plus rhétorique et plus fort : il annonce un retournement de perspective. Registre : soutenu/académique.'},
  {t:'ee',mode:'fill',q:'Complétez avec la forme correcte du subjonctif présent :\n\n« Il est impératif que chaque citoyen ___ (prendre) conscience de ses responsabilités. »',a:'prenne',alt:['PRENNE'],e:'Subjonctif de "prendre" : je prenne, tu prennes, il PRENNE, nous prenions, vous preniez, ils prennent. "Il est impératif que + subjonctif" = es imperativo que + subjuntivo. Comparer : il est sûr que + indicatif (certitude), il est impératif/nécessaire/douteux que + subjonctif (nécessité/doute).'},
  {t:'ee',mode:'fill',q:'Choisissez la préposition correcte dans ce contexte académique :\n\n« Cette analyse s\'inscrit ___ la continuité des travaux de Bourdieu sur le champ culturel. »',a:'dans',alt:['DANS'],e:'"S\'inscrire dans" = inscribirse en / enmarcarse en. "Dans la continuité de" = en la continuidad de. Construction figée en contexte académique. ≠ "s\'inscrire à" (une université, un cours), "s\'inscrire contre" (s\'opposer). Maîtriser les constructions prépositionnelles des verbes académiques = C1 EE.'},
  {t:'ee',mode:'fill',q:'Complétez avec le terme juste issu du vocabulaire académique :\n\n« Cette étude repose sur une méthodologie ___, combinant données qualitatives et quantitatives. »',a:'mixte',alt:['MIXTE'],e:'"Méthodologie mixte" = metodología mixta (combina enfoques cualitativos y cuantitativos). Terme clé des sciences sociales et humaines. Autres qualificatifs courants : méthodologie inductrice, déductive, longitudinale, comparative. "Reposer sur" = basarse en. Vocabulaire de la recherche académique = compétence C1 EE.'},
  /* ── WRITE (11-20) ── */
  {t:'ee',mode:'write',q:'Rédigez l\'introduction d\'un essai argumentatif sur la question suivante : « La liberté d\'expression a-t-elle des limites légitimes ? »',prompt:'Votre introduction doit comporter une accroche, une contextualisation du sujet, une problématique claire et une annonce du plan.',criteria:['Accroche pertinente (citation, fait, question)','Problématique formulée sous forme de question ou de tension','Annonce du plan en 2 ou 3 parties','Registre académique soutenu'],model:'« La liberté sans limites n\'est que tyrannisée des uns sur les droits des autres. » Cette affirmation d\'Albert Camus résonne avec acuité dans un monde où la parole numérique circule sans frontières. La liberté d\'expression, pilier des démocraties libérales, est-elle absolue ou doit-elle se plier à des impératifs supérieurs — la protection de la dignité humaine, la cohésion sociale, la sécurité publique ? C\'est cette tension que nous examinerons, en analysant d\'abord les fondements philosophiques de cette liberté, puis les limites légitimement acceptées par les démocraties, avant d\'interroger les défis contemporains que pose l\'espace numérique.',e:'Introduction académique C1 : 1) Accroche (citation, fait, paradoxe) → 2) Contextualisation → 3) Problématique → 4) Annonce du plan. Registre : "il convient de", "cette question nous invite à", "nous nous interrogerons sur". Éviter le "je" : préférer "nous" ou tournures impersonnelles. "Pilier des démocraties" = pilar de las democracias.'},
  {t:'ee',mode:'write',q:'Rédigez un paragraphe argumentatif (OREO : Opinion, Raison, Exemple, Opinion) sur l\'affirmation suivante : « Le numérique a davantage fragmenté que renforcé le débat démocratique. »',prompt:'Défendez une position nuancée en utilisant au minimum un connecteur de concession et un exemple précis.',criteria:['Position clairement exprimée dès la première phrase','Connecteur de concession utilisé (certes, bien que, si l\'on peut concéder…)','Exemple précis et développé','Retour à la thèse en conclusion de paragraphe'],model:'Il est certes indéniable que le numérique a élargi la participation citoyenne : des pétitions en ligne ont contraint des gouvernements à revoir leurs décisions. Néanmoins, les plateformes algorithmiques ont surtout favorisé la formation de « chambres d\'écho » — ces espaces où l\'on ne rencontre que des opinions similaires aux siennes. L\'affaire Cambridge Analytica (2018) illustre tragiquement comment ces mécanismes peuvent être exploités pour polariser délibérément l\'électorat. Partant, si l\'outil numérique offre des potentiels démocratiques réels, son architecture actuelle fragmente plus qu\'elle ne consolide le débat public.',e:'Paragraphe OREO C1 : O (Opinion) → R (Raison/Argument) → E (Exemple développé) → O (Opinion réaffirmée). "Certes... néanmoins" = concession + réfutation. "Cambridge Analytica" = exemple factuel précis. "Chambres d\'écho" = burbujas de filtro/cámaras de eco. "Partant" (conséquence soutenue) clôt le paragraphe.'},
  {t:'ee',mode:'write',q:'Rédigez un courriel formel à un directeur de recherche pour solliciter un stage de recherche. Précisez votre parcours, votre intérêt pour ses travaux et vos attentes.',prompt:'Longueur : 180-220 mots. Registre : très formel. Incluez une ouverture, un corps en 3 paragraphes et une formule de clôture élaborée.',criteria:['Formule d\'appel correcte (Monsieur/Madame le/la Professeur·e + nom)','Présentation concise mais complète du parcours','Lien explicite avec les travaux du destinataire','Formule de clôture complète (formule longue de politesse)'],model:'Monsieur le Professeur Dupont,\n\nPermettez-moi de me présenter : je suis Marie Chen, étudiante en Master 2 de Sociologie à l\'Université de Montréal, spécialisée dans les dynamiques d\'intégration culturelle en contexte migratoire.\n\nVos travaux sur la transmission identitaire intergénérationnelle au sein des diasporas francophones m\'ont particulièrement interpellée, notamment votre article paru dans la Revue française de sociologie (2023). Je souhaiterais vous soumettre ma candidature pour un stage de recherche de trois mois au sein de votre équipe, afin de contribuer à vos recherches tout en approfondissant mes propres compétences méthodologiques en analyse qualitative.\n\nJe me tiens à votre entière disposition pour un entretien à votre convenance et vous adresse en pièce jointe mon CV ainsi que ma lettre de motivation détaillée.\n\nVeuillez agréer, Monsieur le Professeur, l\'expression de mes sincères et respectueuses salutations.\n\nMarie Chen',e:'Courriel formel C1 : "Permettez-moi de me présenter" = permítame presentarme. Lien avec les travaux : citer un article PRÉCIS = marque d\'authenticité. "Interpeller" = interpelar/llamar la atención. Formule de clôture longue = "Veuillez agréer + titre + expression de mes [adj.] salutations". ≠ simple "Cordialement".'},
  {t:'ee',mode:'write',q:'Rédigez la conclusion d\'un essai ayant défendu l\'idée que « l\'art contemporain doit s\'engager politiquement ». Votre conclusion doit synthétiser les arguments, ouvrir sur une perspective plus large et se terminer par une formule forte.',prompt:'N\'introduisez pas de nouveaux arguments. Synthétisez, ouvrez, concluez de façon mémorable.',criteria:['Synthèse des arguments sans répétition mot à mot','Ouverture sur une perspective plus large ou une question ouverte','Formule finale forte (citation, image, appel)','Absence de nouveaux arguments non développés dans le corps'],model:'Nous avons ainsi montré que l\'engagement politique de l\'art n\'est ni une trahison de sa vocation esthétique, ni une contrainte extérieure, mais une modalité de son plein accomplissement — lorsqu\'il ouvre les yeux plutôt qu\'il ne les ferme. Des fresques de Diego Rivera aux installations de Kara Walker, l\'art engagé a su déplacer les lignes, troubler les certitudes, forcer le regard. La question qui reste ouverte est peut-être celle-ci : dans un monde saturé d\'images et de discours, l\'art a-t-il encore la force de faire ce que nulle autre forme d\'expression ne sait faire — faire ressentir ce que l\'on refuse de comprendre ?',e:'Conclusion C1 : "Nous avons ainsi montré que" = hemos demostrado que (bilan). "Lorsqu\'il ouvre les yeux plutôt qu\'il ne les ferme" = balance syntaxique élégante. Références culturelles : Rivera, Kara Walker = exemples d\'art engagé. Question ouverte finale = ouverture sur la réflexion du lecteur. "Faire ressentir ce que l\'on refuse de comprendre" = formule forte, mémorable.'},
  {t:'ee',mode:'write',q:'Rédigez un compte rendu analytique (150-200 mots) d\'un article fictif intitulé : « Les effets de la précarité sur la santé mentale : une crise silencieuse » (de S. Lefebvre, Revue de psychologie sociale, 2024).',prompt:'Résumez la thèse, les principaux arguments et les conclusions de l\'article. Adoptez un registre neutre et objectif.',criteria:['Thèse principale clairement identifiée','Au moins deux arguments ou dimensions traités','Registre neutre (ne pas exprimer votre propre opinion)','Formulation indirecte (selon l\'auteure, l\'article souligne, Lefebvre montre…)'],model:'Dans cet article, S. Lefebvre examine les liens entre précarité économique et détérioration de la santé mentale dans les sociétés postindustrielles. L\'auteure avance que l\'instabilité professionnelle chronique génère une anxiété diffuse et un sentiment de perte de contrôle que les dispositifs de soin traditionnels peinent à prendre en charge. Lefebvre souligne également que les individus en situation précaire intériorisent souvent leur vulnérabilité comme un échec personnel plutôt qu\'un problème structurel, ce qui aggrave la souffrance psychologique. En conclusion, l\'article appelle à une refonte des politiques de santé mentale pour mieux intégrer les déterminants sociaux et économiques du bien-être.',e:'Compte rendu académique C1 : style indirect libre dominant (selon, l\'auteure avance, souligne, appelle à). Voix neutre : pas de "je pense". Verbes de rapport : avancer, souligner, montrer, conclure, appeler à. "Déterminants sociaux" = determinantes sociales. Longueur contrôlée (150-200 mots) = discipline stylistique.'},
  {t:'ee',mode:'write',q:'Rédigez un paragraphe de synthèse (120-150 mots) comparant deux conceptions de la justice : la justice procédurale (la justice est dans la procédure) et la justice substantielle (la justice est dans le résultat).',prompt:'Utilisez des connecteurs d\'opposition et de comparaison. Concluez par votre propre position motivée en une phrase.',criteria:['Les deux conceptions clairement définies','Au moins un connecteur d\'opposition (alors que, tandis que, en revanche)','Position personnelle en fin de paragraphe','Registre académique soutenu'],model:'La justice procédurale insiste sur l\'équité du processus : une décision est juste si elle résulte d\'une procédure impartiale, indépendamment de son contenu. En revanche, la justice substantielle évalue les résultats : une décision est juste si elle produit des outcomes équitables, quelles que soient les procédures suivies. Alors que la première valorise la neutralité des règles (Rawls), la seconde accepte de les violer si les résultats corrigent des injustices structurelles (affirmative action). Pour ma part, je considère que les deux dimensions sont complémentaires : une procédure équitable est nécessaire mais insuffisante si elle produit systématiquement des résultats inégaux.',e:'Comparaison C1 : "En revanche" = por el contrario. "Alors que" = mientras que. "Rawls" et "affirmative action" = références conceptuelles précises. Position personnelle = "Pour ma part" (soutenu) ou "À mon sens" ≠ "je pense que" (familier). Synthèse comparative = compétence fondamentale C1 EE.'},
  {t:'ee',mode:'write',q:'Rédigez un argumentaire de 150-200 mots pour défendre l\'idée que l\'enseignement des humanités (philosophie, littérature, histoire) est indispensable dans les systèmes éducatifs contemporains.',prompt:'Structurez en 3 arguments distincts, chacun soutenu par un exemple ou une justification. Adoptez un registre convainquant mais nuancé.',criteria:['3 arguments distincts clairement formulés','Chaque argument illustré ou justifié','Registre soutenu mais pas pédant','Conclusion affirmative et mémorable'],model:'Les humanités forment d\'abord des esprits critiques capables de décrypter les discours idéologiques, les manipulations médiatiques et les simplismes politiques : une compétence indispensable à la citoyenneté démocratique. Elles cultivent ensuite l\'empathie et la compréhension de l\'altérité — lire Dostoïevski ou Césaire, c\'est habiter d\'autres vies, élargir son horizon moral. Enfin, elles développent la capacité à supporter l\'incertitude et à formuler des questions plutôt qu\'à se satisfaire de réponses rapides — qualité précieuse dans un monde de complexité croissante. Réduire l\'éducation aux seules compétences professionnalisantes, c\'est former des exécutants habiles mais des citoyens inaptes. Les humanités ne sont pas un luxe de l\'éducation : elles en sont le cœur.',e:'3 arguments : citoyenneté critique + empathie/altérité + tolérance à l\'incertitude. "Habiter d\'autres vies" = vivir otras vidas (métaphore de la lecture). "Exécutants habiles mais citoyens inaptes" = contraste saisissant. "Ne sont pas un luxe... elles en sont le cœur" = chiasme conclusif fort. Dostoïevski + Césaire = références littéraires transculturelles.'},
  {t:'ee',mode:'write',q:'Rédigez un texte de 150-200 mots analysant le paradoxe suivant : « Plus les sociétés sont informées, moins elles semblent capables de consensus. »',prompt:'Formulez une hypothèse explicative, illustrez-la et nuancez votre analyse.',criteria:['Paradoxe clairement exposé','Hypothèse explicative originale et développée','Nuance ou contre-argument en fin de texte','Registre analytique et soutenu'],model:'Le paradoxe de la sur-information tient peut-être à ceci : l\'accès massif à l\'information ne rapproche pas les individus d\'une vérité commune, mais démultiplie les vérités concurrentes. Chaque groupe dispose désormais de ses propres experts, de ses propres médias, de ses propres faits validés — ce que l\'on nomme, non sans ironie, des « faits alternatifs ». Les algorithmes amplifient ce phénomène en créant des écosystèmes informationnels étanches. Dès lors, le consensus ne se brise pas faute d\'information, mais parce que l\'information elle-même est devenue un terrain de bataille identitaire. Nuance importante, cependant : cette fragmentation n\'est pas irréversible. Des expériences de délibération citoyenne (jurys citoyens, assemblées tirées au sort) montrent qu\'exposés à des informations contradictoires dans un cadre structuré, des individus très différents parviennent à des conclusions partagées.',e:'"Sur-information" = sobreinformación. "Vérités concurrentes" = verdades en competencia. "Faits alternatifs" = alternative facts (Trump 2017). "Écosystèmes informationnels étanches" = burbujas informativas herméticas. "Jurys citoyens" = jurados ciudadanos. Nuance finale : démocratie délibérative comme antidote. Raisonnement dialectique C1 (thèse → antithèse → synthèse).'},
  {t:'ee',mode:'write',q:'Rédigez un texte de 150-180 mots exposant votre analyse d\'une œuvre littéraire, cinématographique ou musicale francophone que vous avez appréciée, en montrant en quoi elle dépasse le simple divertissement.',prompt:'Nommez l\'œuvre et son auteur, développez une idée centrale et appuyez-la sur des éléments précis de l\'œuvre.',criteria:['Œuvre et auteur nommés','Thèse sur la portée de l\'œuvre (≠ résumé)','Appui sur des éléments précis (scène, passage, procédé)','Registre critique et analytique'],model:'Dans « L\'Adversaire » (2000), Emmanuel Carrère ne raconte pas seulement l\'histoire vraie de Jean-Claude Romand, meurtrier de sa famille. Il interroge, avec une acuité troublante, la question de l\'identité : qui suis-je quand tout ce que je prétends être s\'effondre ? En choisissant délibérément de s\'impliquer en tant que narrateur — se demandant ce qui le sépare de Romand — Carrère transforme le fait divers en méditation philosophique sur le mensonge constitutif de toute existence sociale. Ce qui fait la puissance du texte, c\'est précisément ce refus du jugement facile : il n\'y a pas de monstre dans ce livre, seulement un homme qui, un jour, n\'a pas su dire la vérité, et que ce silence a englouti.',e:'Analyse littéraire C1 : ne pas résumer → analyser. "Acuité troublante" = perspicacia perturbadora. "Fait divers" = suceso de crónica negra. "Méditation philosophique" = meditación filosófica. "Ce qui fait la puissance du texte" = estructura del análisis. "Silence englouti" = imagen fuerte. Œuvre réelle : "L\'Adversaire" de Carrère (2000).'},
  {t:'ee',mode:'write',q:'Rédigez en 150-200 mots une réfutation d\'un argument que vous jugez fallacieux : « Si les immigrés travaillent, ils prennent les emplois des natifs ; s\'ils ne travaillent pas, ils vivent aux crochets de la société. » Montrez la structure logique défaillante de cet argument.',prompt:'Identifiez le type de sophisme, expliquez pourquoi l\'argument est invalide logiquement, et apportez des données ou un contre-argument factuel.',criteria:['Identification du sophisme (dilemme fallacieux, fausse dichotomie…)','Analyse de la structure logique','Au moins un contre-argument factuel ou conceptuel','Registre critique rigoureux'],model:'Cet argument illustre un « dilemme du panier percé » ou fausse dichotomie : il présente comme exhaustives deux options (travail vs assistanat) alors que la réalité est infiniment plus complexe. Sa structure logique est défaillante à double titre : premièrement, il suppose que l\'emploi est une ressource fixe (somme nulle), alors que les migrations stimulent la demande, créent de nouveaux secteurs et contribuent aux cotisations sociales. Deuxièmement, il ignore que les populations immigrées sont statistiquement plus entrepreneuriales que la moyenne nationale, générant ainsi de l\'emploi plutôt qu\'en consommant. Quand bien même un immigrant ne travaillerait pas, cela n\'implique pas qu\'il "vive aux crochets" : les filets de sécurité existent précisément pour toutes les personnes dans le besoin. L\'argument ne réfute rien : il exploite un biais émotionnel pour masquer son absence de fondement.',e:'"Dilemme du panier percé" / fausse dichotomie = falso dilema. "Somme nulle" = suma cero (économie). "Statistiquement plus entrepreneuriales" = argument factuel contrefactuel. "Biais émotionnel" = sesgo emocional. Déconstruire un sophisme = compétence argumentative C1 EE fondamentale. Registre : rigoureux, factuel, non polémique.'},
],

/* ──────────── C1 · EO ──────────── */
EO_C1: [
  /* ── REPEAT (1-7) ── */
  {t:'eo',mode:'repeat',q:'Répétez à voix haute cette phrase qui illustre un paradoxe rhétorique :',model:'La liberté d\'expression est l\'une des conquêtes les plus fragiles des démocraties : elle se défend moins en l\'élargissant à l\'infini qu\'en en précisant soigneusement les limites.',keywords:['liberté','expression','fragiles','élargissant','précisant'],e:'"Conquête fragile" = conquista frágil. "Se défend moins en l\'élargissant qu\'en précisant ses limites" = construction comparative (moins... qu\'en). Valeur : paradoxe (la limite protège la liberté). Intonation : pause après "fragiles", légère descente sur "à l\'infini", montée sur "soigneusement". Phrase C1 de 30 mots : maîtrise phonatoire, souffle et clarté articulatoire requis.'},
  {t:'eo',mode:'repeat',q:'Répétez à voix haute cette formulation concessive complexe :',model:'Bien que les données empiriques tendent à confirmer cette hypothèse, il serait prématuré d\'en tirer des conclusions définitives sans une réplication de l\'étude dans des contextes culturels plus diversifiés.',keywords:['bien que','empiriques','confirmer','prématuré','réplication'],e:'"Bien que + subjonctif" : "tendent" → présent indicatif (erreur fréquente) ≠ devraient être au subjonctif si on suit la règle stricte : "Bien que les données TENDENT". "Prématuré" = prematuro. "Réplication" = réplication (metodología). Long groupe verbal final : "sans une réplication de l\'étude dans des contextes culturels plus diversifiés" = articuler clairement chaque mot. C1 : souffle long et diction précise.'},
  {t:'eo',mode:'repeat',q:'Répétez à voix haute cet extrait de discours académique en respectant les groupes rythmiques :',model:'La mondialisation / n\'a pas produit / l\'uniformisation culturelle / tant redoutée. / Elle a engendré / au contraire / une multiplication / d\'hybridations imprévisibles / qui redéfinissent / perpétuellement / les frontières de l\'identité.',keywords:['mondialisation','uniformisation','hybridations','imprévisibles','perpétuellement'],e:'Groupes rythmiques indiqués par /. Phrases longues à découper sans perdre le sens. "Imprévisibles" /ɛ̃.pʁe.vi.zibl/ : 5 syllabes, attention à la liaison "d\'hybridations". "Perpétuellement" /pɛʁ.pe.tɥɛl.mɑ̃/ : adverbe à 5 syllabes. Maîtrise de la mélodie descendante en fin de phrase déclarative longue = C1 phonatoire.'},
  {t:'eo',mode:'repeat',q:'Répétez à voix haute cette formule de concession et de nuance :',model:'Certes, on peut concéder que cette politique a produit des résultats tangibles à court terme ; il n\'en demeure pas moins qu\'elle hypothèque gravement les capacités d\'adaptation à long terme.',keywords:['certes','concéder','tangibles','demeure','hypothèque'],e:'"Certes... il n\'en demeure pas moins que" = si bien es verdad que... no es menos cierto que. Structure concessive C1 en deux temps. "Hypothèquer" = hipotecar (comprometer el futuro). Pause après le point-virgule : pause moyenne, changement de direction argumentative. "N\'en demeure pas moins" → liaison facultative : /nɑ̃.də.mœʁ.pa.mwɑ̃/. Intonation de réserve (descente légère après "moins").'},
  {t:'eo',mode:'repeat',q:'Répétez à voix haute cette formule d\'introduction d\'un argument de contrariété :',model:'Or, c\'est précisément là que le bât blesse : si l\'on admet que la démocratie repose sur la délibération, on ne peut simultanément accepter que les décisions soient confisquées par des experts non élus.',keywords:['or','bât','délibération','simultanément','confisquées'],e:'"Le bât blesse" = expression idiomatique (là où le bât blesse = donde aprieta el zapato / el punto débil). "Or" introduit la transition critique. "Confisquées" = confiscadas. "Non élus" = liaison obligatoire /nɔ̃.n‿e.ly/. Intonation ascendante sur "là" (emphase), descente sur "experts non élus" (conclusion de l\'argument). Maîtriser les expressions idiomatiques C1 à l\'oral.'},
  {t:'eo',mode:'repeat',q:'Répétez à voix haute cette reformulation académique en langage inclusif :',model:'Chacun·e d\'entre nous est porteur ou porteuse d\'une identité plurielle, construite à l\'intersection de trajectoires culturelles, sociales et générationnelles qui ne se laissent pas réduire à une seule appartenance.',keywords:['porteur','identité','plurielle','intersection','trajectoires'],e:'"Porteur ou porteuse" = inclusivité de genre à l\'oral (≠ écriture inclusive). "À l\'intersection de" = en la intersección de (interseccionalidad). "Trajectoires culturelles, sociales et générationnelles" = groupe ternaire : marquer une légère élévation de ton sur chaque élément. "Qui ne se laissent pas réduire" = qui résistent à la réduction. Longueur : 30 mots. C1 : endurance phonatoire et clarté des groupes de sens.'},
  {t:'eo',mode:'repeat',q:'Répétez à voix haute cet énoncé philosophique à intonation particulière :',model:'Si comprendre, c\'est toujours comprendre autrement — c\'est-à-dire : donner un sens nouveau à ce qui semblait déjà acquis — alors l\'éducation n\'est pas transmission de savoirs, mais transformation perpétuelle du regard.',keywords:['comprendre','autrement','acquis','transmission','transformation'],e:'"Comprendre autrement" = comprender de otro modo (herméneutique gadamérienne). "Ce qui semblait déjà acquis" = lo que parecía ya sabido. Structure : Si A — c\'est-à-dire B — alors C. Deux tirets = deux pauses marquées, légères baisses de ton pour la parenthèse. "Transformation perpétuelle du regard" = conclusion forte, intonation finale décroissante. Longueur : 33 mots, respiration avant "alors".'},
  /* ── ANSWER (8-15) ── */
  {t:'eo',mode:'answer',q:'À voix haute, expliquez la différence entre « liberté négative » et « liberté positive » telle qu\'Isaiah Berlin la définit. Donnez un exemple concret de chacune.',model:'La liberté négative est l\'absence de contraintes externes : personne ne m\'empêche de faire X. La liberté positive est la capacité réelle d\'agir : j\'ai les moyens, les ressources, les droits d\'accomplir X. Par exemple, formellement libre de voyager (négative), mais sans passeport ni argent, je ne suis pas réellement libre (positive).',keywords:['négative','positive','Berlin','contraintes','capacité'],e:'Isaiah Berlin (1909-1997) : "Two Concepts of Liberty" (1958). Liberté négative = ausencia de obstáculos. Liberté positive = capacidad real de actuar. Exemple : droit de vote (négatif) vs alphabétisation + information pour voter de manière éclairée (positif). Distinction fondamentale en philosophie politique francophone (cours de khâgne, Sciences Po). C1 oral : définir précisément et illustrer.'},
  {t:'eo',mode:'answer',q:'Expliquez à voix haute ce que signifie « construire un cadre théorique » dans une recherche en sciences sociales. Pourquoi est-ce indispensable ?',model:'Construire un cadre théorique signifie choisir les outils conceptuels qui vont guider l\'analyse : quels auteurs, quels concepts, quelle grille de lecture. C\'est indispensable car sans ce cadre, les données empiriques restent muettes — ce sont les concepts qui leur donnent un sens. Par exemple, analyser une émeute urbaine avec la grille de Bourdieu (domination sociale) ou avec celle de Durkheim (anomie) produit deux analyses très différentes.',keywords:['cadre théorique','conceptuels','empiriques','Bourdieu','Durkheim'],e:'"Cadre théorique" = marco teórico. "Grille de lecture" = marco analítico. "Données empiriques restent muettes" = los datos no hablan solos. Exemple : Bourdieu (domination, champ, capital) vs Durkheim (cohésion sociale, anomie). Un cadre théorique = une paire de lunettes analytiques. Vocabulaire de la méthodologie en sciences sociales = C1 oral académique.'},
  {t:'eo',mode:'answer',q:'À voix haute, répondez à cette question : « En quoi le concept de "genre" se distingue-t-il du "sexe" en sciences sociales ? » Développez en 4-5 phrases.',model:'Le "sexe" renvoie aux différences biologiques — chromosomiques, anatomiques, hormonales — entre les individus. Le "genre", lui, désigne la construction sociale et culturelle des rôles, comportements et identités associés au masculin et au féminin. Cette distinction, popularisée par Judith Butler notamment, implique que les comportements considérés comme "naturellement" masculins ou féminins sont en réalité appris, performés et variables selon les cultures et les époques. Le genre n\'est pas une donnée, c\'est une production.',keywords:['sexe','genre','biologique','sociale','Butler'],e:'"Sexe" = sexo biológico (chromosomes, anatomie). "Genre" = género (construcción social). Judith Butler (1956-) : "Gender Trouble" (1990) → "le genre est une performance". "Appris, performés" = aprendidos, performados. "Variable selon les cultures" = relativité culturelle. C1 oral : expliquer une distinction conceptuelle clé de manière claire et structurée, sans jargon excessif.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute à cette question : « Quelle est, selon vous, la responsabilité des intellectuels dans l\'espace public ? » Défendez une position nuancée avec des exemples.',model:'Je pense que les intellectuels ont une double responsabilité : d\'une part, produire des analyses rigoureuses accessibles au grand public — vulgariser sans trahir ; d\'autre part, prendre position sur les questions qui engagent la vie collective. Sartre et Beauvoir l\'ont fait avec éclat, parfois au prix de leur crédibilité. Le risque inverse est l\'intellectuel médiatique qui sacrifie la rigueur à la provocation. L\'idéal me semble être ce qu\'on appellait au XIXe siècle le "clerc" — celui qui maintient une exigence de vérité dans un espace public tenté par le simplisme.',keywords:['intellectuels','espace public','Sartre','vulgariser','exigence'],e:'"Vulgariser sans trahir" = divulgar sin traicionar. "Sartre et Beauvoir" = engagement de la gauche française. "Clerc" (Julien Benda, "La trahison des clercs", 1927) = intelectual que mantiene la exigencia de verdad. "Sacrifier la rigueur à la provocation" = sacrificar el rigor a la provocación. Position nuancée = marque C1 EO.'},
  {t:'eo',mode:'answer',q:'À voix haute, défendez l\'idée que la langue façonne la pensée (hypothèse Sapir-Whorf). Nuancez votre propos.',model:'L\'hypothèse de Sapir et Whorf suggère que la structure d\'une langue influence — voire détermine — la façon dont ses locuteurs perçoivent la réalité. Par exemple, les Inuits ont plusieurs mots pour décrire la neige, permettant des distinctions perceptives plus fines. En français, le genre grammatical peut influencer la représentation mentale des objets. Cela dit, la version forte (le déterminisme linguistique) est aujourd\'hui rejetée : les humains peuvent penser au-delà des mots disponibles dans leur langue. La version faible (l\'influence relative) reste défendue.',keywords:['Sapir-Whorf','langue','pensée','locuteurs','déterminisme'],e:'Sapir (1884-1939) et Whorf (1897-1941). Version forte (déterminisme) = rejetée. Version faible (relativité) = soutenue par études psycholinguistiques. Exemple Inuit = classique mais partiellement nuancé depuis. "Genre grammatical" → expériences de Boroditsky sur les représentations mentales. "Au-delà des mots" = los humanos tienen pensamiento preverbal. C1 oral : maîtriser une controverse scientifique.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute : « Comment distinguez-vous un argument rhétorique d\'un argument logique ? Illustrez avec un exemple. »',model:'Un argument logique tire sa force de sa structure formelle : si les prémisses sont vraies, la conclusion est nécessairement vraie. Un argument rhétorique tire sa force de son effet sur l\'auditoire — émotion, prestige de l\'orateur, cadrage narratif — indépendamment de sa validité logique. Par exemple : "Nous devons agir contre le réchauffement climatique parce que nos enfants le méritent" est rhétorique (appel à l\'émotion) ; "Les émissions de CO₂ augmentent la température, augmenter la température cause des catastrophes, donc réduire les émissions est nécessaire" est logique.',keywords:['rhétorique','logique','prémisses','émotion','structure'],e:'Argument logique = déductif ou inductif (valeur de vérité). Argument rhétorique = persuasion par pathos (émotion), éthos (crédibilité), logos (raison). Aristote : les trois modes de persuasion. "Si les prémisses sont vraies... nécessairement vraie" = validité formelle (modus ponens). "Appel à l\'émotion" = argumentum ad passiones. C1 oral : distinguer logique et rhétorique = clé de l\'esprit critique.'},
  {t:'eo',mode:'answer',q:'À voix haute, expliquez pourquoi la notion de « neutralité » des médias est problématique selon les théories contemporaines de l\'information.',model:'La neutralité médiatique est souvent présentée comme un idéal déontologique : rapporter les faits sans prendre parti. Cependant, les théories de l\'agenda-setting montrent que le simple choix de ce qu\'on couvre — et de ce qu\'on ignore — est déjà une prise de position. De plus, l\'objectivité ne signifie pas équidistance : traiter deux thèses de manière "équilibrée" quand l\'une est scientifiquement établie et l\'autre contestée peut induire une fausse équivalence. La neutralité absolue est donc une fiction utile, mais une fiction.',keywords:['neutralité','agenda-setting','objectivité','équidistance','fausse équivalence'],e:'"Agenda-setting" (McCombs, Shaw, 1972) = el medio no dice quoi pensar, pero sí qué pensar. "Fausse équivalence" = falsa equivalencia (tratar igual lo desigual). "Déontologique" = deontológico. "Fiction utile" = idea reguladora (Kant). La neutralité est un horizon normatif, pas un état atteignable. C1 oral : déconstruire une notion apparemment simple.'},
  {t:'eo',mode:'answer',q:'Répondez à voix haute : « Expliquez le paradoxe de la tolérance de Karl Popper et ses implications pour la démocratie. »',model:'Karl Popper formule ainsi le paradoxe : une société qui tolère tout, y compris l\'intolérance, risque de voir cette intolérance détruire la tolérance elle-même. La tolérance illimitée est donc suicidaire. En conséquence, Popper conclut qu\'une société ouverte doit avoir le droit, voire le devoir, de supprimer les mouvements intolérants avant qu\'ils ne parviennent à supprimer la tolérance. Pour la démocratie, cela signifie que la liberté d\'expression n\'est pas absolue : elle a pour limite l\'expression qui vise à détruire la liberté elle-même.',keywords:['Popper','tolérance','paradoxe','intolérance','démocratie'],e:'Popper, "La Société ouverte et ses ennemis" (1945). "Société ouverte" = sociedad abierta. Le paradoxe : la tolérance pour les intolérants détruit la tolérance. Solution = intolerance de l\'intolérance. Application : censure des discours de haine, interdiction des partis anticonstitutionnels. C1 oral : exposer un paradoxe philosophique avec précision et clarté.'},
  /* ── PRODUCE (16-20) ── */
  {t:'eo',mode:'produce',q:'Développez à voix haute (2-3 minutes) un commentaire critique sur l\'affirmation suivante : « L\'université doit avant tout former des professionnels employables, pas des esprits libres. » Défendez une position nuancée.',model:'Cette affirmation soulève une fausse opposition... D\'un côté, l\'université a une mission de formation professionnelle... De l\'autre, réduire l\'université à cette seule fonction, c\'est... Ce qui me paraît le plus pertinent, c\'est de défendre une vision intégratrice...',keywords:['université','professionnels','esprits libres','formation','mission'],e:'Fausse dichotomie : "professionnels" vs "esprits libres". Arguments pour l\'esprit critique : innovateurs (Jobs, Zuckerberg = humanistes reconvertis), résilience face à la disruption, citoyenneté. Arguments pour l\'employabilité : coût de l\'éducation, attentes des étudiants, chômage des diplômés. Vision intégratrice : "les employeurs cherchent des esprits agiles, pas des exécutants". Humboldtian university model (Allemagne) = conjugue recherche + formation. C1 oral : 2-3 min, structuré, nuancé.'},
  {t:'eo',mode:'produce',q:'Présentez oralement (2-3 minutes) une analyse du concept de « société de surveillance » tel que Foucault le développe à travers la métaphore du Panoptique. Liez-le à un enjeu contemporain.',model:'Dans "Surveiller et Punir" (1975), Foucault utilise le Panoptique de Bentham comme métaphore... Le Panoptique est cette prison circulaire où... Ce qui est fondamental chez Foucault, c\'est l\'idée que... Dans notre monde contemporain, on retrouve cette logique dans...',keywords:['Panoptique','Foucault','surveillance','pouvoir','contemporain'],e:'Panoptique (Bentham, 1791) : prison circulaire avec tour centrale → le détenu est potentiellement visible en permanence → internalise la surveillance. Foucault : le pouvoir disciplinaire fonctionne par le regard. Applications contemporaines : surveillance numérique (Snowden, caméras, algorithmes), réseaux sociaux (auto-surveillance), biométrie. "Surveiller et Punir" (1975). C1 oral : mobiliser un concept théorique et l\'articuler à des exemples actuels.'},
  {t:'eo',mode:'produce',q:'Répondez oralement (2-3 minutes) à cette question d\'oral de type "Sciences Po" : « Peut-on être à la fois patriote et citoyen du monde ? » Développez une réflexion nuancée.',model:'La question pose une tension apparente entre l\'appartenance particulière (la nation) et l\'appartenance universelle (l\'humanité)... D\'un côté... De l\'autre... La position qui me semble la plus cohérente est le cosmopolitisme enraciné, défendu par...',keywords:['patriote','citoyen du monde','cosmopolitisme','appartenance','nation'],e:'"Citoyen du monde" = cosmopolite (Diogène de Sinope). Tension : particularisme (nation, culture, langue) vs universalisme (droits humains, humanité partagée). "Cosmopolitisme enraciné" (Kwame Anthony Appiah) = s\'attacher à ses racines tout en s\'ouvrant à l\'universel. Kwame Nkrumah, Simone Weil, Albert Camus = figures du double attachement. C1 oral : montée en abstraction + ancrage dans des figures et des exemples précis.'},
  {t:'eo',mode:'produce',q:'Présentez à voix haute (2-3 minutes) votre analyse d\'un fait d\'actualité récent à travers le prisme d\'une théorie ou d\'un concept des sciences sociales que vous avez étudié.',model:'Je vais analyser [fait d\'actualité] à travers le prisme de [concept]. Ce fait peut être compris comme... En appliquant la grille de [auteur], on peut voir que... Cette analyse révèle que... Ce qui me frappe dans cette lecture, c\'est...',keywords:['actualité','analyse','prisme','concept','grille'],e:'Structure : 1) Présentation du fait d\'actualité (30 sec), 2) Introduction du cadre théorique choisi (30 sec), 3) Application du concept au fait (60 sec), 4) Ce que révèle cette lecture (30 sec). Exemples possibles : grève et concept de champ (Bourdieu), mouvement social et anomie (Durkheim), désinformation et biais de confirmation (Wason/Kahneman). C1 oral : articuler théorie et pratique de manière cohérente.'},
  {t:'eo',mode:'produce',q:'Développez oralement (2-3 minutes) une réflexion sur cette citation de Paul Ricœur : « Le récit donne une forme narrative à ce qui sans lui resterait une expérience diffuse et sans sens. » Montrez en quoi cette idée est pertinente pour comprendre comment les sociétés construisent leur histoire collective.',keywords:['Ricœur','récit','narrative','expérience','sens'],model:'Ricœur affirme ici que le récit n\'est pas une décoration de l\'expérience, mais sa condition de possibilité... Ce qui est passionnant dans cette idée, c\'est qu\'elle s\'applique non seulement à l\'individu mais aussi aux collectifs... Les nations se construisent par des récits fondateurs... La question politique devient alors : qui a le pouvoir de raconter l\'histoire ?',e:'Ricœur (1913-2005) : "Temps et Récit" (1983-1985). "Identité narrative" = la identidad se construye a través de relatos. "Expérience diffuse" = experiencia fragmentada sin sentido. Applications : mythes fondateurs des nations (Marseillaise + Révolution en France), histoire officielle vs mémoires minoritaires. "Qui a le pouvoir de raconter ?" = question du pouvoir narratif (politique de la mémoire). C1 oral : partir d\'une citation philosophique et en dérouler les implications politiques et sociales.'},
],

/* ──────────── C2 · CE ──────────── */
CE_C2: [
  /* ── PASSAGE 1 : Essai philosophique — Liberté et déterminisme (Q1-4) ── */
  {t:'mc',passage:'La question du libre arbitre constitue l\'une des apories les plus tenaces de la philosophie occidentale. Si le déterminisme est vrai — si chaque état du monde résulte nécessairement des états antérieurs selon des lois causales inexorables — alors la notion de responsabilité morale semble se dissoudre dans une mécanique aveugle. Pourtant, l\'expérience subjective de la délibération, le sentiment d\'être l\'auteur de ses actes, résiste à cette réduction. Les compatibilistes tentent de réconcilier les deux positions en soutenant que la liberté n\'est pas l\'absence de causes, mais la capacité d\'agir conformément à ses désirs rationnels sans contrainte externe. Cette solution, élégante sur le plan formel, laisse néanmoins subsister un malaise : peut-on véritablement se sentir responsable de désirs dont les origines nous échappent ?',q:'Quel problème philosophique central ce texte explore-t-il ?',a:['La définition juridique de la responsabilité pénale','La tension entre déterminisme causal et libre arbitre','Les limites de la philosophie scientifique contemporaine','Le rapport entre conscience et inconscient'],c:1,e:'"Aporie" = aporía (paradoja filosófica sin solución aparente). "Libre arbitre" = libre albedrío. "Déterminisme" = determinismo. "Compatibilisme" = compatibilismo (posición que intenta reconciliar ambas). Structure : problème → solution proposée (compatibilisme) → limite de cette solution. Vocabulaire philosophique C2 = essentiel pour lire des textes académiques complexes.'},
  {t:'mc',passage:'La question du libre arbitre constitue l\'une des apories les plus tenaces de la philosophie occidentale. Si le déterminisme est vrai — si chaque état du monde résulte nécessairement des états antérieurs selon des lois causales inexorables — alors la notion de responsabilité morale semble se dissoudre dans une mécanique aveugle. Pourtant, l\'expérience subjective de la délibération, le sentiment d\'être l\'auteur de ses actes, résiste à cette réduction. Les compatibilistes tentent de réconcilier les deux positions en soutenant que la liberté n\'est pas l\'absence de causes, mais la capacité d\'agir conformément à ses désirs rationnels sans contrainte externe. Cette solution, élégante sur le plan formel, laisse néanmoins subsister un malaise : peut-on véritablement se sentir responsable de désirs dont les origines nous échappent ?',q:'Quelle est la position défendue par les compatibilistes selon le texte ?',a:['Le déterminisme est faux car la conscience transcende les lois causales','La liberté consiste à agir selon ses désirs rationnels sans contrainte externe','La responsabilité morale n\'existe pas dans un monde déterministe','La délibération consciente est une illusion produite par le cerveau'],c:1,e:'Les compatibilistes : "la liberté n\'est pas l\'absence de causes, mais la capacité d\'agir conformément à ses désirs rationnels sans contrainte externe." = la libertad no es ausencia de causas, sino capacidad de actuar según deseos racionales sin coacción. Distinction clé : liberté comme absence de causes vs liberté comme absence de contrainte EXTERNE.'},
  {t:'tf',passage:'La question du libre arbitre constitue l\'une des apories les plus tenaces de la philosophie occidentale. Si le déterminisme est vrai — si chaque état du monde résulte nécessairement des états antérieurs selon des lois causales inexorables — alors la notion de responsabilité morale semble se dissoudre dans une mécanique aveugle. Pourtant, l\'expérience subjective de la délibération, le sentiment d\'être l\'auteur de ses actes, résiste à cette réduction. Les compatibilistes tentent de réconcilier les deux positions en soutenant que la liberté n\'est pas l\'absence de causes, mais la capacité d\'agir conformément à ses désirs rationnels sans contrainte externe. Cette solution, élégante sur le plan formel, laisse néanmoins subsister un malaise : peut-on véritablement se sentir responsable de désirs dont les origines nous échappent ?',q:'L\'auteur considère que la solution compatibiliste résout entièrement le problème du libre arbitre.',c:false,e:'Faux. "Cette solution, élégante sur le plan formel, laisse néanmoins subsister un malaise" = esta solución, elegante en términos formales, deja no obstante subsistir una incomodidad. "Néanmoins" = sin embargo. "Subsister un malaise" = persiste un malestar. L\'auteur reconnaît l\'élégance formelle mais souligne la persistance du problème.'},
  {t:'mc',passage:'La question du libre arbitre constitue l\'une des apories les plus tenaces de la philosophie occidentale. Si le déterminisme est vrai — si chaque état du monde résulte nécessairement des états antérieurs selon des lois causales inexorables — alors la notion de responsabilité morale semble se dissoudre dans une mécanique aveugle. Pourtant, l\'expérience subjective de la délibération, le sentiment d\'être l\'auteur de ses actes, résiste à cette réduction. Les compatibilistes tentent de réconcilier les deux positions en soutenant que la liberté n\'est pas l\'absence de causes, mais la capacité d\'agir conformément à ses désirs rationnels sans contrainte externe. Cette solution, élégante sur le plan formel, laisse néanmoins subsister un malaise : peut-on véritablement se sentir responsable de désirs dont les origines nous échappent ?',q:'La question rhétorique finale du texte sert principalement à :',a:['Réfuter complètement la position compatibiliste','Proposer une nouvelle solution au problème','Signaler la limite résiduelle de la solution proposée','Introduire le sujet de la conscience et de l\'inconscient'],c:2,e:'La question finale = "peut-on véritablement se sentir responsable de désirs dont les origines nous échappent ?" Elle ne réfute pas le compatibilisme mais en pointe la limite résiduelle : même si la contrainte externe disparaît, les origines profondes de nos désirs restent opaques. Fonction : problématiser davantage plutôt que conclure = marque du style philosophique C2.'},
  /* ── PASSAGE 2 : Critique littéraire (Q5-7) ── */
  {t:'mc',passage:'Proust n\'écrit pas pour raconter, au sens traditionnel du terme ; il écrit pour ressaisir. L\'œuvre entière de "La Recherche" repose sur cette ambition paradoxale : retrouver, par le biais de la mémoire involontaire, non le passé tel qu\'il fut, mais le passé tel qu\'il est encore, vivant sous la croûte des habitudes et de l\'oubli volontaire. La fameuse madeleine n\'est pas un procédé littéraire : c\'est une épiphanie phénoménologique. Ce que Proust donne à voir, c\'est moins la biographie d\'un narrateur que la topographie d\'une conscience en train de se saisir elle-même dans l\'acte de se souvenir. En ce sens, "La Recherche" est peut-être le roman qui a le plus radicalement remis en question ce qu\'écrire veut dire.',q:'Selon la critique, quelle est l\'ambition centrale de l\'œuvre proustienne ?',a:['Raconter la vie d\'un personnage de manière chronologique','Analyser les structures sociales de la bourgeoisie française','Retrouver le passé vivant par le biais de la mémoire involontaire','Décrire les mécanismes de l\'oubli volontaire'],c:2,e:'"Ressaisir" = volver a aprehender/recuperar. "Mémoire involontaire" = mémoire proustienne (vs mémoire volontaire). "Le passé tel qu\'il est encore, vivant sous la croûte des habitudes" = el pasado tal como todavía está, vivo bajo la costra de los hábitos. Proust ≠ biographie → phénoménologie de la mémoire. "La Recherche du temps perdu" (1913-1927) = roman-fleuve majeur.'},
  {t:'tf',passage:'Proust n\'écrit pas pour raconter, au sens traditionnel du terme ; il écrit pour ressaisir. L\'œuvre entière de "La Recherche" repose sur cette ambition paradoxale : retrouver, par le biais de la mémoire involontaire, non le passé tel qu\'il fut, mais le passé tel qu\'il est encore, vivant sous la croûte des habitudes et de l\'oubli volontaire. La fameuse madeleine n\'est pas un procédé littéraire : c\'est une épiphanie phénoménologique. Ce que Proust donne à voir, c\'est moins la biographie d\'un narrateur que la topographie d\'une conscience en train de se saisir elle-même dans l\'acte de se souvenir. En ce sens, "La Recherche" est peut-être le roman qui a le plus radicalement remis en question ce qu\'écrire veut dire.',q:'Selon l\'auteur de la critique, la madeleine proustienne est avant tout un artifice stylistique utilisé à des fins narratives.',c:false,e:'Faux. "La fameuse madeleine n\'est pas un procédé littéraire : c\'est une épiphanie phénoménologique." Le critique refuse la lecture superficielle (artifice/procédé) pour proposer une lecture philosophique (épiphanie phénoménologique = révélation sur la nature de la conscience). "Épiphanie" = epifanía. "Phénoménologique" = fenomenológico (de la phenomenología = ciencia de la experiencia consciente).'},
  {t:'mc',passage:'Proust n\'écrit pas pour raconter, au sens traditionnel du terme ; il écrit pour ressaisir. L\'œuvre entière de "La Recherche" repose sur cette ambition paradoxale : retrouver, par le biais de la mémoire involontaire, non le passé tel qu\'il fut, mais le passé tel qu\'il est encore, vivant sous la croûte des habitudes et de l\'oubli volontaire. La fameuse madeleine n\'est pas un procédé littéraire : c\'est une épiphanie phénoménologique. Ce que Proust donne à voir, c\'est moins la biographie d\'un narrateur que la topographie d\'une conscience en train de se saisir elle-même dans l\'acte de se souvenir. En ce sens, "La Recherche" est peut-être le roman qui a le plus radicalement remis en question ce qu\'écrire veut dire.',q:'Que signifie « la topographie d\'une conscience » dans le contexte de cette critique ?',a:['La carte géographique des lieux décrits dans le roman','La cartographie des mécanismes intérieurs d\'une conscience qui se saisit elle-même','La biographie chronologique du narrateur','La structure narrative en couches superposées'],c:1,e:'"Topographie" = topografía (lit. descripción de un lugar). Ici, métaphoriquement : la cartographie/estructura de l\'espace intérieur de la conscience. "En train de se saisir elle-même" = en el acto de aprehenderse a sí misma. Proust cartographie la conscience dans l\'acte de se souvenir, pas un espace physique. Métaphore spatiale appliquée à l\'intériorité = registre C2.'},
  /* ── PASSAGE 3 : Texte sur le langage et la pensée (Q8-11) ── */
  {t:'mc',passage:'La thèse de la relativité linguistique, dans sa version forte, affirme que la structure de la langue que l\'on parle détermine la structure de la pensée. Si cette thèse est exacte, il s\'ensuit qu\'une langue sans futur grammatical — comme certaines langues amazoniennes — produirait des locuteurs incapables de penser le temps à venir de manière similaire aux locuteurs du français ou de l\'anglais. Les études empiriques, toutefois, tempèrent considérablement cette affirmation : si la langue influence bien la manière dont on catégorise certaines expériences — notamment les couleurs, les relations spatiales ou le temps —, elle ne la détermine pas de façon absolue. On parle désormais de "relativité faible" : la langue oriente la pensée sans l\'enchaîner.',q:'Quelle est la différence entre la version forte et la version faible de la relativité linguistique, selon le texte ?',a:['La version forte concerne les langues européennes, la faible les langues non-européennes','La version forte affirme que la langue détermine la pensée ; la version faible qu\'elle l\'oriente seulement','La version forte est prouvée scientifiquement, la faible reste une hypothèse','La version forte est défendue par les linguistes, la faible par les philosophes'],c:1,e:'Version forte : la langue DÉTERMINE la pensée (les locuteurs seraient prisonniers de leur langue). Version faible : la langue ORIENTE la pensée sans l\'enchaîner. "Tempérer" = moderar/suavizar. "Catégoriser" = categorizar. "Enchaîner" = encadenar. Linguistes associés : Sapir-Whorf (version forte), Slobin (version faible).'},
  {t:'tf',passage:'La thèse de la relativité linguistique, dans sa version forte, affirme que la structure de la langue que l\'on parle détermine la structure de la pensée. Si cette thèse est exacte, il s\'ensuit qu\'une langue sans futur grammatical — comme certaines langues amazoniennes — produirait des locuteurs incapables de penser le temps à venir de manière similaire aux locuteurs du français ou de l\'anglais. Les études empiriques, toutefois, tempèrent considérablement cette affirmation : si la langue influence bien la manière dont on catégorise certaines expériences — notamment les couleurs, les relations spatiales ou le temps —, elle ne la détermine pas de façon absolue. On parle désormais de "relativité faible" : la langue oriente la pensée sans l\'enchaîner.',q:'Les études empiriques confirment entièrement la version forte de la relativité linguistique.',c:false,e:'Faux. "Les études empiriques tempèrent considérablement cette affirmation" = los estudios empíricos moderan considerablemente esta afirmación. "Tempérer" = moderar. La version forte est réfutée : la langue influence (oriente), mais ne détermine pas de façon absolue. Les études ont conduit à adopter la "relativité faible".'},
  {t:'mc',passage:'La thèse de la relativité linguistique, dans sa version forte, affirme que la structure de la langue que l\'on parle détermine la structure de la pensée. Si cette thèse est exacte, il s\'ensuit qu\'une langue sans futur grammatical — comme certaines langues amazoniennes — produirait des locuteurs incapables de penser le temps à venir de manière similaire aux locuteurs du français ou de l\'anglais. Les études empiriques, toutefois, tempèrent considérablement cette affirmation : si la langue influence bien la manière dont on catégorise certaines expériences — notamment les couleurs, les relations spatiales ou le temps —, elle ne la détermine pas de façon absolue. On parle désormais de "relativité faible" : la langue oriente la pensée sans l\'enchaîner.',q:'L\'expression « il s\'ensuit que » dans le texte introduit :',a:['Une concession faite à la position adverse','Une conséquence logique découlant de la thèse précédente','Une condition hypothétique pour la validité de la thèse','Une définition du terme "relativité linguistique"'],c:1,e:'"Il s\'ensuit que" = se sigue que / por lo tanto (introduce una consecuencia lógica). "Il s\'ensuit que [une langue sans futur]... produirait des locuteurs incapables de..." = la consecuencia lógica de la premisa sería... Marqueur de raisonnement déductif = indispensable pour la lecture de textes académiques C2.'},
  {t:'mc',passage:'La thèse de la relativité linguistique, dans sa version forte, affirme que la structure de la langue que l\'on parle détermine la structure de la pensée. Si cette thèse est exacte, il s\'ensuit qu\'une langue sans futur grammatical — comme certaines langues amazoniennes — produirait des locuteurs incapables de penser le temps à venir de manière similaire aux locuteurs du français ou de l\'anglais. Les études empiriques, toutefois, tempèrent considérablement cette affirmation : si la langue influence bien la manière dont on catégorise certaines expériences — notamment les couleurs, les relations spatiales ou le temps —, elle ne la détermine pas de façon absolue. On parle désormais de "relativité faible" : la langue oriente la pensée sans l\'enchaîner.',q:'Quelle métaphore l\'auteur utilise-t-il pour décrire le rapport entre langue et pensée dans la version faible ?',a:['La langue est une prison dont on ne peut s\'échapper','La langue est un miroir qui reflète exactement la réalité','La langue oriente sans enchaîner — comme un guide sans contrainte absolue','La langue est un outil neutre que l\'on peut utiliser à volonté'],c:2,e:'"La langue oriente la pensée sans l\'enchaîner." "Enchaîner" = encadenar (metáfora de la esclavitud). "Orienter sans enchaîner" = guiar sin encarcelar. La version faible = influence sans déterminisme absolu. Version forte = chaînes. Version faible = boussole/guide. Reconnaître les métaphores sous-jacentes dans un texte académique = compétence C2.'},
  /* ── PASSAGE 4 : Texte sur l\'art contemporain (Q12-14) ── */
  {t:'mc',passage:'L\'art contemporain suscite souvent un malaise que ses détracteurs imputent à l\'absence supposée de maîtrise technique, et ses défenseurs attribuent à l\'inconfort de la nouveauté. Mais ce malaise révèle peut-être quelque chose de plus fondamental : notre difficulté à tolérer l\'œuvre qui résiste à l\'interprétation, qui se refuse à la signification univoque. Si l\'art classique "montre", l\'art contemporain, dans ses expressions les plus radicales, "creuse" : il ouvre des béances dans la représentation sans prétendre les refermer. Accepter cela exige un changement de posture du spectateur — de consommateur de sens à co-producteur de sens en suspens.',q:'Selon le texte, quelle posture l\'art contemporain radical exige-t-il du spectateur ?',a:['Consommer passivement les significations proposées par l\'artiste','Devenir co-producteur d\'un sens maintenu en suspens','Rejeter toute signification et rester dans le vide','Chercher une interprétation unique et définitive'],c:1,e:'"Co-producteur de sens en suspens" = co-productor de un sentido mantenido en suspenso. "Béances" = brechas/vacíos (en la representación). "Signification univoque" = significado unívoco/único. L\'art contemporain ne "referme" pas les béances qu\'il ouvre → le spectateur doit habiter l\'ambiguïté. Vocabulaire esthétique C2.'},
  {t:'tf',passage:'L\'art contemporain suscite souvent un malaise que ses détracteurs imputent à l\'absence supposée de maîtrise technique, et ses défenseurs attribuent à l\'inconfort de la nouveauté. Mais ce malaise révèle peut-être quelque chose de plus fondamental : notre difficulté à tolérer l\'œuvre qui résiste à l\'interprétation, qui se refuse à la signification univoque. Si l\'art classique "montre", l\'art contemporain, dans ses expressions les plus radicales, "creuse" : il ouvre des béances dans la représentation sans prétendre les refermer. Accepter cela exige un changement de posture du spectateur — de consommateur de sens à co-producteur de sens en suspens.',q:'L\'auteur suggère que le malaise face à l\'art contemporain s\'explique uniquement par le manque de compétence technique des artistes.',c:false,e:'Faux. L\'auteur présente deux explications (détracteurs : manque technique ; défenseurs : inconfort de la nouveauté), puis propose une troisième, plus fondamentale : notre difficulté à tolérer l\'œuvre qui "résiste à l\'interprétation". Il dépasse les deux positions initiales pour une analyse plus profonde. "Imputer à" = atribuir a.'},
  {t:'mc',passage:'L\'art contemporain suscite souvent un malaise que ses détracteurs imputent à l\'absence supposée de maîtrise technique, et ses défenseurs attribuent à l\'inconfort de la nouveauté. Mais ce malaise révèle peut-être quelque chose de plus fondamental : notre difficulté à tolérer l\'œuvre qui résiste à l\'interprétation, qui se refuse à la signification univoque. Si l\'art classique "montre", l\'art contemporain, dans ses expressions les plus radicales, "creuse" : il ouvre des béances dans la représentation sans prétendre les refermer. Accepter cela exige un changement de posture du spectateur — de consommateur de sens à co-producteur de sens en suspens.',q:'La distinction entre l\'art classique qui « montre » et l\'art contemporain qui « creuse » illustre :',a:['La supériorité technique de l\'art classique sur l\'art contemporain','Deux conceptions différentes du rôle de l\'œuvre d\'art face au sens','L\'incapacité des artistes contemporains à transmettre un message clair','Le fait que l\'art contemporain est réservé aux experts'],c:1,e:'Montrer" vs "creuser" = deux métaphores pour deux poétiques. L\'art classique : montrer une signification = presentar un significado. L\'art contemporain radical : creuser = abrir brechas, no cerrarlas. L\'œuvre n\'est plus un message à déchiffrer mais un espace d\'incertitude productive. Lecture métaphorique d\'un texte esthétique = compétence C2.'},
  /* ── MATCH + standalone Q15-20 ── */
  {t:'match',q:'Associez chaque terme philosophique ou rhétorique à sa définition.',p:[['Aporie','Paradoxe philosophique sans solution apparente'],['Épiphanie','Révélation soudaine d\'une vérité profonde'],['Synecdoque','Figure qui prend la partie pour le tout'],['Tautologie','Affirmation qui se répète en disant la même chose']],e:'Termes C2 essentiels : "Aporie" (Platon) = aporía. "Épiphanie" (Joyce) = epifanía. "Synecdoque" = sinécdoque (ex : "une voile" pour "un bateau"). "Tautologie" = tautología (ex : "un célibataire est un homme non marié"). Maîtrise du métalangage littéraire et philosophique = marque du niveau C2.'},
  {t:'mc',q:'Dans un essai philosophique, que signifie l\'expression « l\'expérience subjective résiste à la réduction » ?',a:['L\'expérience personnelle est trop simple pour être analysée','La conscience ne peut être entièrement expliquée par des mécanismes physiques ou causaux','L\'expérience subjective est la seule réalité qui existe','La réduction des données est impossible en philosophie'],c:1,e:'"Résister à la réduction" = resistir la reducción (a lo físico, causal, material). En philosophie de l\'esprit : la "réduction" = l\'idée que l\'esprit/conscience = pur mécanisme physique. Si l\'expérience subjective "résiste", c\'est qu\'elle contient quelque chose d\'irréductible aux causes physiques. Lien avec le problème difficile de la conscience (Chalmers).'},
  {t:'tf',q:'En français littéraire soutenu, « il n\'en demeure pas moins que » est une formule qui introduit une concession avant d\'affirmer le contraire.',c:true,e:'Vrai. "Il n\'en demeure pas moins que" = sin embargo / no obstante. Structure : [concession de l\'argument adverse] + "il n\'en demeure pas moins que" + [affirmation de sa propre thèse]. Équivalent : "néanmoins", "cela dit", "quoi qu\'il en soit". Registre très soutenu, fréquent dans les textes académiques et les essais C2.'},
  {t:'mc',q:'Dans la critique proustienne, l\'expression « topographie d\'une conscience » exploite une métaphore de quel domaine ?',a:['La biologie','La géographie','La musique','La physique'],c:1,e:'"Topographie" = topografía (del griego: topos = lugar + graphé = descripción). Terme géographique appliqué à l\'intériorité psychique. Métaphore spatiale → l\'intérieur de la conscience est traité comme un paysage cartographiable. Usage métaphorique de termes d\'autres disciplines = procédé stylistique C2 fréquent dans la critique littéraire.'},
  {t:'mc',q:'Laquelle de ces affirmations décrit le mieux la « version faible » de la relativité linguistique ?',a:['La langue emprisonne totalement la pensée','La langue n\'a aucune influence sur la pensée','La langue oriente certaines catégorisations de l\'expérience sans les déterminer absolument','La langue et la pensée sont deux systèmes entièrement indépendants'],c:2,e:'Version faible (Slobin, Boroditsky) : la langue influence (oriente) la manière de catégoriser l\'expérience, mais ne détermine pas absolument la pensée. Distinction clé : influence ≠ déterminisme. Exemples empiriques : les locuteurs du russe (qui distinguent le bleu clair du bleu foncé par des mots différents) perçoivent ces nuances plus rapidement. Mais ils peuvent aussi penser les nuances intermédiaires.'},
  {t:'mc',q:'Dans le texte sur l\'art contemporain, que signifie que l\'artiste contemporain radical « ouvre des béances sans prétendre les refermer » ?',a:['L\'artiste laisse son œuvre inachevée par manque de compétence','L\'artiste crée intentionnellement des zones d\'ambiguïté que le spectateur doit habiter','L\'artiste refuse tout contact avec son public','L\'artiste critique explicitement la tradition artistique classique'],c:1,e:'"Béances" = brechas/vacíos (espaces vides dans la représentation). "Sans prétendre les refermer" = sin pretender cerrarlos. L\'artiste ne fournit pas de signification close → le spectateur doit co-construire le sens dans cet espace d\'ambiguïté. "Habiter l\'ambiguïté" = vivir/residir en la ambigüedad. Esthétique de l\'ouverture = caractéristique de l\'art contemporain radical.'},
],

/* ──────────── C2 · CO ──────────── */
CO_C2: [
  /* ── CONFÉRENCE : Philosophie du langage (Q1-3) ── */
  {t:'mc',audio:'Permettez-moi de poser une question qui peut sembler triviale mais qui recèle une profondeur vertigineuse : quand nous disons "je", à quoi référons-nous exactement ? Le "je" grammatical est l\'un des mots les plus usités de la langue, et pourtant il désigne quelque chose d\'insaisissable. Les philosophes du langage distinguent entre le "je" indexical — qui désigne simplement le locuteur en train de parler — et le "je" phénoménal — qui renvoie à l\'expérience subjective de soi, à ce flux de conscience dont parlait William James. Cette distinction n\'est pas anodine : elle soulève la question de savoir si le moi est une entité stable ou une construction narrative que le langage rend possible.',q:'Quelle distinction philosophique centrale est introduite dans cette conférence ?',a:['Entre le "je" grammatical et le "je" poétique dans la littérature','Entre le "je" indexical (locuteur) et le "je" phénoménal (expérience subjective)','Entre le langage parlé et le langage écrit dans la philosophie','Entre la grammaire française et la grammaire universelle'],c:1,e:'"Je indexical" = je qui désigne le locuteur en train de parler (= función deíctica). "Je phénoménal" = je qui renvoie à l\'expérience subjective intérieure. "Indexical" = del lat. index = índice, señalador. "Phénoménal" = relatif à la phénoménologie (science de l\'expérience consciente). William James = philosophe américain (courant de conscience). Niveau C2 : saisir des distinctions philosophiques subtiles à l\'oral.'},
  {t:'tf',audio:'Permettez-moi de poser une question qui peut sembler triviale mais qui recèle une profondeur vertigineuse : quand nous disons "je", à quoi référons-nous exactement ? Le "je" grammatical est l\'un des mots les plus usités de la langue, et pourtant il désigne quelque chose d\'insaisissable. Les philosophes du langage distinguent entre le "je" indexical — qui désigne simplement le locuteur en train de parler — et le "je" phénoménal — qui renvoie à l\'expérience subjective de soi, à ce flux de conscience dont parlait William James. Cette distinction n\'est pas anodine : elle soulève la question de savoir si le moi est une entité stable ou une construction narrative que le langage rend possible.',q:'L\'orateur affirme que le "je" est un mot dont le sens est clair et universellement compris.',c:false,e:'Faux. "Il désigne quelque chose d\'insaisissable" = designa algo inaprensible. "Insaisissable" = inaprensible, que no se puede atrapar. La question de départ ("à quoi référons-nous exactement ?") établit que le "je" est problématique malgré son usage courant. Paradoxe : le mot le plus utilisé désigne ce qui est le plus difficile à cerner.'},
  {t:'mc',audio:'Permettez-moi de poser une question qui peut sembler triviale mais qui recèle une profondeur vertigineuse : quand nous disons "je", à quoi référons-nous exactement ? Le "je" grammatical est l\'un des mots les plus usités de la langue, et pourtant il désigne quelque chose d\'insaisissable. Les philosophes du langage distinguent entre le "je" indexical — qui désigne simplement le locuteur en train de parler — et le "je" phénoménal — qui renvoie à l\'expérience subjective de soi, à ce flux de conscience dont parlait William James. Cette distinction n\'est pas anodine : elle soulève la question de savoir si le moi est une entité stable ou une construction narrative que le langage rend possible.',q:'Que signifie l\'expression « cette distinction n\'est pas anodine » dans ce contexte ?',a:['La distinction est facile à comprendre et à mémoriser','La distinction est récente et peu connue des spécialistes','La distinction a des implications philosophiques significatives','La distinction n\'est valable que pour le français'],c:2,e:'"Anodin(e)" = anodino/inofensivo/insignificante. "Cette distinction n\'est pas anodine" = esta distinción no es trivial/sin importancia. Elle soulève la question de la stabilité ou de la construction narrative du moi. Formule litotique fréquente dans le discours académique français pour souligner l\'importance d\'un point sans tomber dans l\'emphase excessive. Reconnaître les litotes = compétence C2.'},
  /* ── CONFÉRENCE LITTÉRAIRE : Ironie narrative (Q4-6) ── */
  {t:'mc',audio:'L\'ironie narrative est l\'une des formes les plus sophistiquées du discours littéraire, précisément parce qu\'elle repose sur un écart entre ce qui est dit et ce qui est signifié — un écart que le lecteur doit détecter et combler lui-même. Dans "Candide" de Voltaire, le narrateur nous présente avec un enthousiasme imperturbable des horreurs guerrières et des injustices comme si elles faisaient partie de l\'ordre naturel des choses. Cet enthousiasme factice est l\'arme critique de Voltaire : en faisant "comme si" le monde allait bien, il révèle avec une efficacité redoutable combien il va mal. L\'ironie voltairienne fonctionne ainsi comme un scalpel qui découpe la réalité en la décrivant exactement à l\'envers.',q:'Comment fonctionne l\'ironie narrative dans "Candide" selon cet exposé ?',a:['Par l\'utilisation d\'un vocabulaire technique incompréhensible pour le lecteur','En décrivant les horreurs avec un enthousiasme apparent qui révèle leur absurdité','Par des commentaires explicites du narrateur sur les injustices du monde','En faisant parler les personnages avec ironie dans leurs dialogues'],c:1,e:'L\'ironie voltairienne = décrire le mal comme s\'il était naturel ou bon → l\'écart entre ton enthousiaste et contenu horrible crée l\'effet critique. "Imperturbable" = imperturbable. "Factice" = fingido/artificial. "Scalpel" = bisturí (metáfora chirurgicale de la précision critique). "Découper la réalité en la décrivant à l\'envers" = représenter la réalité par son inverse.'},
  {t:'tf',audio:'L\'ironie narrative est l\'une des formes les plus sophistiquées du discours littéraire, précisément parce qu\'elle repose sur un écart entre ce qui est dit et ce qui est signifié — un écart que le lecteur doit détecter et combler lui-même. Dans "Candide" de Voltaire, le narrateur nous présente avec un enthousiasme imperturbable des horreurs guerrières et des injustices comme si elles faisaient partie de l\'ordre naturel des choses. Cet enthousiasme factice est l\'arme critique de Voltaire : en faisant "comme si" le monde allait bien, il révèle avec une efficacité redoutable combien il va mal. L\'ironie voltairienne fonctionne ainsi comme un scalpel qui découpe la réalité en la décrivant exactement à l\'envers.',q:'Selon l\'exposé, l\'ironie narrative nécessite une participation active du lecteur pour produire son effet.',c:true,e:'Vrai. "Un écart que le lecteur doit détecter et combler lui-même." L\'ironie n\'est efficace que si le lecteur saisit l\'écart entre le dit et le signifié. Si le lecteur ne détecte pas l\'ironie, il prend le texte au premier degré et l\'effet critique est perdu. Participation herméneutique du lecteur = condition de l\'ironie.'},
  {t:'mc',audio:'L\'ironie narrative est l\'une des formes les plus sophistiquées du discours littéraire, précisément parce qu\'elle repose sur un écart entre ce qui est dit et ce qui est signifié — un écart que le lecteur doit détecter et combler lui-même. Dans "Candide" de Voltaire, le narrateur nous présente avec un enthousiasme imperturbable des horreurs guerrières et des injustices comme si elles faisaient partie de l\'ordre naturel des choses. Cet enthousiasme factice est l\'arme critique de Voltaire : en faisant "comme si" le monde allait bien, il révèle avec une efficacité redoutable combien il va mal. L\'ironie voltairienne fonctionne ainsi comme un scalpel qui découpe la réalité en la décrivant exactement à l\'envers.',q:'La métaphore du « scalpel » dans ce passage suggère que l\'ironie voltairienne est :',a:['Douloureuse pour l\'auteur qui l\'emploie','Précise et chirurgicalement efficace dans sa critique','Violente et destructrice de la réalité','Incompréhensible pour le lecteur non spécialiste'],c:1,e:'"Scalpel" = bisturí (instrumento de precisión quirúrgica). La métaphore suggère : précision + capacité à inciser/révéler ce qui est caché. "Découper la réalité" = sectionner/révéler la vérité. Voltaire = précis, efficace, sans pathos superflu. Le scalpel ne détruit pas — il révèle, expose, incise avec précision. Analyser une métaphore à l\'oral = compétence C2.'},
  /* ── DÉBAT PHILOSOPHIQUE : Bonheur et société (Q7-9) ── */
  {t:'mc',audio:'Intervieweuse : Notre invitée, philosophe, s\'est consacrée à la question du bonheur dans les sociétés libérales. Philosophe : Ce qui me frappe, c\'est l\'injonction au bonheur — cette pression sociale implicite qui nous dit que nous "devons" être heureux, épanouis, réalisés. Cette injonction est paradoxale : elle transforme le bonheur, qui devrait être une expérience spontanée, en performance. Et quand on "rate" cette performance, on ne ressent pas seulement de la tristesse — on ressent de la honte. C\'est la médicalisation du malheur ordinaire : la souffrance devient pathologie, et la pathologie devient un marché pour l\'industrie pharmaceutique et thérapeutique. Intervieweuse : Vous remettez en question le bonheur comme idéal ? Philosophe : Je remets en question l\'injonction, pas le bonheur lui-même.',q:'Quelle est la critique principale formulée par la philosophe ?',a:['Les médicaments sont inefficaces contre la dépression','La quête du bonheur est fondamentalement impossible','L\'injonction sociale au bonheur transforme une expérience spontanée en performance contraignante','La psychologie positive est une pseudo-science'],c:2,e:'"Injonction au bonheur" = mandato/obligación social de ser feliz. "Performance" = actuación (terme théâtral). Le bonheur performé ≠ bonheur vécu. Quand on "rate" → honte (et non plus simple tristesse). "Médicalisation du malheur ordinaire" = convertir la tristesse ordinaire en pathologie. Critique de l\'industrie pharmaceutique/thérapeutique. Registre : philosophie critique de la société.'},
  {t:'tf',audio:'Intervieweuse : Notre invitée, philosophe, s\'est consacrée à la question du bonheur dans les sociétés libérales. Philosophe : Ce qui me frappe, c\'est l\'injonction au bonheur — cette pression sociale implicite qui nous dit que nous "devons" être heureux, épanouis, réalisés. Cette injonction est paradoxale : elle transforme le bonheur, qui devrait être une expérience spontanée, en performance. Et quand on "rate" cette performance, on ne ressent pas seulement de la tristesse — on ressent de la honte. C\'est la médicalisation du malheur ordinaire : la souffrance devient pathologie, et la pathologie devient un marché pour l\'industrie pharmaceutique et thérapeutique. Intervieweuse : Vous remettez en question le bonheur comme idéal ? Philosophe : Je remets en question l\'injonction, pas le bonheur lui-même.',q:'La philosophe est opposée au bonheur comme valeur en soi.',c:false,e:'Faux. "Je remets en question l\'injonction, pas le bonheur lui-même." Elle distingue clairement : critique de l\'INJONCTION SOCIALE au bonheur (la pression) vs le bonheur comme expérience (qu\'elle ne rejette pas). Nuance essentielle. Comprendre les distinctions implicites dans un discours oral = compétence C2.'},
  {t:'mc',audio:'Intervieweuse : Notre invitée, philosophe, s\'est consacrée à la question du bonheur dans les sociétés libérales. Philosophe : Ce qui me frappe, c\'est l\'injonction au bonheur — cette pression sociale implicite qui nous dit que nous "devons" être heureux, épanouis, réalisés. Cette injonction est paradoxale : elle transforme le bonheur, qui devrait être une expérience spontanée, en performance. Et quand on "rate" cette performance, on ne ressent pas seulement de la tristesse — on ressent de la honte. C\'est la médicalisation du malheur ordinaire : la souffrance devient pathologie, et la pathologie devient un marché pour l\'industrie pharmaceutique et thérapeutique. Intervieweuse : Vous remettez en question le bonheur comme idéal ? Philosophe : Je remets en question l\'injonction, pas le bonheur lui-même.',q:'Que désigne la « médicalisation du malheur ordinaire » dans ce discours ?',a:['Le développement de nouveaux médicaments contre les maladies rares','Le fait de traiter comme une maladie ce qui est une tristesse normale et humaine','La tendance des médecins à prescrire trop d\'antidépresseurs sans raison','L\'utilisation de la médecine pour améliorer les performances cognitives'],c:1,e:'"Médicalisation" = medicalización (convertir en problema médico algo que no lo es). "Malheur ordinaire" = tristeza común/cotidiana. La souffrance ordinaire → pathologie (maladie) → marché (antidépresseurs, thérapies). Critique de la psychiatrisation de la tristesse normale. Ivan Illich a écrit sur la "médicalisation de la vie" (1975). Phénomène actuel : la tristesse → dépression → traitement.'},
  /* ── ESSAI LU : Mémoire collective (Q10-12) ── */
  {t:'mc',audio:'La mémoire collective n\'est pas la simple somme des mémoires individuelles. Elle est construite, sélective, et surtout disputée. Les sociétés choisissent ce qu\'elles veulent se rappeler et ce qu\'elles préfèrent oublier — et ces choix sont toujours politiques. L\'historien Paul Ricœur parlait de "mémoire obligée" pour désigner les événements qu\'une société est contrainte de commémorer, et d\'"oubli nécessaire" pour ceux qu\'elle doit effacer afin de permettre la réconciliation ou la refondation. Ce paradoxe — devoir se souvenir pour ne pas répéter, devoir oublier pour avancer — est au cœur de ce que les sociologues appellent désormais "le travail de deuil collectif".',q:'Quelle distinction Ricœur établit-il selon cet extrait ?',a:['Entre mémoire individuelle et mémoire collective','Entre mémoire obligée et oubli nécessaire','Entre histoire officielle et histoire révisionniste','Entre mémoire vivante et archives historiques'],c:1,e:'Ricœur distingue : "mémoire obligée" (ce qu\'on doit commémorer) vs "oubli nécessaire" (ce qu\'on doit effacer pour la réconciliation). Paul Ricœur = philosophe français (1913-2005), "La Mémoire, l\'Histoire, l\'Oubli" (2000). "Mémoire obligée" = memoria impuesta/necesaria. "Oubli nécessaire" = olvido necesario. Le paradoxe : se souvenir pour ne pas répéter / oublier pour avancer.'},
  {t:'tf',audio:'La mémoire collective n\'est pas la simple somme des mémoires individuelles. Elle est construite, sélective, et surtout disputée. Les sociétés choisissent ce qu\'elles veulent se rappeler et ce qu\'elles préfèrent oublier — et ces choix sont toujours politiques. L\'historien Paul Ricœur parlait de "mémoire obligée" pour désigner les événements qu\'une société est contrainte de commémorer, et d\'"oubli nécessaire" pour ceux qu\'elle doit effacer afin de permettre la réconciliation ou la refondation. Ce paradoxe — devoir se souvenir pour ne pas répéter, devoir oublier pour avancer — est au cœur de ce que les sociologues appellent désormais "le travail de deuil collectif".',q:'Selon cet extrait, la mémoire collective est un processus neutre et objectif.',c:false,e:'Faux. "Elle est construite, sélective, et surtout disputée." + "ces choix sont toujours politiques." La mémoire collective ≠ neutre/objective : elle est construite (pas naturelle), sélective (choisit ce qu\'elle garde) et disputée (objet de conflits). "Disputée" = en disputa/contestada. Caractère politique de la mémoire = thèse centrale.'},
  {t:'mc',audio:'La mémoire collective n\'est pas la simple somme des mémoires individuelles. Elle est construite, sélective, et surtout disputée. Les sociétés choisissent ce qu\'elles veulent se rappeler et ce qu\'elles préfèrent oublier — et ces choix sont toujours politiques. L\'historien Paul Ricœur parlait de "mémoire obligée" pour désigner les événements qu\'une société est contrainte de commémorer, et d\'"oubli nécessaire" pour ceux qu\'elle doit effacer afin de permettre la réconciliation ou la refondation. Ce paradoxe — devoir se souvenir pour ne pas répéter, devoir oublier pour avancer — est au cœur de ce que les sociologues appellent désormais "le travail de deuil collectif".',q:'L\'expression « travail de deuil collectif » suggère que la gestion du passé douloureux d\'une société est :',a:['Un processus rapide et naturel qui s\'accomplit sans effort','Un processus actif, difficile et qui demande un effort conscient','Identique dans toutes les cultures et sociétés','Exclusivement pris en charge par les historiens professionnels'],c:1,e:'"Travail" = trabajo (implica esfuerzo activo, no pasivo). "Deuil" = duelo (proceso de elaboración de una pérdida). "Deuil collectif" = duelo colectivo de una sociedad face à ses traumatismes. L\'expression emprunte à Freud le concept de "travail de deuil" (Trauerarbeit) et l\'applique à la dimension collective. "Actif et conscient" = elaboración activa, no olvido espontáneo.'},
  /* ── MATCH + standalone Q13-20 ── */
  {t:'match',audio:'Voici quatre concepts-clés de la pensée française contemporaine. Le libre arbitre désigne la capacité à choisir librement ses actes. La mémoire involontaire est le mécanisme proustien par lequel un souvenir surgit sans effort conscient. L\'injonction au bonheur désigne la pression sociale à être heureux. Enfin, la relativité linguistique est l\'hypothèse selon laquelle la langue structure notre façon de penser.',q:'Associez chaque concept à sa description.',p:[['Libre arbitre','Capacité à choisir librement ses actes'],['Mémoire involontaire','Souvenir qui surgit sans effort conscient'],['Injonction au bonheur','Pression sociale à être heureux'],['Relativité linguistique','La langue structure la façon de penser']],e:'Concepts clés du niveau C2 : Libre arbitre (Kant, Sartre), mémoire involontaire (Proust), injonction au bonheur (critique sociale contemporaine), relativité linguistique (Sapir-Whorf). Maîtriser ces concepts philosophiques et littéraires à l\'oral = compétence C2 fondamentale.'},
  {t:'mc',audio:'La notion d\'aliénation, telle que Marx la développe dans les Manuscrits de 1844, désigne la situation du travailleur qui se retrouve étranger à son propre travail : il produit un objet qui ne lui appartient pas, selon des règles qui ne sont pas les siennes, au service d\'intérêts qui ne sont pas les siens. L\'aliénation n\'est pas psychologique mais structurelle : elle est inscrite dans les rapports de production capitalistes.',q:'Selon cet extrait, l\'aliénation marxiste est principalement :',a:['Un état psychologique de mal-être subjectif','Une pathologie que la psychothérapie peut guérir','Une condition structurelle inscrite dans les rapports de production','Un sentiment temporaire lié à de mauvaises conditions de travail'],c:2,e:'"Structurelle" = estructural (≠ psychologique, ≠ temporaire). "Inscrite dans les rapports de production capitalistes" = encodée dans el sistema, pas dans l\'individu. L\'aliénation ≠ simple sentiment de mal-être → condition objective. Karl Marx, "Manuscrits de 1844". "Rapports de production" = relaciones de producción (estructura económica del capitalismo).'},
  {t:'tf',audio:'Dans la philosophie existentialiste de Sartre, l\'existence précède l\'essence. Cette formule renverse la tradition philosophique classique : l\'homme n\'a pas de nature prédéfinie, il se définit par ses choix et ses actes. Sartre en tire une conclusion radicale : nous sommes condamnés à être libres.',q:'Selon Sartre, les humains ont une nature fixe qui précède leur existence concrète.',c:false,e:'Faux. "L\'existence précède l\'essence" = l\'existencia precede a la esencia. Chez Sartre : il n\'y a pas de nature humaine prédéfinie. L\'être humain d\'abord EXISTE (est jeté dans le monde), puis se DÉFINIT par ses choix. Conséquence : "condamnés à être libres" = no podemos escapar de la libertad de elegir. Oppose la tradition classique et religieuse (essence avant existence).'},
  {t:'mc',audio:'L\'œuvre de Roland Barthes a profondément renouvelé la manière dont nous pensons le texte littéraire. Dans "La Mort de l\'auteur" (1968), Barthes argüe que le sens d\'un texte ne se trouve pas dans l\'intention de l\'auteur, mais dans la lecture elle-même. Une fois le texte publié, l\'auteur "meurt" : il ne peut plus contrôler les significations que les lecteurs lui attribuent. Cette thèse, provocatrice, libère le lecteur tout en le chargeant d\'une responsabilité herméneutique nouvelle.',q:'Que signifie la « mort de l\'auteur » dans la théorie de Barthes ?',a:['Les auteurs meurent physiquement avant de voir leur œuvre publiée','Une fois publié, le texte échappe à l\'intention de l\'auteur et appartient aux lecteurs','Les auteurs contemporains ne lisent pas les textes des auteurs classiques','Le sens d\'un texte est fixé une fois pour toutes à sa publication'],c:1,e:'"La mort de l\'auteur" = metáfora de la pérdida de autoridad del autor sobre su texto. Une fois publié, le texte est autonome. Le sens naît de la LECTURE, pas de l\'INTENTION de l\'auteur. "Responsabilité herméneutique" = responsabilidad de interpretación. Herméneutique = ciencia de la interpretación. Barthes (1915-1980) = sémiologue français, essai publié dans "Manteia".'},
  {t:'mc',audio:'La distinction entre discours et récit, fondamentale dans la narratologie de Gérard Genette, permet de comprendre comment le même matériau événementiel peut donner lieu à des textes radicalement différents selon la façon dont il est mis en forme. Le "récit" est la séquence des événements dans leur ordre réel. Le "discours" est la façon dont le narrateur les présente — avec ses ellipses, ses analepses, ses prolepses, ses variations de rythme. La littérature réside moins dans ce qui est raconté que dans comment cela est raconté.',q:'Selon Genette, qu\'est-ce qui distingue principalement le « discours » du « récit » ?',a:['Le discours est à l\'oral et le récit à l\'écrit','Le discours est la mise en forme narrative, le récit est la séquence réelle des événements','Le discours utilise la première personne et le récit la troisième','Le discours est fictif et le récit factuel'],c:1,e:'"Récit" (Genette) = l\'histoire dans son ordre chronologique réel (fábula). "Discours" = la façon dont le narrateur présente l\'histoire (sjuzhet). "Ellipse" = omisión temporal. "Analepse" = flashback (regreso al pasado). "Prolepse" = anticipación (adelanto al futuro). "La littérature réside dans le comment, pas dans le quoi" = message central de la narratologie.'},
  {t:'tf',audio:'La déconstruction, telle que Jacques Derrida la développe à partir de la fin des années 1960, ne vise pas à détruire les textes ou les systèmes conceptuels, mais à en révéler les contradictions internes, les tensions et les hiérarchies implicites que le texte lui-même cherche à dissimuler. Déconstruire, c\'est lire contre le grain.',q:'Selon Derrida, la déconstruction vise principalement à détruire et invalider les textes philosophiques.',c:false,e:'Faux. "Ne vise pas à détruire... mais à en révéler les contradictions internes." Déconstruire ≠ détruire. "Lire contre le grain" = leer a contrapelo (le bois = el texto, contre le grain = en contra de la dirección natural). Derrida (1930-2004) = philosophe franco-algérien. La déconstruction révèle ce que le texte cherche à masquer. Méthode de lecture, pas de destruction.'},
  {t:'mc',audio:'Dans "Le Deuxième Sexe" (1949), Simone de Beauvoir formule la thèse centrale du féminisme existentialiste : "On ne naît pas femme, on le devient." Cette affirmation signifie que la féminité n\'est pas une donnée biologique mais une construction sociale et culturelle, imposée par les normes, les pratiques et les discours dominants. Beauvoir refuse ainsi tout essentialisme : aucune propriété ne définit la "nature féminine" par avance.',q:'Que signifie la célèbre formule de Beauvoir : « On ne naît pas femme, on le devient » ?',a:['Les femmes acquièrent leur identité par une cérémonie d\'initiation','La féminité est une construction sociale et non une donnée biologique','Les femmes naissent avec une nature différente de celle des hommes','Le devenir-femme est un processus biologique de maturation'],c:1,e:'"On ne naît pas femme, on le devient" = No se nace mujer, se llega a serlo. Anti-essentialisme : la féminité ≠ nature biologique → elle est construite par la société (normes, éducation, discours). Simone de Beauvoir (1908-1986) = existentialiste féministe. Cette phrase = fondement du féminisme constructiviste et préfigure les théories du genre (Butler). CO C2 : saisir la thèse philosophique fondamentale d\'une citation célèbre.'},
  {t:'mc',audio:'L\'œuvre de Marcel Proust illustre magistralement la tension entre la mémoire volontaire — qui cherche délibérément à retrouver le passé — et la mémoire involontaire — qui surgit à l\'improviste, déclenchée par une sensation. Pour Proust, seule la mémoire involontaire restitue le passé dans sa plénitude sensible, car elle n\'est pas filtrée par l\'intellect. La mémoire volontaire, au contraire, ne produit que des reconstructions froides et abstraites. C\'est pourquoi l\'acte de manger la madeleine, dans "Du côté de chez Swann", ne constitue pas un simple souvenir mais une résurrection — une totale réapparition de l\'être passé.',q:'En quoi la mémoire involontaire est-elle supérieure à la mémoire volontaire selon la vision proustienne présentée ici ?',a:['Elle est plus rapide et plus efficace que la mémoire volontaire','Elle n\'est pas filtrée par l\'intellect et restitue le passé dans sa plénitude sensible','Elle est contrôlable et peut être activée à volonté','Elle ne produit que des souvenirs heureux et positifs'],c:1,e:'Mémoire volontaire = reconstructions "froides et abstraites" (filtradas por el intelecto). Mémoire involontaire = surgit sans filtre intellectuel → restitue le passé dans sa "plénitude sensible" (plenitud sensorial). "Résurrection" = résurrection (no simple recuerdo sino reaparición total del ser pasado). La madeleine trempée dans le thé → déclenchement involontaire. Proust = expérience directe, non médiatisée, du passé vécu. CO C2 : comprendre une distinction conceptuelle subtile dans un discours de haute densité philosophique.'},
],


/* ──────────── C2 · EE ──────────── */
EE_C2: [
  /* ── FILL (1-10) ── */
  {t:'ee',mode:'fill',
   q:'Complétez avec la forme correcte du subjonctif plus-que-parfait :\n\n« Je regrettais qu\'il n\'___ pas ___ (prévenir) ses collaborateurs de ce changement. »',
   a:'eût prévenu',alt:['EÛT PRÉVENU','eut prévenu','EUT PREVENU','eût prevenu'],
   e:'Subjonctif plus-que-parfait = subjonctif imparfait de AVOIR/ÊTRE + participe passé. AVOIR au subjonctif imparfait : eusse, eusses, EÛT, eussions, eussiez, eussent. PRÉVENIR → prévenu. "Qu\'il eût prévenu" = que hubiera/hubiese advertido. Temps littéraire rare mais présent dans les textes C2. Registre : très soutenu, littéraire.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le terme rhétorique correct :\n\n« La répétition de "jamais, jamais, jamais" à la fin du discours constitue une ___ frappante. »\n(anaphore / métonymie / synecdoque)',
   a:'anaphore',alt:['ANAPHORE'],
   e:'"Anaphore" = anáfora (repetición de la misma palabra al comienzo de frases/versos consecutivos). "Métonymie" = metonimia (la partie pour le tout, le contenant pour le contenu). "Synecdoque" = sinécdoque (variante de la métonymie). Ex. d\'anaphore célèbre : discours de Winston Churchill "We shall fight on the beaches... we shall fight..." ou Aragon "Il n\'y a pas d\'amour heureux".'},
  {t:'ee',mode:'fill',
   q:'Reformulez en utilisant la construction impersonnelle soutenue :\n\n« On pourrait objecter que cette démonstration est incomplète.\n→ Il ___ que cette démonstration est incomplète. »',
   a:'pourrait être objecté',alt:['POURRAIT ÊTRE OBJECTÉ','pourrait etre objecte','POURRAIT ETRE OBJECTE'],
   e:'Construction impersonnelle passive soutenue : "Il pourrait être objecté que" = cabría objetar que. Équivalents : "Il convient de noter que", "Il est à signaler que", "Il importe de souligner que". Ces tournures impersonnelles passives sont caractéristiques du registre académique C2. Elles permettent l\'objectivité apparente du discours scientifique.'},
  {t:'ee',mode:'fill',
   q:'Choisissez le connecteur argumentatif le plus précis :\n\n« La thèse est séduisante ; ___, elle omet de prendre en compte les données les plus récentes. »\n(partant / force est de constater que / or)',
   a:'or',alt:['OR'],
   e:'"Or" = pues bien / ahora bien (introduce un hecho que contradice, matiza ou complique ce qui précède). "Partant" = por tanto (conséquence). "Force est de constater que" = es forzoso reconocer que (concession). Ici, on introduit un CONTREPOINT à la thèse séduisante → "or" est le seul connecteur qui introduit ce renversement de façon neutre. Usage académique et littéraire.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le participe passé en accordant correctement :\n\n« Les œuvres que ce musée nous a ___ (prêter) sont d\'une rareté exceptionnelle. »',
   a:'prêtées',alt:['PRÊTÉES','pretees','PRETEES'],
   e:'PRÊTER → prêté. COD antéposé : "les œuvres" (féminin pluriel) → accord : prêtées. Avec AVOIR : accord du participe passé avec le COD si ANTÉPOSÉ. "Les œuvres que [COD antéposé] ce musée nous a prêtées [accord féminin pluriel]." Vérifier : que = "les œuvres" → féminin pluriel → prêtées.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec la locution conjonctive soutenue correcte :\n\n« ___ les résultats soient encourageants, plusieurs limites méthodologiques doivent être signalées. »\n(quoique / afin que / depuis que)',
   a:'Quoique',alt:['QUOIQUE','quoique'],
   e:'"Quoique + subjonctif" = aunque / si bien. "Afin que + subjonctif" = para que (finalité). "Depuis que + indicatif" = desde que (temporel). Ici, structure de concession avant une nuance critique → "quoique" (+ soient = subjonctif). Quoique ≠ quoi que (qui signifie "quoi qu\'il en soit"). Registre formel/académique.'},
  {t:'ee',mode:'fill',
   q:'Reformulez en utilisant le gérondif passé :\n\n« Après avoir achevé sa thèse, elle a publié un article remarqué.\n→ ___ sa thèse, elle a publié un article remarqué. »',
   a:'Ayant achevé',alt:['AYANT ACHEVÉ','Ayant acheve','AYANT ACHEVE'],
   e:'Gérondif passé (ou proposition participiale passée) = AYANT + participe passé. "Ayant achevé" = habiendo terminado / una vez terminada. Indique l\'antériorité par rapport à l\'action principale. "Après avoir + infinitif passé" est équivalent mais moins soutenu. Registre littéraire/académique C2.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec le terme stylistique correct :\n\n« "La mort le prit soudainement" est un exemple de ___, car "prendre" est employé à la place d\'un verbe plus direct. »\n(euphémisme / ellipse / hyperbole)',
   a:'euphémisme',alt:['EUPHÉMISME','EUPHEMISME','euphemisme'],
   e:'"Euphémisme" = eufemismo (atténuer une réalité dure par une expression plus douce). "La mort le prit" = el eufemismo para decir "il mourut brusquement". "Ellipse" = omisión de palabras. "Hyperbole" = exagération. La mort = réalité difficile → "le prendre" = image moins directe que "mourir". Reconnaître et nommer les figures de style = compétence C2.'},
  {t:'ee',mode:'fill',
   q:'Complétez avec la forme littéraire du conditionnel passé 2e forme :\n\n« S\'il ___ mieux préparé, il n\'aurait pas échoué. »',
   a:'eût été',alt:['EÛT ÉTÉ','eut été','EUT ETE','eût ete'],
   e:'Conditionnel passé 2e forme = subjonctif plus-que-parfait employé à la place du conditionnel passé. "S\'il eût été mieux préparé" = Si hubiera estado mejor preparado (irréel du passé, registre très soutenu). Équivalent courant : "S\'il avait été mieux préparé, il n\'aurait pas échoué." Forme littéraire présente dans les textes classiques et contemporains soutenu.'},
  {t:'ee',mode:'fill',
   q:'Identifiez la figure de style : « Il a des tonnes de travail. »\n\nCette phrase contient une ___ (figure d\'exagération).',
   a:'hyperbole',alt:['HYPERBOLE'],
   e:'"Hyperbole" = hipérbole (figura de exageración). "Des tonnes de travail" = une quantité irréelle pour exprimer l\'intensité. Autres hyperboles : "je meurs de faim", "c\'est à mourir de rire", "je t\'ai attendu une éternité". À distinguer de la litote (atténuation) et de l\'euphémisme (atténuation d\'une réalité difficile). L\'hyperbole intensifie ; la litote minimise.'},
  /* ── WRITE (11-20) ── */
  {t:'ee',mode:'write',
   q:'Rédigez un essai argumentatif dense (8-10 phrases) sur la question : « La littérature peut-elle changer le monde ? » Prenez position avec nuance et appuyez-vous sur des œuvres ou des auteurs précis.',
   prompt:'Présentez une thèse, développez-la avec 3 arguments illustrés par des exemples littéraires, anticipez une objection et répondez-y. Concluez en élargissant la réflexion.',
   criteria:['Thèse nuancée et argumentée','3 arguments distincts avec exemples littéraires réels ou vraisemblables','Anticipation et réfutation d\'une objection','Conclusion qui ouvre sur une réflexion plus large','Connecteurs de niveau C2 (or, partant, quoique, certes... mais)'],
   model:'La question de l\'efficacité politique de la littérature est l\'une des plus débattues de l\'histoire des idées. Il serait naïf d\'affirmer que la littérature change le monde de manière directe et mécanique ; or, il serait tout aussi simpliste de lui dénier toute portée transformatrice. Premièrement, certaines œuvres ont effectivement contribué à faire évoluer les mentalités : "La Case de l\'Oncle Tom" d\'Harriet Beecher Stowe a alimenté le mouvement abolitionniste américain, et "Les Misérables" de Victor Hugo a renforcé la conscience sociale de la misère urbaine au XIXe siècle. Deuxièmement, la littérature agit de manière indirecte, en élargissant l\'empathie du lecteur — elle lui permet d\'habiter des vies et des conditions qui ne sont pas les siennes, ce qui est le préalable à toute transformation politique sérieuse. Troisièmement, même sans portée immédiate, la littérature préserve des voix et des expériences que l\'histoire officielle aurait oubliées. Certes, on objectera que lire Proust n\'a jamais nourri un enfant pauvre. Mais cette objection confond les effets immédiats avec les transformations longues de la conscience collective. Partant, la littérature ne change pas le monde comme une loi le ferait — mais elle change ceux qui le lisent, et ce sont eux qui, parfois, changent le monde.',
   e:'Essai C2 : thèse + développement en 3 arguments illustrés + concession/réfutation + ouverture. Connecteurs C2 : "or" (transition-renversement), "partant" (conséquence formelle), "certes... mais" (concession), "quoique". Niveau d\'abstraction attendu : distinguer effets directs/indirects, courts termes/longs termes. Exemples réels = Stowe, Hugo (ou fictifs vraisemblables).'},
  {t:'ee',mode:'write',
   q:'Rédigez une critique de fond (8-9 phrases) d\'un essai fictif intitulé "La Société du spectacle retrouvée" qui prétend que les réseaux sociaux constituent l\'aboutissement de la thèse de Guy Debord. Évaluez la pertinence de cette thèse et ses limites.',
   prompt:'Présentez la thèse de l\'essai, montrez en quoi elle est pertinente, puis identifiez au moins deux limites argumentatives. Concluez sur l\'intérêt de l\'essai malgré ses limites.',
   criteria:['Thèse de l\'essai clairement restituée','Pertinence argumentée avec exemples','Au moins 2 limites identifiées et développées','Conclusion nuancée (ni totalement favorable ni défavorable)','Registre de critique académique soutenu'],
   model:'L\'essai de [auteur fictif] "La Société du spectacle retrouvée" défend l\'idée stimulante que les réseaux sociaux constituent la réalisation complète — voire le dépassement — de la thèse de Guy Debord selon laquelle la vie sociale se transforme en accumulation de spectacles. La démonstration est, dans ses grandes lignes, convaincante : l\'économie de l\'attention, la mise en scène permanente de soi sur Instagram, et la transformation de l\'expérience vécue en contenu monétisable semblent donner raison à Debord avec une acuité qu\'il n\'aurait peut-être pas anticipée. Cependant, deux limites importantes affaiblissent la démonstration. D\'abord, l\'auteur traite les utilisateurs comme de purs objets passifs du spectacle, occultant les pratiques de résistance, de détournement et d\'activisme que les mêmes plateformes rendent possibles. Ensuite, l\'homogénéisation du concept de "spectacle" — appliqué indifféremment à un selfie et à une propagande d\'État — dilue la précision analytique originale de Debord. Ces réserves faites, l\'essai a le mérite indéniable de relancer un débat théorique crucial et de montrer que la pensée situationniste garde une puissance heuristique réelle à l\'ère numérique.',
   e:'Critique académique C2 : restituer fidèlement + évaluer les forces + identifier les failles + conclure avec nuance. Guy Debord (1931-1994) = théoricien situationniste, "La Société du spectacle" (1967). "Heuristique" = heurístico (que permite descubrir/comprender). "Acuité" = agudeza. "Détournement" = terme situationniste = subversion des codes culturels.'},
  {t:'ee',mode:'write',
   q:'Rédigez une analyse rhétorique courte (7-9 phrases) d\'un discours fictif : « Citoyens, l\'histoire nous juge. Nous pouvons subir ce moment ou le façonner. Chaque silence est une complicité. Chaque acte, une signature. » Identifiez les figures de style et analysez leur effet.',
   prompt:'Nommez et analysez au moins 3 figures de style distinctes. Évaluez l\'effet rhétorique global du discours.',
   criteria:['Au moins 3 figures de style identifiées et correctement nommées','Analyse de l\'effet de chaque figure sur l\'auditoire','Évaluation globale de la rhétorique du discours','Registre d\'analyse stylistique maintenu','Cohérence et progression de l\'analyse'],
   model:'Ce bref extrait de discours politique mobilise un arsenal rhétorique dense pour produire un effet d\'urgence et de responsabilisation. En premier lieu, l\'apostrophe "Citoyens" (figure d\'adresse directe) instaure une relation de proximité et de co-responsabilité entre l\'orateur et son auditoire. L\'antithèse "subir ce moment ou le façonner" oppose la passivité à l\'action, contraignant l\'auditeur à se positionner dans l\'un ou l\'autre camp. La maxime "Chaque silence est une complicité" constitue une hyperbole morale : elle élève le silence au rang de faute active, produisant un effet culpabilisant efficace. Enfin, le parallélisme "Chaque silence... Chaque acte..." crée un rythme martelé qui renforce la mémorisation et l\'impact émotionnel. Sur le plan global, cette rhétorique fonctionne par accumulation de pression : chaque phrase resserre l\'étau de la responsabilité individuelle. L\'effet est puissant mais potentiellement manipulatoire, dans la mesure où il nie la complexité des situations en imposant une dichotomie tranchée entre la passivité coupable et l\'action vertueuse.',
   e:'Analyse rhétorique C2 : nommer les figures (apostrophe, antithèse, maxime, parallélisme, hyperbole) + analyser l\'effet (proximité, responsabilisation, culpabilisation, mémorisation) + évaluation globale. Registre : "mobilise un arsenal rhétorique", "resserre l\'étau de", "potentiellement manipulatoire". Niveau C2 = analyser ET évaluer, pas seulement identifier.'},
  {t:'ee',mode:'write',
   q:'Rédigez un texte de 8-9 phrases explorant la question : « Peut-on être moralement responsable de ce qu\'on ne sait pas ? » en vous appuyant sur un exemple concret (personnel ou de société).',
   prompt:'Construisez un argument rigoureux : définissez le cadre de la question, analysez un exemple, tirez une conclusion nuancée. Utilisez les structures logiques du français soutenu.',
   criteria:['Cadre de la question clairement posé','Exemple concret développé et analysé','Nuance : ni réponse simple oui ni non absolu','Au moins 2 structures C2 (subjonctif plus-que-parfait, conditionnel passé 2e forme, etc.)','Conclusion philosophique qui élargit la réflexion'],
   model:'La question de la responsabilité morale dans l\'ignorance est l\'une des plus délicates de l\'éthique. Dans sa formulation la plus simple, elle semble appeler une réponse négative : on ne saurait tenir quelqu\'un responsable de fautes qu\'il n\'eût pu anticiper. Pourtant, cette position soulève une difficulté : tout dépend de la nature de l\'ignorance. L\'ignorance involontaire — ne pas savoir ce qu\'on ne pouvait raisonnablement savoir — allège effectivement la responsabilité. Mais l\'ignorance volontaire — choisir de ne pas savoir pour éviter d\'avoir à agir — est une faute à part entière. L\'exemple de l\'acheteur de vêtements fabriqués dans des conditions d\'exploitation illustre ce dilemme : dans les années 1980, l\'ignorance du consommateur était acceptable ; aujourd\'hui, elle est un choix, car l\'information est disponible. En ce sens, nous sommes responsables de maintenir ouverts nos canaux d\'information et de ne pas cultiver sciemment notre propre cécité morale. "L\'ignorance choisie", pourrait-on dire, est la complicité par confort.',
   e:'Argumentation éthique C2 : "on ne saurait tenir responsable" = condicional de SAVOIR (muy formal). "Ne pas savoir ce qu\'on ne pouvait raisonnablement savoir" = cláusula de razonabilidad. "Ignorance volontaire" = ignorancia voluntaria (culpable). "Cécité morale" = ceguera moral. Structures C2 : "on ne saurait", "ne ... que", "en ce sens". Philosophes associés : Rawls (ignorance et justice), Arendt (banalité du mal et ignorance).'},
  {t:'ee',mode:'write',
   q:'Rédigez une entrée de glossaire critique (7-8 phrases) pour le terme « démocratie » tel qu\'il est utilisé dans le discours politique contemporain. Analysez les tensions et glissements de sens du terme.',
   prompt:'Ne donnez pas une simple définition. Explorez comment le terme est utilisé, contesté, instrumentalisé. Citez au moins deux usages contradictoires.',
   criteria:['Définition minimale suivie d\'une analyse critique','Au moins 2 usages contradictoires ou problématiques identifiés','Tension entre l\'idéal et la réalité du terme analysée','Registre encyclopédique et critique maintenu','Conclusion qui révèle la complexité sémantique du terme'],
   model:'Démocratie (n.f.) : du grec "demos" (peuple) et "kratos" (pouvoir). Dans son sens littéral, la démocratie désigne un régime politique dans lequel le pouvoir appartient au peuple. Cette définition, apparemment simple, se révèle extrêmement instable dès qu\'on l\'examine de près. D\'abord, qui est "le peuple" ? Historiquement, le terme a exclu les femmes, les esclaves, les étrangers — ceux qui étaient pourtant soumis au pouvoir. Ensuite, le terme est aujourd\'hui utilisé de manière contradictoire : la "démocratie libérale" insiste sur les droits individuels et la séparation des pouvoirs, tandis que certains régimes autoritaires se réclament de la "démocratie populaire" ou "illibérale" pour légitimer des majorités sans protection des minorités. Le terme est ainsi devenu un signifiant flottant, que chaque acteur politique s\'approprie selon ses intérêts. Cette instabilité sémantique n\'est pas le signe d\'une faiblesse conceptuelle, mais d\'un territoire symbolique qui est par nature contesté, car il touche aux questions les plus fondamentales du vivre-ensemble.',
   e:'Entrée de glossaire critique C2 : définition étymologique + analyse des tensions. "Signifiant flottant" = terme dont le sens est instable et approprié différemment selon les contextes (concept de Laclau). "Démocratie illibérale" = terme de Viktor Orbán (Hongrie). Structure : définition → instabilité → usages contradictoires → conclusion méta-sémantique.'},
  {t:'ee',mode:'write',
   q:'Traduisez cette idée en un texte argumentatif court (7-8 phrases) : « L\'oubli est nécessaire à la mémoire. » Développez le paradoxe apparent et montrez en quoi il est fécond.',
   prompt:'Clarifiez d\'abord en quoi l\'affirmation est paradoxale, puis montrez pourquoi ce paradoxe est en réalité une vérité profonde. Appuyez-vous sur des exemples (psychologiques, historiques ou littéraires).',
   criteria:['Le paradoxe apparent clairement exposé','Résolution du paradoxe argumentée','Exemples pertinents (psychologie, mémoire collective, littérature)','Style C2 : formulations abstraites + images concrètes','Conclusion synthétique et mémorable'],
   model:'L\'affirmation "l\'oubli est nécessaire à la mémoire" semble, au premier abord, auto-contradictoire : comment ce qui nie la mémoire pourrait-il la servir ? Pourtant, cette tension est en réalité féconde. Sur le plan neurologique, le cerveau n\'est pas une archive exhaustive : il sélectionne, consolide et efface en permanence — et c\'est précisément cette sélection qui permet de constituer des souvenirs significatifs plutôt qu\'un flot indifférencié d\'information. "Funes el memorioso", la nouvelle de Borges, illustre magistralement ce paradoxe : le personnage, incapable d\'oublier le moindre détail, est paralysé, incapable de penser — car penser, c\'est abstraire, et abstraire, c\'est oublier les particularités. Sur le plan collectif, Ricœur soulignait qu\'un certain "oubli nécessaire" permet à une société meurtrie de se reconstruire sans être engloutie par le passé. L\'oubli n\'est donc pas l\'ennemi de la mémoire, mais son condition : il en trie la matière première. Sans lui, la mémoire ne serait qu\'une saturation sans forme.',
   e:'"Funes el memorioso" (Jorge Luis Borges, 1944) = personnage qui ne peut oublier → paralysé. Référence C2. Paul Ricœur (philosophe, "oubli nécessaire"). "Abstraire" = abstraer. "Flot indifférencié" = flujo indiferenciado. "Saturation sans forme" = image finale synthétique. Structure : paradoxe apparent → résolution neurologique → exemple littéraire → exemple historique → conclusion synthétique.'},
  {t:'ee',mode:'write',
   q:'Rédigez une note critique (7-8 phrases) sur l\'usage du mot « identité » dans le débat politique contemporain. Analysez comment ce terme peut être utilisé à des fins contradictoires.',
   prompt:'Distinguez au moins 3 sens ou usages différents du terme. Montrez comment ces usages révèlent des présupposés idéologiques divergents.',
   criteria:['Au moins 3 sens ou usages du terme identifiés','Présupposés idéologiques de chaque usage analysés','Tension entre identité fixe et identité construite abordée','Registre d\'analyse critique du discours maintenu','Conclusion qui révèle la complexité politique du terme'],
   model:'Le terme "identité" est l\'un des plus utilisés — et des plus instrumentalisés — du débat politique contemporain, au point qu\'il est devenu difficile de s\'y retrouver. Dans un premier sens, l\'identité désigne l\'ensemble des caractéristiques stables qui définissent un individu ou un groupe (identité nationale, culturelle, religieuse) : c\'est l\'identité comme essence, conçue comme fixe et transmissible. Dans un second sens, hérité des théories postmodernes et des études de genre, l\'identité est une construction, une performance — elle n\'est pas donnée mais produite et négociée en permanence. Ces deux sens entrent en tension frontale dans les débats sur l\'immigration ou le mariage pour tous : les uns invoquent une identité essentialiste à "protéger", les autres une identité fluide à "reconnaître". Un troisième usage — l\'identité comme outil de mobilisation politique — apparaît dans ce qu\'on appelle la "politique identitaire" : chaque groupe (femmes, LGBTQ+, minorités ethniques) revendique une identité collective pour demander des droits. Ces trois usages ne sont pas simplement des définitions alternatives, mais des prises de position idéologiques sur ce que signifie être un être humain dans une société. Qui contrôle le sens du mot "identité" contrôle, dans une large mesure, les termes du débat politique.',
   e:'Analyse critique du discours C2 : "instrumentalisé" = instrumentalizado. "Identité essentialiste" = identidad esencialista (fija, dada). "Identité performative" = identidad performativa (Butler). "Politique identitaire" = identity politics. "Usages ne sont pas des définitions alternatives, mais des prises de position idéologiques" = analysis metalinguistique de niveau C2.'},
  {t:'ee',mode:'write',
   q:'Rédigez un fragment de réflexion intime (7-8 phrases) à la manière d\'un essai personnel (à la Montaigne), sur l\'expérience du doute. Utilisez la première personne et un style à la fois personnel et universel.',
   prompt:'Mêlez observation personnelle et réflexion générale. Utilisez des formules caractéristiques de l\'essai personnel : "j\'ai toujours...", "il me semble que...", "peut-être est-ce là...". Concluez par une formule mémorable.',
   criteria:['Première personne et ton intime maintenus','Réflexion qui passe du particulier au général','Au moins une observation personnelle concrète','Style essayistique : phrases variées, images, formules réflexives','Conclusion mémorable et condensée'],
   model:'J\'ai toujours entretenu avec le doute une relation ambiguë. Il y a des jours où le doute me semble le luxe des gens qui ont le temps de ne pas décider ; et d\'autres où il m\'apparaît comme la seule posture intellectuellement honnête dans un monde trop prompt à la certitude. Montaigne écrivait : "Que sais-je ?" — non pas pour avouer une ignorance définitive, mais pour garder la question ouverte, comme on maintient une fenêtre entrebâillée dans une pièce trop close. Le doute, à ce titre, n\'est pas l\'opposé de la conviction : il en est la condition. Car une conviction qui n\'a jamais traversé le doute est moins une certitude qu\'une peur déguisée. Ce que j\'ai appris de longues années de lecture et de tâtonnements intellectuels, c\'est que les personnes les plus sûres d\'elles sont souvent les moins fiables — et que ceux qui doutent le plus travaillent davantage à comprendre. Peut-être est-ce là la seule sagesse à laquelle on puisse prétendre : non pas avoir raison, mais rester digne de la question.',
   e:'Essai personnel à la Montaigne C2 : "Que sais-je ?" (devise de Montaigne). Style : phrases longues + brèves alternées, images ("fenêtre entrebâillée"), paradoxes ("le doute... condition de la conviction"). Formules essayistiques : "j\'ai toujours", "il y a des jours où", "peut-être est-ce là". Clôture mémorable = formule condensée et universelle. Registre : intime + universel = marque de l\'essai personnel C2.'},
  {t:'ee',mode:'write',
   q:'Rédigez un commentaire composé court (8-9 phrases) du vers de Rimbaud : « Je est un autre. » Analysez le sens grammatical, philosophique et poétique de cette formule.',
   prompt:'Commencez par le paradoxe grammatical, passez au sens philosophique et terminez par la portée poétique. Montrez comment cette formule condense une révolution littéraire.',
   criteria:['Analyse grammaticale du paradoxe (accord "Je est")','Sens philosophique développé (identité, altérité)','Portée poétique et littéraire expliquée','Mise en perspective avec le contexte du symbolisme','Formulation synthétique et mémorable en conclusion'],
   model:'La formule de Rimbaud, extraite d\'une lettre de 1871 connue sous le nom de "Lettre du voyant", concentre en trois mots une révolution philosophique et poétique d\'une densité rare. Sur le plan grammatical, l\'accord "Je EST" viole délibérément la règle de la conjugaison (on attend "je suis") : Rimbaud traite le "je" comme un sujet extérieur à lui-même, comme si la conscience était un objet observable de l\'extérieur. Sur le plan philosophique, cette formule anticipe les théories modernes de l\'identité fragmentée : le moi n\'est pas une unité stable, mais un lieu traversé par des forces qui lui sont étrangères. Rimbaud préfigure ainsi Lacan ("le moi est une fiction") et les théories de l\'altérité constitutive du sujet. Sur le plan poétique, cette phrase-manifeste fonde la conception rimbaldienne du poète comme médium passif : "Je est un autre" signifie que la création poétique n\'est pas le produit de la volonté personnelle, mais d\'une dépossession de soi. En renversant la grammaire elle-même, Rimbaud montre que la langue ordinaire est insuffisante pour dire l\'expérience intérieure — et que la poésie doit briser ses règles pour atteindre ce que la prose ne peut nommer.',
   e:'"Je est un autre" (Lettre du voyant, mai 1871) = formule fondatrice du symbolisme/surréalisme. Lacan = psychanalyste français ("le moi est une fiction"). "Médium passif" = instrumento pasivo de la creación. "Dépossession de soi" = despojo de sí mismo. Violation grammaticale intentionnelle = geste poétique. Commentaire composé C2 = 3 axes (grammatical → philosophique → poétique) avec progression.'},
  {t:'ee',mode:'write',
   q:'Rédigez une synthèse de documents fictifs (8-9 phrases) à partir des informations suivantes : (1) Un rapport scientifique indique que 45 % des emplois actuels sont automatisables d\'ici 20 ans. (2) Un philosophe argüe que le travail n\'est pas seulement économique mais constitutif de l\'identité humaine. (3) Un économiste propose le revenu universel comme solution. Dites en quoi ces trois sources se complètent et divergent.',
   prompt:'Ne résumez pas chaque source séparément. Faites dialoguer les trois positions autour d\'une problématique centrale : que signifie le travail pour l\'être humain si les machines peuvent le faire à sa place ?',
   criteria:['Problématique centrale clairement posée','Les trois sources mises en dialogue (pas résumées séparément)','Points de convergence et de divergence identifiés','Prise de position personnelle nuancée en fin de synthèse','Connecteurs de synthèse C2 utilisés'],
   model:'Ces trois documents converge nt autour d\'une même question abyssale : si les machines peuvent faire notre travail, qu\'est-ce que cela révèle sur ce que nous sommes ? Le rapport scientifique pose les termes du problème avec une froideur implacable : 45 % des emplois actuels pourraient disparaître — chiffre dont la banalisation ne doit pas masquer l\'ampleur des bouleversements humains qu\'il préfigure. Là où l\'économiste se satisfait d\'une solution redistributive (le revenu universel), le philosophe soulève une objection plus fondamentale : si le travail est constitutif de l\'identité humaine, le supprimer — même en donnant de l\'argent à sa place — ne résout pas la question du sens. Or, c\'est précisément là que les deux positions divergent : l\'économiste traite le travail comme un moyen (produire, gagner) ; le philosophe le conçoit comme une fin (se réaliser, contribuer). La synthèse que ces documents appellent est peut-être celle-ci : avant de décider comment compenser la perte du travail, il faudrait décider ce que nous entendons par là — et ce que nous voulons en faire.',
   e:'Synthèse C2 : faire dialoguer les sources ≠ résumer. "Ces trois documents convergent" = connecteur de synthèse. "Question abyssale" = question sin fondo/sin respuesta fácil. "Banalisation ne doit pas masquer" = critique méta-discursive. Divergence-clé : travail comme moyen (économiste) vs comme fin (philosophe). Conclusion : problématiser le problème = marque du niveau C2 en expression écrite.'},
],

/* ──────────── C2 · EO ──────────── */
EO_C2: [
  /* ── REPEAT (1-8) ── */
  {t:'eo',mode:'repeat',q:'Répétez cet extrait de discours philosophique en articulant avec précision chaque terme et en maintenant le rythme de la phrase :',model:'Si l\'on admet, avec Hegel, que la conscience de soi ne se constitue que par la médiation du regard de l\'autre, alors toute philosophie de l\'identité est nécessairement une philosophie de la relation.',keywords:['conscience','médiation','regard','philosophie','relation'],e:'"Si l\'on admet, avec Hegel" = si se admite, con Hegel. "Médiation du regard de l\'autre" = mediación de la mirada del otro (Hegel → Sartre). "Ne se constitue que par" = ne se constitue QUE par = solamente se constituye a través de. Structure conditionnelle + conséquence philosophique. Rythme : longue pause après "Hegel", descente sur "relation".'},
  {t:'eo',mode:'repeat',q:'Répétez cet extrait de critique littéraire complexe en articulant les groupes nominaux :',model:'Ce que Proust donne à voir, ce n\'est pas tant la biographie d\'un narrateur que la topographie mouvante d\'une conscience aux prises avec l\'irrémédiable fuite du temps.',keywords:['Proust','biographie','topographie','conscience','irrémédiable'],e:'"Ce que... ce n\'est pas tant X que Y" = structure de correction en registre soutenu. "Topographie mouvante" = topografía cambiante. "Aux prises avec" = en lucha contra / haciendo frente a. "L\'irrémédiable fuite du temps" = la irremedable fuga del tiempo. Prononciation : liaisons obligatoires "aux_prises", "irrémédiable_fuite". Rythme pensif et littéraire.'},
  {t:'eo',mode:'repeat',q:'Répétez cette maxime philosophique développée en registre très soutenu :',model:'L\'homme est condamné à être libre, non parce que la liberté serait un don, mais parce que nul ne peut se soustraire à la nécessité de choisir — et qu\'ainsi, l\'abstention elle-même est un choix.',keywords:['condamné','liberté','soustraire','abstention','choix'],e:'"Condamné à être libre" = condenado a ser libre (Sartre). "Nul ne peut se soustraire à" = nadie puede sustraerse a. "L\'abstention elle-même est un choix" = la abstención misma es una elección. "Ainsi" (connecteur de conséquence) = así. Structure : affirmation → explication par la négative → conséquence paradoxale. Insister sur "nul" et "ainsi".'},
  {t:'eo',mode:'repeat',q:'Répétez cet énoncé de critique institutionnelle avec le ton d\'un intellectuel engagé :',model:'Il est profondément symptomatique que les institutions qui prétendent le plus haut et le plus fort défendre la liberté d\'expression soient précisément celles qui en délimitent le plus jalousement les contours.',keywords:['symptomatique','institutions','prétendent','liberté','jalousement'],e:'"Symptomatique" = sintomático (révèle quelque chose de caché). "Prétendre + haut et fort" = proclamar en voz alta. "Délimiter jalousement" = delimitar celosamente. Structure : "Il est symptomatique que + subjonctif" → "soient" (subjonctif de ÊTRE). Paradoxe : défenseurs officiels de la liberté = ses premiers censeurs. Ton : détaché mais critique.'},
  {t:'eo',mode:'repeat',q:'Répétez cet extrait d\'un texte de Simone de Beauvoir en soignant l\'intonation :',model:'On ne naît pas femme, on le devient. Aucun destin biologique, psychique, économique ne définit la figure que revêt au sein de la société la femelle humaine ; c\'est l\'ensemble de la civilisation qui élabore ce produit intermédiaire entre le mâle et le castrat qu\'on qualifie de féminin.',keywords:['naît','devient','destin','civilisation','féminin'],e:'Citation célèbre de "Le Deuxième Sexe" (1949). "Revêtir" = revestir/adoptar. "Le castrat" = el castrado (terme provocateur de Beauvoir). "Ce produit intermédiaire... qu\'on qualifie de féminin" = esta construcción intermedia que se denomina femenino. Beauvoir refuse toute essence naturelle du "féminin" : tout est construction culturelle. Intonation : première phrase brève et percutante ; deuxième phrase : longue, analytique.'},
  {t:'eo',mode:'repeat',q:'Répétez cet énoncé en registre diplomatique très formel, en marquant les modalisateurs :',model:'Sans préjuger des conclusions auxquelles la commission d\'enquête pourrait être amenée, il nous paraît néanmoins souhaitable que les parties concernées s\'engagent, dans les meilleurs délais, dans un processus de dialogue constructif.',keywords:['préjuger','commission','néanmoins','souhaitable','constructif'],e:'"Sans préjuger de" = sin prejuzgar/sin anticipar. "Pourrait être amenée" = podría verse llevada a. "Il nous paraît souhaitable que + subjonctif" = nos parece deseable que. "Dans les meilleurs délais" = a la mayor brevedad. Style diplomatique : modalisateurs ("pourrait", "il nous paraît", "souhaitable") pour ménager toutes les parties. Vocabulaire de la diplomatie C2.'},
  {t:'eo',mode:'repeat',q:'Répétez cet énoncé ironique avec le ton et la distance qui conviennent :',model:'Il est réjouissant de constater avec quelle constance les mêmes erreurs de gouvernance sont répétées d\'une génération à l\'autre, comme si chaque nouveau gouvernement avait pour mission secrète de réinventer, avec une application remarquable, tous les échecs de ses prédécesseurs.',keywords:['réjouissant','constance','gouvernance','réinventer','prédécesseurs'],e:'"Réjouissant" = reconfortante/¡qué alegría! (ici ironique : le contraire est vrai). "Avec quelle constance" = con qué constancia (exclamation indirecte). "Comme si + imparfait" = como si (irréel). "Application remarquable" = esmero notable (ironique). L\'ironie repose sur l\'écart entre les mots élogieux et la réalité négative. Maintenir un ton faussement enthousiaste = défi C2.'},
  {t:'eo',mode:'repeat',q:'Répétez cet extrait d\'introduction académique en articulant clairement la structure argumentative :',model:'La présente étude se propose d\'examiner, dans une perspective interdisciplinaire, les conditions d\'émergence du concept de dignité humaine dans la pensée juridique contemporaine, en interrogeant notamment les tensions qui existent entre son fondement universaliste et ses applications nécessairement contextuelles.',keywords:['propose','interdisciplinaire','dignité','universaliste','contextuelles'],e:'"Se propose d\'examiner" = se propone examinar (intention formelle). "Dans une perspective interdisciplinaire" = desde una perspectiva interdisciplinar. "Conditions d\'émergence" = condiciones de emergencia. "Fondement universaliste" = fundamento universalista. "Applications contextuelles" = aplicaciones contextuales. Registre académique C2 : chaque phrase énonce une intention, un cadre et une problématique.'},
  /* ── ANSWER (9-15) ── */
  {t:'eo',mode:'answer',q:'Analysez oralement la distinction que Sartre fait entre l\'existence et l\'essence, et dites pourquoi elle a des implications éthiques fondamentales.',model:'Selon Sartre, l\'existence précède l\'essence, ce qui signifie... Contrairement à la tradition philosophique qui... Les implications éthiques sont considérables : si... alors...',keywords:['existence','essence','liberté','responsabilité','Sartre'],e:'Sartre (1905-1980) : "L\'existence précède l\'essence" = renversement de la tradition (Dieu/nature donnait d\'abord une essence, puis l\'homme existait). Pour Sartre : l\'homme existe d\'abord, puis se définit par ses actes. Conséquence éthique : responsabilité totale = "nous sommes condamnés à être libres". Implications : pas d\'excuse (nature, Dieu, inconscient) = radical pour la morale. "En mauvaise foi" (bad faith) = se mentir à soi-même en niant sa liberté.'},
  {t:'eo',mode:'answer',q:'Développez oralement votre interprétation de la déconstruction derridienne. En quoi remet-elle en question les certitudes des textes philosophiques classiques ?',model:'La déconstruction, telle que Derrida la pratique, consiste à... Elle révèle que les textes philosophiques contiennent... Ce qui est fondamental dans cette approche, c\'est...',keywords:['déconstruction','Derrida','texte','hiérarchies','contradictions'],e:'Derrida (1930-2004) : "lire contre le grain". La déconstruction révèle les hiérarchies implicites (présence vs absence, parole vs écriture), les contradictions et les suppléments que le texte cherche à dissimuler. "Différance" = terme inventé par Derrida (différer + différence). "Logocentrisme" = biais de la tradition occidentale qui privilégie la parole sur l\'écriture. La déconstruction ≠ nihilisme : elle donne plus de richesse au texte en révélant sa complexité.'},
  {t:'eo',mode:'answer',q:'Commentez oralement cette affirmation de Roland Barthes : « La littérature, c\'est ce qui s\'enseigne. » Êtes-vous d\'accord ? Développez une analyse nuancée.',model:'Cette formule provocatrice de Barthes suggère que... D\'un côté, elle révèle... De l\'autre, on peut lui reprocher... Ma propre position est que...',keywords:['littérature','enseignement','canon','institution','Barthes'],e:'Barthes : la littérature est définie par son enseignement, pas par une essence. "Canon littéraire" = corpus oficial de textos reconocidos. Implication : la littérature est une construction institutionnelle, pas une donnée naturelle. Ce qui est enseigné dans les lycées = "la" littérature. Critique possible : réducteur (quid de la littérature populaire, des littératures marginales ?) ; ou au contraire, révélateur (la valeur littéraire est socialement produite).'},
  {t:'eo',mode:'answer',q:'Développez oralement votre analyse de la notion de « bien commun » dans les sociétés libérales contemporaines. Est-elle compatible avec l\'individualisme libéral ?',model:'La notion de bien commun pose une tension fondamentale avec l\'individualisme libéral. D\'un côté... De l\'autre... La question est de savoir si...',keywords:['bien commun','individualisme','libéralisme','tension','société'],e:'"Bien commun" = bien común (lo que beneficia a todos). Tension avec le libéralisme : le libéralisme valorise les droits individuels ; le bien commun peut exiger des sacrifices individuels (impôts, vaccination obligatoire, restrictions de liberté). Philosophes : John Rawls ("voile d\'ignorance"), John Stuart Mill (utilité maximale), Amartya Sen (capacités). Question C2 : peut-on concilier liberté individuelle et bien collectif sans dériver vers le totalitarisme ou l\'égoïsme absolu ?'},
  {t:'eo',mode:'answer',q:'Donnez oralement votre analyse de la phrase de Pascal : « Le cœur a ses raisons que la raison ne connaît point. » En quoi cette formule illustre-t-elle la complexité de la vie intérieure humaine ?',model:'Cette formule de Pascal articule une tension fondamentale entre... D\'un côté, la "raison" au sens cartésien... De l\'autre, le "cœur" représente... Ce qui me semble profond dans cette formule, c\'est...',keywords:['Pascal','cœur','raison','sentiment','tension'],e:'Pascal (1623-1662), "Pensées". "Raison" = lógica, razón demostrativa. "Cœur" = intuition, sentiment, foi. Pascal ≠ irrationaliste : il reconnaît deux ordres de vérité. "Ordre du cœur" vs "ordre de la raison". Implications : les vérités les plus profondes (amour, foi, amitié) ne se prouvent pas — elles se vivent. Lien avec les neurosciences (Damasio : les émotions sont nécessaires à la décision rationnelle).'},
  {t:'eo',mode:'answer',q:'Analysez oralement la place de l\'ironie dans la pensée critique française, en vous appuyant sur des exemples précis (Voltaire, Flaubert, ou un auteur contemporain de votre choix).',model:'L\'ironie occupe une place centrale dans la tradition intellectuelle française, notamment parce que... Voltaire, dans "Candide", utilise l\'ironie pour... Flaubert, lui, développe une ironie... Cette tradition se prolonge dans...',keywords:['ironie','Voltaire','Flaubert','critique','tradition'],e:'Ironie française = outil d\'analyse sociale et politique depuis les Lumières. Voltaire ("Candide") = ironie narrative. Flaubert ("Bouvard et Pécuchet") = ironie de la bêtise humaine (dénonce la sottise par accumulation). Flaubert a le "gueuloir" pour tester ses phrases. Auteurs contemporains : Michel Houellebecq (ironie froide, nihiliste), Annie Ernaux (ironie sociale). "La tradition de l\'ironie française" = tradition de pensée critique par le décalage entre signe et signifié.'},
  {t:'eo',mode:'answer',q:'Présentez oralement votre conception de l\'idéal de « l\'honnête homme » du XVIIe siècle français, et dites dans quelle mesure cet idéal est encore pertinent ou révélateur pour comprendre certaines valeurs culturelles françaises contemporaines.',model:'L\'idéal de l\'"honnête homme" au XVIIe siècle était... Il incarnait des valeurs comme... Ce qui est intéressant, c\'est que cet idéal révèle encore aujourd\'hui... Cependant, ses limites étaient...',keywords:['honnête homme','XVIIe','idéal','culture','valeurs'],e:'"L\'honnête homme" (XVIIe siècle) = idéal de l\'aristocrate cultivé : maîtrise des arts, de la conversation, de la galanterie, mais sans excès de spécialisation. "Il faut qu\'il sache un peu de tout et n\'approfondisse rien" (Pascal). Lien contemporain : le généralisme, le goût pour les "grandes questions", la méfiance française envers le spécialisme excessif. Limites : exclusivement masculin, aristocratique, élitiste. Héritage : le modèle des "intellectuels publics" à la française (Sartre, Camus, Bourdieu).'},
  /* ── PRODUCE (16-20) ── */
  {t:'eo',mode:'produce',q:'Développez oralement (2-3 minutes) une réflexion philosophique sur la question : « Peut-on vivre sans croire à quelque chose ? » Construisez un argument rigoureux avec thèse, développement et conclusion.',model:'Cette question touche à ce que les philosophes appellent le besoin de sens. Je défendrais l\'idée que... Premièrement... Deuxièmement... Cependant, il convient de nuancer... En conclusion...',keywords:['croire','sens','illusion','nécessaire','humain'],e:'Réflexion sur la croyance et le sens C2 : "besoin de sens" = necesidad de sentido. Arguments possibles : la croyance (religieuse, idéologique, affective) comme condition de l\'action humaine ; sans croyance minimale (en autrui, en l\'avenir, en la valeur de ses actes), l\'action paraît absurde. Camus : "l\'homme absurde" qui agit malgré l\'absence de sens. Nietzsche : "Dieu est mort" → crise de sens → nihilisme puis réévaluation des valeurs. Nuance : distinguer croyance et certitude.'},
  {t:'eo',mode:'produce',q:'Présentez oralement (2-3 minutes) votre analyse d\'un problème éthique contemporain lié à la biotechnologie (clonage, modification génétique, intelligence artificielle consciencieuse). Développez les enjeux, les positions en présence et votre propre jugement motivé.',model:'Le problème éthique que je choisis d\'analyser est... Il se pose de la manière suivante... Les positions en présence sont... Pour ma part, je pense que...',keywords:['éthique','biotechnologie','enjeux','positions','jugement'],e:'Éthique de la biotechnologie C2 : distinction entre "jouer à Dieu" (argument religieux/naturel) et "étendre les capacités humaines" (transhumanisme). Hans Jonas : "principe responsabilité" (agir en tenant compte des effets à long terme sur les générations futures). "CRISPR-Cas9" = édition génomique. "Intelligence artificielle généralisée" = IA qui égalerait ou dépasserait l\'intelligence humaine. "Principe de précaution" = principe de precaución. Enjeux : consentement, équité d\'accès, brevetabilité du vivant.'},
  {t:'eo',mode:'produce',q:'Improvisez oralement (2-3 minutes) un commentaire sur cette affirmation de Simone Weil : « L\'attention est la forme la plus rare et la plus pure de la générosité. » Développez le sens, les implications et une réflexion personnelle.',model:'Cette affirmation de Simone Weil touche à quelque chose de profond sur... "L\'attention" ici ne signifie pas seulement... Elle implique... Ce qui me frappe dans cette formule, c\'est...',keywords:['attention','générosité','Weil','présence','rare'],e:'Simone Weil (1909-1943) = philosophe, mystique et militante française. "L\'attention" = présence totale à l\'autre, sans jugement, sans projet. "La forme la plus pure de la générosité" = donner du temps de présence, pas seulement de l\'argent ou des actes. Lien : philosophie du care (Noddings, Gilligan) → l\'attention à l\'autre comme fondement de l\'éthique. "Rare" = dans un monde de distraction permanente, l\'attention devient un cadeau extraordinaire. Personnel : connecter à une expérience d\'avoir été vraiment écouté/écoutée.'},
  {t:'eo',mode:'produce',q:'Présentez oralement (2-3 minutes) une analyse comparative de deux conceptions de la justice : la justice distributive d\'Aristote et la justice comme équité de Rawls. Dites laquelle vous paraît la plus pertinente pour les sociétés contemporaines.',model:'Aristote concevait la justice comme... Rawls, dans "Théorie de la justice", propose une conception différente... Ce qui distingue fondamentalement ces deux approches est... Pour les sociétés contemporaines, je pense que...',keywords:['justice','Aristote','Rawls','distributive','équité'],e:'Aristote : justice distributive = donner à chacun selon son mérite (proportionnalité). Rawls (1921-2002) : "Théorie de la justice" (1971). "Voile d\'ignorance" = vélo d\'ignorancia : si on ignorait notre position sociale, on choisirait les principes les plus favorables aux plus défavorisés. "Principe de différence" = les inégalités sont justes seulement si elles profitent aux moins favorisés. Pertinence contemporaine : Rawls = plus adapté aux sociétés pluralistes (pas de consensus sur le "mérite"). Aristote = risque de naturaliser les hiérarchies existantes.'},
  {t:'eo',mode:'produce',q:'Clôturez ce parcours de langue française en développant oralement (2-3 minutes) votre réflexion personnelle sur cette question : « Qu\'est-ce que maîtriser une langue étrangère dit de soi ? » Appuyez-vous sur votre propre expérience d\'apprentissage du français.',model:'Maîtriser une langue étrangère, c\'est bien plus qu\'acquérir un outil de communication. C\'est... Pour moi, apprendre le français a signifié... Ce que cette expérience m\'a appris sur moi-même, c\'est...',keywords:['maîtriser','langue','identité','expérience','transformation'],e:'Réflexion méta-linguistique et identitaire C2 : "maîtriser une langue" = dominar un idioma. Dimensions : cognitive (pensée dans une autre langue), identitaire (se voir autrement), culturelle (accéder à un autre imaginaire), relationnelle (se lier à d\'autres locuteurs). Wittgenstein : "Les limites de mon langage sont les limites de mon monde." Apprendre une langue = repousser les limites de son monde. Réflexion personnelle = authenticité + profondeur = exigence maximale du C2 oral.'},
],

}; // end QUESTIONS
